window.ITLS_DATA = {"manifest":{"id":"itls","title":"ITLS — International Trauma Life Support","subtitle":"The Ultimate Provider Course Reviewer","version":"1.0.0","edition":"Based on ITLS 8th Edition curriculum","description":"A comprehensive, self-contained study reviewer for prehospital trauma care. Each chapter includes a concise summary, clinical pearls, red flags, common mistakes, memory aids, decision trees, high-yield flashcards, NREMT/ITLS-style quiz questions, and realistic EMS scenarios. Designed for EMTs, Paramedics, Emergency Nurses, and nursing students preparing for ITLS Provider certification.","icon":"trauma-cross","color":"#c8102e","accentColor":"#1f6feb","estimatedHours":24,"difficulty":"Intermediate to Advanced","certification":"ITLS Provider","examLink":"https://www.itrauma.org/","audience":["EMT","AEMT","Paramedic","Emergency Nurse","Nursing Student"],"prerequisites":["Current EMS or nursing certification/licensure","Basic anatomy and physiology","BLS / CPR provider competency"],"contentTypes":["summary","flashcards","quizzes","scenarios","algorithms","tables"],"chapters":[{"id":"c01","number":1,"title":"Scene Size-Up","section":"Assessment","difficulty":"Intermediate"},{"id":"c02","number":2,"title":"Trauma Assessment and Management","section":"Assessment","difficulty":"Intermediate"},{"id":"c03","number":3,"title":"ITLS Primary and Secondary Survey (Skills)","section":"Assessment","difficulty":"Intermediate"},{"id":"c04","number":4,"title":"Airway Management","section":"Airway & Breathing","difficulty":"Intermediate"},{"id":"c05","number":5,"title":"Airway Management Skills","section":"Airway & Breathing","difficulty":"Advanced"},{"id":"c06","number":6,"title":"Thoracic Trauma","section":"Airway & Breathing","difficulty":"Advanced"},{"id":"c07","number":7,"title":"Thoracic Trauma Skills (Needle Decompression)","section":"Airway & Breathing","difficulty":"Advanced"},{"id":"c08","number":8,"title":"Shock","section":"Circulation","difficulty":"Advanced"},{"id":"c09","number":9,"title":"Vascular Access Skills (IV / IO)","section":"Circulation","difficulty":"Intermediate"},{"id":"c10","number":10,"title":"Head Trauma and Traumatic Brain Injury","section":"Disability","difficulty":"Advanced"},{"id":"c11","number":11,"title":"Spinal Trauma","section":"Disability","difficulty":"Advanced"},{"id":"c12","number":12,"title":"Spinal Motion Restriction Skills","section":"Disability","difficulty":"Intermediate"},{"id":"c13","number":13,"title":"Abdominal Trauma","section":"Regional Trauma","difficulty":"Intermediate"},{"id":"c14","number":14,"title":"Extremity Trauma","section":"Regional Trauma","difficulty":"Intermediate"},{"id":"c15","number":15,"title":"Extremity Trauma Skills (Traction Splinting)","section":"Regional Trauma","difficulty":"Intermediate"},{"id":"c16","number":16,"title":"Burns","section":"Regional Trauma","difficulty":"Advanced"},{"id":"c17","number":17,"title":"Pediatric Trauma","section":"Special Populations","difficulty":"Advanced"},{"id":"c18","number":18,"title":"Geriatric Trauma","section":"Special Populations","difficulty":"Intermediate"},{"id":"c19","number":19,"title":"Trauma in Pregnancy","section":"Special Populations","difficulty":"Advanced"},{"id":"c20","number":20,"title":"The Impaired Patient","section":"Special Populations","difficulty":"Intermediate"},{"id":"c21","number":21,"title":"Trauma Arrest","section":"Special Populations","difficulty":"Advanced"},{"id":"c22","number":22,"title":"Standard and Transmission-Based Precautions","section":"Provider Safety","difficulty":"Intermediate"}]},"chapters":{"c01":{"id":"c01","title":"Scene Size-Up in Trauma Care: A Comprehensive Guide for Emergency Providers","shortTitle":"Scene Size-Up","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Discuss the steps of the scene size-up.","List the two basic mechanisms of motion injury.","Identify the three collisions associated with a motor-vehicle collision (MVC) and relate potential patient injuries to deformity of the vehicle, interior structures, and body structures.","Name the five common forms of MVCs.","Describe potential injuries from proper and improper use of seat restraints, headrests, and air bags in a head-on collision.","Describe potential injuries from rear-end collisions.","Describe the three assessment criteria for falls and relate them to anticipated injuries.","Identify the two most common forms of penetrating injuries and discuss associated mechanisms and extent of injuries.","Relate five injury mechanisms involved in blast injuries and how they relate to scene size-up and patient assessment."],"summary":[{"title":"Scene Size-Up Overview","content":"Scene size-up is the first step in the ITLS Primary survey. It involves taking standard precautions, evaluating the scene for dangers, determining the total number of patients, identifying essential equipment needed, and recognizing mechanisms of injuries. This process helps prevent exposure to blood and other potentially infectious materials and ensures patient safety."},{"title":"Standard Precautions","content":"Emergency care providers must take standard precautions such as wearing gloves, using a face shield in many situations, and sometimes protective gowns or chemical suits. These measures are crucial for preventing exposure to blood and other potentially infectious materials (OPIM)."},{"title":"Scene Safety","content":"Before approaching the patient, assess the scene for potential dangers such as fire, toxic substances, unstable structures, low oxygen levels, or hazardous chemicals. Determine a safe place to park the ambulance and decide if it is safe to approach the patient."},{"title":"Total Number of Patients","content":"Determine the total number of patients present at the scene. If more than one patient is involved, call for additional resources and establish medical command or multiple-casualty incident (MCI) protocols. Carefully evaluate the scene to ensure all patients are accounted for."},{"title":"Essential Equipment","content":"Carry essential equipment such as personal protective equipment, patient transport devices, oxygen and airway equipment, trauma boxes, and special extrication tools if needed. Ensure that you have enough resources to handle the number of patients present."},{"title":"Mechanism of Injury (MOI)","content":"Assess the mechanism of injury by considering factors such as direction and speed of impact, patient kinetics, physical size, and signs of energy release. This information helps predict potential injuries and guide further assessment."}],"clinicalPearls":["Always wear personal protective equipment (PPE) to prevent exposure to blood and other potentially infectious materials.","Be aware that a high-energy event may result in severe injuries even if the patient initially appears stable.","Use the three-collision concept when assessing MVCs: machine collision, body collision, and organ collision."],"redFlags":["Do not enter hazardous areas such as those with potential for fire or toxic chemicals without proper protective equipment.","Be cautious of secondary collisions involving objects inside a vehicle that may become projectiles during an accident.","Recognize the signs of a high-energy event, which can lead to severe injuries even if vital signs are initially normal."],"commonMistakes":["Failing to perform a scene size-up before approaching the patient, which can result in exposure to hazardous materials or failure to anticipate serious injuries.","Overlooking the need for additional equipment or personnel when more patients than expected are present.","Not considering the mechanism of injury thoroughly, leading to missed or overlooked critical injuries."],"memoryAids":["Remember that standard precautions include wearing gloves and a face shield in most situations.","Use the mnemonic 'SOS' (Scene, Safety, Patients) to recall the initial steps of scene size-up.","For MVCs, remember the three collisions: machine collision, body collision, and organ collision."],"decisionTrees":[{"title":"Decision Tree for Scene Size-Up","content":"1. Assess the scene for safety.\n2. Determine if standard precautions are needed (gloves, face shield).\n3. Identify potential hazards such as fire or toxic chemicals.\n4. Count the number of patients and determine additional resources needed.\n5. Evaluate the mechanism of injury to predict potential injuries."}],"references":["Almogy, G., Y. Mintz, G. Zamir, T. Bdolah-Abram, R. Elazary, L. Dotan, M. Faruga, and A.I. Rivkind. “Suicide Bombing Attacks: Can External Signs Predict Internal Injuries?” Annals of Surgery 243, no. 4 (April 2006): 541–46.","Alson, R.L., and W. B. Patterson. Access: First on Scene—Rapid Vehicle Entry Provider Manual, 2nd ed. Downers Grove, IL: ITLS, 2006.","American Academy of Pediatrics, Committee on Injury and Poison Prevention. “Personal Watercraft Use by Children and Adolescents.” Pediatrics 105, no. 2 (February 1, 2000): 452–53."]},"c02":{"id":"c02","title":"Trauma Assessment and Management","shortTitle":"Trauma Assessment","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Outline the steps in trauma assessment and management.","Describe the ITLS Primary Survey.","Explain the initial assessment and how it relates to the rapid trauma survey and the focused exam.","Describe when the initial assessment can be interrupted.","Describe when critical interventions should be made and where to make them.","Identify which patients have critical conditions and how they should be managed.","Describe the ITLS Ongoing Exam.","Describe the ITLS Secondary Survey."],"summary":[{"title":"Scene Size-Up","content":"The scene size-up is performed before approaching a patient to ensure safety. It includes identifying hazards, assessing the number of patients, and determining if additional resources are needed. The mechanism of injury (MOI) should be identified."},{"title":"Initial Assessment","content":"The initial assessment evaluates the patient's general impression, level of consciousness (LOC), airway, breathing, and circulation (ABCs). It is performed quickly to prioritize treatment and identify life-threatening conditions. The AVPU scale is used to assess LOC."},{"title":"Rapid Trauma Survey or Focused Exam","content":"The rapid trauma survey is a brief exam from head to toe, while the focused exam is limited to areas affected by specific injuries. Both are performed based on the mechanism of injury and initial assessment findings. The goal is to identify life-threatening conditions."},{"title":"Critical Interventions","content":"Critical interventions include controlling major external bleeding, maintaining an open airway, ventilating if necessary, applying oxygen, sealing sucking chest wounds, stabilizing flail segments, decompressing tension pneumothorax, and managing penetrating objects. These should be performed immediately."},{"title":"ITLS Ongoing Exam","content":"The ITLS Ongoing Exam is an abbreviated exam to assess for changes in the patient’s condition during transport. It includes reassessing ABCs, mental status, vital signs, and interventions. This should be performed every 5-15 minutes."},{"title":"ITLS Secondary Survey","content":"The ITLS Secondary Survey is a more comprehensive exam to identify additional injuries not found in the primary survey. It includes a detailed head-to-toe examination, vital signs, and neurological assessment. This may be performed if time allows."}],"clinicalPearls":["Always perform a scene size-up before approaching a patient.","Use the AVPU scale to assess the level of consciousness.","Maintain spinal motion restriction (SMR) during assessments and interventions.","Delegate tasks to team members while continuing the assessment sequence."],"redFlags":["Do not interrupt the initial assessment for interventions unless it is an emergency.","Be aware that patients with altered mental status may have non-traumatic causes such as hypoglycemia or drug overdose."],"commonMistakes":["Failing to perform a scene size-up before approaching the patient.","Interrupting the initial assessment for interventions without completing it.","Overlooking critical signs during the rapid trauma survey."],"memoryAids":["Use the AVPU scale to assess LOC: Alert, Verbal, Pain, Unresponsive.","Remember the ABCs: Airway, Breathing, Circulation.","Perform a scene size-up before approaching any patient."],"decisionTrees":[{"title":"Decision Tree for Initial Assessment","content":"1. Perform scene size-up.\n2. Identify mechanism of injury (MOI).\n3. Approach the patient and perform initial assessment: General impression, LOC, airway, breathing, circulation.\n4. Determine if rapid trauma survey or focused exam is needed based on MOI."},{"title":"Decision Tree for Critical Interventions","content":"1. Control major external bleeding.\n2. Maintain an open and patent airway (position, sweep, suction; intubate if necessary).\n3. Ventilate the patient if needed.\n4. Apply oxygen, CP, seal sucking chest wounds, stabilize flail segments, decompress tension pneumothorax when indicated."}],"references":["Alam, H. B., D. Burris, J. A. DaCorta, and P. Rhee. “Hemorrhage Control in the Battlefield: Role of New Hemostatic Agents.” Military Medicine 170, no. 1 (January 2005): 63–69.","Brooke, M., J. Walton, and D. Scutt. “Paramedic Application of Ultrasound in the Management of Patients in the Prehospital Setting: A Review of the Literature.” Emergency Medicine Journal 27, no. 9 (September 2010): 702–7.","Jansen, T. C., J. van Bommel, P. G. Mulder, J. H. Rommes, S. J. Schieveld, and J. Bakker. “The Prognostic Value of Blood Lactate Levels Relative to That of Vital Signs in the Prehospital Setting: A Pilot Study.” Critical Care 12, no. 6 (2008): 160–66."]},"c03":{"id":"c03","title":"ITLS Primary and Secondary Survey: Assessment Skills","shortTitle":"Assessment Skills","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Correctly perform the ITLS Primary Survey and identify within two minutes which patients require load-and-go.","Describe when to perform critical interventions during the survey.","Correctly perform the ITLS Ongoing (reassessment) Exam.","Correctly perform the ITLS Secondary Survey.","Demonstrate proper communication with medical direction.","Demonstrate the proper sequence of rapid assessment and management of the multiple-trauma patient."],"summary":[{"title":"Structure of the ITLS Primary Survey","content":"The ITLS Primary Survey is a rapid, prioritized assessment built from the scene size-up, the initial assessment (general impression, level of consciousness, airway, breathing, circulation), and either a rapid trauma survey (for generalized/unknown mechanism) or a focused exam (for localized mechanism). Its purpose is to find and treat immediate threats to life and to identify load-and-go patients within about two minutes of patient contact."},{"title":"Initial Assessment and CABC","content":"After forming a general impression, address obvious life-threatening external bleeding immediately (the C in C-A-B-C), then assess level of consciousness using AVPU. Evaluate the airway for snoring, gurgling, stridor, or silence; assess breathing for presence, rate, depth, and effort; and assess circulation by checking radial and carotid pulses, skin color/temperature/moisture, and capillary refill. Fix airway and breathing problems the moment you find them."},{"title":"Rapid Trauma Survey vs. Focused Exam","content":"When the mechanism is generalized or unknown, perform a head-to-toe rapid trauma survey (head/neck, chest, abdomen, pelvis, extremities, posterior). When the mechanism is localized (for example an isolated extremity injury), perform a focused exam of the injured area. The decision between the two is driven by the mechanism of injury and findings in the initial assessment."},{"title":"Load-and-Go Decision","content":"At the end of the ITLS Primary Survey, decide whether the patient is critical (load-and-go) or stable. Critical trauma situations demand immediate transport, with only essential critical interventions performed on scene. Every procedure done on scene trades minutes of the patient's Golden Period, so judgment is essential."},{"title":"ITLS Ongoing Exam (Reassessment)","content":"The Ongoing Exam reassesses subjective changes, mental status and pupils, the ABCs, the neck and chest, the abdomen, identified injuries, all interventions (tube position, oxygen, IVs, dressings, decompression needle, splints), and monitors. Repeat it whenever the patient's condition changes, after any intervention, and after any move (scene to ambulance, ambulance to ED)."},{"title":"ITLS Secondary Survey","content":"The Secondary Survey is a detailed head-to-toe exam (DCAP-BLS and TIC) performed after life threats are managed. Quickly repeat the initial assessment, complete the SAMPLE history and vital signs, calculate the Glasgow Coma Scale for altered patients, and examine head, neck, chest, abdomen, pelvis, and extremities for distal pulses/motor/sensation. Critical patients receive it en route only if time permits; stable patients may receive it on scene."}],"clinicalPearls":["Do not approach the patient until the scene size-up is complete.","Give ventilation instructions as soon as you assess airway and breathing—do not wait until the survey is finished.","Use DCAP-BLS (Deformities, Contusions, Abrasions, Punctures/Penetrations, Burns, Lacerations, Swelling) and TIC (Tenderness, Instability, Crepitation) as your inspection/palpation checklist.","Repeat the Ongoing Exam after every intervention, every condition change, and every patient move.","Communicate early with medical direction and the receiving facility when you have a critical patient."],"redFlags":["Do not interrupt the ITLS Primary Survey except for immediate threats to life—airway obstruction, cardiac arrest, severe hemorrhage—or if the scene becomes unsafe.","Prophylactic hyperventilation is not recommended; reserve it for head-injured patients showing signs of cerebral herniation.","Unequal or fixed/dilated pupils with a GCS of 8 or less suggest cerebral herniation.","Critical patients should not have traction splints applied on scene—they take too long."],"commonMistakes":["Spending too long on scene performing non-essential interventions on a load-and-go patient.","Failing to reassess interventions (tube, IV, dressings, decompression needle) during the Ongoing Exam.","Skipping the posterior exam, which is done during the log roll onto or off the backboard.","Forgetting to obtain a blood glucose level on any patient with a decreased level of consciousness."],"memoryAids":["C-A-B-C: control Catastrophic bleeding first, then Airway, Breathing, Circulation.","AVPU: Alert, responds to Voice, responds to Pain, Unresponsive.","DCAP-BLS + TIC for the detailed exam of each body region.","SAMPLE: Symptoms, Allergies, Medications, Past history, Last oral intake, Events leading up."],"decisionTrees":[{"title":"ITLS Patient Assessment Flow","content":"1. Scene Size-Up → standard precautions, hazards, # patients, resources, mechanism of injury.\n2. Initial Assessment → general impression, control life-threatening bleeding, LOC (AVPU), Airway, Breathing, Circulation.\n3. Decide: critical situation? SMR indicated? Generalized vs. localized MOI?\n4. Generalized/unknown MOI → Rapid Trauma Survey.   Localized MOI → Focused Exam.\n5. Critical → load-and-go, transport immediately, interventions en route.\n6. En route → Ongoing Exam (repeat as needed) and, if time permits, Secondary Survey."}],"references":["International Trauma Life Support, 8th ed. Chapter 3: Assessment Skills.","Campbell, J.E., and R.L. Alson. International Trauma Life Support for Emergency Care Providers."]},"c04":{"id":"c04","title":"Airway Management in the Trauma Patient","shortTitle":"Airway Management","estimatedStudyTime":35,"difficulty":"Intermediate","learningObjectives":["Describe the anatomy and physiology of the respiratory system.","Explain the importance of observation as it relates to airway control.","Describe methods to deliver supplemental oxygen to the trauma patient.","Describe the indications, contraindications, advantages, and disadvantages of bag-valve masks, blind insertion airway devices, endotracheal intubation, FROPVDs, nasopharyngeal airways, and oropharyngeal airways.","Describe the predictors of difficult mask ventilation and endotracheal intubation.","Describe apneic oxygenation and external laryngeal manipulation.","Describe the essential components of an airway kit."],"summary":[{"title":"Airway Is the First Priority","content":"Of all field tasks, airway control is the most important because it cannot wait for hospital arrival. Maintaining an open airway and adequate ventilation prevents hypoxia, which is rapidly fatal and worsens outcomes in shock and brain injury. The trauma airway is challenging due to blood, vomitus, facial injuries, the need for cervical-spine motion restriction, and difficult field conditions."},{"title":"Respiratory Anatomy and Physiology","content":"The airway is divided into upper (nose, mouth, pharynx, larynx) and lower (trachea, bronchi, alveoli) structures. Ventilation moves air; oxygenation loads hemoglobin and tissues with oxygen. Tidal volume is the air moved per breath; minute volume is tidal volume times respiratory rate. Adequate minute ventilation and lung compliance are required for gas exchange at the alveoli."},{"title":"Observation and Basic Airway Maneuvers","content":"Look, listen, and feel for air movement, chest rise, and abnormal sounds (snoring, gurgling, stridor). In trauma, open the airway with a modified jaw thrust to protect the cervical spine. Suction blood and secretions. Insert an oropharyngeal airway (no gag reflex) or nasopharyngeal airway (intact gag, but avoid with suspected basilar skull fracture)."},{"title":"Oxygen Delivery and Ventilation Devices","content":"Deliver high-concentration oxygen by nonrebreather mask at 15 L/min for the spontaneously breathing trauma patient. Assist inadequate ventilations with a bag-valve mask (BVM) and supplemental oxygen at 8–10 breaths/min for adults. Flow-restricted oxygen-powered ventilation devices (FROPVDs) and pulse oximetry/capnography monitor and support ventilation. Confirm adequate tidal volume by visible chest rise and fall."},{"title":"Advanced Airways: BIAD and Endotracheal Intubation","content":"Blind insertion airway devices (BIADs, e.g., supraglottic airways) provide a rescue or primary airway without visualizing the cords. Endotracheal intubation is the gold standard for airway protection and ventilatory control in the adult but is more difficult; placement must be confirmed with waveform capnography. Drug-assisted intubation (DAI), rapid sequence intubation (RSI), and rapid sequence airway (RSA) are advanced techniques used within scope and protocol."},{"title":"Predicting Difficulty and Optimizing First-Pass Success","content":"Use MMAP and related predictors to anticipate a difficult airway: Mallampati/mouth opening, Mask seal/obstruction/obesity, Anatomic problems (neck/short, immobilization), and Position. Apneic oxygenation (nasal cannula oxygen during intubation attempts) and external laryngeal manipulation (ELM/BURP) improve success and prolong safe apnea time. Always have a backup plan and a stocked airway kit."}],"clinicalPearls":["Open the trauma airway with a modified jaw thrust, not a head-tilt, to protect the cervical spine.","Confirm and continuously monitor endotracheal tube placement with waveform capnography.","Apneic oxygenation via nasal cannula during laryngoscopy extends safe apnea time.","A nonrebreather at 15 L/min provides high-concentration oxygen for the spontaneously breathing trauma patient.","Adequate tidal volume is confirmed by visible, symmetric chest rise—not by squeezing the bag harder or faster."],"redFlags":["Avoid nasopharyngeal airways and nasotracheal intubation when a basilar skull fracture is suspected (raccoon eyes, Battle's sign, CSF rhinorrhea).","Hyperventilation drops cerebral perfusion and increases intrathoracic pressure—avoid it unless treating cerebral herniation.","An unrecognized esophageal intubation is rapidly fatal—capnography is mandatory for confirmation and ongoing monitoring.","Repeated prolonged intubation attempts cause hypoxia; if unsuccessful, ventilate by BVM or insert a BIAD."],"commonMistakes":["Ventilating too fast or with too much volume, causing gastric insufflation and decreased venous return.","Failing to suction before attempting to visualize the airway.","Relying on chest auscultation alone instead of capnography to confirm tube placement.","Not preparing a backup airway plan before the first attempt."],"memoryAids":["MMAP for difficult-airway prediction: Mallampati, Mask seal/Obstruction/Obesity, Anatomy, Position.","LOOK-LISTEN-FEEL to assess air movement and chest rise.","Adult BVM rate: 8–10 breaths per minute with oxygen; confirm chest rise.","BURP/ELM = Backward, Upward, Rightward Pressure on the larynx to improve the view."],"decisionTrees":[{"title":"Trauma Airway Management","content":"1. Open airway with modified jaw thrust; suction as needed.\n2. Insert OPA (no gag) or NPA (gag intact, no basilar skull fracture).\n3. Spontaneous and adequate? → Oxygen by nonrebreather 15 L/min.\n4. Inadequate/absent ventilation? → BVM with oxygen, 8–10/min, confirm chest rise.\n5. Need definitive airway → attempt intubation (apneic oxygenation + ELM) → confirm with capnography.\n6. Failed intubation → BVM or insert BIAD; consider surgical airway per protocol."}],"references":["International Trauma Life Support, 8th ed. Chapter 4: Airway Management.","Magee, K., and R.D. Stewart. Airway Management in Prehospital Trauma Care."]},"c05":{"id":"c05","title":"Airway Management Skills","shortTitle":"Airway Skills","estimatedStudyTime":35,"difficulty":"Advanced","learningObjectives":["Suction the airway safely and effectively.","Insert nasopharyngeal and oropharyngeal airways.","Use the pocket mask and the bag-valve mask.","Use the pulse oximeter.","Perform airway management using supraglottic (BIAD) devices.","Prepare for and perform laryngoscopic orotracheal and nasotracheal intubation.","Confirm endotracheal tube placement using capnography and anchor the tube.","Understand the use of medications to assist with intubation."],"summary":[{"title":"Finesse Over Force","content":"Loss of airway is a leading cause of preventable trauma death. Successful airway management depends on clear team communication and a calm, deliberate approach—finesse is more important than force. Never rush an airway; prepare equipment, assign roles, and have a backup plan before acting."},{"title":"Suctioning Technique","content":"Test the suction unit, measure the catheter (corner of mouth to earlobe), insert without suction, then apply suction while withdrawing. Limit suctioning to about 15 seconds (less in children) because it removes oxygen as well as fluid. Reoxygenate between attempts and keep a rigid (Yankauer) tip ready for thick blood and debris."},{"title":"Basic Adjuncts and Ventilation","content":"Size an OPA from the corner of the mouth to the earlobe/angle of jaw; size an NPA from the nostril to the earlobe. Use the pocket mask or two-rescuer bag-valve mask for assisted ventilation, maintaining a good seal and confirming chest rise. Monitor oxygenation continuously with a pulse oximeter."},{"title":"Supraglottic (BIAD) Airways","content":"Supraglottic airways are inserted blindly into the hypopharynx and seal over the glottic opening, providing rapid ventilation when intubation is difficult or unavailable. They are effective primary or rescue airways, require minimal neck movement, and are confirmed and monitored with waveform capnography."},{"title":"Endotracheal Intubation","content":"Preoxygenate, prepare equipment (tube, stylet, laryngoscope, suction, capnography, backup), and maintain in-line cervical stabilization. Perform laryngoscopy with external laryngeal manipulation to visualize the cords, pass the tube, inflate the cuff, and confirm placement. Nasotracheal intubation is an option in select spontaneously breathing patients but is avoided with suspected basilar skull fracture."},{"title":"Confirmation, Anchoring, and Medications","content":"Confirm tube placement with waveform capnography plus chest rise and bilateral breath sounds; reconfirm after every move. Anchor the tube securely and note depth at the teeth. Medications (sedatives and paralytics) may facilitate intubation through drug-assisted intubation, RSI, or RSA within scope and protocol; have suction, monitoring, and rescue devices ready before administering."}],"clinicalPearls":["Measure the suction catheter and limit each pass to ~15 seconds; reoxygenate between attempts.","Confirm every advanced airway with waveform capnography and reconfirm after each patient move.","Two-rescuer BVM (one seals the mask, one ventilates) provides a far better seal than one rescuer alone.","Maintain manual in-line cervical stabilization throughout intubation in trauma.","Have a backup airway device immediately available before the first attempt."],"redFlags":["Prolonged suctioning or intubation attempts cause hypoxia—limit attempts and re-oxygenate.","Avoid nasotracheal intubation and NPAs when a basilar skull fracture is suspected.","Never administer a paralytic without the ability to ventilate and a rescue airway plan.","An esophageal tube without capnographic detection is rapidly fatal."],"commonMistakes":["Poor mask seal during BVM, leading to inadequate ventilation and gastric insufflation.","Failing to preoxygenate before an intubation attempt.","Not measuring the OPA/NPA, causing airway trauma or worsened obstruction.","Forgetting to re-confirm tube placement after moving the patient."],"memoryAids":["Suction: measure, insert without suction, suction on withdrawal, ≤15 seconds.","OPA size = corner of mouth to earlobe; NPA size = nostril to earlobe.","Confirm tube: capnography + chest rise + bilateral breath sounds.","Prepare = SOAP ME (Suction, Oxygen, Airways, Pharmacology, Monitoring, Equipment)."],"decisionTrees":[{"title":"Stepwise Airway Skill Selection","content":"1. Open + suction; insert OPA/NPA.\n2. Apneic/inadequate → two-rescuer BVM with oxygen, confirm chest rise.\n3. Need advanced airway → preoxygenate, prepare, maintain in-line stabilization.\n4. Attempt intubation (ELM, apneic oxygenation) → confirm with capnography → anchor.\n5. Failed/difficult → insert supraglottic (BIAD) → confirm with capnography.\n6. Cannot ventilate by any means → surgical airway per protocol."}],"references":["International Trauma Life Support, 8th ed. Chapter 5: Airway Skills.","Seitz, S.R., B. Page, and R.L. Alson. Prehospital Airway Skills."]},"c06":{"id":"c06","title":"Thoracic Trauma","shortTitle":"Thoracic Trauma","estimatedStudyTime":35,"difficulty":"Advanced","learningObjectives":["Identify the major symptoms and signs of thoracic trauma.","List the immediate life-threatening thoracic injuries.","Define flail chest and describe its findings and management.","Explain the pathophysiology and management of an open pneumothorax.","Explain the pathophysiology and management of massive hemothorax.","Describe the clinical signs and management of tension pneumothorax and contrast them with massive hemothorax.","List three indications to perform emergency chest decompression.","Identify the findings of cardiac tamponade, including Beck's triad.","Explain the cardiac involvement and management of blunt chest injury."],"summary":[{"title":"Why the Chest Kills","content":"Thoracic injuries account for a large share of trauma deaths because the chest houses the heart, great vessels, and lungs. The mediastinum contains the heart and great vessels; the pleural space is the potential space where air or blood collects. Symptoms include chest pain, dyspnea, and a sense of impending doom; signs include tachypnea, asymmetry, contusions, crepitus, and abnormal breath sounds."},{"title":"The Immediate Life Threats","content":"The immediately life-threatening thoracic injuries that must be found in the Primary Survey are airway obstruction, tension pneumothorax, open (sucking) pneumothorax, massive hemothorax, flail chest, and cardiac tamponade. Each can be lethal within minutes and several have field interventions—seal, decompress, or assist ventilation."},{"title":"Tension Pneumothorax","content":"Air enters the pleural space and cannot escape, collapsing the lung and shifting the mediastinum, which compresses the great veins and drops cardiac output. Signs include severe respiratory distress, absent breath sounds and hyperresonance on the affected side, distended neck veins, and tracheal deviation (a late sign), progressing to shock. Treatment is immediate needle chest decompression."},{"title":"Open Pneumothorax and Massive Hemothorax","content":"An open (sucking) chest wound lets air move through the wound instead of the trachea; treat by applying a vented (three-sided or commercial) occlusive dressing and watching for a developing tension pneumothorax. Massive hemothorax is large blood loss into the chest (often >1,500 mL), producing both shock (hypovolemia) and respiratory compromise; treat shock, give oxygen, and transport rapidly—decompression does not help blood."},{"title":"Flail Chest and Pulmonary Contusion","content":"Flail chest is two or more adjacent ribs each fractured in two or more places, creating a segment that moves paradoxically. The real danger is the underlying pulmonary contusion and hypoventilation. Support ventilation, give oxygen, and consider positive-pressure ventilation; do not over-resuscitate with fluids, which worsens the contused lung."},{"title":"Cardiac Tamponade and Blunt Cardiac Injury","content":"Pericardial tamponade is blood in the pericardial sac compressing the heart, classically producing Beck's triad: hypotension, distended neck veins, and muffled heart tones, often with a paradoxical pulse (pulsus paradoxus). It is rapidly fatal and requires rapid transport for pericardiocentesis or surgery. Blunt cardiac injury can cause dysrhythmias—apply cardiac monitoring early."}],"clinicalPearls":["Tension pneumothorax is a clinical diagnosis—treat it by decompression before it causes arrest; do not wait for tracheal deviation.","Seal an open chest wound with a vented occlusive dressing and monitor for tension pneumothorax.","Beck's triad (hypotension, JVD, muffled heart tones) suggests pericardial tamponade.","Distended neck veins with shock point to an obstructive cause (tension pneumothorax or tamponade), not hypovolemia.","Apply early cardiac monitoring after significant blunt chest trauma to detect dysrhythmias."],"redFlags":["Hypotension + JVD + decreased/absent breath sounds + hyperresonance = tension pneumothorax → decompress now.","Hypotension + JVD + muffled heart tones (Beck's triad) = cardiac tamponade → rapid transport.","An occlusive dressing without venting can convert an open pneumothorax into a tension pneumothorax.","Massive hemothorax can exsanguinate the patient into the chest—treat shock and transport immediately."],"commonMistakes":["Confusing massive hemothorax (dull, flat neck veins) with tension pneumothorax (hyperresonant, distended neck veins).","Over-resuscitating a pulmonary contusion or hemothorax patient with crystalloid fluids.","Sealing an open chest wound completely with no vent, risking a tension pneumothorax.","Delaying decompression of an obvious tension pneumothorax while awaiting more signs."],"memoryAids":["Immediate life threats — 'ATOM-FC': Airway obstruction, Tension pneumothorax, Open pneumothorax, Massive hemothorax, Flail chest, Cardiac tamponade.","Beck's triad: hypoTension, JVD (distended neck veins), muffled heart Tones.","Hyperresonant + JVD = tension pneumothorax; Dull + flat veins = hemothorax.","Decompression indications: signs of tension pneumothorax PLUS respiratory distress/cyanosis, lost radial pulse, or decreasing LOC."],"decisionTrees":[{"title":"Unequal Breath Sounds in Chest Trauma","content":"1. Unequal breath sounds → percuss the affected side.\n2. Hyperresonant + distended neck veins + shock/respiratory distress → Tension pneumothorax → needle decompression.\n3. Dull + flat neck veins + shock → Massive hemothorax → treat shock, oxygen, rapid transport.\n4. Open wound bubbling air → Open pneumothorax → vented occlusive dressing; monitor for tension.\n5. Muffled heart tones + JVD + hypotension → Cardiac tamponade → rapid transport for pericardiocentesis/surgery."}],"references":["International Trauma Life Support, 8th ed. Chapter 6: Thoracic Trauma.","Bauzá, G.M., and A.B. Peitzman. Thoracic Trauma in Prehospital Care."]},"c07":{"id":"c07","title":"Thoracic Trauma Skills: Needle Chest Decompression","shortTitle":"Needle Decompression","estimatedStudyTime":20,"difficulty":"Advanced","learningObjectives":["Explain the advantages, disadvantages, and complications of needle decompression by the anterior and lateral approaches.","Describe the indications for emergency decompression of a tension pneumothorax.","Perform needle decompression of a tension pneumothorax by either the anterior or lateral approach."],"summary":[{"title":"Purpose of Needle Decompression","content":"Needle chest decompression is a life-saving procedure that converts a tension pneumothorax into a simple (open) pneumothorax by releasing trapped pleural air, restoring venous return and cardiac output. It is a temporizing measure; definitive treatment is a chest tube at the hospital."},{"title":"Indications","content":"Decompress when there are signs of a tension pneumothorax PLUS more than one of the following: respiratory distress and cyanosis, loss of the radial pulse (obvious shock), loss of consciousness, or an obviously decreasing level of consciousness. The indications are the same in civilian and tactical settings."},{"title":"Anterior Approach","content":"The traditional anterior site is the second or third intercostal space at the midclavicular line, inserting just over the top of the lower rib to avoid the neurovascular bundle beneath each rib. Because chest-wall thickness varies, a large-bore catheter (about 14 gauge, 8 French) that is 6 to 9 cm (2.5 to 3.5 inches) long is recommended so it reaches the pleural space."},{"title":"Lateral Approach","content":"The lateral approach uses the fourth or fifth intercostal space at the anterior axillary line (some courses use the third intercostal space laterally). It is favored in tactical settings because it can be performed without removing body armor and may more reliably reach the pleural space. The third intercostal lateral site has theoretically less risk of injuring the liver or spleen and may be faster in combat settings."},{"title":"Technique and Confirmation","content":"Identify the landmark, prep the site, and insert the catheter perpendicular to the chest wall just superior to the rib. A rush of air or improvement in the patient confirms success. Secure the catheter, monitor for re-accumulation, and reassess frequently; the needle can kink, clot, or dislodge, so be prepared to repeat decompression. Systems with ultrasound can confirm pneumothorax before the procedure."}],"clinicalPearls":["Always insert just over the TOP of the rib to avoid the nerve, artery, and vein that run along the bottom of each rib.","Use a catheter long enough (6–9 cm) to reach the pleural space, especially in muscular or obese patients.","A successful decompression often produces an audible rush of air and rapid clinical improvement.","The lateral approach allows decompression without removing body armor in tactical care.","Needle decompression is temporary—monitor for re-accumulation and prepare to repeat it."],"redFlags":["Too-short catheters frequently fail to reach the pleural space at the anterior site.","Inserting below the rib can lacerate the intercostal neurovascular bundle.","Decompression treats air, not blood—it will not help a massive hemothorax.","Failure to reassess can miss a re-tensioning pneumothorax requiring repeat decompression."],"commonMistakes":["Using a catheter that is too short for the patient's chest-wall thickness.","Placing the needle medially toward the great vessels instead of straight in at the landmark.","Decompressing a hemothorax mistaken for a tension pneumothorax.","Not securing the catheter, leading to kinking or dislodgement."],"memoryAids":["Anterior site: 2nd–3rd intercostal space, midclavicular line.","Lateral site: 4th–5th intercostal space, anterior axillary line.","Always go OVER the top of the lower rib.","Indications = tension signs + >1 of: distress/cyanosis, lost radial pulse, decreasing LOC."],"decisionTrees":[{"title":"Needle Decompression Procedure","content":"1. Confirm tension pneumothorax signs + qualifying severity criteria.\n2. Choose site: anterior (2nd–3rd ICS, midclavicular) or lateral (4th–5th ICS, anterior axillary line).\n3. Prep site; select large-bore catheter 6–9 cm long.\n4. Insert perpendicular, just over the TOP of the rib, into the pleural space.\n5. Listen/feel for air rush; reassess patient.\n6. Secure catheter; monitor for re-accumulation and repeat as needed; transport for chest tube."}],"references":["International Trauma Life Support, 8th ed. Chapter 7: Thoracic Trauma Skills.","Seitz, S.R., and A. Proust. Needle Chest Decompression Technique."]},"c08":{"id":"c08","title":"Shock in the Trauma Patient","shortTitle":"Shock","estimatedStudyTime":35,"difficulty":"Advanced","learningObjectives":["List the four components of the vascular system necessary for normal tissue perfusion.","Describe the symptoms and signs of shock in the order they develop.","Describe the four common clinical shock syndromes.","Explain the pathophysiology of hemorrhagic shock and compare it to mechanical and neurogenic shock.","Describe the management of controllable hemorrhage, uncontrollable hemorrhage, and nonhemorrhagic shock.","Discuss the use of hemostatic agents for uncontrolled extremity hemorrhage.","Discuss current indications for IV fluids in hemorrhagic shock.","Describe when to use tranexamic acid (TXA) in hemorrhage management."],"summary":[{"title":"What Shock Is","content":"Shock is inadequate tissue perfusion—cells do not receive enough oxygen to meet metabolic demand. Normal perfusion requires four components: an intact pump (heart), adequate volume (blood), intact pipes (blood vessels), and adequate oxygen-carrying capacity. Failure of any component produces shock and, untreated, cellular death and organ failure."},{"title":"Progression of Shock","content":"Shock develops in a predictable order. Early (compensated) shock shows anxiety/restlessness, tachycardia, cool and pale skin, delayed capillary refill, and a narrowing pulse pressure as the body vasoconstricts to preserve blood pressure. As compensation fails, hypotension, altered mental status, and decompensated shock appear. Falling blood pressure is a late sign—do not wait for it to treat."},{"title":"Four Shock Syndromes","content":"Hypovolemic (hemorrhagic) shock is from blood/fluid loss and is the most common in trauma. Cardiogenic (a form of mechanical) shock is pump failure. Mechanical/obstructive shock is from obstruction to filling or output (tension pneumothorax, cardiac tamponade). Distributive shock includes neurogenic shock (loss of sympathetic tone from spinal cord injury) and septic/anaphylactic causes."},{"title":"Hemorrhagic vs. Neurogenic vs. Mechanical","content":"Hemorrhagic shock: tachycardia, cool/pale/clammy skin, narrow pulse pressure. Neurogenic shock: hypotension with a normal or slow heart rate and warm, dry skin below the injury because sympathetic tone is lost. Mechanical (obstructive) shock: hypotension with distended neck veins from a tension pneumothorax or tamponade. Recognizing the pattern guides treatment."},{"title":"Hemorrhage Control and Resuscitation","content":"Control external bleeding first: direct pressure, then a tourniquet for uncontrolled extremity hemorrhage, and hemostatic agents/dressings for junctional or deep wounds not controllable by a tourniquet. For internal hemorrhage, the field cannot stop the bleeding—rapid transport to surgery is the priority. IV fluids are given judiciously to support perfusion (permissive/controlled hypotension targeting a palpable radial pulse or systolic ~80–90 mmHg in many protocols), avoiding over-resuscitation that worsens bleeding."},{"title":"TXA and Special Considerations","content":"Tranexamic acid (TXA) is an antifibrinolytic that reduces mortality when given early (ideally within 3 hours of injury) to patients with significant hemorrhage or signs of hemorrhagic shock. Keep the patient warm to prevent the lethal triad (hypothermia, acidosis, coagulopathy). For head-injured patients, maintain blood pressure to preserve cerebral perfusion. For neurogenic shock, fluids plus vasopressor support per protocol may be needed."}],"clinicalPearls":["Falling blood pressure is a LATE sign of shock—treat based on early signs (tachycardia, cool skin, anxiety, narrowing pulse pressure).","Control catastrophic external bleeding first—tourniquets are fast and life-saving for extremity hemorrhage.","Distended neck veins with shock indicate an obstructive cause (tension pneumothorax or tamponade), not hypovolemia.","Keep the patient warm—hypothermia worsens coagulopathy and the lethal triad.","Give TXA early (within ~3 hours) in significant hemorrhage per protocol."],"redFlags":["Internal hemorrhage cannot be controlled in the field—rapid surgical transport is the life-saving intervention.","Over-aggressive fluid resuscitation can pop clots, dilute clotting factors, and worsen bleeding.","Neurogenic shock (hypotension with bradycardia and warm skin) is a diagnosis of exclusion—assume hemorrhage until proven otherwise.","Do not allow head-injured patients to become hypotensive; hypotension dramatically worsens brain-injury outcomes."],"commonMistakes":["Waiting for hypotension before recognizing and treating shock.","Attributing all hypotension in a spine-injured patient to neurogenic shock and missing concurrent hemorrhage.","Pouring in large fluid volumes for uncontrolled internal hemorrhage.","Forgetting to keep the patient warm during resuscitation."],"memoryAids":["Four perfusion components: Pump, Volume, Pipes (vessels), and Oxygen-carrying capacity.","Early shock signs: Anxiety, Tachycardia, cool/pale skin, delayed cap refill, narrowing pulse pressure.","Hemorrhage control ladder: Direct pressure → Tourniquet → Hemostatic dressing.","Lethal triad: Hypothermia + Acidosis + Coagulopathy."],"decisionTrees":[{"title":"Approach to the Shock Patient","content":"1. Control catastrophic external bleeding (pressure → tourniquet → hemostatic).\n2. Airway/oxygen; assess perfusion (pulse, skin, mental status, cap refill).\n3. Distended neck veins + shock? → obstructive cause (decompress tension pneumothorax / transport for tamponade).\n4. Flat neck veins + tachycardia + cool skin → hemorrhagic shock → control bleeding, controlled IV fluids, rapid transport, TXA early.\n5. Hypotension + bradycardia + warm dry skin + spinal injury → neurogenic shock (after excluding hemorrhage).\n6. Keep warm; maintain BP in head injury; reassess frequently."}],"references":["International Trauma Life Support, 8th ed. Chapter 8: Shock.","Fowler, R.L., P.E. Pepe, et al. Prehospital Management of Shock and Hemorrhage.","CRASH-2 Collaborators. Effects of tranexamic acid on death in trauma patients. Lancet 2010."]},"c09":{"id":"c09","title":"Vascular Access Skills: IV and Intraosseous Access","shortTitle":"Vascular Access","estimatedStudyTime":25,"difficulty":"Intermediate","learningObjectives":["Perform cannulation of the external jugular vein.","Recite indications for intraosseous (IO) infusion.","Perform IO infusion using a drill device at tibial and humeral sites.","Perform sternal IO infusion using an approved sternal device.","Use length-based resuscitation tape to estimate a child's weight."],"summary":[{"title":"When and Why to Obtain Access","content":"Vascular access allows fluid resuscitation and medication delivery, but in trauma it should rarely delay transport—start IVs en route whenever possible. Providers are expected to already be proficient at peripheral IVs of the forearm and antecubital fossa; this chapter focuses on alternatives when peripheral access fails: the external jugular vein and intraosseous routes."},{"title":"External Jugular (EJ) Cannulation","content":"The external jugular vein runs from the angle of the jaw to the junction of the medial and middle third of the clavicle and is usually visible through the skin. Pressing just above the clavicle distends it. It is indicated for the adult or pediatric patient who needs IV access when no suitable peripheral vein is found. Position the patient supine, head turned away, and cannulate toward the clavicle/shoulder."},{"title":"Intraosseous (IO) Access","content":"IO infusion delivers fluids and drugs into the marrow cavity, providing rapid access when peripheral and EJ access fail or in critical patients who need immediate access. Drill devices place catheters in the proximal tibia or proximal humerus; sternal devices use the manubrium. The marrow acts as a non-collapsible vein with rapid central circulation."},{"title":"IO Sites and Technique","content":"Common drill sites are the proximal tibia (flat medial surface below the tuberosity) and the proximal humerus (greater tubercle, arm adducted). Confirm placement by needle stability, marrow aspiration, and free flow without extravasation. IO infusion is painful in conscious patients—consider lidocaine through the IO per protocol before flushing. Flush briskly to open the marrow channel."},{"title":"Pediatric Weight Estimation","content":"A length-based resuscitation tape (e.g., Broselow) estimates a child's weight from length and provides corresponding drug doses, fluid volumes, and equipment sizes. This reduces dosing errors in the high-stress pediatric resuscitation. Measure the child from head to heel and read the corresponding color zone."}],"clinicalPearls":["In trauma, establish IV access en route—do not delay transport of a critical patient to start a line.","Distend the external jugular by pressing just above the clavicle, and cannulate pointing toward the shoulder.","IO access is fast and reliable when peripheral veins collapse in shock.","Give IO lidocaine (per protocol) before flushing in a conscious patient—IO infusion is painful.","Use a length-based tape to estimate pediatric weight and reduce dosing errors."],"redFlags":["Avoid IO placement in a bone that is fractured or has had a recent IO attempt (fluid will extravasate).","Avoid IO at sites with overlying infection or in bones with known osteoporosis-related fragility where appropriate.","Air embolism and infiltration are risks of EJ cannulation—watch the site and secure the line.","Never let vascular access attempts delay surgical transport for uncontrolled internal hemorrhage."],"commonMistakes":["Spending excessive on-scene time attempting access on a load-and-go patient.","Failing to confirm IO placement before infusing, causing extravasation into soft tissue.","Not flushing the IO briskly, resulting in poor flow.","Using adult drug doses for children instead of a length-based tape estimate."],"memoryAids":["Access priority when peripheral fails: External Jugular → Intraosseous.","IO drill sites: proximal Tibia and proximal Humerus; sternal device on the manubrium.","Confirm IO: stands upright, aspirate marrow, flows freely without swelling.","Length-based tape = weight + doses + equipment sizes for kids."],"decisionTrees":[{"title":"Vascular Access Algorithm","content":"1. Need access? Attempt peripheral IV (forearm/antecubital) — preferably en route.\n2. No peripheral vein found → external jugular cannulation.\n3. Critical patient or EJ unavailable/failed → intraosseous (proximal tibia/humerus, or sternal device).\n4. Confirm IO placement (stability, aspiration, free flow); give IO lidocaine if conscious; flush.\n5. Pediatric patient → use length-based tape for weight, doses, and equipment sizes."}],"references":["International Trauma Life Support, 8th ed. Chapter 9: Vascular Access Skills.","Seitz, S.R., and K. Han. Prehospital Vascular Access Techniques."]},"c10":{"id":"c10","title":"Head Trauma and Traumatic Brain Injury","shortTitle":"Head Trauma / TBI","estimatedStudyTime":35,"difficulty":"Advanced","learningObjectives":["Describe the anatomy of the head and brain.","Describe the pathophysiology of traumatic brain injury.","Explain the difference between primary and secondary brain injury.","Describe the mechanisms that produce secondary brain injury.","Describe the assessment of the head-injured patient.","Describe the prehospital management of traumatic brain injury.","Recognize and manage the cerebral herniation syndrome.","Identify potential pitfalls in managing the head-injured patient."],"summary":[{"title":"Anatomy and the Monro-Kellie Doctrine","content":"The skull is a rigid box containing brain tissue, blood, and cerebrospinal fluid. The Monro-Kellie Doctrine states that because the skull cannot expand, an increase in any one component (such as a hematoma or swelling) must be offset by a decrease in another; once compensation is exhausted, intracranial pressure (ICP) rises sharply."},{"title":"Primary vs. Secondary Brain Injury","content":"Primary brain injury is the damage that occurs at the moment of impact (coup and contrecoup contusions, diffuse axonal injury, lacerations)—it cannot be reversed in the field. Secondary brain injury develops afterward from hypoxia, hypotension, hypoglycemia/hyperglycemia, hyper/hypocapnia, increased ICP, and edema. Preventing secondary injury is the central goal of prehospital care."},{"title":"ICP, CPP, and Cushing's Reflex","content":"Cerebral perfusion pressure (CPP) = mean arterial pressure (MAP) − intracranial pressure (ICP). As ICP rises, CPP falls and the brain becomes ischemic. Cushing's reflex—hypertension, bradycardia, and irregular respirations—is a late sign of dangerously raised ICP. The no-reflow phenomenon describes failure of microcirculation after severe injury."},{"title":"Assessment","content":"Assess level of consciousness with the Glasgow Coma Scale (eyes, verbal, motor), pupil size/reactivity, and motor function. Look for signs of basilar skull fracture (raccoon eyes, Battle's sign, CSF leak). Obtain a blood glucose. A GCS of 8 or less indicates severe TBI and an inability to protect the airway. Reassess frequently—a deteriorating GCS signals expanding injury."},{"title":"Management: Prevent Secondary Injury","content":"Maintain oxygenation (SpO2 ≥ 94%) and ventilation at a normal rate; avoid both hypoxia and routine hyperventilation. Prevent hypotension—maintain systolic blood pressure (commonly ≥ 110–120 mmHg)—because a single episode of hypotension dramatically worsens outcome. Elevate the head ~30 degrees if not contraindicated, treat seizures, keep the patient normothermic and euglycemic, and transport to an appropriate trauma/neurosurgical center."},{"title":"Cerebral Herniation Syndrome","content":"Herniation presents with a decreasing GCS (often <8) plus a dilated/unequal or fixed pupil, abnormal (extensor) posturing, and Cushing's signs. Only in this setting is controlled mild hyperventilation appropriate—target an ETCO2 of about 30–35 mmHg—while maintaining oxygenation and blood pressure. Otherwise ventilate to normal ETCO2 (35–45 mmHg)."}],"clinicalPearls":["The brain's worst enemies are hypoxia and hypotension—prevent both at all costs.","Cerebral perfusion pressure = MAP − ICP; keep MAP up and ICP down.","A single episode of hypotension can double mortality in severe TBI—maintain systolic ~110–120 mmHg.","Cushing's reflex (hypertension, bradycardia, irregular respirations) is a late sign of rising ICP.","Hyperventilation is reserved ONLY for signs of active cerebral herniation."],"redFlags":["A decreasing GCS with a blown (dilated, fixed) pupil signals herniation—act immediately.","Routine hyperventilation lowers CPP and worsens ischemia—avoid it unless herniation signs are present.","Hypoglycemia and hyperglycemia both worsen brain injury—check and correct glucose.","GCS ≤ 8 means the patient cannot protect the airway—secure it."],"commonMistakes":["Allowing the head-injured patient to become hypoxic or hypotensive.","Hyperventilating all head-injured patients rather than only those herniating.","Failing to recheck the GCS and pupils frequently to detect deterioration.","Overlooking other injuries causing hypotension while focusing on the head."],"memoryAids":["GCS components: Eyes (4), Verbal (5), Motor (6) = max 15.","CPP = MAP − ICP.","Cushing's triad: Hypertension, Bradycardia, irregular Respirations.","Herniation = decreasing GCS + dilated/fixed pupil + posturing → controlled hyperventilation (ETCO2 30–35)."],"decisionTrees":[{"title":"TBI Management Priorities","content":"1. Secure airway if GCS ≤ 8; oxygenate to SpO2 ≥ 94%; ventilate to normal ETCO2 (35–45).\n2. Prevent hypotension — maintain systolic ~110–120 mmHg; treat hemorrhage.\n3. Check glucose; treat seizures; keep normothermic.\n4. Elevate head ~30° if not contraindicated.\n5. Signs of herniation (decreasing GCS, dilated/fixed pupil, posturing)? → controlled mild hyperventilation to ETCO2 30–35 while maintaining BP and oxygenation.\n6. Rapid transport to a trauma/neurosurgical center; reassess GCS and pupils frequently."}],"references":["International Trauma Life Support, 8th ed. Chapter 10: Head Trauma and Traumatic Brain Injury.","Brain Trauma Foundation. Guidelines for Prehospital Management of Traumatic Brain Injury."]},"c11":{"id":"c11","title":"Spinal Trauma and Patient-Centered Spinal Motion Restriction","shortTitle":"Spinal Trauma & SMR","estimatedStudyTime":35,"difficulty":"Advanced","learningObjectives":["Explain the normal anatomy and physiology of the spinal column and spinal cord.","Define spinal motion restriction (SMR) and its relationship to patient safety.","Describe injury, history, and assessment elements that identify patients who benefit from SMR.","Describe at least one mechanism for which SMR can significantly decrease survival.","Explain the difference between Emergency Rescue and rapid extrication and when to use each.","Differentiate neurogenic shock from hemorrhagic shock using clinical evaluation."],"summary":[{"title":"Spinal Anatomy","content":"The spinal column is 33 vertebrae (cervical, thoracic, lumbar, sacral, coccygeal) protecting the spinal cord, which carries motor and sensory pathways between the brain and body. The cervical region is the most mobile and most vulnerable. Damage to the cord causes loss of motor function, sensation, and autonomic control below the level of injury."},{"title":"Primary vs. Secondary Cord Injury","content":"Primary spinal-cord injury occurs at the moment of trauma. Secondary spinal-cord injury results from movement of an unstable spine, hypoxia, hypotension, and edema after the event. The goal of spinal motion restriction is to prevent secondary injury by limiting movement of a potentially unstable spine while not harming the patient with unnecessary immobilization."},{"title":"Patient-Centered SMR (Selective Immobilization)","content":"Not every trauma patient needs full immobilization. Apply SMR when there is a concerning mechanism PLUS any of: altered mental status/intoxication, midline spinal tenderness or deformity, neurologic deficit (numbness, weakness, paresthesia), a distracting injury, or an unreliable exam. A reliable, alert patient with no midline tenderness, no neuro deficit, no intoxication, and no distracting injury may not require SMR."},{"title":"Harms of Over-Immobilization","content":"Rigid backboards and full immobilization can cause pressure sores, pain, agitation, aspiration risk, and impaired breathing. In penetrating trauma to the torso/neck without neurologic deficit, immobilization can delay transport and has been associated with increased mortality—so routine SMR is not applied to isolated penetrating trauma."},{"title":"Emergency Rescue vs. Rapid Extrication","content":"Emergency Rescue is the immediate removal of a patient from a scene that is too dangerous to allow normal care (fire, drowning, hostile environment)—life over spine. Rapid extrication is a controlled, faster removal (manual stabilization, no full device) used when the patient is critical/load-and-go or the scene is unstable. Standard extrication with a short device is reserved for stable patients in a stable scene."},{"title":"Neurogenic vs. Hemorrhagic Shock","content":"Neurogenic shock results from loss of sympathetic tone after cord injury: hypotension with a normal or slow heart rate and warm, dry, pink skin below the lesion. Hemorrhagic shock presents with tachycardia and cool, pale, clammy skin. Because the two can coexist, always assume and exclude hemorrhage first in a hypotensive spine-injured patient."}],"clinicalPearls":["SMR aims to prevent secondary cord injury without the harms of unnecessary immobilization.","Maintain neutral in-line alignment; pad behind the head/torso as needed (especially children and the elderly).","Isolated penetrating trauma without neurologic deficit generally should NOT be immobilized.","Neurogenic shock = hypotension + bradycardia + warm, dry skin; hemorrhagic shock = hypotension + tachycardia + cool, clammy skin.","Emergency Rescue prioritizes life over spine when the scene is immediately dangerous."],"redFlags":["Routine spinal immobilization of penetrating torso/neck trauma can increase mortality—avoid it without neuro deficit.","A distracting injury or intoxication makes the spinal exam unreliable—apply SMR.","Hypotension in a spine-injured patient is hemorrhage until proven otherwise.","Forcing a patient into neutral alignment against resistance or worsening pain/neuro symptoms is contraindicated—immobilize in the position found."],"commonMistakes":["Immobilizing every trauma patient regardless of selective criteria.","Attributing all shock in a spinal patient to neurogenic causes and missing hemorrhage.","Forcing neutral alignment when it causes pain or neurologic change.","Performing a slow standard extrication on a critical/load-and-go patient."],"memoryAids":["SMR criteria (apply if any): Altered mental status, Intoxication, Midline tenderness/deformity, Neuro deficit, Distracting injury.","Neurogenic shock = warm, dry, slow (bradycardia). Hemorrhagic shock = cool, clammy, fast (tachycardia).","Emergency Rescue = life over spine (immediate danger). Rapid extrication = critical patient/unstable scene.","Penetrating trauma + no deficit = no routine SMR."],"decisionTrees":[{"title":"Do I Apply SMR?","content":"1. Concerning mechanism? If clearly none and exam reliable → SMR may not be needed.\n2. Any of: altered mental status/intoxication, midline spinal tenderness/deformity, neuro deficit (numbness/weakness/paresthesia), distracting injury, unreliable exam? → Apply SMR.\n3. Isolated penetrating trauma without neuro deficit → do NOT routinely immobilize.\n4. Scene immediately dangerous → Emergency Rescue (life over spine).\n5. Critical patient or unstable scene → Rapid extrication.\n6. Stable patient, stable scene → standard extrication with short device, neutral in-line alignment."}],"references":["International Trauma Life Support, 8th ed. Chapter 11: Spinal Trauma and Patient-Centered SMR.","National Association of EMS Physicians & ACS-COT. EMS Spinal Precautions and the Use of the Long Backboard (position statement)."]},"c12":{"id":"c12","title":"Spine Management Skills","shortTitle":"Spine Management Skills","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Describe the essential components of a spinal motion-restriction (SMR) system.","Describe the goals and principles of SMR and explain when to use it.","Explain when to perform an Emergency Rescue and a rapid extrication.","Perform SMR with a short extrication device and log roll a patient onto a long backboard.","Properly secure a patient to a long backboard and transfer using a scoop stretcher.","Stabilize the head and neck when neutral position cannot be safely attained.","Perform a rapid extrication.","Explain when helmets should and should not be removed and remove a motorcycle helmet properly."],"summary":[{"title":"Components of an SMR System","content":"Effective SMR uses a combination of devices and techniques: manual in-line stabilization, a properly sized rigid cervical collar, and a full-body device (long backboard, scoop stretcher, or vacuum mattress) with straps and head blocks. The long backboard is primarily an extrication and transfer tool; patients can often be transported on a padded stretcher with the collar and straps rather than left on a rigid board."},{"title":"Goals and Principles","content":"The goals are to maintain neutral in-line alignment, limit harmful movement of a potentially unstable spine, and do so without causing pressure injury, pain, or airway compromise. Maintain manual stabilization from first contact until the patient is fully secured. Secure the torso before the head so the head is never the anchor point."},{"title":"Log Roll and Securing to a Board","content":"Log rolling moves the patient as a unit while a leader maintains head/neck alignment and gives commands. Use the roll to inspect the posterior (DCAP-BLS, TIC) and slide the board. Secure the torso (chest, hips), then the legs, and finally immobilize the head with blocks/tape—never strap the head first. Reassess distal pulses, motor, and sensation before and after."},{"title":"Short Devices, Scoop, and Vacuum Mattress","content":"A short extrication device (vest-type) provides SMR to a seated, stable patient before extrication. The scoop stretcher splits to slide under the patient with minimal movement and is excellent for transfers. A vacuum mattress conforms to the body, distributes pressure, and is comfortable for prolonged transport while maintaining alignment."},{"title":"Emergency Rescue, Rapid Extrication, and Helmets","content":"Emergency Rescue removes a patient from immediate danger (life over spine). Rapid extrication uses manual stabilization to quickly move a critical patient or one in an unstable scene. Remove a helmet if it prevents airway access or assessment, does not fit snugly (allowing head movement), or interferes with immobilization—remove it with two rescuers maintaining alignment. Leave a well-fitting helmet in place if the airway is accessible and the head is held securely, padding as needed."}],"clinicalPearls":["Secure the torso before the head—the head should never be the anchor point of immobilization.","Maintain manual in-line stabilization from first contact until the patient is fully secured.","Use the log roll to inspect and palpate the posterior (DCAP-BLS, TIC).","Reassess distal PMS (pulses, motor, sensation) before and after moving the patient.","Two rescuers remove a helmet together—one maintains alignment while the other spreads and removes it."],"redFlags":["Strapping the head before the torso allows torso shift that loads the neck—always torso first.","Do not force neutral alignment if it causes pain or new neuro symptoms—stabilize as found.","Leaving a patient on a rigid backboard for prolonged transport risks pressure injury and respiratory compromise.","Removing a helmet by a single rescuer risks dangerous head/neck movement."],"commonMistakes":["Immobilizing the head first, then the body.","Using a long backboard as the transport surface rather than transferring to a padded stretcher/vacuum mattress.","Failing to recheck distal neurovascular status after packaging.","Improper collar sizing leading to flexion or extension."],"memoryAids":["Order of securing: Torso → Hips/Legs → Head (last).","Helmet removal indications: Airway access, poor fit, interferes with immobilization.","Log roll = move as a unit, leader at the head gives commands.","Devices: collar + manual stabilization + full-body device (board/scoop/vacuum) + straps + head blocks."],"decisionTrees":[{"title":"Packaging the Spine-Injured Patient","content":"1. Manual in-line stabilization + sized cervical collar.\n2. Choose device: short device (seated stable) / rapid extrication (critical/unstable) / Emergency Rescue (immediate danger).\n3. Log roll as a unit → inspect posterior → place board/scoop.\n4. Secure torso → hips/legs → head blocks/tape LAST.\n5. Reassess distal pulses, motor, sensation.\n6. Consider transfer to padded stretcher or vacuum mattress for transport.\n7. Helmet: remove if it blocks airway/assessment, fits poorly, or impairs immobilization (two rescuers)."}],"references":["International Trauma Life Support, 8th ed. Chapter 12: Spine Management Skills.","Seitz, S.R., and D.L. Copeland. Spinal Motion Restriction Techniques."]},"c13":{"id":"c13","title":"Abdominal Trauma","shortTitle":"Abdominal Trauma","estimatedStudyTime":25,"difficulty":"Intermediate","learningObjectives":["Identify the basic anatomy of the abdomen and explain how abdominal and chest injuries may be related.","Differentiate blunt and penetrating injuries and their characteristic complications.","Describe the treatment for a patient with protruding viscera (evisceration).","Describe how to identify and stabilize a pelvic fracture, why it matters, and contraindications.","Relate external abdominal findings to possible underlying structural damage.","Describe findings indicating intra-abdominal injury based on history, exam, and mechanism of injury.","List the critical interventions for patients with abdominal injuries."],"summary":[{"title":"Abdominal Anatomy Regions","content":"The abdomen is divided into the true abdomen (the peritoneal cavity), the intrathoracic abdomen (upper abdomen protected by the lower ribs—liver, spleen, stomach, diaphragm), and the retroperitoneal abdomen (kidneys, pancreas, great vessels, duodenum). Because the lower ribs overlie upper-abdominal organs, chest and abdominal injuries are frequently linked."},{"title":"Blunt vs. Penetrating Trauma","content":"Blunt trauma compresses and shears solid organs (liver, spleen), causing internal hemorrhage that may be occult. Penetrating trauma (stab, gunshot) injures whatever the object crosses and can perforate hollow organs, causing bleeding and contamination/peritonitis. The abdomen is a place where large volumes of blood can be lost with few external signs."},{"title":"Assessment and the Hidden Hemorrhage","content":"Suspect intra-abdominal injury from mechanism, a seat-belt sign (bruising across the abdomen), distention, tenderness, rigidity, guarding, or unexplained shock. The abdominal exam is unreliable in intoxicated or head-injured patients. Serious intra-abdominal bleeding can present only as developing shock—do not wait for a rigid abdomen to act."},{"title":"Evisceration Management","content":"For protruding viscera (evisceration), do NOT push the organs back in. Cover them with a moist, sterile dressing and then an occlusive layer to retain warmth and moisture; keep the patient still, flex the knees if helpful, and transport. Treat for shock and handle gently to avoid further injury and contamination."},{"title":"Pelvic Fractures","content":"An unstable (open-book) pelvic fracture can lacerate the rich pelvic venous plexus and arteries, causing massive, life-threatening hemorrhage. Assess the pelvis gently once; if unstable or there is concerning mechanism with signs of shock, apply a pelvic binder at the level of the greater trochanters to close the pelvic volume and tamponade bleeding. Do not rock or repeatedly spring the pelvis."},{"title":"Critical Interventions","content":"The field cannot stop intra-abdominal or pelvic hemorrhage—rapid transport to surgery is the life-saving intervention. Provide oxygen, control external bleeding, stabilize the pelvis if indicated, give judicious IV fluids/TXA per protocol, keep the patient warm, and transport to a trauma center. Stabilize impaled objects in place; never remove them in the field."}],"clinicalPearls":["The abdomen can hide massive hemorrhage with minimal external signs—rely on mechanism and developing shock.","A seat-belt sign across the abdomen suggests underlying bowel, mesenteric, or solid-organ injury.","Do NOT push eviscerated organs back in—cover with a moist sterile then occlusive dressing.","Apply a pelvic binder at the greater trochanters for an unstable pelvis with shock to tamponade bleeding.","Stabilize impaled objects in place; removal can cause uncontrollable hemorrhage."],"redFlags":["Unexplained shock with a concerning mechanism is intra-abdominal/pelvic hemorrhage until proven otherwise.","Repeatedly springing/rocking the pelvis can dislodge clots and worsen hemorrhage—assess gently once.","A normal-appearing abdomen does not exclude serious injury, especially in intoxicated or head-injured patients.","Penetrating abdominal trauma can perforate bowel, causing delayed peritonitis and sepsis."],"commonMistakes":["Pushing eviscerated organs back into the abdomen.","Waiting for abdominal rigidity before treating for shock.","Removing an impaled object in the field.","Repeatedly manipulating an unstable pelvis."],"memoryAids":["Three abdominal regions: True (peritoneal), Intrathoracic (under lower ribs), Retroperitoneal.","Seat-belt sign = suspect bowel/mesenteric/solid-organ injury.","Evisceration: Moist sterile dressing → occlusive cover → do NOT replace organs.","Unstable pelvis + shock = binder at the greater trochanters + rapid transport."],"decisionTrees":[{"title":"Suspected Abdominal/Pelvic Injury","content":"1. Mechanism + exam (seat-belt sign, distention, tenderness, guarding) or unexplained shock → suspect intra-abdominal hemorrhage.\n2. Evisceration → moist sterile dressing + occlusive cover; do not replace organs.\n3. Assess pelvis gently ONCE. Unstable + shock → apply pelvic binder at greater trochanters.\n4. Impaled object → stabilize in place, do not remove.\n5. Treat shock (oxygen, controlled fluids/TXA per protocol), keep warm.\n6. Rapid transport to surgical/trauma center—field cannot control internal bleeding."}],"references":["International Trauma Life Support, 8th ed. Chapter 13: Abdominal Trauma.","Bloom, I., M. White, and A.H. Yancey. Prehospital Abdominal and Pelvic Trauma."]},"c14":{"id":"c14","title":"Extremity Trauma","shortTitle":"Extremity Trauma","estimatedStudyTime":30,"difficulty":"Intermediate","learningObjectives":["Prioritize extremity trauma within the assessment and management of life-threatening injuries.","Discuss the complications and treatment of amputations, crush injuries, dislocations, fractures, impaled objects, neurovascular injuries, open wounds, and sprains/strains.","Discuss the pathophysiology of compartment syndrome and which injuries most often cause it.","Describe the potential blood loss from pelvic and femur fractures.","Discuss mechanisms, associated injuries, complications, and management of injuries to the major bones and joints."],"summary":[{"title":"Priorities: Life Before Limb","content":"Extremity injuries are dramatic but rarely immediately life-threatening except when they bleed massively or accompany other injuries. Address airway, breathing, circulation, and major hemorrhage first. Only life-threatening extremity hemorrhage is managed during the Primary Survey (direct pressure, tourniquet); definitive splinting is done after life threats are controlled or en route for critical patients."},{"title":"Fractures, Dislocations, and Open Wounds","content":"A closed fracture has intact overlying skin; an open fracture has a wound communicating with the bone (higher infection risk—cover with sterile dressing). Joint dislocations threaten the neurovascular structures crossing the joint. Assess and document distal pulses, motor function, and sensation (PMS) before and after any splinting or movement. Splint to immobilize the joint above and below the injury."},{"title":"Blood Loss From Major Fractures","content":"Long-bone and pelvic fractures can cause significant internal blood loss: a closed femur fracture can lose roughly 1 to 1.5 liters, and an unstable pelvic fracture can lose enough to cause exsanguinating hemorrhage. Bilateral femur fractures or an unstable pelvis should make you anticipate and treat for shock."},{"title":"Amputations and Crush Injuries","content":"Control bleeding from amputations with direct pressure and a tourniquet if needed. Preserve the amputated part: wrap in moist sterile gauze, seal in a bag, and keep cool (on ice but not frozen or directly on ice). Crush injuries can cause rhabdomyolysis and, on release of prolonged compression, crush syndrome with hyperkalemia and renal failure—coordinate fluid resuscitation with medical direction."},{"title":"Compartment Syndrome and Neurovascular Injury","content":"Compartment syndrome is rising pressure within a closed muscle compartment (often the lower leg or forearm after fractures or crush) that compromises perfusion. The hallmark is pain out of proportion to injury, worsened by passive stretch, with later paresthesia, pallor, pulselessness, and paralysis (the 'P's'). It is a surgical emergency—recognize early and transport. Always reassess distal neurovascular status after splinting; a splint too tight can cause it."},{"title":"Splinting Principles and Special Injuries","content":"Realign grossly angulated long-bone fractures with gentle traction to restore distal circulation if there is no pulse, then splint; immobilize dislocations in the position found if pulses are intact. Stabilize impaled objects in place. Cover open wounds with sterile dressings. For most critical patients, rapid packaging and transport take priority over meticulous splinting—do not delay a load-and-go patient to apply a traction splint."}],"clinicalPearls":["Life before limb—manage ABCs and major hemorrhage before splinting.","Always check and document distal pulses, motor, and sensation (PMS) before and after splinting.","A closed femur fracture can lose 1–1.5 liters of blood; anticipate shock with bilateral femur or pelvic fractures.","Pain out of proportion to injury, worsened by passive stretch, is the earliest sign of compartment syndrome.","Preserve amputated parts moist, bagged, and cool—not frozen and not directly on ice."],"redFlags":["An absent distal pulse after a fracture/dislocation requires prompt realignment and rapid transport—limb-threatening ischemia.","Pulselessness and paralysis are LATE signs of compartment syndrome—act on early pain before they appear.","Release of a prolonged crush can precipitate crush syndrome (hyperkalemia, dysrhythmias)—coordinate with medical direction.","Do not apply time-consuming traction splints to critical, load-and-go patients."],"commonMistakes":["Becoming distracted by a dramatic extremity injury and missing life threats.","Failing to reassess distal PMS after splinting (a too-tight splint can cause ischemia).","Freezing or placing an amputated part directly on ice, causing tissue damage.","Forcing a dislocation with intact pulses into alignment rather than splinting as found."],"memoryAids":["The 6 P's of compartment syndrome / ischemia: Pain, Paresthesia, Pallor, Pulselessness, Paralysis, Poikilothermia (cool).","Check PMS (Pulses, Motor, Sensation) before AND after splinting.","Femur fracture ≈ 1–1.5 L blood loss.","Amputated part: Moist sterile gauze → sealed bag → cool (not frozen)."],"decisionTrees":[{"title":"Extremity Injury Management","content":"1. Manage ABCs and control life-threatening hemorrhage (pressure → tourniquet) first.\n2. Assess distal PMS.\n3. Open wound → cover with sterile dressing. Impaled object → stabilize in place.\n4. Angulated long bone with absent distal pulse → gentle traction realignment, then splint; recheck pulse.\n5. Dislocation with intact pulse → splint in position found.\n6. Splint joint above and below; reassess PMS after splinting.\n7. Suspect compartment syndrome (pain out of proportion) or crush syndrome → rapid transport, notify destination.\n8. Critical patient → package and transport; defer time-consuming splints."}],"references":["International Trauma Life Support, 8th ed. Chapter 14: Extremity Trauma.","Braithwaite, S., and S.R. Seitz. Prehospital Management of Extremity Injuries."]},"c15":{"id":"c15","title":"Extremity Trauma Skills: Traction Splinting and Hemorrhage Control","shortTitle":"Traction & Hemorrhage Skills","estimatedStudyTime":25,"difficulty":"Intermediate","learningObjectives":["Explain when to use a traction splint and describe its complications.","Apply the most common traction splints (Hare, Sager, and Thomas).","Demonstrate pelvic stabilization techniques.","Explain the use of and demonstrate tourniquet application.","Explain the use of and demonstrate hemostatic agent application."],"summary":[{"title":"Indications for Traction Splints","content":"Traction splints are designed to immobilize mid-shaft femur fractures. They realign the fracture, reduce pain, decrease blood loss into the thigh, and prevent further soft-tissue injury. They are NOT useful for fractures of the hip, knee, or lower leg, and should not be used when those areas or the pelvis are involved."},{"title":"Contraindications and Complications","content":"Do not apply a traction splint with a suspected pelvic fracture, hip injury/dislocation, knee injury, lower-leg or ankle fracture, or partial amputation. Applying traction across a fractured or dislocated knee can tear the popliteal vessels. Complications include neurovascular compromise from excessive traction, pressure injury at the ischium/ankle hitch, and delay of a critical patient—so they are deferred in load-and-go situations."},{"title":"Traction Splint Types","content":"The Hare and Thomas splints are unipolar/bipolar frame splints that apply traction against the ischium with an ankle hitch. The Sager splint applies traction from a single bar between the legs, can splint both legs, and is lower-profile. Always assess distal pulses, motor, and sensation before and after application, and apply only enough traction to realign and relieve pain."},{"title":"Pelvic Stabilization","content":"For a suspected unstable pelvic fracture, apply a commercial pelvic binder (or an improvised sheet) centered over the greater trochanters to close the pelvic ring and tamponade hemorrhage. Assess the pelvis gently only once. Handle the patient minimally, use a scoop stretcher for transfer, and treat for shock with rapid transport."},{"title":"Tourniquets and Hemostatic Agents","content":"For life-threatening extremity hemorrhage not controlled by direct pressure, apply a tourniquet 2–3 inches proximal to the wound (not over a joint), tighten until bleeding stops and the distal pulse is gone, and note the time. For junctional or deep wounds where a tourniquet cannot be placed, pack the wound with a hemostatic dressing and hold firm, direct pressure for the recommended time. Do not periodically loosen a tourniquet."}],"clinicalPearls":["Traction splints are for mid-shaft femur fractures only—never for hip, knee, lower-leg, or pelvic injuries.","Assess distal PMS before and after applying any splint.","Apply a tourniquet tight enough to eliminate the distal pulse, and write down the time of application.","Center a pelvic binder over the greater trochanters, not the iliac crests.","Pack hemostatic dressings directly into the bleeding source and hold sustained pressure."],"redFlags":["Applying traction across a fractured/dislocated knee can lacerate the popliteal artery.","Do not use a traction splint when a pelvic fracture is suspected.","Never periodically loosen a properly applied tourniquet to 'let blood flow.'","Do not delay a critical, load-and-go patient to apply a traction splint."],"commonMistakes":["Using a traction splint for a lower-leg, knee, hip, or pelvic injury.","Applying too little tourniquet pressure (venous tourniquet) that increases bleeding.","Placing a pelvic binder too high over the iliac crests instead of the trochanters.","Failing to reassess distal neurovascular status after splinting."],"memoryAids":["Traction splint = femur shaft ONLY.","Tourniquet: 2–3 inches proximal, not over a joint, tighten until pulse gone, note the TIME.","Pelvic binder = greater TROCHANTERS.","Hemorrhage control ladder: Pressure → Tourniquet → Hemostatic packing."],"decisionTrees":[{"title":"Extremity Hemorrhage and Splinting","content":"1. Life-threatening extremity bleeding? → direct pressure → tourniquet (2–3 in proximal, note time) → hemostatic packing for junctional wounds.\n2. Isolated mid-shaft femur fracture, stable patient? → traction splint (assess PMS before/after).\n3. Hip/knee/lower-leg/pelvis involved? → do NOT use traction splint; immobilize appropriately.\n4. Suspected unstable pelvis? → pelvic binder at greater trochanters, minimal handling, scoop transfer.\n5. Critical/load-and-go patient? → package and transport; defer traction splinting."}],"references":["International Trauma Life Support, 8th ed. Chapter 15: Extremity Trauma Skills.","Committee on Tactical Combat Casualty Care. Guidelines for Tourniquet and Hemostatic Use."]},"c16":{"id":"c16","title":"Burns","shortTitle":"Burns","estimatedStudyTime":30,"difficulty":"Advanced","learningObjectives":["Identify the basic anatomy and functions of the skin.","Describe types of burns by depth and estimate burn depth from appearance.","Estimate the extent of a burn using the rule of nines.","Identify complications and describe initial management of thermal, chemical, and electrical burns.","Identify signs of thermal airway/inhalation injury and carbon monoxide poisoning.","Explain how carbon monoxide causes hypoxia and describe its initial treatment.","Identify which patients require transport to a burn center."],"summary":[{"title":"Skin Anatomy and Function","content":"The skin has two main layers: the epidermis (outer) and the dermis (deeper, containing nerves, vessels, hair follicles, and glands). It protects against infection and injury, regulates temperature and fluid balance, and provides sensation. Burns disrupt these functions, leading to fluid loss, infection risk, and impaired thermoregulation."},{"title":"Burn Depth","content":"Superficial (first-degree) burns involve only the epidermis—red, painful, no blisters (like sunburn). Partial-thickness (second-degree) burns extend into the dermis—red, blistered, moist, very painful. Full-thickness (third-degree) burns destroy the entire dermis—dry, leathery, white/charred, and painless in the burned area because nerves are destroyed; surrounding partial-thickness areas remain painful."},{"title":"Estimating Extent: Rule of Nines","content":"The rule of nines estimates the percentage of total body surface area (TBSA) burned in adults: head 9%, each arm 9%, anterior trunk 18%, posterior trunk 18%, each leg 18%, and genitalia 1%. The patient's palm (including fingers) is roughly 1% TBSA for scattered burns. Children have proportionally larger heads, so a modified chart or a pediatric rule is used. Only partial- and full-thickness burns are counted."},{"title":"Airway and Inhalation Injury","content":"Suspect inhalation/thermal airway injury with facial burns, singed nasal/facial hair, soot in the mouth/nose, carbonaceous sputum, hoarseness, stridor, or a history of fire in an enclosed space. The airway can swell rapidly—secure it early, before edema makes intubation impossible. Give high-flow oxygen and monitor closely."},{"title":"Carbon Monoxide and Cyanide","content":"Carbon monoxide binds hemoglobin with ~250 times the affinity of oxygen, forming carboxyhemoglobin and causing tissue hypoxia despite a normal (falsely reassuring) pulse oximeter reading. Treat with 100% oxygen, which speeds CO elimination. Closed-space fires can also cause cyanide toxicity. Headache, confusion, and altered mental status in a fire victim should raise suspicion."},{"title":"Burn Management and Burn-Center Criteria","content":"Stop the burning process (remove from source, remove smoldering clothing/jewelry), ensure airway/breathing, and cover burns with clean dry dressings—avoid prolonged cooling that causes hypothermia. Provide fluid resuscitation for large burns per protocol and keep the patient warm. Chemical burns: brush off dry chemical, then irrigate copiously. Electrical burns: ensure scene safety, expect deep tissue and cardiac injury (monitor). Transport to a burn center for large/deep burns, burns of the face/hands/feet/genitalia/major joints, airway involvement, electrical/chemical burns, and burns with associated trauma or in extremes of age."}],"clinicalPearls":["Full-thickness burns are painless in the burned area—pain usually comes from surrounding partial-thickness burns.","Secure the airway EARLY in inhalation injury—waiting for edema can make intubation impossible.","A normal pulse oximeter reading does NOT exclude carbon monoxide poisoning—treat with 100% oxygen.","Use the rule of nines for adults and the palm (~1%) for scattered burns.","Cover burns with clean, dry dressings and keep the patient warm—avoid prolonged wet cooling."],"redFlags":["Facial burns, soot, singed hairs, hoarseness, or stridor signal impending airway obstruction—act before swelling closes the airway.","Pulse oximetry reads falsely normal in CO poisoning—rely on history and treat empirically with high-flow oxygen.","Circumferential full-thickness burns can compromise breathing (chest) or circulation (limbs).","Electrical injury causes deep tissue damage and dysrhythmias far beyond visible skin burns—apply cardiac monitoring."],"commonMistakes":["Underestimating airway risk and delaying intubation in inhalation injury.","Over-cooling burns and inducing hypothermia.","Trusting a normal SpO2 in a fire victim with possible CO poisoning.","Counting superficial (first-degree) burns in TBSA estimates."],"memoryAids":["Rule of Nines (adult): Head 9, each Arm 9, Front trunk 18, Back trunk 18, each Leg 18, Genitals 1.","Burn depth: Superficial (red), Partial (blisters, painful), Full (leathery, painless).","Inhalation clues: Face burns, Soot, Singed hairs, Hoarseness, enclosed-Space fire.","CO poisoning → 100% oxygen (don't trust the SpO2)."],"decisionTrees":[{"title":"Initial Burn Management","content":"1. Scene safety; stop the burning process (remove source, smoldering clothing, jewelry).\n2. Airway: signs of inhalation injury (facial burns, soot, hoarseness)? → high-flow oxygen, secure airway EARLY.\n3. Suspected CO? → 100% oxygen regardless of SpO2.\n4. Estimate depth and TBSA (rule of nines; count partial + full thickness).\n5. Cover with clean dry dressings; keep warm; fluid resuscitation for large burns per protocol.\n6. Chemical: brush off dry agent, irrigate copiously. Electrical: monitor for dysrhythmias, expect deep injury.\n7. Meets burn-center criteria? → transport to burn center."}],"references":["International Trauma Life Support, 8th ed. Chapter 16: Burns.","American Burn Association. Burn Center Referral Criteria."]},"c17":{"id":"c17","title":"Pediatric Trauma","shortTitle":"Pediatric Trauma","estimatedStudyTime":35,"difficulty":"Advanced","learningObjectives":["Describe techniques for gaining the confidence of children and their parents.","Predict pediatric injuries based on common mechanisms of injury.","Describe the ITLS Primary and Secondary Surveys in the pediatric patient.","Understand the need for immediate transport in life-threatening circumstances regardless of immediate consent.","Differentiate the equipment needs of pediatric patients from adults.","Describe spinal motion restriction in children and how it differs from adults.","Recognize signs of child abuse and the EMS role in reporting."],"summary":[{"title":"Anatomic and Physiologic Differences","content":"Children are not small adults. They have proportionally larger heads (more head injuries and neck flexion when supine), larger tongues and smaller airways (easily obstructed), more flexible ribs (lung contusion without rib fracture), and a relatively larger body surface area (rapid heat loss). Their organs are closer together and less protected, so multisystem injury is common."},{"title":"Robust Compensation, Then Sudden Collapse","content":"Children compensate for blood loss extremely well by raising heart rate and vasoconstricting, maintaining blood pressure until a large volume is lost—then they crash suddenly. Tachycardia is the earliest sign of shock; hypotension is a late, ominous finding. Estimate weight and drug doses with a length-based resuscitation tape to avoid dosing errors."},{"title":"Airway and Breathing","content":"Position the airway in a neutral 'sniffing' position (pad under the torso/shoulders, not the head, because the large occiput flexes the neck). Children are prone to rapid hypoxia; respiratory failure is the leading path to pediatric arrest. Use appropriately sized equipment and ventilate at age-appropriate rates, confirming chest rise."},{"title":"Pediatric SMR and SCIWORA","content":"Pad under the torso to maintain neutral alignment given the large head. Use size-appropriate devices (pediatric immobilizers, properly sized collars, or padding within a car seat for stable extrication). SCIWORA (Spinal Cord Injury Without Radiographic Abnormality) reflects that a child's elastic spine can stretch and injure the cord without a visible fracture—maintain a high index of suspicion based on mechanism and symptoms."},{"title":"Fluids, Equipment, and Hypothermia","content":"For decompensated shock, give weight-based fluid boluses (commonly 20 mL/kg of warmed isotonic crystalloid, reassessed and repeated per protocol). Use length-based tape for equipment and drug sizing. Children lose heat rapidly—keep them warm. Vascular access may require intraosseous placement when peripheral access fails."},{"title":"Consent and Child Abuse","content":"Provide immediate life-saving care regardless of the availability of parental consent (implied/emergency consent). Maintain a high index of suspicion for non-accidental trauma: injuries inconsistent with the stated mechanism or developmental stage, patterned injuries, multiple injuries in different healing stages, delayed presentation, or inconsistent histories. EMS providers are mandated reporters—document objectively and report per protocol."}],"clinicalPearls":["Children compensate well then crash suddenly—tachycardia is the earliest sign of shock; hypotension is late.","Pad under the torso (not the head) to keep a child's airway and spine neutral.","Use a length-based resuscitation tape for weight, drug doses, fluid volumes, and equipment sizes.","Respiratory failure is the most common path to pediatric cardiac arrest—aggressively support oxygenation/ventilation.","Provide life-saving care under implied consent when a parent is not immediately available."],"redFlags":["Hypotension in a child is a late, pre-arrest sign—treat aggressively before it appears.","SCIWORA: a normal-appearing spine does not exclude cord injury in children—rely on mechanism and symptoms.","Injuries inconsistent with the history or developmental stage suggest abuse—report per mandate.","Hypothermia develops quickly in children and worsens shock—keep them warm."],"commonMistakes":["Using adult drug doses or equipment instead of a length-based tape.","Padding under the head (worsening neck flexion) instead of under the torso.","Being falsely reassured by a normal blood pressure in an injured child.","Failing to recognize and report suspected non-accidental trauma."],"memoryAids":["Kids: big Head, big Tongue, small Airway, flexible Ribs, big surface area (heat loss).","Shock: Tachycardia early, Hypotension late (and ominous).","Pediatric fluid bolus ≈ 20 mL/kg warmed isotonic crystalloid, reassess and repeat.","Length-based tape = weight + doses + equipment sizes."],"decisionTrees":[{"title":"Pediatric Trauma Priorities","content":"1. Airway: neutral 'sniffing' position, pad under torso; suction; size-appropriate adjuncts.\n2. Breathing: high-flow oxygen; support ventilation early (respiratory failure → arrest).\n3. Circulation: tachycardia = early shock; control bleeding; IV/IO access; weight-based boluses (~20 mL/kg) per protocol; keep warm.\n4. SMR: pad under torso; size-appropriate device; suspect SCIWORA by mechanism.\n5. Use length-based tape for weight/doses/equipment.\n6. Provide life-saving care under implied consent; assess for and report suspected abuse.\n7. Rapid transport to a pediatric-capable trauma center."}],"references":["International Trauma Life Support, 8th ed. Chapter 17: Pediatric Trauma.","Maloney, P.J., and A.M. Dietrich. Prehospital Pediatric Trauma Care."]},"c18":{"id":"c18","title":"Geriatric Trauma","shortTitle":"Geriatric Trauma","estimatedStudyTime":25,"difficulty":"Intermediate","learningObjectives":["Describe the physiologic changes that occur with aging.","Explain how these changes affect assessment and management of the geriatric trauma patient.","Describe the assessment of the geriatric trauma patient.","Describe the management of the geriatric trauma patient."],"summary":[{"title":"The Pathophysiology of Aging","content":"Aging reduces physiologic reserve in every system: stiffer blood vessels and a less responsive heart, decreased lung elasticity and respiratory reserve, reduced kidney function, brain atrophy, thinning skin, and osteoporosis with kyphotic deformity of the spine. These changes mean older patients tolerate injury poorly and deteriorate faster, even from seemingly minor mechanisms."},{"title":"Blunted Compensation and Masking Medications","content":"Older adults have a limited ability to compensate for blood loss; a 'normal' heart rate may actually be inappropriately slow for the degree of shock. Beta-blockers and other medications blunt the tachycardic response, masking shock. A pacemaker fixes the heart rate. Anticoagulants and antiplatelet agents dramatically increase bleeding, especially intracranial hemorrhage after head trauma."},{"title":"Deceptive Vital Signs and Baseline Hypertension","content":"A blood pressure that looks normal may be low for a chronically hypertensive patient—relative hypotension. Maintain a high index of suspicion for occult injury and shock. Brain atrophy stretches bridging veins, so subdural hematomas can develop slowly after minor head trauma; symptoms may be delayed."},{"title":"Assessment Challenges","content":"Sensory deficits (hearing, vision), dementia, and baseline cognitive impairment complicate history and exam—obtain the patient's baseline from caregivers. Kyphosis requires padding to achieve comfortable, neutral spinal alignment. Osteoporotic bones fracture easily, including ribs (impairing ventilation) and the pelvis/hip from low-energy falls."},{"title":"Management Priorities","content":"Manage ABCs as in any trauma, but anticipate rapid decompensation and limited reserve. Provide oxygen, support ventilation (fragile ribs/low reserve), handle gently, and pad bony prominences and spinal curves. Maintain perfusion while avoiding over-aggressive fluids that can precipitate heart failure. Have a low threshold for transport to a trauma center, and account for anticoagulation when assessing head injury risk."}],"clinicalPearls":["Older patients have little physiologic reserve—they tolerate injury poorly and crash quickly.","Beta-blockers and pacemakers can mask the tachycardia of shock—do not be reassured by a 'normal' heart rate.","Anticoagulants/antiplatelets greatly increase bleeding, especially intracranial hemorrhage after head trauma.","A 'normal' blood pressure may be relative hypotension in a chronically hypertensive patient.","Pad kyphotic curves to achieve comfortable, neutral spinal alignment."],"redFlags":["A minor mechanism can cause major injury in the elderly—low-energy falls can fracture the hip, pelvis, or ribs.","Subdural hematoma can develop slowly after minor head trauma due to brain atrophy—symptoms may be delayed.","Rib fractures in the elderly markedly increase morbidity from impaired ventilation and pneumonia.","Over-aggressive fluid resuscitation can precipitate pulmonary edema/heart failure."],"commonMistakes":["Being falsely reassured by 'normal' vital signs that are actually abnormal for the patient.","Forgetting to ask about anticoagulants and antiplatelet medications.","Forcing a kyphotic spine flat against a board.","Underestimating the severity of low-energy mechanisms."],"memoryAids":["Aging = decreased reserve in every system.","Masked shock: Beta-blockers + Pacemaker = no tachycardia.","Anticoagulants + head injury = high intracranial bleeding risk.","Normal BP may be relative hypotension in the chronically hypertensive elder."],"decisionTrees":[{"title":"Geriatric Trauma Considerations","content":"1. Assume limited reserve—anticipate rapid decompensation even with minor mechanisms.\n2. Ask about medications (beta-blockers, anticoagulants/antiplatelets) and pacemaker.\n3. Interpret vitals relative to baseline (normal BP may be relative hypotension; HR may be masked).\n4. Support oxygenation/ventilation (fragile ribs, low reserve); avoid fluid overload.\n5. Pad kyphosis/bony prominences for comfortable neutral alignment.\n6. Low threshold for trauma-center transport; heightened concern for head injury on blood thinners."}],"references":["International Trauma Life Support, 8th ed. Chapter 18: Geriatric Trauma.","Heimbach, L.J., J.G. Newman, and J.F. Baldwin. Trauma in the Older Adult."]},"c19":{"id":"c19","title":"Trauma in Pregnancy","shortTitle":"Trauma in Pregnancy","estimatedStudyTime":25,"difficulty":"Advanced","learningObjectives":["Understand the dual goals in managing the pregnant trauma patient.","Describe the physiologic changes associated with pregnancy.","Understand the pregnant trauma patient's response to hypovolemia.","Describe the injuries most commonly associated with the pregnant trauma patient.","Describe the initial assessment and management of the pregnant trauma patient.","Discuss trauma prevention in pregnancy."],"summary":[{"title":"The Dual Goals","content":"Caring for the pregnant trauma patient means caring for two patients, but the best way to save the fetus is to resuscitate the mother. Prioritize the mother's airway, breathing, and circulation; what is good for the mother is good for the fetus. Any pregnant trauma patient beyond about 20 weeks gestation needs evaluation even after seemingly minor trauma."},{"title":"Physiologic Changes of Pregnancy","content":"Blood volume increases by roughly 40–50%, and heart rate rises by 15–20 beats/min, so a pregnant patient can lose a large volume of blood before showing signs of shock—and the fetus may be compromised while maternal vitals still look normal. Respiratory rate and oxygen demand increase, gastric emptying slows (aspiration risk), and the diaphragm is elevated by the gravid uterus."},{"title":"Supine Hypotension Syndrome","content":"After about 20 weeks, the gravid uterus can compress the inferior vena cava when the patient lies supine, reducing venous return and causing hypotension. Prevent or treat this by tilting the patient 15–30 degrees to the left (or manually displacing the uterus to the left), which relieves aortocaval compression and improves cardiac output—while maintaining spinal motion restriction by tilting the whole board."},{"title":"Patterns of Injury","content":"Common injuries include blunt abdominal trauma, and pregnancy-specific concerns such as abruptio placenta (placental separation—vaginal bleeding, abdominal pain, uterine tenderness/rigidity, and fetal distress), uterine rupture, and preterm labor. Domestic violence is an important and under-recognized cause of trauma in pregnancy—assess and document carefully."},{"title":"Assessment and Management","content":"Resuscitate the mother first: high-flow oxygen, support ventilation, control hemorrhage, and give fluids generously (the mother's increased volume needs replacement, and the fetus depends on maternal perfusion). Transport in the left-tilt position, monitor for vaginal bleeding and contractions, and transport to a facility capable of maternal and fetal care. Even minor mechanisms warrant evaluation because placental abruption can occur without external signs."}],"clinicalPearls":["The best treatment for the fetus is aggressive resuscitation of the mother.","A pregnant patient can lose substantial blood before showing shock—maternal vitals can be falsely reassuring.","After ~20 weeks, tilt the patient (and the board) 15–30 degrees to the left to relieve aortocaval compression.","Give oxygen and resuscitate generously—the fetus depends entirely on maternal perfusion.","Even minor trauma warrants evaluation; placental abruption can occur with few external signs."],"redFlags":["Vaginal bleeding, abdominal pain, and a tender/rigid uterus suggest abruptio placenta—a fetal and maternal emergency.","Maternal hypotension or distress signals fetal compromise even when fetal signs are not directly assessed.","Supine positioning after 20 weeks can itself cause hypotension—always tilt left.","Consider and screen for domestic violence as a cause of injury in pregnancy."],"commonMistakes":["Transporting a late-pregnancy patient flat and supine, causing supine hypotension.","Being falsely reassured by 'normal' maternal vitals despite a significant mechanism.","Withholding oxygen or under-resuscitating the mother.","Discharging/clearing a pregnant patient after a minor mechanism without evaluation."],"memoryAids":["Two patients, one priority: resuscitate the MOTHER to save the fetus.","Left tilt 15–30° after 20 weeks for supine hypotension syndrome.","Abruptio placenta: bleeding + pain + tender/rigid uterus + fetal distress.","Pregnancy: +40–50% blood volume, +15–20 bpm — shock signs appear late."],"decisionTrees":[{"title":"Pregnant Trauma Patient","content":"1. Resuscitate the mother first: high-flow oxygen, support ABCs, control hemorrhage, generous fluids.\n2. After ~20 weeks → tilt patient (and board) 15–30° left, or manually displace uterus left.\n3. Assess for vaginal bleeding, abdominal pain, uterine tenderness/rigidity (abruptio placenta), contractions.\n4. Recognize maternal vitals may look normal while the fetus is compromised—treat aggressively.\n5. Screen/document for domestic violence.\n6. Transport (even after minor mechanisms) to a facility with maternal/fetal capability."}],"references":["International Trauma Life Support, 8th ed. Chapter 19: Trauma in Pregnancy.","Bradley, W.J. Prehospital Care of the Pregnant Trauma Patient."]},"c20":{"id":"c20","title":"The Impaired Patient","shortTitle":"Impaired Patient","estimatedStudyTime":20,"difficulty":"Intermediate","learningObjectives":["List the signs and symptoms of patients under the influence of alcohol and/or drugs.","Describe strategies to gain cooperation during assessment and management.","Define excited delirium.","List special considerations for assessing and managing patients with suspected substance abuse."],"summary":[{"title":"Why Impairment Is Dangerous in Trauma","content":"Alcohol and drugs impair judgment, mask pain, and cloud the mental status exam, making it dangerous to attribute altered behavior to intoxication alone. Impaired patients are at higher risk of trauma and of having serious injuries (head injury, hemorrhage, hypoxia, hypoglycemia) hidden behind the assumption that they are 'just drunk.' Always assume a medical or traumatic cause for altered behavior until proven otherwise."},{"title":"Signs of Alcohol and Drug Influence","content":"Signs include slurred speech, unsteady gait, the odor of alcohol, dilated or constricted pupils, altered mental status, mood lability, agitation or somnolence, and abnormal vital signs. Different substances produce different patterns (stimulants cause tachycardia/agitation/hyperthermia; opioids cause sedation, pinpoint pupils, and respiratory depression). These signs overlap with head injury, hypoglycemia, hypoxia, and shock."},{"title":"Gaining Cooperation","content":"Use a calm, nonjudgmental, and reassuring interactive style. Introduce yourself, explain what you are doing, set clear and simple expectations, and use closed-ended questions when the patient is difficult. Minimize stimulation, avoid confrontation, allow personal space when safe, and enlist trusted bystanders. Maintain scene safety and your own safety at all times."},{"title":"Excited Delirium","content":"Excited delirium is a life-threatening state of extreme agitation, aggression, paranoia, hyperthermia, and apparent superhuman strength, often associated with stimulant use or psychiatric illness. It can rapidly progress to cardiovascular collapse and sudden death. It is a true medical emergency requiring rapid, coordinated control, sedation per protocol, cooling, and continuous monitoring—not simply prolonged physical restraint."},{"title":"Capacity, Restraint, and Special Considerations","content":"An impaired patient may lack the decision-making capacity to refuse care; involve medical direction and follow local protocol and law. Use restraint only when necessary for the safety of the patient or crew, applying it humanely and never in a position that compromises breathing (avoid prone/hog-tie positioning, which risks positional asphyxia). Continuously reassess the restrained patient. Always check glucose and oxygenation, and search diligently for occult injury."}],"clinicalPearls":["Never assume altered behavior is 'just intoxication'—rule out head injury, hypoglycemia, hypoxia, and shock first.","Check a blood glucose and oxygen saturation on every impaired patient.","A calm, nonjudgmental approach gains more cooperation than confrontation.","Excited delirium is a medical emergency that can cause sudden death—act rapidly and cool the patient.","Never restrain a patient prone or in a hog-tie position—risk of positional asphyxia."],"redFlags":["Attributing a deteriorating mental status to alcohol while missing an expanding intracranial hemorrhage.","Excited delirium can progress to cardiovascular collapse and sudden death—do not under-triage it.","Prone/hog-tie restraint and excessive struggle can cause positional asphyxia and death.","Opioid-impaired patients can have life-threatening respiratory depression—support ventilation and consider naloxone."],"commonMistakes":["Dismissing serious injury or illness as intoxication.","Failing to check glucose and oxygenation.","Escalating confrontation instead of de-escalating.","Leaving a restrained patient unmonitored or in a dangerous position."],"memoryAids":["Impaired + altered = assume a treatable cause (Head injury, Hypoglycemia, Hypoxia, Shock) until proven otherwise.","Always check glucose and SpO2.","De-escalate: Calm, Nonjudgmental, Clear, Space, Safety.","Excited delirium = agitation + hyperthermia + collapse risk → medical emergency."],"decisionTrees":[{"title":"Approach to the Impaired Patient","content":"1. Ensure scene and personal safety.\n2. Assume a medical/traumatic cause for altered behavior—do not blame intoxication.\n3. Check glucose and SpO2; support airway/ventilation (especially opioids).\n4. De-escalate with a calm, nonjudgmental approach; use closed-ended questions if needed.\n5. Excited delirium (extreme agitation, hyperthermia)? → medical emergency: control, sedate per protocol, cool, monitor.\n6. Restraint only if necessary; never prone/hog-tie; reassess continuously.\n7. Address capacity with medical direction; search for and treat occult injury; transport."}],"references":["International Trauma Life Support, 8th ed. Chapter 20: The Impaired Patient.","Newman, J.G. Assessment and Management of the Impaired Patient."]},"c21":{"id":"c21","title":"Trauma Arrest (Traumatic Cardiopulmonary Arrest)","shortTitle":"Trauma Arrest","estimatedStudyTime":25,"difficulty":"Advanced","learningObjectives":["Identify the treatable causes of traumatic cardiopulmonary arrest.","Describe the proper evaluation and management of the patient in traumatic cardiopulmonary arrest.","Identify patients in traumatic cardiac arrest for whom resuscitation should be withheld."],"summary":[{"title":"Trauma Arrest Is Different","content":"Traumatic cardiopulmonary arrest (TCPA) differs fundamentally from medical cardiac arrest. The cause is usually a mechanical or reversible problem (hypovolemia, hypoxia, obstructive shock), not a primary cardiac dysrhythmia. Survival depends on rapidly identifying and correcting the treatable cause and getting the patient to definitive surgical care—chest compressions alone rarely help if the underlying cause is not addressed."},{"title":"Treatable Causes","content":"Focus on the reversible causes of TCPA: severe hypoxia (airway obstruction, including foreign-body airway obstruction/FBAO), tension pneumothorax, cardiac tamponade, and massive hemorrhage/hypovolemia. These map onto the classic 'H's and T's' but with a trauma emphasis. Each has a specific intervention: secure/clear the airway and oxygenate, decompress the chest bilaterally, relieve tamponade (surgical), and control hemorrhage with rapid transport for surgery and blood."},{"title":"Evaluation and Management","content":"Work efficiently and simultaneously: open and secure the airway with oxygenation/ventilation; decompress both sides of the chest if tension pneumothorax is suspected; control external hemorrhage (pressure, tourniquet, hemostatic, pelvic binder); and provide rapid transport to a trauma center for definitive surgical control and blood products. High-quality compressions are provided, but the priority is correcting the mechanical cause. For penetrating trauma with recent signs of life, rapid transport for possible surgical intervention may be life-saving."},{"title":"When to Withhold or Terminate Resuscitation","content":"Some trauma patients are unsalvageable, and resuscitation may be withheld. Generally, withhold resuscitation for injuries obviously incompatible with life (decapitation, hemicorporectomy, incineration, dependent lividity, rigor mortis, decomposition) and for blunt or penetrating trauma patients found apneic, pulseless, and without other signs of life with prolonged arrest. Follow local protocol; involving medical direction is appropriate when criteria are unclear."},{"title":"Foreign-Body Airway Obstruction","content":"FBAO can cause a hypoxic arrest that is rapidly reversible. For a conscious choking patient with a severe obstruction, deliver abdominal thrusts (chest thrusts for pregnant/obese patients); for the unconscious patient, begin CPR and look for/remove the visualized obstruction. Direct laryngoscopy with Magill forceps can remove an obstructing object. Restoring the airway can immediately reverse the arrest."}],"clinicalPearls":["In trauma arrest, fix the mechanical cause—compressions alone rarely work if hypovolemia or obstruction persists.","Suspect and decompress bilateral tension pneumothorax in any traumatic arrest with chest trauma.","Control hemorrhage aggressively and transport rapidly for surgery and blood.","FBAO arrest is rapidly reversible—relieve the obstruction immediately.","Know your local criteria for withholding/terminating resuscitation in unsalvageable trauma."],"redFlags":["Failure to address hypovolemia, tension pneumothorax, or tamponade makes compressions futile.","Injuries obviously incompatible with life (decapitation, incineration) warrant withholding resuscitation per protocol.","Penetrating-trauma arrest with recent signs of life is time-critical—transport immediately for possible surgery.","Do not delay transport of a salvageable trauma-arrest patient for prolonged on-scene efforts."],"commonMistakes":["Treating trauma arrest like medical arrest (focusing on rhythm/drugs instead of the mechanical cause).","Failing to decompress the chest in a traumatic arrest with chest injury.","Continuing prolonged resuscitation on an obviously unsalvageable patient against protocol.","Delaying transport for a salvageable penetrating-trauma arrest."],"memoryAids":["Treatable TCPA causes: Hypoxia (airway/FBAO), Tension pneumothorax, Tamponade, Hypovolemia (hemorrhage).","Fix the cause → then compressions matter.","Chest trauma arrest → decompress BOTH sides.","Unsalvageable signs: decapitation, hemicorporectomy, incineration, rigor, dependent lividity, decomposition."],"decisionTrees":[{"title":"Traumatic Cardiac Arrest Management","content":"1. Injuries incompatible with life or protocol criteria met? → withhold resuscitation per protocol.\n2. Otherwise, address treatable causes simultaneously:\n   - Airway: open/secure, oxygenate/ventilate; relieve FBAO if present.\n   - Breathing: suspect tension pneumothorax → bilateral chest decompression.\n   - Circulation: control hemorrhage (pressure, tourniquet, hemostatic, pelvic binder); IV/IO; blood per protocol.\n3. Provide high-quality CPR while correcting the mechanical cause.\n4. Penetrating trauma with recent signs of life → immediate transport for possible surgery.\n5. Rapid transport to a trauma center; consider termination per protocol if no response and criteria met."}],"references":["International Trauma Life Support, 8th ed. Chapter 21: Trauma Arrest.","Fowler, R., A. Idris, and J. Brywczynski. Management of Traumatic Cardiopulmonary Arrest."]},"c22":{"id":"c22","title":"Standard Precautions and Transmission-Based Precautions","shortTitle":"Standard Precautions","estimatedStudyTime":20,"difficulty":"Intermediate","learningObjectives":["Discuss the three most common bloodborne viral illnesses to which providers may be exposed.","Discuss signs/symptoms of airborne and droplet-transmitted diseases and protective measures.","Describe precautions to prevent exposure to blood and other potentially infectious materials.","Describe the steps to take after an exposure, including post-exposure prophylaxis (PEP)."],"summary":[{"title":"Standard Precautions","content":"Standard precautions treat the blood and body fluids of every patient as potentially infectious. They include hand hygiene, gloves, and—when splashing is possible—face/eye protection, gowns, and masks. Apply them universally regardless of a patient's known diagnosis, because infection status is often unknown. They protect against exposure to blood and other potentially infectious materials (OPIM)."},{"title":"Bloodborne Viral Illnesses","content":"The three most important bloodborne viral illnesses for providers are hepatitis B virus (HBV), hepatitis C virus (HCV), and human immunodeficiency virus (HIV). HBV is the most transmissible of the three and is vaccine-preventable—providers should be vaccinated. HCV has no vaccine. HIV has a lower transmission risk per exposure but serious consequences. All are spread through blood and certain body fluids via needlesticks, mucous membranes, or non-intact skin."},{"title":"Transmission-Based Precautions","content":"When standard precautions are not enough, add transmission-based precautions: Contact precautions (gowns/gloves for organisms spread by touch), Droplet precautions (a surgical mask for diseases spread by large respiratory droplets, e.g., influenza, meningococcus), and Airborne precautions (a fit-tested N95/respirator and patient masking for small-particle diseases such as tuberculosis, measles, and varicella). Recognize symptoms (cough, fever, rash) and apply the right level early."},{"title":"Tuberculosis and the BCG Note","content":"Tuberculosis (TB) is spread by the airborne route; suspect it in patients with chronic cough, fever, night sweats, and weight loss, and use airborne precautions (N95 for the provider, surgical mask on the patient). The bacille Calmette-Guérin (BCG) vaccine, used in some countries, can cause a positive TB skin test, complicating screening—interpretation requires clinical context."},{"title":"Post-Exposure Management","content":"After a significant exposure (needlestick, splash to mucous membranes or non-intact skin): immediately wash the site with soap and water (flush mucous membranes with water/saline), report the exposure per protocol, and seek evaluation promptly. Post-exposure prophylaxis (PEP) for HIV is time-sensitive and most effective when started as soon as possible (within hours). HBV-vaccinated providers have strong protection; HBV immune globulin/vaccination and follow-up testing are arranged as indicated. There is no PEP for HCV, but early identification allows monitoring and treatment."}],"clinicalPearls":["Treat every patient's blood and body fluids as potentially infectious—apply standard precautions universally.","HBV is vaccine-preventable—be vaccinated; HCV and HIV have no vaccine.","Match the precaution to the route: Contact (touch), Droplet (surgical mask), Airborne (fit-tested N95).","Suspect TB with chronic cough/fever/night sweats/weight loss—use airborne precautions early.","Start HIV post-exposure prophylaxis as soon as possible after a significant exposure—time matters."],"redFlags":["A needlestick or mucous-membrane splash is a true exposure—wash, report, and seek evaluation immediately.","Delaying HIV PEP reduces its effectiveness—it is time-sensitive.","Failing to don a fit-tested N95 for a suspected TB/measles patient risks airborne transmission.","Assuming a patient is 'low risk' and skipping precautions—infection status is frequently unknown."],"commonMistakes":["Selectively applying precautions based on assumptions about a patient instead of universally.","Using a surgical mask when a fit-tested N95 (airborne) is required.","Delaying reporting and PEP after an exposure.","Not being vaccinated against hepatitis B."],"memoryAids":["Three bloodborne viruses: HBV (vaccine), HCV (no vaccine), HIV (time-sensitive PEP).","Transmission precautions: Contact (gown/gloves), Droplet (surgical mask), Airborne (N95).","Airborne diseases: TB, Measles, Varicella ('My Chicken-pox TB').","After exposure: Wash → Report → Evaluate → PEP (start HIV PEP ASAP)."],"decisionTrees":[{"title":"Precautions and Exposure Response","content":"1. Every patient → standard precautions (hand hygiene, gloves; add eye/face/gown for splash risk).\n2. Suspected transmissible disease → add precautions: Contact (touch organisms), Droplet (surgical mask: influenza, meningococcus), Airborne (N95 + patient mask: TB, measles, varicella).\n3. Exposure occurs (needlestick/splash) → wash site with soap and water / flush mucous membranes.\n4. Report per protocol and seek evaluation immediately.\n5. Start HIV PEP as soon as possible; arrange HBV prophylaxis/testing as indicated; monitor for HCV (no PEP)."}],"references":["International Trauma Life Support, 8th ed. Chapter 22: Standard Precautions and Transmission-Based Precautions.","CDC. Guideline for Isolation Precautions and Bloodborne Pathogen Standards (OSHA)."]}},"flashcards":{"c01":{"chapter":"c01","cards":[{"id":"c01_fc01","question":"What are the first steps and decisions you need to make upon arrival at a trauma scene?","answer":"Consider these questions: Is the scene safe? Are responders or victims in potential danger? What protective clothing is required? Other than the spill, are there other potential hazards? How many patients do you have? What additional equipment may be required?","category":"Scene Size-Up"},{"id":"c01_fc02","question":"What does a 'windshield survey' involve before leaving your response vehicle at the scene?","answer":"A windshield survey involves considering potential dangers such as crash/rescue scenes, farms, crime scenes, bystanders, and mass-shooting events.","category":"Scene Safety"},{"id":"c01_fc03","question":"What are the essential steps in managing a blast scene according to this chapter?","answer":"If it is necessary to enter the blast zone, do so using protective clothing and respiratory protection. Identify those who are still alive prior to entry if possible. Rapidly rescue patients who are too injured to walk.","category":"Blast Injuries"},{"id":"c01_fc04","question":"What is the significance of a deformed steering wheel in a head-on collision?","answer":"A deformed steering wheel indicates high kinetic energy and should heighten your index of suspicion for possible occult injuries, especially to the face, neck, thoracic, or abdominal regions.","category":"Motor-Vehicle Collisions"},{"id":"c01_fc05","question":"What are the common injuries associated with a rear-impact collision?","answer":"Common injuries include cervical-spine injury, respiratory distress due to pulmonary contusions or pneumothorax, and flail chest.","category":"Motor-Vehicle Collisions"},{"id":"c01_fc06","question":"What are the key differences between a frontal-impact collision and a lateral-impact (T-bone) collision?","answer":"Frontal-impact collisions involve rapid forward deceleration, while lateral-impact collisions include both body and organ collisions with additional lateral displacement injuries.","category":"Motor-Vehicle Collisions"},{"id":"c01_fc07","question":"What are the potential injuries from a rear-end collision?","answer":"Potential injuries include cervical-spine injury, exposure to all mechanisms of injury with increased mortality.","category":"Motor-Vehicle Collisions"},{"id":"c01_fc08","question":"What are the common forms of penetrating wounds mentioned in this chapter?","answer":"Common forms include knife and gun wounds. Knife wounds depend on anatomic area, blade length, and angle of penetration, while gunshot wounds vary based on bullet factors like size, deformity, and construction.","category":"Penetrating Injuries"},{"id":"c01_fc09","question":"What are the primary mechanisms of injury in a tractor accident?","answer":"The primary mechanism is crush injuries. Additional mechanisms include chemical burns, thermal burns, and potential prolonged entrapment leading to crush syndrome.","category":"Tractor Accidents"},{"id":"c01_fc10","question":"What are the key factors in assessing a fall injury?","answer":"Key factors include distance of fall, anatomic area impacted, and surface struck. These should be relayed to medical direction.","category":"Falls"},{"id":"c01_fc11","question":"What are the five mechanisms of injury associated with blast injuries?","answer":"Primary (direct effect of blast overpressure), secondary (patient struck by shrapnel), tertiary (body thrown and impacted), quaternary (inhalation or thermal burns from explosion fireball), and quinary (hyperinflammatory state due to exposure to contaminants).","category":"Blast Injuries"},{"id":"c01_fc12","question":"What is the significance of a high-energy event in trauma assessment?","answer":"A high-energy event signifies a large release of uncontrolled energy, and patients are at risk for severe injuries. Consider the patient injured until proven otherwise.","category":"Mechanism of Injury"},{"id":"c01_fc16","question":"What are the first steps and decisions you need to make upon arrival at a trauma scene according to the chapter?","answer":"First, ensure the scene is safe. Determine if responders or victims are in potential danger. Identify required protective clothing. Check for other potential hazards. Assess the total number of patients. Determine additional equipment needed.","category":"Scene Size-Up"},{"id":"c01_fc17","question":"What is a high-energy event, and why is it significant in trauma assessment?","answer":"A high-energy event is an injury mechanism involving a large release of uncontrolled kinetic energy. It signifies increased chances for serious injuries, even with normal vital signs initially.","category":"Mechanism of Injury"},{"id":"c01_fc18","question":"What are the three basic mechanisms of motion injury as discussed in the chapter?","answer":"The three basic mechanisms of motion injury are blunt, penetrating, and blast injuries.","category":"Mechanism of Injury"},{"id":"c01_fc19","question":"What is a key factor to consider when assessing a patient involved in a motor-vehicle collision (MVC)?","answer":"Consider the mechanism of injury, as it can predict occult injuries such as head, cervical-spine, and chest injuries.","category":"Motor-Vehicle Collisions"},{"id":"c01_fc20","question":"What are the three types of collisions in a motor-vehicle crash according to the chapter?","answer":"The three types of collisions are machine collision, body collision, and organ collision.","category":"Motor-Vehicle Collisions"},{"id":"c01_fc21","question":"What is a potential injury from an unrestrained driver in a head-on collision with the steering wheel?","answer":"Potential injuries include face, neck, thoracic, or abdominal trauma due to the ring and column of the steering wheel.","category":"Motor-Vehicle Collisions"},{"id":"c01_fc22","question":"What are the key steps in assessing a patient involved in a rear-impact collision?","answer":"Check for deformity of the vehicle, assess dash and steering wheel for injuries, look for facial trauma, coup/contracoup brain injury, hyperextension/flexion of the cervical spine, pelvis, hip, and knee trauma.","category":"Motor-Vehicle Collisions"},{"id":"c01_fc23","question":"What is a common mechanism of injury in tractor accidents?","answer":"Tractor accidents commonly involve crush injuries due to the high center of gravity and potential for overturning.","category":"Tractor Accidents"},{"id":"c01_fc24","question":"What are the two basic types of tractors mentioned in the chapter?","answer":"The two basic types of tractors are two-wheel drive and four-wheel drive.","category":"Tractor Accidents"},{"id":"c01_fc25","question":"What is a key factor to consider when managing a patient involved in a fall?","answer":"Consider the distance of the fall, the anatomic area impacted, and the surface struck.","category":"Falls"},{"id":"c01_fc26","question":"What are the three parts of a gunshot wound as described in the chapter?","answer":"The three parts of a gunshot wound are entry wound, exit wound, and internal wound.","category":"Penetrating Injuries"},{"id":"c01_fc27","question":"What is the primary mechanism of injury in blast injuries?","answer":"The primary mechanism of injury in blast injuries is caused by the direct effect of blast overpressure on air-filled structures such as the lungs, ears, and gastrointestinal tract.","category":"Blast Injuries"},{"id":"c01_fc28","question":"What are the five factors associated with blast injuries?","answer":"The five factors are primary (initial air blast), secondary (material propelled by blast force), tertiary (body thrown and impacted), quaternary (explosion fireball, thermal burns, inhalation of toxic dust or fumes), and quinary (hyperinflammatory state from exposure to contaminants).","category":"Blast Injuries"}]},"c02":{"chapter":"c02","cards":[{"id":"c02_fc01","question":"What are the four reasons to interrupt the ITLS Primary Survey during patient assessment?","answer":"The four reasons to interrupt the ITLS Primary Survey are: (1) the scene becomes unsafe, (2) exsanguinating hemorrhage requires treatment, (3) an airway obstruction needs to be addressed, or (4) cardiac arrest occurs.","category":"Trauma Assessment"},{"id":"c02_fc02","question":"What does the AVPU scale stand for and what does it assess?","answer":"The AVPU scale stands for Alert, Verbal, Pain, Unresponsive. It assesses the patient's level of consciousness by evaluating their responsiveness to verbal stimuli and pain.","category":"Initial Assessment"},{"id":"c02_fc03","question":"What is the purpose of the ITLS Primary Survey?","answer":"The purpose of the ITLS Primary Survey is to determine if immediately life-threatening conditions exist and to identify those patients who should have immediate transport to the hospital.","category":"Trauma Assessment"},{"id":"c02_fc04","question":"What are the steps in the ITLS Primary Survey?","answer":"The steps in the ITLS Primary Survey include: scene size-up, initial assessment (general impression and level of consciousness), rapid trauma survey or focused exam.","category":"Trauma Assessment"},{"id":"c02_fc05","question":"What is the difference between a rapid trauma survey and a focused exam?","answer":"A rapid trauma survey is performed when there is a dangerous generalized mechanism of injury or an unknown mechanism, while a focused exam is limited to the area affected by a localized injury.","category":"Trauma Assessment"},{"id":"c02_fc06","question":"What are the key components of the initial assessment during the ITLS Primary Survey?","answer":"The key components include general impression, level of consciousness (AVPU scale), and manual spinal motion restriction.","category":"Initial Assessment"},{"id":"c02_fc07","question":"What should be done if a patient has an altered mental status during the initial assessment?","answer":"If a patient has an altered mental status, assess it using the AVPU scale and check for signs of increased intracranial pressure. A brief neurologic exam may also be performed.","category":"Initial Assessment"},{"id":"c02_fc08","question":"What is the purpose of the ITLS Ongoing Exam?","answer":"The purpose of the ITLS Ongoing Exam is to assess for changes in the patient's condition and monitor ongoing interventions.","category":"Ongoing Assessment"},{"id":"c02_fc09","question":"How often should an ITLS Ongoing Exam be performed during transport?","answer":"The ITLS Ongoing Exam should be performed no less than every five minutes for critical patients and every 15 minutes for stable patients.","category":"Ongoing Assessment"},{"id":"c02_fc10","question":"What is the purpose of the ITLS Secondary Survey?","answer":"The purpose of the ITLS Secondary Survey is to pick up additional injuries that might have been missed in the brief ITLS Primary Survey.","category":"Secondary Assessment"},{"id":"c02_fc11","question":"What elements should be included when performing an ITLS Secondary Survey?","answer":"Elements include repeating the initial assessment, considering monitors (cardiac, pulse oximeter), recording vital signs, and performing a detailed head-to-toe exam.","category":"Secondary Assessment"},{"id":"c02_fc12","question":"What are some adjuncts for trauma patient assessment mentioned in the text?","answer":"Adjuncts include serum lactate and portable ultrasound, which can help distinguish between patients with critical injuries who need immediate transport to a trauma center and those who may be stable initially but could decompensate later.","category":"Assessment Tools"},{"id":"c02_fc16","question":"What is the purpose of the initial assessment in trauma care?","answer":"The initial assessment prioritizes the patient and identifies immediately life-threatening conditions, guiding critical interventions and transport decisions.","category":"Trauma Assessment"},{"id":"c02_fc17","question":"What does AVPU stand for in assessing a trauma patient's level of consciousness?","answer":"Alert, Verbal, Pain, Unresponsive","category":"Consciousness Assessment"},{"id":"c02_fc18","question":"When should you interrupt the ITLS Primary Survey during assessment of a trauma patient?","answer":"You should interrupt if the scene becomes unsafe, there is exsanguinating hemorrhage, an airway obstruction, or cardiac arrest.","category":"Assessment Interruptions"},{"id":"c02_fc19","question":"What are the key components of the ITLS Primary Survey?","answer":"Scene size-up, initial assessment, and rapid trauma survey or focused exam.","category":"Primary Survey Components"},{"id":"c02_fc20","question":"Describe the steps involved in performing a rapid trauma survey on a trauma patient.","answer":"Evaluate head and neck, chest, abdomen, pelvis, and lower/upper extremities for life-threatening injuries; check for bleeding control and vital signs.","category":"Rapid Trauma Survey"},{"id":"c02_fc21","question":"What is the purpose of the ITLS Ongoing Exam?","answer":"To assess changes in the patient's condition during transport, ensuring timely interventions and monitoring.","category":"Ongoing Exam Purpose"},{"id":"c02_fc22","question":"What is the difference between an ITLS Primary Survey and an ITLS Secondary Survey?","answer":"The primary survey is brief, focusing on life-threatening conditions; the secondary survey is comprehensive, evaluating all injuries.","category":"Survey Differences"},{"id":"c02_fc23","question":"What should you do if a trauma patient has an altered mental status during assessment?","answer":"Perform a brief neurologic exam to identify possible increased intracranial pressure and document findings.","category":"Altered Mental Status"},{"id":"c02_fc24","question":"What are the key elements of the ITLS Secondary Survey?","answer":"Repeat initial assessment, consider using monitors, record vital signs, perform a detailed head-to-toe exam.","category":"Secondary Survey Elements"},{"id":"c02_fc25","question":"What is the significance of the Glasgow Coma Scale in trauma care?","answer":"It assesses level of consciousness and helps guide treatment decisions for patients with head injuries.","category":"Glasgow Coma Scale"},{"id":"c02_fc26","question":"What are the steps involved in performing a detailed exam during an ITLS Secondary Survey?","answer":"Inspect, auscultate, palpate, and percuss; check for medical identification tags, medication patches, and implanted devices.","category":"Detailed Exam"},{"id":"c02_fc27","question":"What is the purpose of a load-and-go situation in trauma care?","answer":"To transport a patient immediately due to critical conditions that require urgent medical attention.","category":"Load-and-Go"},{"id":"c02_fc28","question":"What are some adjuncts used for trauma triage in the prehospital setting?","answer":"Serum lactate and ultrasound can predict occult internal bleeding and assess for intra-abdominal hemorrhage, pneumothoraces, and cardiac tamponade.","category":"Trauma Triage Adjuncts"}]},"c03":{"chapter":"c03","cards":[{"id":"c03_fc01","question":"What are the three major components of the ITLS Primary Survey?","answer":"Scene size-up, initial assessment, and either the rapid trauma survey (generalized/unknown MOI) or the focused exam (localized MOI).","category":"Primary Survey"},{"id":"c03_fc02","question":"Within what timeframe should the ITLS Primary Survey identify a load-and-go patient?","answer":"Within about two minutes of patient contact.","category":"Primary Survey"},{"id":"c03_fc03","question":"What does the AVPU scale stand for?","answer":"Alert, responds to Voice, responds to Pain, Unresponsive.","category":"Initial Assessment"},{"id":"c03_fc04","question":"What does the 'C' before A-B-C (CABC) emphasize in the initial assessment?","answer":"Control of catastrophic/life-threatening external bleeding before moving on to airway, breathing, and circulation.","category":"Initial Assessment"},{"id":"c03_fc05","question":"What four airway sounds should you listen for during the initial assessment?","answer":"Snoring, gurgling, stridor, and silence—each suggests a specific airway problem requiring immediate action.","category":"Airway"},{"id":"c03_fc06","question":"What does gurgling in the airway indicate and what is the action?","answer":"Gurgling indicates fluid (blood, secretions, vomitus) in the airway; the action is suction.","category":"Airway"},{"id":"c03_fc07","question":"When should a rapid trauma survey be performed instead of a focused exam?","answer":"When the mechanism of injury is generalized or unknown. A focused exam is used for a localized mechanism such as an isolated extremity injury.","category":"Assessment"},{"id":"c03_fc08","question":"What does DCAP-BLS stand for?","answer":"Deformities, Contusions, Abrasions, Punctures/Penetrations, Burns, Lacerations, Swelling.","category":"Detailed Exam"},{"id":"c03_fc09","question":"What does TIC stand for when palpating a body region?","answer":"Tenderness, Instability, Crepitation.","category":"Detailed Exam"},{"id":"c03_fc10","question":"In the rapid trauma survey, what neck findings suggest a tension pneumothorax?","answer":"Distended neck veins and tracheal deviation (a late sign), along with absent/decreased breath sounds on the affected side.","category":"Rapid Trauma Survey"},{"id":"c03_fc11","question":"If breath sounds are unequal, what should you do next to differentiate the cause?","answer":"Percuss the chest: hyperresonance suggests pneumothorax, dullness suggests hemothorax.","category":"Chest"},{"id":"c03_fc12","question":"What does SAMPLE history stand for?","answer":"Symptoms, Allergies, Medications, Past medical history, Last oral intake, Events leading to the injury.","category":"History"},{"id":"c03_fc13","question":"What baseline vital signs and parameters are recorded in the Primary Survey?","answer":"Level of consciousness, respirations, pulse, blood pressure, pulse oximetry, core temperature, and level of discomfort (pain).","category":"Vital Signs"},{"id":"c03_fc14","question":"When is the Disability (pupils/GCS) portion done during the Primary Survey?","answer":"Immediately if the patient has altered mental status; otherwise it is postponed to the Secondary Survey.","category":"Disability"},{"id":"c03_fc15","question":"Name the signs of cerebral herniation syndrome.","answer":"Unresponsiveness, dilated/unequal pupil(s), hypertension, bradycardia, and abnormal posturing (Cushing's response pattern).","category":"Disability"},{"id":"c03_fc16","question":"When should the ITLS Ongoing Exam be repeated?","answer":"Whenever the patient's condition changes, after any intervention, and after any move (scene to ambulance, ambulance to ED).","category":"Ongoing Exam"},{"id":"c03_fc17","question":"List several interventions you must recheck during the Ongoing Exam.","answer":"ET tube position, oxygen flow and tubing, IV rate and fluid, seals on chest wounds, decompression needle, dressings, splints, impaled-object stabilization, position of the pregnant patient, and all monitors.","category":"Ongoing Exam"},{"id":"c03_fc18","question":"How does management of the critical vs. stable patient differ for the Secondary Survey?","answer":"Critical patients get the Secondary Survey en route only if time permits; stable patients may receive it on scene.","category":"Secondary Survey"},{"id":"c03_fc19","question":"What head findings during the Secondary Survey suggest a basilar skull fracture?","answer":"Battle's sign (mastoid bruising), raccoon eyes (periorbital bruising), and cerebrospinal fluid or blood draining from the ears or nose.","category":"Secondary Survey"},{"id":"c03_fc20","question":"What does PMS refer to when assessing extremities?","answer":"Distal Pulses, Motor function, and Sensation—assessed in each extremity.","category":"Extremities"},{"id":"c03_fc21","question":"Why should you not apply a traction splint to a critical patient on scene?","answer":"Traction splinting takes too long and delays transport of a load-and-go patient; it can be done en route or deferred.","category":"Management"},{"id":"c03_fc22","question":"What glucose-related step is required for every patient with decreased LOC?","answer":"Check for a medical identification device and obtain a finger-stick blood glucose level.","category":"Disability"}]},"c04":{"chapter":"c04","cards":[{"id":"c04_fc01","question":"Why is airway control considered the most important field task in trauma care?","answer":"Because hypoxia is rapidly fatal and cannot wait for hospital arrival—an unprotected or obstructed airway kills before any other injury is treated.","category":"Priorities"},{"id":"c04_fc02","question":"What is the difference between ventilation and oxygenation?","answer":"Ventilation is the mechanical movement of air in and out of the lungs; oxygenation is the loading of oxygen onto hemoglobin and delivery to tissues.","category":"Physiology"},{"id":"c04_fc03","question":"How is minute volume calculated?","answer":"Minute volume = tidal volume × respiratory rate.","category":"Physiology"},{"id":"c04_fc04","question":"What airway-opening maneuver is preferred in trauma and why?","answer":"The modified jaw thrust, because it opens the airway without extending the neck, protecting the cervical spine.","category":"Basic Airway"},{"id":"c04_fc05","question":"When is an oropharyngeal airway (OPA) appropriate?","answer":"In a patient with no gag reflex (deeply unresponsive). It holds the tongue off the posterior pharynx.","category":"Adjuncts"},{"id":"c04_fc06","question":"When should a nasopharyngeal airway (NPA) be avoided?","answer":"When a basilar skull fracture is suspected (raccoon eyes, Battle's sign, CSF drainage), due to risk of intracranial passage.","category":"Adjuncts"},{"id":"c04_fc07","question":"What oxygen device and flow rate is used for a spontaneously breathing trauma patient needing high oxygen?","answer":"A nonrebreather mask at 15 liters per minute.","category":"Oxygen Delivery"},{"id":"c04_fc08","question":"What is the adult bag-valve-mask ventilation rate for an apneic patient?","answer":"8–10 breaths per minute with supplemental oxygen, confirming chest rise with each breath.","category":"Ventilation"},{"id":"c04_fc09","question":"How is correct endotracheal tube placement confirmed and monitored?","answer":"With waveform capnography (continuous end-tidal CO2), supplemented by chest rise and bilateral breath sounds.","category":"Intubation"},{"id":"c04_fc10","question":"What is a BIAD?","answer":"A blind insertion airway device (supraglottic airway) placed without visualizing the vocal cords; used as a primary or rescue airway.","category":"Advanced Airway"},{"id":"c04_fc11","question":"Why is endotracheal intubation considered the gold standard for the adult trauma airway?","answer":"It provides the most secure protection against aspiration and the best control of ventilation, though it is technically more difficult than other methods.","category":"Advanced Airway"},{"id":"c04_fc12","question":"What does the mnemonic MMAP help predict?","answer":"A difficult airway: Mallampati/mouth opening, Mask seal (obstruction/obesity), Anatomy, and Position.","category":"Difficult Airway"},{"id":"c04_fc13","question":"What is apneic oxygenation?","answer":"Delivering oxygen (often by nasal cannula) during laryngoscopy/apnea to prolong the time before desaturation during intubation attempts.","category":"Optimization"},{"id":"c04_fc14","question":"What is external laryngeal manipulation (ELM)?","answer":"Manual pressure on the larynx (often BURP—backward, upward, rightward pressure) to bring the glottis into view and improve intubation success.","category":"Optimization"},{"id":"c04_fc15","question":"What is the danger of ventilating too fast or with too much volume?","answer":"Gastric insufflation (raising aspiration risk) and increased intrathoracic pressure that decreases venous return and cardiac output.","category":"Ventilation"},{"id":"c04_fc16","question":"Differentiate RSI, RSA, and DAI.","answer":"Drug-assisted intubation (DAI) uses medications to facilitate intubation; rapid sequence intubation (RSI) uses a sedative plus paralytic to intubate; rapid sequence airway (RSA) uses the same drugs to place a supraglottic device.","category":"Pharmacology"},{"id":"c04_fc17","question":"What is a FROPVD?","answer":"A flow-restricted oxygen-powered ventilation device—a manually triggered device delivering oxygen at a regulated flow to ventilate a patient.","category":"Devices"},{"id":"c04_fc18","question":"How do you confirm adequate tidal volume during assisted ventilation?","answer":"By observing visible, symmetric chest rise and fall—not by bag speed or force.","category":"Ventilation"},{"id":"c04_fc19","question":"What monitors should accompany trauma airway management?","answer":"Pulse oximetry for oxygenation and waveform capnography for ventilation and tube confirmation.","category":"Monitoring"},{"id":"c04_fc20","question":"What should you always have ready before the first intubation attempt?","answer":"A backup airway plan and a fully stocked airway kit (suction, BVM, adjuncts, BIAD, tubes, capnography, surgical airway option).","category":"Preparation"}]},"c05":{"chapter":"c05","cards":[{"id":"c05_fc01","question":"Why is finesse emphasized over force in airway management?","answer":"Forceful, rushed attempts cause trauma and hypoxia; a calm, prepared, deliberate approach with good team communication produces better outcomes.","category":"Principles"},{"id":"c05_fc02","question":"How do you measure a suction catheter before insertion?","answer":"From the corner of the mouth to the earlobe (or angle of the jaw); insert without suction and apply suction only on withdrawal.","category":"Suctioning"},{"id":"c05_fc03","question":"How long should a single suction attempt last in an adult?","answer":"No more than about 15 seconds (less in children), because suction also removes oxygen; reoxygenate between attempts.","category":"Suctioning"},{"id":"c05_fc04","question":"How is an oropharyngeal airway (OPA) sized?","answer":"From the corner of the mouth to the earlobe or angle of the jaw.","category":"Adjuncts"},{"id":"c05_fc05","question":"How is a nasopharyngeal airway (NPA) sized?","answer":"From the nostril to the earlobe; diameter roughly matching the patient's nostril.","category":"Adjuncts"},{"id":"c05_fc06","question":"What is the advantage of two-rescuer bag-valve-mask ventilation?","answer":"One rescuer maintains a two-handed mask seal while the other ventilates, producing a far better seal and more effective ventilation than one rescuer.","category":"Ventilation"},{"id":"c05_fc07","question":"What does a pulse oximeter measure and what is a concerning trauma reading?","answer":"It measures oxygen saturation (SpO2); a reading below 95% in a trauma patient warrants supplemental oxygen and reassessment.","category":"Monitoring"},{"id":"c05_fc08","question":"How does a supraglottic (BIAD) airway work?","answer":"It is inserted blindly into the hypopharynx and seals over the glottic opening to allow ventilation without visualizing the cords.","category":"Supraglottic"},{"id":"c05_fc09","question":"When are supraglottic airways especially useful?","answer":"When intubation is difficult or unavailable, as a rapid primary or rescue airway requiring minimal neck movement.","category":"Supraglottic"},{"id":"c05_fc10","question":"What does the mnemonic SOAP-ME stand for in airway preparation?","answer":"Suction, Oxygen, Airways (adjuncts/tubes), Pharmacology, Monitoring, and Equipment (laryngoscope/backup).","category":"Preparation"},{"id":"c05_fc11","question":"What cervical-spine precaution is maintained during trauma intubation?","answer":"Manual in-line stabilization of the cervical spine throughout the procedure.","category":"Intubation"},{"id":"c05_fc12","question":"How is endotracheal tube placement confirmed?","answer":"Primarily by waveform capnography, plus visible chest rise and bilateral breath sounds; reconfirm after every move.","category":"Confirmation"},{"id":"c05_fc13","question":"When is nasotracheal intubation contraindicated?","answer":"When a basilar skull fracture is suspected and in apneic patients (it requires spontaneous breathing).","category":"Intubation"},{"id":"c05_fc14","question":"Why must the tube be anchored and depth noted?","answer":"To prevent displacement during movement; note centimeter depth at the teeth so dislodgement can be detected and corrected.","category":"Confirmation"},{"id":"c05_fc15","question":"What must always be available before giving a paralytic for intubation?","answer":"The ability to ventilate (BVM), monitoring (SpO2/capnography), suction, and a rescue airway/backup plan.","category":"Pharmacology"},{"id":"c05_fc16","question":"What is external laryngeal manipulation used for during laryngoscopy?","answer":"Applying pressure on the larynx (BURP) to bring the vocal cords into view and improve first-pass intubation success.","category":"Intubation"},{"id":"c05_fc17","question":"What is a common cause of failed BVM ventilation?","answer":"A poor mask seal; correct with a two-handed/two-rescuer technique and proper airway positioning with an adjunct.","category":"Ventilation"},{"id":"c05_fc18","question":"Why preoxygenate before intubation?","answer":"To build an oxygen reserve that prolongs safe apnea time and prevents desaturation during the attempt.","category":"Optimization"},{"id":"c05_fc19","question":"What is the purpose of apneic oxygenation during intubation?","answer":"Delivering oxygen (e.g., nasal cannula) during the attempt to extend the time before the patient desaturates.","category":"Optimization"},{"id":"c05_fc20","question":"What should the team do if an intubation attempt fails and the patient desaturates?","answer":"Stop, ventilate with BVM and reoxygenate, then either reattempt with optimization or place a supraglottic rescue airway.","category":"Rescue"}]},"c06":{"chapter":"c06","cards":[{"id":"c06_fc01","question":"What are the six immediately life-threatening thoracic injuries (ATOM-FC)?","answer":"Airway obstruction, Tension pneumothorax, Open pneumothorax, Massive hemothorax, Flail chest, and Cardiac tamponade.","category":"Life Threats"},{"id":"c06_fc02","question":"What is the mediastinum?","answer":"The central compartment of the chest containing the heart, great vessels, trachea, and esophagus.","category":"Anatomy"},{"id":"c06_fc03","question":"What is the pleural space?","answer":"The potential space between the lung (visceral pleura) and chest wall (parietal pleura) where air (pneumothorax) or blood (hemothorax) can collect.","category":"Anatomy"},{"id":"c06_fc04","question":"Describe the pathophysiology of a tension pneumothorax.","answer":"Air enters the pleural space and cannot escape, collapsing the lung and shifting the mediastinum, which compresses the great veins, reduces venous return, and drops cardiac output—leading to obstructive shock.","category":"Tension Pneumothorax"},{"id":"c06_fc05","question":"List the signs of a tension pneumothorax.","answer":"Severe respiratory distress, absent breath sounds and hyperresonance on the affected side, distended neck veins, hypotension/shock, and tracheal deviation (a late sign).","category":"Tension Pneumothorax"},{"id":"c06_fc06","question":"What is the treatment for a tension pneumothorax?","answer":"Immediate needle chest decompression of the affected side, plus oxygen and ventilatory support.","category":"Tension Pneumothorax"},{"id":"c06_fc07","question":"How do you manage an open (sucking) chest wound?","answer":"Apply a vented occlusive dressing (three-sided or commercial chest seal), give oxygen, and monitor closely for development of a tension pneumothorax.","category":"Open Pneumothorax"},{"id":"c06_fc08","question":"Why can a fully occlusive dressing be dangerous on an open chest wound?","answer":"It can trap air in the pleural space and convert an open pneumothorax into a tension pneumothorax.","category":"Open Pneumothorax"},{"id":"c06_fc09","question":"What defines a massive hemothorax and what are its two main effects?","answer":"Large blood loss into the chest (often >1,500 mL). It causes both hypovolemic shock and respiratory compromise from lung compression.","category":"Hemothorax"},{"id":"c06_fc10","question":"How do neck veins differ between tension pneumothorax and massive hemothorax?","answer":"Tension pneumothorax typically has distended neck veins (obstructed venous return); massive hemothorax usually has flat neck veins (hypovolemia).","category":"Differentiation"},{"id":"c06_fc11","question":"What percussion finding distinguishes pneumothorax from hemothorax?","answer":"Pneumothorax is hyperresonant (air); hemothorax is dull (blood/fluid).","category":"Differentiation"},{"id":"c06_fc12","question":"Define flail chest.","answer":"Two or more adjacent ribs each fractured in two or more places, creating a free segment that moves paradoxically with respiration.","category":"Flail Chest"},{"id":"c06_fc13","question":"What is the main danger of a flail chest?","answer":"The underlying pulmonary contusion and resulting hypoventilation/hypoxia—not the paradoxical wall motion itself.","category":"Flail Chest"},{"id":"c06_fc14","question":"How is flail chest managed in the field?","answer":"Oxygen and ventilatory support (positive-pressure ventilation as needed), pain consideration, and avoidance of fluid overload; rapid transport.","category":"Flail Chest"},{"id":"c06_fc15","question":"What is Beck's triad?","answer":"Hypotension, distended neck veins (JVD), and muffled heart tones—classic signs of pericardial (cardiac) tamponade.","category":"Tamponade"},{"id":"c06_fc16","question":"What is a paradoxical pulse (pulsus paradoxus)?","answer":"An exaggerated fall in systolic blood pressure during inspiration; it can accompany cardiac tamponade.","category":"Tamponade"},{"id":"c06_fc17","question":"What is the field management of cardiac tamponade?","answer":"Recognize Beck's triad, support oxygenation and perfusion, and transport rapidly for pericardiocentesis or surgery—it is rapidly fatal.","category":"Tamponade"},{"id":"c06_fc18","question":"What are the indications for emergency chest decompression?","answer":"Signs of tension pneumothorax PLUS more than one of: respiratory distress and cyanosis, loss of radial pulse (shock), or decreasing/loss of level of consciousness.","category":"Decompression"},{"id":"c06_fc19","question":"How can blunt cardiac injury present and what monitoring is needed?","answer":"It can cause dysrhythmias and contusion; apply early cardiac monitoring after significant blunt chest trauma.","category":"Blunt Cardiac Injury"},{"id":"c06_fc20","question":"Why avoid aggressive fluid resuscitation in pulmonary contusion or hemothorax?","answer":"Excess crystalloid worsens contused-lung oxygenation and can increase intrathoracic bleeding; use permissive, controlled resuscitation.","category":"Management"},{"id":"c06_fc21","question":"Distended neck veins with shock should make you think of which two chest emergencies?","answer":"Tension pneumothorax and cardiac tamponade—both are obstructive causes of shock, not hypovolemia.","category":"Differentiation"},{"id":"c06_fc22","question":"What general symptoms suggest serious thoracic trauma?","answer":"Chest pain, dyspnea/shortness of breath, anxiety or a sense of impending doom, and tachypnea.","category":"Assessment"}]},"c07":{"chapter":"c07","cards":[{"id":"c07_fc01","question":"What does needle chest decompression accomplish?","answer":"It releases trapped pleural air, converting a life-threatening tension pneumothorax into a simple pneumothorax and restoring venous return and cardiac output.","category":"Purpose"},{"id":"c07_fc02","question":"Is needle decompression definitive treatment?","answer":"No—it is a temporizing measure. Definitive treatment is a chest tube (tube thoracostomy) at the hospital.","category":"Purpose"},{"id":"c07_fc03","question":"What are the indications for emergency chest decompression?","answer":"Signs of tension pneumothorax PLUS more than one of: respiratory distress and cyanosis, loss of radial pulse (shock), loss of consciousness, or obviously decreasing LOC.","category":"Indications"},{"id":"c07_fc04","question":"Where is the anterior decompression site?","answer":"The second or third intercostal space at the midclavicular line.","category":"Anterior Approach"},{"id":"c07_fc05","question":"Where is the lateral decompression site?","answer":"The fourth or fifth intercostal space at the anterior axillary line (some courses use the third intercostal space laterally).","category":"Lateral Approach"},{"id":"c07_fc06","question":"Why insert the needle just over the top of the rib?","answer":"The intercostal nerve, artery, and vein run along the underside (inferior margin) of each rib; going over the top avoids injuring them.","category":"Technique"},{"id":"c07_fc07","question":"What catheter length and gauge are recommended for the anterior approach?","answer":"A large-bore catheter about 14 gauge (8 French) and 6 to 9 cm (2.5 to 3.5 inches) long to reach the pleural space.","category":"Equipment"},{"id":"c07_fc08","question":"Why is catheter length important?","answer":"Chest-wall thickness varies; a too-short catheter may not reach the pleural space, causing a failed decompression—common with shorter anterior catheters.","category":"Equipment"},{"id":"c07_fc09","question":"What confirms a successful needle decompression?","answer":"An audible rush of air on insertion and rapid clinical improvement (better breathing, return of radial pulse, improved LOC).","category":"Confirmation"},{"id":"c07_fc10","question":"Why is the lateral approach favored in tactical settings?","answer":"It can be performed without removing body armor and may more reliably enter the pleural space.","category":"Lateral Approach"},{"id":"c07_fc11","question":"What is a theoretical advantage of the third intercostal lateral site?","answer":"Less risk of injuring solid organs (liver, spleen) than a lower site, and potentially faster access in combat.","category":"Lateral Approach"},{"id":"c07_fc12","question":"Will needle decompression help a massive hemothorax?","answer":"No—decompression releases air, not blood. A hemothorax requires shock management and rapid transport for surgical care.","category":"Pitfalls"},{"id":"c07_fc13","question":"What should you do after a successful decompression?","answer":"Secure the catheter, reassess frequently, and be prepared to repeat decompression if the pneumothorax re-accumulates.","category":"Aftercare"},{"id":"c07_fc14","question":"How can ultrasound assist with this procedure?","answer":"Prehospital ultrasound can confirm the presence of a pneumothorax before decompression, improving accuracy.","category":"Adjuncts"},{"id":"c07_fc15","question":"What are common complications of needle decompression?","answer":"Failure to reach the pleural space (too-short catheter), neurovascular injury (inserting below the rib), catheter kinking/clotting/dislodgement, and creating a pneumothorax if one was not present.","category":"Complications"},{"id":"c07_fc16","question":"Are the indications for decompression different in tactical versus civilian care?","answer":"No—the indications are the same regardless of the environment.","category":"Indications"}]},"c08":{"chapter":"c08","cards":[{"id":"c08_fc01","question":"Define shock.","answer":"Inadequate tissue perfusion—cells receive insufficient oxygen to meet metabolic demand, leading to cellular dysfunction and, if untreated, organ failure and death.","category":"Concepts"},{"id":"c08_fc02","question":"What four components are necessary for normal tissue perfusion?","answer":"An intact pump (heart), adequate volume (blood), intact pipes (blood vessels), and adequate oxygen-carrying capacity.","category":"Physiology"},{"id":"c08_fc03","question":"List the early (compensated) signs of shock.","answer":"Anxiety/restlessness, tachycardia, cool and pale skin, delayed capillary refill, and a narrowing pulse pressure.","category":"Assessment"},{"id":"c08_fc04","question":"Why is falling blood pressure a late sign of shock?","answer":"The body compensates with vasoconstriction and tachycardia to maintain blood pressure; by the time pressure falls, 30% or more of blood volume may already be lost.","category":"Assessment"},{"id":"c08_fc05","question":"What are the four common shock syndromes?","answer":"Hypovolemic (hemorrhagic), cardiogenic (pump failure), mechanical/obstructive (tension pneumothorax, tamponade), and distributive (neurogenic, septic, anaphylactic).","category":"Classification"},{"id":"c08_fc06","question":"What is the most common cause of shock in trauma?","answer":"Hemorrhagic (hypovolemic) shock from blood loss.","category":"Classification"},{"id":"c08_fc07","question":"How does neurogenic shock present differently from hemorrhagic shock?","answer":"Neurogenic shock has hypotension with a normal or slow heart rate and warm, dry skin below the injury (loss of sympathetic tone); hemorrhagic shock has tachycardia with cool, pale, clammy skin.","category":"Differentiation"},{"id":"c08_fc08","question":"What causes neurogenic shock?","answer":"Loss of sympathetic vascular tone from a spinal cord injury, causing vasodilation and pooling of blood.","category":"Neurogenic"},{"id":"c08_fc09","question":"What is mechanical (obstructive) shock and its trauma causes?","answer":"Shock from obstruction to cardiac filling or output—classically tension pneumothorax and cardiac tamponade—often with distended neck veins.","category":"Mechanical"},{"id":"c08_fc10","question":"What is the first step in controlling external hemorrhage?","answer":"Direct pressure on the wound; escalate to a tourniquet for uncontrolled extremity bleeding and hemostatic dressings for junctional/deep wounds.","category":"Hemorrhage Control"},{"id":"c08_fc11","question":"When is a tourniquet indicated?","answer":"For life-threatening extremity hemorrhage not controlled by direct pressure; apply it early and tightly enough to stop the bleeding.","category":"Hemorrhage Control"},{"id":"c08_fc12","question":"When are hemostatic agents used?","answer":"For uncontrolled hemorrhage in junctional areas or deep wounds where a tourniquet cannot be applied, packed into the wound with sustained pressure.","category":"Hemorrhage Control"},{"id":"c08_fc13","question":"Why can the field provider not fix internal hemorrhage?","answer":"Internal bleeding requires surgical control; the field priority is rapid transport to a surgical facility with supportive resuscitation.","category":"Internal Bleeding"},{"id":"c08_fc14","question":"What is permissive (controlled) hypotension?","answer":"Giving just enough fluid to maintain perfusion (e.g., a palpable radial pulse) without raising pressure so much that it dislodges clots and worsens bleeding.","category":"Fluids"},{"id":"c08_fc15","question":"Why is aggressive crystalloid resuscitation harmful in uncontrolled hemorrhage?","answer":"It can dislodge clots, dilute clotting factors and oxygen-carrying cells, and worsen bleeding and hypothermia.","category":"Fluids"},{"id":"c08_fc16","question":"What is tranexamic acid (TXA) and when is it given?","answer":"An antifibrinolytic that stabilizes clots; given early (ideally within 3 hours of injury) to patients with significant hemorrhage or hemorrhagic shock, per protocol.","category":"TXA"},{"id":"c08_fc17","question":"What is the lethal triad of trauma?","answer":"Hypothermia, acidosis, and coagulopathy—each worsens the others and increases mortality.","category":"Lethal Triad"},{"id":"c08_fc18","question":"Why is keeping the trauma patient warm important?","answer":"Hypothermia impairs clotting and contributes to the lethal triad, worsening hemorrhage and outcomes.","category":"Management"},{"id":"c08_fc19","question":"What blood pressure goal applies to the head-injured shock patient?","answer":"Avoid hypotension—maintain adequate blood pressure (often systolic ~110–120 mmHg) to preserve cerebral perfusion.","category":"Head Injury"},{"id":"c08_fc20","question":"What does narrowing pulse pressure indicate in shock?","answer":"Rising diastolic pressure from vasoconstriction as the body compensates for falling volume—an early warning of hemorrhagic shock.","category":"Assessment"},{"id":"c08_fc21","question":"Why should hypotension in a spinal-injury patient not be assumed to be neurogenic?","answer":"Hemorrhage commonly coexists; neurogenic shock is a diagnosis of exclusion—rule out and treat bleeding first.","category":"Pitfalls"},{"id":"c08_fc22","question":"What is capillary refill time and what is abnormal?","answer":"The time for color to return after blanching a nail bed; greater than ~2 seconds suggests poor peripheral perfusion (less reliable in cold environments).","category":"Assessment"}]},"c09":{"chapter":"c09","cards":[{"id":"c09_fc01","question":"In trauma, when should IV access be established?","answer":"Whenever possible, en route to the hospital—vascular access should rarely delay transport of a critical patient.","category":"Principles"},{"id":"c09_fc02","question":"Where does the external jugular vein run anatomically?","answer":"From the angle of the jaw to the junction of the medial and middle third of the clavicle, draining into the subclavian vein.","category":"External Jugular"},{"id":"c09_fc03","question":"How do you make the external jugular vein more prominent?","answer":"Press on it just above the clavicle, which distends the vein and makes it easier to cannulate.","category":"External Jugular"},{"id":"c09_fc04","question":"What is the indication for external jugular cannulation?","answer":"An adult or pediatric patient who needs IV access and in whom no suitable peripheral vein can be found.","category":"External Jugular"},{"id":"c09_fc05","question":"How should the patient be positioned for EJ cannulation?","answer":"Supine with the head turned away from the side being cannulated; cannulate pointing toward the clavicle/shoulder.","category":"External Jugular"},{"id":"c09_fc06","question":"What is intraosseous (IO) infusion?","answer":"Delivery of fluids and medications into the bone marrow cavity, which acts as a non-collapsible vein with rapid central circulation.","category":"Intraosseous"},{"id":"c09_fc07","question":"When is IO access indicated?","answer":"When rapid access is needed and peripheral/EJ access fails or is impractical—common in shock where peripheral veins collapse.","category":"Intraosseous"},{"id":"c09_fc08","question":"What are common IO drill sites?","answer":"The proximal tibia (flat medial surface below the tuberosity) and the proximal humerus (greater tubercle with the arm adducted).","category":"Intraosseous"},{"id":"c09_fc09","question":"Where does a sternal IO device place the catheter?","answer":"In the manubrium of the sternum.","category":"Intraosseous"},{"id":"c09_fc10","question":"How do you confirm correct IO placement?","answer":"The needle stands upright/stable, marrow can be aspirated, and fluid flows freely without extravasation (soft-tissue swelling).","category":"Intraosseous"},{"id":"c09_fc11","question":"Why give lidocaine through an IO in a conscious patient?","answer":"IO infusion is painful; slow IO lidocaine (per protocol) before flushing reduces the pain of the fluid bolus.","category":"Intraosseous"},{"id":"c09_fc12","question":"Why must an IO be flushed briskly after placement?","answer":"A rapid flush opens the marrow channel and establishes free flow for fluids and medications.","category":"Intraosseous"},{"id":"c09_fc13","question":"Name contraindications to placing an IO in a particular bone.","answer":"Fracture of that bone, a recent prior IO attempt in the same bone (extravasation risk), overlying infection, or inability to identify landmarks.","category":"Intraosseous"},{"id":"c09_fc14","question":"What is a length-based resuscitation tape used for?","answer":"Estimating a child's weight from body length and providing corresponding drug doses, fluid volumes, and equipment sizes.","category":"Pediatrics"},{"id":"c09_fc15","question":"How is a child measured with a length-based tape?","answer":"From head to heel; the corresponding color zone gives the estimated weight and reference values.","category":"Pediatrics"},{"id":"c09_fc16","question":"What complications can occur with EJ cannulation?","answer":"Air embolism, infiltration, hematoma, and dislodgement—secure the line and monitor the site.","category":"Complications"},{"id":"c09_fc17","question":"Why is the marrow described as a 'non-collapsible vein'?","answer":"The bony cavity keeps the vascular network open even in profound shock when peripheral veins collapse, making IO reliable.","category":"Intraosseous"},{"id":"c09_fc18","question":"Should vascular access ever delay surgical transport in uncontrolled internal hemorrhage?","answer":"No—rapid transport to surgery is the priority; obtain access en route.","category":"Principles"}]},"c10":{"chapter":"c10","cards":[{"id":"c10_fc01","question":"What does the Monro-Kellie Doctrine state?","answer":"Because the skull is rigid, an increase in any intracranial component (brain, blood, or CSF—e.g., from a hematoma or swelling) must be offset by a decrease in another; once compensation is exhausted, ICP rises sharply.","category":"Pathophysiology"},{"id":"c10_fc02","question":"What three components occupy the rigid skull?","answer":"Brain tissue, blood, and cerebrospinal fluid (CSF).","category":"Anatomy"},{"id":"c10_fc03","question":"Define primary brain injury.","answer":"Damage occurring at the moment of impact (contusions, coup/contrecoup, diffuse axonal injury, lacerations)—it cannot be reversed in the field.","category":"Injury Types"},{"id":"c10_fc04","question":"Define secondary brain injury.","answer":"Injury that develops after the initial impact from hypoxia, hypotension, abnormal glucose, abnormal CO2, raised ICP, and edema—largely preventable with good prehospital care.","category":"Injury Types"},{"id":"c10_fc05","question":"What are the major causes of secondary brain injury?","answer":"Hypoxia, hypotension, hypo/hyperglycemia, hyper/hypocapnia, increased intracranial pressure, and cerebral edema.","category":"Injury Types"},{"id":"c10_fc06","question":"What is the formula for cerebral perfusion pressure (CPP)?","answer":"CPP = Mean Arterial Pressure (MAP) − Intracranial Pressure (ICP).","category":"Physiology"},{"id":"c10_fc07","question":"Why are hypoxia and hypotension so dangerous in TBI?","answer":"They are the leading causes of preventable secondary brain injury; even a single episode of hypotension can dramatically increase mortality.","category":"Management"},{"id":"c10_fc08","question":"What is Cushing's reflex (triad)?","answer":"Hypertension, bradycardia, and irregular respirations—a late sign of dangerously elevated intracranial pressure.","category":"ICP"},{"id":"c10_fc09","question":"What is the difference between coup and contrecoup injury?","answer":"Coup injury occurs at the site of impact; contrecoup injury occurs on the opposite side as the brain rebounds within the skull.","category":"Injury Types"},{"id":"c10_fc10","question":"What are the three components scored by the Glasgow Coma Scale?","answer":"Eye opening (max 4), Verbal response (max 5), and Motor response (max 6), for a maximum of 15.","category":"Assessment"},{"id":"c10_fc11","question":"What GCS indicates severe TBI and inability to protect the airway?","answer":"A GCS of 8 or less.","category":"Assessment"},{"id":"c10_fc12","question":"What are the signs of cerebral herniation syndrome?","answer":"Decreasing GCS (often <8), a dilated/unequal or fixed pupil, abnormal (extensor) posturing, and Cushing's signs.","category":"Herniation"},{"id":"c10_fc13","question":"When is hyperventilation appropriate in TBI, and to what target?","answer":"Only when there are signs of active cerebral herniation; use controlled mild hyperventilation targeting an ETCO2 of about 30–35 mmHg.","category":"Herniation"},{"id":"c10_fc14","question":"What is the normal ETCO2 target for a head-injured patient WITHOUT herniation?","answer":"Normal ventilation to an ETCO2 of about 35–45 mmHg—avoid both hyper- and hypoventilation.","category":"Management"},{"id":"c10_fc15","question":"What blood pressure goal helps protect the injured brain?","answer":"Avoid hypotension; maintain systolic blood pressure (commonly ≥ 110–120 mmHg) to preserve cerebral perfusion.","category":"Management"},{"id":"c10_fc16","question":"What oxygen saturation should be maintained in TBI?","answer":"At least 94%; avoid hypoxia, which worsens secondary injury.","category":"Management"},{"id":"c10_fc17","question":"What signs suggest a basilar skull fracture?","answer":"Raccoon eyes (periorbital bruising), Battle's sign (mastoid bruising), and CSF or blood draining from the ears or nose.","category":"Assessment"},{"id":"c10_fc18","question":"Why check and correct blood glucose in head injury?","answer":"Both hypoglycemia and hyperglycemia worsen brain injury; glucose should be measured and abnormal values corrected.","category":"Management"},{"id":"c10_fc19","question":"What is the no-reflow phenomenon?","answer":"Failure of microcirculatory blood flow to the brain after severe injury despite restored perfusion pressure, contributing to ischemia.","category":"Pathophysiology"},{"id":"c10_fc20","question":"What head positioning may help reduce ICP if not contraindicated?","answer":"Elevating the head of the bed/board about 30 degrees and keeping the head midline to promote venous drainage.","category":"Management"},{"id":"c10_fc21","question":"Why must the GCS and pupils be reassessed frequently?","answer":"A declining GCS or a newly dilated pupil signals an expanding lesion or herniation requiring immediate action.","category":"Assessment"},{"id":"c10_fc22","question":"Why is it a mistake to attribute hypotension to an isolated head injury?","answer":"Isolated brain injury rarely causes hypotension (except as a terminal event); hypotension usually means hemorrhage elsewhere that must be found and treated.","category":"Pitfalls"}]},"c11":{"chapter":"c11","cards":[{"id":"c11_fc01","question":"How many vertebrae make up the spinal column and what are the regions?","answer":"33 vertebrae: cervical (7), thoracic (12), lumbar (5), sacral (5 fused), and coccygeal (4 fused).","category":"Anatomy"},{"id":"c11_fc02","question":"Which spinal region is most mobile and most vulnerable to injury?","answer":"The cervical spine.","category":"Anatomy"},{"id":"c11_fc03","question":"What is the goal of spinal motion restriction (SMR)?","answer":"To prevent secondary spinal-cord injury by limiting movement of a potentially unstable spine—without causing the harms of unnecessary immobilization.","category":"SMR"},{"id":"c11_fc04","question":"Differentiate primary and secondary spinal-cord injury.","answer":"Primary injury occurs at the moment of trauma; secondary injury results from movement of an unstable spine, hypoxia, hypotension, and edema afterward.","category":"Pathophysiology"},{"id":"c11_fc05","question":"List the criteria that indicate a patient needs SMR.","answer":"A concerning mechanism plus any of: altered mental status/intoxication, midline spinal tenderness or deformity, neurologic deficit (numbness/weakness/paresthesia), a distracting injury, or an unreliable exam.","category":"Indications"},{"id":"c11_fc06","question":"When might a trauma patient NOT require SMR?","answer":"When the patient is alert and reliable with no midline tenderness, no neurologic deficit, no intoxication, and no distracting injury.","category":"Indications"},{"id":"c11_fc07","question":"Why is routine SMR avoided in isolated penetrating trauma?","answer":"In penetrating torso/neck trauma without neurologic deficit, immobilization delays transport and is associated with increased mortality.","category":"Pitfalls"},{"id":"c11_fc08","question":"What harms can result from unnecessary full immobilization?","answer":"Pressure sores, pain, agitation, impaired breathing, increased aspiration risk, and delayed transport.","category":"Harms"},{"id":"c11_fc09","question":"What is neutral in-line alignment and when is it not forced?","answer":"Positioning the head and spine in a neutral, anatomically aligned position; do not force it if it causes pain, resistance, or new/worsening neurologic symptoms—immobilize in the position found.","category":"Technique"},{"id":"c11_fc10","question":"How does neurogenic shock present?","answer":"Hypotension with a normal or slow heart rate and warm, dry, pink skin below the level of injury, from loss of sympathetic tone.","category":"Neurogenic Shock"},{"id":"c11_fc11","question":"How does hemorrhagic shock present compared to neurogenic shock?","answer":"Hemorrhagic shock: tachycardia with cool, pale, clammy skin. Neurogenic shock: normal/slow heart rate with warm, dry skin.","category":"Differentiation"},{"id":"c11_fc12","question":"Why must hemorrhage be excluded in a hypotensive spinal-injury patient?","answer":"Neurogenic and hemorrhagic shock can coexist; hypotension is hemorrhage until proven otherwise, and missing bleeding can be fatal.","category":"Differentiation"},{"id":"c11_fc13","question":"What is an Emergency Rescue?","answer":"Immediate removal of a patient from a scene too dangerous to allow normal care (fire, drowning, hostile environment)—prioritizing life over spine.","category":"Extrication"},{"id":"c11_fc14","question":"What is rapid extrication and when is it used?","answer":"A faster, controlled removal using manual stabilization (without a full short device), used for critical/load-and-go patients or when the scene is unstable.","category":"Extrication"},{"id":"c11_fc15","question":"When is standard extrication with a short device appropriate?","answer":"For a stable patient in a stable scene who meets SMR criteria.","category":"Extrication"},{"id":"c11_fc16","question":"What is paresthesia and why is it significant?","answer":"An abnormal sensation such as tingling or 'pins and needles'; it indicates possible spinal-cord involvement and is a sign warranting SMR.","category":"Assessment"},{"id":"c11_fc17","question":"Why does cord injury cause loss of autonomic control below the lesion?","answer":"The cord carries sympathetic and motor/sensory pathways; injury interrupts them, causing loss of vascular tone (neurogenic shock), sensation, and movement below the level.","category":"Pathophysiology"},{"id":"c11_fc18","question":"What special padding considerations apply to children and the elderly during SMR?","answer":"Children have large heads (pad under the torso to avoid neck flexion); the elderly may have kyphosis (pad behind the head/under gaps) to maintain neutral, comfortable alignment.","category":"Technique"},{"id":"c11_fc19","question":"What single mechanism category is associated with worse survival when routinely immobilized?","answer":"Isolated penetrating trauma (to the torso/neck) without neurologic deficit.","category":"Evidence"},{"id":"c11_fc20","question":"What two physiologic insults worsen secondary cord injury and must be prevented?","answer":"Hypoxia and hypotension (along with avoiding unnecessary spinal movement).","category":"Management"}]},"c12":{"chapter":"c12","cards":[{"id":"c12_fc01","question":"What are the essential components of an SMR system?","answer":"Manual in-line stabilization, a properly sized rigid cervical collar, and a full-body device (long backboard, scoop stretcher, or vacuum mattress) with straps and head blocks.","category":"Components"},{"id":"c12_fc02","question":"What is the primary role of the long backboard?","answer":"It is mainly an extrication and transfer tool; patients can often be transported on a padded stretcher with collar and straps rather than left on the rigid board.","category":"Devices"},{"id":"c12_fc03","question":"In what order do you secure a patient to a backboard?","answer":"Torso first (chest and hips), then the legs, and finally the head—never the head first.","category":"Securing"},{"id":"c12_fc04","question":"Why must the torso be secured before the head?","answer":"If the head is anchored first, any shift of the torso loads and moves the cervical spine; securing the torso first prevents this.","category":"Securing"},{"id":"c12_fc05","question":"When is manual in-line stabilization maintained?","answer":"From first patient contact until the patient is fully secured to the device.","category":"Principles"},{"id":"c12_fc06","question":"What is the purpose of the log roll?","answer":"To move the patient as a single unit while maintaining alignment, allowing inspection/palpation of the posterior (DCAP-BLS, TIC) and placement of the board.","category":"Log Roll"},{"id":"c12_fc07","question":"Who directs the log roll and gives commands?","answer":"The rescuer maintaining head/neck stabilization (the team leader at the head).","category":"Log Roll"},{"id":"c12_fc08","question":"When is a short extrication (vest-type) device used?","answer":"To provide SMR to a seated, stable patient before extrication from a vehicle.","category":"Short Device"},{"id":"c12_fc09","question":"What is the advantage of a scoop stretcher?","answer":"It splits to slide under the patient from both sides with minimal movement, ideal for transfers and lifting onto a stretcher.","category":"Devices"},{"id":"c12_fc10","question":"What are the benefits of a vacuum mattress?","answer":"It conforms to the body, distributes pressure (reducing sores), maintains neutral alignment, and is comfortable for prolonged transport.","category":"Devices"},{"id":"c12_fc11","question":"What is an Emergency Rescue?","answer":"Immediate removal of a patient from a scene of immediate danger (fire, drowning), prioritizing life over spine.","category":"Extrication"},{"id":"c12_fc12","question":"When is rapid extrication performed?","answer":"When the patient is critical/load-and-go or the scene is unstable—using manual stabilization to move quickly without a full short device.","category":"Extrication"},{"id":"c12_fc13","question":"When should a helmet be removed?","answer":"When it prevents airway access or assessment, fits poorly (allowing head movement inside it), or interferes with immobilization.","category":"Helmets"},{"id":"c12_fc14","question":"When can a helmet be left in place?","answer":"When it fits snugly, the airway is accessible, and the head can be securely immobilized—pad behind the head/shoulders as needed for neutral alignment.","category":"Helmets"},{"id":"c12_fc15","question":"How many rescuers are needed to remove a helmet and why?","answer":"Two—one maintains in-line stabilization from below while the other spreads and removes the helmet, preventing head/neck movement.","category":"Helmets"},{"id":"c12_fc16","question":"What must be reassessed before and after packaging?","answer":"Distal pulses, motor function, and sensation (PMS) in all extremities.","category":"Assessment"},{"id":"c12_fc17","question":"What padding is needed for a child to maintain neutral alignment?","answer":"Padding under the torso, because the proportionally large head would otherwise flex the neck.","category":"Special Populations"},{"id":"c12_fc18","question":"What is a risk of prolonged immobilization on a rigid board?","answer":"Pressure sores, pain, agitation, and respiratory compromise—reasons to transfer to a padded surface when possible.","category":"Harms"},{"id":"c12_fc19","question":"If neutral alignment cannot be safely attained, what should you do?","answer":"Stabilize the head and neck in the position found and immobilize there—do not force movement that causes pain or neuro changes.","category":"Technique"},{"id":"c12_fc20","question":"Why size the cervical collar correctly?","answer":"An ill-fitting collar can force flexion or extension; correct sizing maintains neutral alignment and effective restriction.","category":"Technique"}]},"c13":{"chapter":"c13","cards":[{"id":"c13_fc01","question":"What are the three anatomical regions of the abdomen?","answer":"The true abdomen (peritoneal cavity), the intrathoracic abdomen (upper organs under the lower ribs—liver, spleen, stomach, diaphragm), and the retroperitoneal abdomen (kidneys, pancreas, great vessels, duodenum).","category":"Anatomy"},{"id":"c13_fc02","question":"Why are chest and abdominal injuries frequently related?","answer":"The lower ribs overlie upper-abdominal organs (intrathoracic abdomen), so lower chest trauma can injure the liver, spleen, stomach, or diaphragm.","category":"Anatomy"},{"id":"c13_fc03","question":"How does blunt abdominal trauma typically injure organs?","answer":"By compression and shearing of solid organs (liver, spleen), causing internal hemorrhage that may be occult.","category":"Mechanisms"},{"id":"c13_fc04","question":"What complications are characteristic of penetrating abdominal trauma?","answer":"Bleeding from injured vessels/organs and perforation of hollow organs leading to contamination and peritonitis/sepsis.","category":"Mechanisms"},{"id":"c13_fc05","question":"What is a seat-belt sign and what does it suggest?","answer":"Bruising across the abdomen from the lap belt; it suggests underlying bowel, mesenteric, or solid-organ injury.","category":"Assessment"},{"id":"c13_fc06","question":"Why can the abdomen hide life-threatening hemorrhage?","answer":"Large volumes of blood can accumulate in the peritoneal and retroperitoneal spaces with few external signs—shock may be the only clue.","category":"Assessment"},{"id":"c13_fc07","question":"In which patients is the abdominal exam unreliable?","answer":"Intoxicated, head-injured, or distracted patients—and those with spinal cord injury affecting sensation.","category":"Assessment"},{"id":"c13_fc08","question":"How do you manage an evisceration (protruding viscera)?","answer":"Do NOT push the organs back in; cover with a moist sterile dressing then an occlusive layer to retain warmth and moisture, treat for shock, and transport.","category":"Evisceration"},{"id":"c13_fc09","question":"Why not push eviscerated organs back into the abdomen?","answer":"It risks further injury, contamination, and infection; the organs are covered and protected instead.","category":"Evisceration"},{"id":"c13_fc10","question":"Why is an unstable pelvic fracture dangerous?","answer":"It can lacerate the rich pelvic venous plexus and arteries, causing massive, life-threatening hemorrhage into the pelvis.","category":"Pelvis"},{"id":"c13_fc11","question":"What is an open-book pelvic fracture?","answer":"A fracture pattern that opens the pelvic ring (like a book), increasing pelvic volume and allowing large-volume bleeding.","category":"Pelvis"},{"id":"c13_fc12","question":"Where is a pelvic binder applied and why?","answer":"At the level of the greater trochanters, to close the pelvic ring volume and tamponade venous/arterial bleeding.","category":"Pelvis"},{"id":"c13_fc13","question":"How should you assess a suspected unstable pelvis?","answer":"Gently and only once—do not repeatedly rock or spring the pelvis, which can dislodge clots and worsen bleeding.","category":"Pelvis"},{"id":"c13_fc14","question":"How are impaled objects in the abdomen managed?","answer":"Stabilize them in place with bulky dressings; never remove them in the field, as removal can cause uncontrollable hemorrhage.","category":"Management"},{"id":"c13_fc15","question":"What is the most important field intervention for serious intra-abdominal hemorrhage?","answer":"Rapid transport to a surgical/trauma center—the field cannot control internal abdominal bleeding.","category":"Management"},{"id":"c13_fc16","question":"List critical interventions for the abdominal-trauma patient.","answer":"Oxygen, control external bleeding, stabilize an unstable pelvis, judicious IV fluids/TXA per protocol, keep warm, stabilize impaled objects, and rapid transport.","category":"Management"},{"id":"c13_fc17","question":"What does abdominal rigidity or guarding indicate?","answer":"Peritoneal irritation from blood or spilled contents—a sign of significant intra-abdominal injury.","category":"Assessment"},{"id":"c13_fc18","question":"What is the retroperitoneal abdomen and why is bleeding there easily missed?","answer":"The space behind the peritoneum (kidneys, pancreas, great vessels); bleeding there may not cause obvious distention or peritoneal signs, presenting only as shock.","category":"Anatomy"}]},"c14":{"chapter":"c14","cards":[{"id":"c14_fc01","question":"What is the guiding priority principle for extremity trauma?","answer":"Life before limb—manage airway, breathing, circulation, and major hemorrhage before addressing extremity injuries.","category":"Priorities"},{"id":"c14_fc02","question":"Which extremity problems ARE addressed during the Primary Survey?","answer":"Only life-threatening extremity hemorrhage—managed with direct pressure and a tourniquet if needed.","category":"Priorities"},{"id":"c14_fc03","question":"What distinguishes an open from a closed fracture?","answer":"An open fracture has a wound communicating with the bone (higher infection risk); a closed fracture has intact overlying skin.","category":"Fractures"},{"id":"c14_fc04","question":"What must be assessed before and after splinting any extremity?","answer":"Distal pulses, motor function, and sensation (PMS).","category":"Assessment"},{"id":"c14_fc05","question":"How much blood can a closed femur fracture lose?","answer":"Roughly 1 to 1.5 liters, enough to contribute to hypovolemic shock.","category":"Blood Loss"},{"id":"c14_fc06","question":"What should bilateral femur fractures or an unstable pelvis make you anticipate?","answer":"The development of hypovolemic shock—treat proactively.","category":"Blood Loss"},{"id":"c14_fc07","question":"How do you preserve an amputated part?","answer":"Wrap it in moist sterile gauze, seal it in a bag, and keep it cool—not frozen and not directly on ice.","category":"Amputation"},{"id":"c14_fc08","question":"How is bleeding from an amputation controlled?","answer":"Direct pressure first, then a tourniquet if bleeding is not controlled.","category":"Amputation"},{"id":"c14_fc09","question":"What is crush syndrome?","answer":"A systemic condition after release of prolonged crushing compression—rhabdomyolysis releases potassium and myoglobin, causing hyperkalemia, dysrhythmias, and renal failure.","category":"Crush Injury"},{"id":"c14_fc10","question":"What is compartment syndrome?","answer":"Increased pressure within a closed muscle compartment that compromises perfusion, threatening the muscle and nerves—a surgical emergency.","category":"Compartment Syndrome"},{"id":"c14_fc11","question":"What is the earliest and most reliable sign of compartment syndrome?","answer":"Pain out of proportion to the injury, worsened by passive stretch of the muscles in the compartment.","category":"Compartment Syndrome"},{"id":"c14_fc12","question":"What are the 6 P's of compartment syndrome/limb ischemia?","answer":"Pain, Paresthesia, Pallor, Pulselessness, Paralysis, and Poikilothermia (coolness)—pulselessness and paralysis are late.","category":"Compartment Syndrome"},{"id":"c14_fc13","question":"Which injuries most commonly cause compartment syndrome?","answer":"Fractures and crush injuries of the lower leg (tibia) and forearm, and overly tight splints/casts.","category":"Compartment Syndrome"},{"id":"c14_fc14","question":"How do you manage an angulated long-bone fracture with NO distal pulse?","answer":"Apply gentle in-line traction to realign and attempt to restore distal circulation, then splint and recheck the pulse.","category":"Splinting"},{"id":"c14_fc15","question":"How do you manage a dislocation with an intact distal pulse?","answer":"Splint it in the position found—do not force realignment when perfusion is intact.","category":"Splinting"},{"id":"c14_fc16","question":"What is the basic rule for splinting a long-bone fracture?","answer":"Immobilize the joint above and the joint below the fracture.","category":"Splinting"},{"id":"c14_fc17","question":"How are impaled objects in an extremity managed?","answer":"Stabilize them in place with bulky dressings; do not remove them in the field.","category":"Management"},{"id":"c14_fc18","question":"Why must distal PMS be rechecked after splinting?","answer":"A splint applied too tightly can compromise circulation and nerves or precipitate compartment syndrome.","category":"Assessment"},{"id":"c14_fc19","question":"Should a traction splint be applied to a critical load-and-go patient on scene?","answer":"No—it takes too long; package and transport, deferring time-consuming splinting or doing it en route.","category":"Priorities"},{"id":"c14_fc20","question":"How are open fractures and open wounds covered?","answer":"With sterile dressings to reduce contamination/infection; control bleeding and immobilize.","category":"Wounds"},{"id":"c14_fc21","question":"What is a neurovascular injury and why does it matter in joint trauma?","answer":"Injury to the nerves and vessels crossing a joint; dislocations/fractures near joints can compromise them, threatening the limb if not promptly addressed.","category":"Neurovascular"},{"id":"c14_fc22","question":"What distinguishes a sprain from a strain?","answer":"A sprain is an injury to a ligament (joint), while a strain is an injury to a muscle or tendon.","category":"Soft Tissue"}]},"c15":{"chapter":"c15","cards":[{"id":"c15_fc01","question":"What injury is a traction splint designed to immobilize?","answer":"A mid-shaft femur fracture.","category":"Indications"},{"id":"c15_fc02","question":"What benefits does a traction splint provide for a femur fracture?","answer":"It realigns the fracture, reduces pain, decreases blood loss into the thigh, and prevents further soft-tissue injury.","category":"Indications"},{"id":"c15_fc03","question":"For which injuries should a traction splint NOT be used?","answer":"Fractures of the hip, knee, lower leg, or ankle; pelvic fractures; and partial amputations.","category":"Contraindications"},{"id":"c15_fc04","question":"Why is traction across a fractured or dislocated knee dangerous?","answer":"It can tear the popliteal blood vessels behind the knee.","category":"Contraindications"},{"id":"c15_fc05","question":"Name the three common traction splints.","answer":"The Hare splint, the Sager splint, and the Thomas splint.","category":"Devices"},{"id":"c15_fc06","question":"How does the Sager splint differ from the Hare/Thomas?","answer":"It applies traction from a single bar between the legs (can splint both legs), is lower-profile, and uses a different traction mechanism.","category":"Devices"},{"id":"c15_fc07","question":"What must be assessed before and after applying a traction splint?","answer":"Distal pulses, motor function, and sensation (PMS).","category":"Assessment"},{"id":"c15_fc08","question":"How much traction should be applied?","answer":"Only enough to realign the fracture and relieve pain—excessive traction can cause neurovascular compromise.","category":"Technique"},{"id":"c15_fc09","question":"Where is a pelvic binder centered?","answer":"Over the greater trochanters, to close the pelvic ring and tamponade hemorrhage—not over the iliac crests.","category":"Pelvic Stabilization"},{"id":"c15_fc10","question":"How many times should you assess a suspected unstable pelvis?","answer":"Gently, only once—repeated manipulation can dislodge clots and worsen bleeding.","category":"Pelvic Stabilization"},{"id":"c15_fc11","question":"Where is a tourniquet placed relative to the wound?","answer":"About 2–3 inches proximal to the wound, not directly over a joint.","category":"Tourniquet"},{"id":"c15_fc12","question":"How tight should a tourniquet be?","answer":"Tight enough to stop the bleeding and eliminate the distal pulse; an under-tightened tourniquet (venous only) increases bleeding.","category":"Tourniquet"},{"id":"c15_fc13","question":"What must always be recorded with tourniquet use?","answer":"The time of application.","category":"Tourniquet"},{"id":"c15_fc14","question":"Should a tourniquet be periodically loosened in the field?","answer":"No—do not periodically loosen a properly applied tourniquet; it can worsen bleeding and is harmful.","category":"Tourniquet"},{"id":"c15_fc15","question":"When are hemostatic agents used and how?","answer":"For junctional or deep wounds where a tourniquet cannot be applied; pack the dressing into the bleeding source and hold firm, direct pressure for the recommended time.","category":"Hemostatic Agents"},{"id":"c15_fc16","question":"What complications can traction splints cause?","answer":"Neurovascular compromise from excessive traction, pressure injury at the ischial strap or ankle hitch, and delayed transport of a critical patient.","category":"Complications"},{"id":"c15_fc17","question":"Why are traction splints deferred for load-and-go patients?","answer":"They are time-consuming to apply and delay transport of a critical patient; package and transport, applying the splint en route if at all.","category":"Priorities"},{"id":"c15_fc18","question":"What transfer device minimizes pelvic movement?","answer":"A scoop stretcher, which splits to slide under the patient with minimal manipulation.","category":"Pelvic Stabilization"}]},"c16":{"chapter":"c16","cards":[{"id":"c16_fc01","question":"What are the two main layers of the skin?","answer":"The epidermis (outer) and the dermis (deeper, containing nerves, vessels, hair follicles, and glands).","category":"Anatomy"},{"id":"c16_fc02","question":"What are the major functions of the skin?","answer":"Protection from infection/injury, temperature and fluid regulation, and sensation.","category":"Anatomy"},{"id":"c16_fc03","question":"Describe a superficial (first-degree) burn.","answer":"Involves only the epidermis—red, painful, dry, with no blisters (like a sunburn).","category":"Burn Depth"},{"id":"c16_fc04","question":"Describe a partial-thickness (second-degree) burn.","answer":"Extends into the dermis—red, moist, blistered, and very painful.","category":"Burn Depth"},{"id":"c16_fc05","question":"Describe a full-thickness (third-degree) burn.","answer":"Destroys the entire dermis—dry, leathery, white or charred, and painless in the burned area because nerves are destroyed.","category":"Burn Depth"},{"id":"c16_fc06","question":"Why might a full-thickness burn be painless while the patient still reports pain?","answer":"The full-thickness area has destroyed nerve endings (painless), but surrounding partial-thickness burns remain very painful.","category":"Burn Depth"},{"id":"c16_fc07","question":"State the adult rule of nines percentages.","answer":"Head 9%, each arm 9%, anterior trunk 18%, posterior trunk 18%, each leg 18%, and genitalia 1%.","category":"Rule of Nines"},{"id":"c16_fc08","question":"How is the palm used to estimate burn size?","answer":"The patient's palm (including fingers) is approximately 1% of total body surface area, useful for scattered burns.","category":"Rule of Nines"},{"id":"c16_fc09","question":"Which burns are counted in TBSA estimates?","answer":"Only partial-thickness and full-thickness burns; superficial (first-degree) burns are not counted.","category":"Rule of Nines"},{"id":"c16_fc10","question":"Why is the rule of nines modified for children?","answer":"Children have proportionally larger heads and smaller legs, so the percentages differ from adults.","category":"Rule of Nines"},{"id":"c16_fc11","question":"What signs suggest inhalation/thermal airway injury?","answer":"Facial burns, singed nasal/facial hair, soot in the mouth/nose, carbonaceous sputum, hoarseness, stridor, and a fire in an enclosed space.","category":"Airway"},{"id":"c16_fc12","question":"Why must the airway be secured early in inhalation injury?","answer":"Airway edema can progress rapidly and make intubation impossible—secure the airway before swelling closes it.","category":"Airway"},{"id":"c16_fc13","question":"How does carbon monoxide cause hypoxia?","answer":"It binds hemoglobin with about 250 times the affinity of oxygen, forming carboxyhemoglobin that cannot carry oxygen, causing tissue hypoxia.","category":"Carbon Monoxide"},{"id":"c16_fc14","question":"Why is pulse oximetry unreliable in CO poisoning?","answer":"Standard pulse oximeters cannot distinguish carboxyhemoglobin from oxyhemoglobin, giving a falsely normal reading.","category":"Carbon Monoxide"},{"id":"c16_fc15","question":"What is the initial treatment for carbon monoxide poisoning?","answer":"High-flow 100% oxygen, which greatly speeds elimination of carbon monoxide from hemoglobin.","category":"Carbon Monoxide"},{"id":"c16_fc16","question":"How do you manage a dry chemical burn?","answer":"Brush off the dry chemical first, then irrigate copiously with water; remove contaminated clothing.","category":"Chemical Burns"},{"id":"c16_fc17","question":"What special hazards accompany electrical burns?","answer":"Deep tissue damage along the current path, cardiac dysrhythmias/arrest, and entry/exit wounds—apply cardiac monitoring and ensure scene safety.","category":"Electrical Burns"},{"id":"c16_fc18","question":"How are burns covered in the field?","answer":"With clean, dry dressings; avoid prolonged wet cooling that causes hypothermia, and keep the patient warm.","category":"Management"},{"id":"c16_fc19","question":"List criteria for transport to a burn center.","answer":"Large/deep burns; burns of the face, hands, feet, genitalia, or major joints; airway/inhalation injury; electrical or chemical burns; burns with associated trauma; and burns at extremes of age.","category":"Disposition"},{"id":"c16_fc20","question":"Why is over-cooling a burn harmful?","answer":"Large burns lose the ability to thermoregulate; prolonged cooling causes hypothermia, which worsens outcomes.","category":"Management"},{"id":"c16_fc21","question":"What is the first step in burn management?","answer":"Ensure scene safety and stop the burning process—remove the patient from the source and remove smoldering clothing and jewelry.","category":"Management"},{"id":"c16_fc22","question":"Why are circumferential full-thickness burns dangerous?","answer":"They can restrict chest expansion (impairing breathing) or act as a tourniquet on a limb (impairing circulation), sometimes needing escharotomy.","category":"Complications"}]},"c17":{"chapter":"c17","cards":[{"id":"c17_fc01","question":"Why are children described as 'not small adults' anatomically?","answer":"They have proportionally larger heads, larger tongues and smaller airways, more flexible ribs, organs closer together, and a larger body surface area—changing injury patterns and management.","category":"Anatomy"},{"id":"c17_fc02","question":"How does a child's large head affect injury and airway positioning?","answer":"It increases head injuries and flexes the neck when supine; pad under the torso/shoulders to keep the airway and spine neutral.","category":"Anatomy"},{"id":"c17_fc03","question":"Why can a child have a pulmonary contusion without rib fractures?","answer":"Their flexible, compliant ribs transmit force to the underlying lung without breaking, causing contusion without fracture.","category":"Anatomy"},{"id":"c17_fc04","question":"What is the earliest sign of shock in a child?","answer":"Tachycardia—children compensate by raising heart rate and vasoconstricting before blood pressure falls.","category":"Shock"},{"id":"c17_fc05","question":"Why is hypotension in an injured child so concerning?","answer":"Children compensate well until a large volume is lost, so hypotension is a late, pre-arrest sign indicating decompensation.","category":"Shock"},{"id":"c17_fc06","question":"What is the most common path to cardiac arrest in children?","answer":"Respiratory failure/hypoxia—aggressively support oxygenation and ventilation early.","category":"Airway"},{"id":"c17_fc07","question":"How should a child be positioned for optimal airway alignment?","answer":"In a neutral 'sniffing' position, padding under the torso/shoulders (not the head) to offset the large occiput.","category":"Airway"},{"id":"c17_fc08","question":"What is a length-based resuscitation tape used for in pediatrics?","answer":"Estimating weight and providing corresponding drug doses, fluid volumes, and equipment sizes to reduce errors.","category":"Equipment"},{"id":"c17_fc09","question":"What is the typical pediatric fluid bolus for decompensated shock?","answer":"About 20 mL/kg of warmed isotonic crystalloid, reassessed and repeated per protocol.","category":"Fluids"},{"id":"c17_fc10","question":"What is SCIWORA?","answer":"Spinal Cord Injury Without Radiographic Abnormality—a child's elastic spine can stretch and injure the cord without a visible fracture on imaging.","category":"Spine"},{"id":"c17_fc11","question":"How does pediatric SMR differ from adult SMR?","answer":"Pad under the torso to maintain neutral alignment (large head), use size-appropriate devices, and maintain suspicion for SCIWORA by mechanism.","category":"Spine"},{"id":"c17_fc12","question":"Why do children lose body heat rapidly?","answer":"Their relatively large body surface area increases heat loss; hypothermia develops quickly and worsens shock—keep them warm.","category":"Thermoregulation"},{"id":"c17_fc13","question":"What is the rule about consent for a critically injured child?","answer":"Provide immediate life-saving care under implied/emergency consent regardless of whether a parent is available to consent.","category":"Consent"},{"id":"c17_fc14","question":"What findings should raise suspicion of child abuse (non-accidental trauma)?","answer":"Injuries inconsistent with the stated mechanism or developmental stage, patterned injuries, multiple injuries in different healing stages, delayed presentation, and inconsistent histories.","category":"Child Abuse"},{"id":"c17_fc15","question":"What is the EMS provider's responsibility regarding suspected abuse?","answer":"EMS providers are mandated reporters—document objectively and report suspicions per protocol.","category":"Child Abuse"},{"id":"c17_fc16","question":"How can you build rapport with an injured child and parents?","answer":"Stay calm, get to the child's eye level, speak softly and honestly, allow a caregiver to stay close when possible, and explain procedures simply.","category":"Approach"},{"id":"c17_fc17","question":"When peripheral IV access fails in a critically injured child, what is the alternative?","answer":"Intraosseous (IO) access, commonly at the proximal tibia.","category":"Access"},{"id":"c17_fc18","question":"Why is multisystem injury common in children?","answer":"Their organs are closer together and less protected by fat and muscle, so a single force often injures multiple systems.","category":"Anatomy"},{"id":"c17_fc19","question":"How should equipment be sized for a pediatric patient?","answer":"Using a length-based tape or a pediatric reference to select correctly sized airway, IV, and immobilization equipment.","category":"Equipment"},{"id":"c17_fc20","question":"What ventilation principle applies to children?","answer":"Ventilate at age-appropriate rates with appropriately sized devices, confirming chest rise and avoiding over-ventilation.","category":"Breathing"}]},"c18":{"chapter":"c18","cards":[{"id":"c18_fc01","question":"What is the central physiologic theme of aging relevant to trauma?","answer":"Decreased physiologic reserve in every organ system, so older patients tolerate injury poorly and deteriorate faster.","category":"Pathophysiology"},{"id":"c18_fc02","question":"How does aging affect the cardiovascular system's response to injury?","answer":"Stiffer vessels and a less responsive heart limit the ability to compensate for blood loss, so shock develops and worsens quickly.","category":"Cardiovascular"},{"id":"c18_fc03","question":"How can beta-blockers affect a geriatric trauma assessment?","answer":"They blunt the tachycardic response to shock, so a 'normal' heart rate may falsely reassure you that the patient is stable.","category":"Medications"},{"id":"c18_fc04","question":"How does a pacemaker complicate shock assessment?","answer":"It fixes the heart rate, preventing the compensatory tachycardia that normally signals shock.","category":"Medications"},{"id":"c18_fc05","question":"Why are anticoagulants and antiplatelet agents dangerous in geriatric trauma?","answer":"They dramatically increase bleeding, especially intracranial hemorrhage after head trauma.","category":"Medications"},{"id":"c18_fc06","question":"What is 'relative hypotension' in an elderly patient?","answer":"A blood pressure that appears normal but is actually low for a chronically hypertensive patient, indicating shock.","category":"Assessment"},{"id":"c18_fc07","question":"Why can subdural hematomas develop slowly in the elderly?","answer":"Brain atrophy stretches the bridging veins, which tear easily and bleed slowly, so symptoms may be delayed after minor head trauma.","category":"Head Injury"},{"id":"c18_fc08","question":"What is kyphotic deformity and how does it affect SMR?","answer":"An exaggerated forward curvature of the thoracic spine; pad the voids to achieve comfortable, neutral alignment rather than forcing the spine flat.","category":"Spine"},{"id":"c18_fc09","question":"Why do low-energy mechanisms cause major injuries in the elderly?","answer":"Osteoporosis makes bones fragile, so even ground-level falls can fracture the hip, pelvis, or ribs.","category":"Mechanisms"},{"id":"c18_fc10","question":"Why are rib fractures especially dangerous in older adults?","answer":"They impair ventilation, cause pain that limits breathing, and substantially increase the risk of pneumonia and death.","category":"Chest"},{"id":"c18_fc11","question":"Why must fluid resuscitation be cautious in the elderly?","answer":"Reduced cardiac and renal reserve mean over-aggressive fluids can precipitate pulmonary edema and heart failure.","category":"Management"},{"id":"c18_fc12","question":"How does decreased respiratory reserve affect management?","answer":"Older patients desaturate faster and tolerate hypoventilation poorly—support oxygenation and ventilation early.","category":"Respiratory"},{"id":"c18_fc13","question":"Why is obtaining the patient's baseline important?","answer":"Dementia, sensory deficits, and chronic conditions alter the exam; knowing baseline mental status and function (from caregivers) helps interpret findings.","category":"Assessment"},{"id":"c18_fc14","question":"Why handle elderly patients gently and pad bony prominences?","answer":"Thin skin and fragile bones are easily injured; padding prevents pressure injury and provides comfortable alignment.","category":"Management"},{"id":"c18_fc15","question":"What should you always ask about in a geriatric head-injury patient?","answer":"Use of anticoagulant or antiplatelet medications, which greatly raise the risk of intracranial bleeding.","category":"Medications"},{"id":"c18_fc16","question":"Why should you maintain a low threshold for trauma-center transport in the elderly?","answer":"Limited reserve and high risk of occult, serious injury mean older patients benefit from higher-level care even after seemingly minor trauma.","category":"Disposition"},{"id":"c18_fc17","question":"How does reduced kidney function affect geriatric trauma care?","answer":"It impairs handling of fluids and drugs, increasing the risk of fluid overload and altered drug effects.","category":"Renal"},{"id":"c18_fc18","question":"What is the danger of trusting 'normal' vital signs in the elderly trauma patient?","answer":"Medications and baseline hypertension can mask shock; normal-appearing vitals may conceal serious injury and decompensation.","category":"Assessment"}]},"c19":{"chapter":"c19","cards":[{"id":"c19_fc01","question":"What are the dual goals in managing the pregnant trauma patient?","answer":"Caring for two patients—but the best way to protect the fetus is to aggressively resuscitate the mother. What is good for the mother is good for the fetus.","category":"Principles"},{"id":"c19_fc02","question":"How does blood volume change in pregnancy and why does it matter?","answer":"It increases about 40–50%, so the mother can lose a large volume before showing signs of shock—maternal vitals can be falsely reassuring while the fetus is compromised.","category":"Physiology"},{"id":"c19_fc03","question":"How does heart rate change in pregnancy?","answer":"It rises by about 15–20 beats per minute, altering the baseline against which you interpret tachycardia.","category":"Physiology"},{"id":"c19_fc04","question":"What is supine hypotension syndrome?","answer":"After ~20 weeks, the gravid uterus compresses the inferior vena cava when the patient lies supine, reducing venous return and causing hypotension.","category":"Supine Hypotension"},{"id":"c19_fc05","question":"How do you prevent or treat supine hypotension syndrome?","answer":"Tilt the patient 15–30 degrees to the left (tilting the whole board to maintain SMR) or manually displace the uterus to the left to relieve aortocaval compression.","category":"Supine Hypotension"},{"id":"c19_fc06","question":"What is abruptio placenta and its signs?","answer":"Premature separation of the placenta from the uterine wall—causing vaginal bleeding, abdominal pain, a tender/rigid uterus, and fetal distress.","category":"Injuries"},{"id":"c19_fc07","question":"Why does maternal hypotension threaten the fetus?","answer":"The fetus depends entirely on maternal perfusion; maternal hypotension reduces uterine blood flow and causes fetal compromise.","category":"Physiology"},{"id":"c19_fc08","question":"Why give oxygen and fluids generously to the pregnant trauma patient?","answer":"The mother's increased blood volume needs replacement, and adequate maternal oxygenation and perfusion are essential for fetal survival.","category":"Management"},{"id":"c19_fc09","question":"Why is aspiration risk increased in pregnancy?","answer":"Slowed gastric emptying and the upward pressure of the gravid uterus increase the risk of vomiting and aspiration.","category":"Physiology"},{"id":"c19_fc10","question":"How does the elevated diaphragm in pregnancy affect breathing?","answer":"The gravid uterus elevates the diaphragm, reducing functional lung volume and increasing the tendency to desaturate.","category":"Physiology"},{"id":"c19_fc11","question":"Why must even minor trauma in pregnancy be evaluated?","answer":"Placental abruption and fetal compromise can occur with few or no external signs after a seemingly minor mechanism.","category":"Assessment"},{"id":"c19_fc12","question":"What under-recognized cause of trauma should you screen for in pregnancy?","answer":"Domestic (intimate partner) violence—assess and document carefully.","category":"Special Considerations"},{"id":"c19_fc13","question":"What is the correct transport position for a late-pregnancy trauma patient?","answer":"Tilted 15–30 degrees to the left (board and all) to relieve aortocaval compression while maintaining spinal motion restriction.","category":"Transport"},{"id":"c19_fc14","question":"What other pregnancy-specific injuries should you consider after abdominal trauma?","answer":"Uterine rupture and preterm labor, in addition to placental abruption.","category":"Injuries"},{"id":"c19_fc15","question":"Why can a fetus be in distress while maternal vitals appear normal?","answer":"The mother compensates for blood loss by shunting blood away from the uterus, so the fetus suffers before the mother shows shock.","category":"Physiology"},{"id":"c19_fc16","question":"What should you monitor for during transport of a pregnant trauma patient?","answer":"Vaginal bleeding, abdominal pain, uterine tenderness/rigidity, and contractions (signs of abruption or preterm labor), plus maternal vital signs.","category":"Monitoring"},{"id":"c19_fc17","question":"Where should a significantly injured pregnant patient be transported?","answer":"To a facility capable of both maternal trauma care and fetal/obstetric care.","category":"Disposition"},{"id":"c19_fc18","question":"What single principle best summarizes pregnant trauma resuscitation?","answer":"Resuscitate the mother first and aggressively—saving the mother is the best way to save the fetus.","category":"Principles"}]},"c20":{"chapter":"c20","cards":[{"id":"c20_fc01","question":"Why is it dangerous to attribute altered behavior to intoxication alone?","answer":"Serious conditions—head injury, hemorrhage, hypoxia, hypoglycemia—can be masked by the assumption that the patient is 'just drunk.' Assume a treatable cause until proven otherwise.","category":"Principles"},{"id":"c20_fc02","question":"What are common signs of alcohol/drug influence?","answer":"Slurred speech, unsteady gait, odor of alcohol, abnormal pupils, altered mental status, mood lability, agitation or somnolence, and abnormal vital signs.","category":"Signs"},{"id":"c20_fc03","question":"How do stimulant and opioid intoxication differ in presentation?","answer":"Stimulants cause tachycardia, agitation, dilated pupils, and hyperthermia; opioids cause sedation, pinpoint pupils, and respiratory depression.","category":"Signs"},{"id":"c20_fc04","question":"What two bedside tests should you perform on every impaired patient?","answer":"A blood glucose check and pulse oximetry (oxygen saturation).","category":"Assessment"},{"id":"c20_fc05","question":"What interactive style best gains cooperation from an impaired patient?","answer":"A calm, nonjudgmental, reassuring approach—explain actions, set simple expectations, avoid confrontation, and allow personal space when safe.","category":"Communication"},{"id":"c20_fc06","question":"When are closed-ended questions useful?","answer":"When the patient is difficult, agitated, or has limited cooperation—simple yes/no questions are easier to answer and reduce confrontation.","category":"Communication"},{"id":"c20_fc07","question":"What is excited delirium?","answer":"A life-threatening state of extreme agitation, aggression, paranoia, hyperthermia, and apparent superhuman strength, often from stimulants or psychiatric illness, that can progress to sudden death.","category":"Excited Delirium"},{"id":"c20_fc08","question":"Why is excited delirium a true medical emergency?","answer":"It can rapidly progress to cardiovascular collapse and sudden death, requiring rapid control, sedation per protocol, cooling, and continuous monitoring.","category":"Excited Delirium"},{"id":"c20_fc09","question":"How should excited delirium be managed?","answer":"Coordinated rapid control, sedation per protocol, active cooling, oxygenation, and continuous monitoring—not prolonged physical struggle/restraint.","category":"Excited Delirium"},{"id":"c20_fc10","question":"What is decision-making capacity and why does it matter?","answer":"The ability to understand the situation and consequences and make an informed decision; impairment may remove capacity to refuse care, so involve medical direction and follow protocol/law.","category":"Capacity"},{"id":"c20_fc11","question":"When is patient restraint appropriate?","answer":"Only when necessary for the safety of the patient or crew, applied humanely, and never in a position that compromises breathing.","category":"Restraint"},{"id":"c20_fc12","question":"What restraint position must be avoided and why?","answer":"Prone or hog-tie positioning, because it risks positional asphyxia and death.","category":"Restraint"},{"id":"c20_fc13","question":"What must you do after restraining a patient?","answer":"Continuously reassess and monitor breathing, circulation, and the patient's condition.","category":"Restraint"},{"id":"c20_fc14","question":"Why must opioid-impaired patients be watched closely?","answer":"They can have life-threatening respiratory depression—support ventilation and consider naloxone per protocol.","category":"Special Considerations"},{"id":"c20_fc15","question":"What treatable causes mimic intoxication and must be excluded?","answer":"Head injury, hypoglycemia, hypoxia, shock, stroke, infection, and other metabolic causes.","category":"Assessment"},{"id":"c20_fc16","question":"What is the priority before approaching an agitated impaired patient?","answer":"Scene safety and personal/crew safety.","category":"Safety"},{"id":"c20_fc17","question":"Why search diligently for occult injury in an impaired patient?","answer":"Drugs and alcohol mask pain, so significant injuries can be missed without a careful, systematic exam.","category":"Assessment"},{"id":"c20_fc18","question":"How can bystanders help with an impaired patient?","answer":"Trusted family or friends can help calm the patient and provide history, improving cooperation and safety.","category":"Communication"}]},"c21":{"chapter":"c21","cards":[{"id":"c21_fc01","question":"How does traumatic cardiopulmonary arrest (TCPA) differ from medical cardiac arrest?","answer":"The cause is usually a mechanical/reversible problem (hypovolemia, hypoxia, obstructive shock) rather than a primary cardiac dysrhythmia, so survival depends on correcting the cause—not on drugs/rhythm management alone.","category":"Concepts"},{"id":"c21_fc02","question":"What are the four key treatable causes of TCPA?","answer":"Severe hypoxia (airway obstruction/FBAO), tension pneumothorax, cardiac tamponade, and massive hemorrhage/hypovolemia.","category":"Treatable Causes"},{"id":"c21_fc03","question":"Why do chest compressions alone rarely work in trauma arrest?","answer":"If the underlying mechanical cause (empty tank, obstructed venous return, or hypoxia) is not corrected, there is nothing for compressions to circulate.","category":"Concepts"},{"id":"c21_fc04","question":"What chest intervention is indicated in a traumatic arrest with chest trauma?","answer":"Bilateral needle chest decompression for suspected tension pneumothorax.","category":"Management"},{"id":"c21_fc05","question":"How is hemorrhage addressed in trauma arrest?","answer":"Aggressive hemorrhage control (direct pressure, tourniquet, hemostatic dressing, pelvic binder), IV/IO access, blood products per protocol, and rapid surgical transport.","category":"Management"},{"id":"c21_fc06","question":"What is the priority for a penetrating-trauma arrest with recent signs of life?","answer":"Immediate, rapid transport for possible surgical intervention—this is time-critical and potentially survivable.","category":"Management"},{"id":"c21_fc07","question":"List signs/injuries that are obviously incompatible with life.","answer":"Decapitation, hemicorporectomy, incineration, decomposition, rigor mortis, and dependent lividity.","category":"Withholding Resuscitation"},{"id":"c21_fc08","question":"When may resuscitation be withheld in trauma arrest?","answer":"For injuries incompatible with life, and for blunt/penetrating trauma patients found apneic, pulseless, and without other signs of life with prolonged arrest—per local protocol.","category":"Withholding Resuscitation"},{"id":"c21_fc09","question":"What is an unsalvageable patient?","answer":"A trauma patient whose injuries or arrest state make survival impossible, for whom resuscitation is appropriately withheld or terminated.","category":"Withholding Resuscitation"},{"id":"c21_fc10","question":"What is FBAO and why does it matter in arrest?","answer":"Foreign-body airway obstruction—a cause of hypoxic arrest that is rapidly reversible if the obstruction is relieved.","category":"FBAO"},{"id":"c21_fc11","question":"How do you manage a conscious patient with a severe foreign-body airway obstruction?","answer":"Deliver abdominal thrusts (chest thrusts for pregnant or markedly obese patients) until the object is expelled or the patient becomes unconscious.","category":"FBAO"},{"id":"c21_fc12","question":"How do you manage an unconscious choking (FBAO) patient?","answer":"Begin CPR, look in the mouth and remove a visualized object, and consider direct laryngoscopy with Magill forceps to extract the obstruction.","category":"FBAO"},{"id":"c21_fc13","question":"What is the overarching priority in managing TCPA?","answer":"Rapidly identify and correct the treatable mechanical cause while providing oxygenation and transporting for definitive surgical care.","category":"Concepts"},{"id":"c21_fc14","question":"Why is treating trauma arrest like a medical arrest a mistake?","answer":"Focusing on rhythm and drugs ignores the mechanical causes (hemorrhage, tension pneumothorax, tamponade) that must be fixed for any chance of survival.","category":"Pitfalls"},{"id":"c21_fc15","question":"What airway actions are taken in trauma arrest?","answer":"Open and secure the airway, oxygenate and ventilate, and relieve any foreign-body obstruction.","category":"Management"},{"id":"c21_fc16","question":"Should you delay transport of a salvageable trauma-arrest patient for prolonged on-scene care?","answer":"No—after addressing immediate reversible causes, rapid transport to surgical/blood resources is critical.","category":"Management"},{"id":"c21_fc17","question":"What role do blood products play in TCPA from hemorrhage?","answer":"Blood products replace lost volume and oxygen-carrying capacity; give per protocol along with hemorrhage control and rapid surgical transport.","category":"Management"},{"id":"c21_fc18","question":"When is involving medical direction appropriate in trauma arrest?","answer":"When withholding/termination criteria are unclear or local protocol requires consultation.","category":"Withholding Resuscitation"}]},"c22":{"chapter":"c22","cards":[{"id":"c22_fc01","question":"What is the core principle of standard precautions?","answer":"Treat the blood and body fluids of every patient as potentially infectious, applying protective measures universally regardless of known diagnosis.","category":"Standard Precautions"},{"id":"c22_fc02","question":"What measures make up standard precautions?","answer":"Hand hygiene, gloves, and—when splashing is possible—face/eye protection, masks, and gowns.","category":"Standard Precautions"},{"id":"c22_fc03","question":"What does OPIM stand for?","answer":"Other Potentially Infectious Materials—body fluids besides blood that can transmit pathogens.","category":"Definitions"},{"id":"c22_fc04","question":"What are the three most important bloodborne viral illnesses for providers?","answer":"Hepatitis B virus (HBV), hepatitis C virus (HCV), and human immunodeficiency virus (HIV).","category":"Bloodborne Viruses"},{"id":"c22_fc05","question":"Which bloodborne virus is vaccine-preventable?","answer":"Hepatitis B (HBV)—providers should be vaccinated; HCV and HIV have no vaccine.","category":"Bloodborne Viruses"},{"id":"c22_fc06","question":"Which of the three bloodborne viruses is the most transmissible?","answer":"Hepatitis B (HBV) is the most readily transmitted of the three.","category":"Bloodborne Viruses"},{"id":"c22_fc07","question":"How are bloodborne viruses transmitted to providers?","answer":"Through blood and certain body fluids via needlesticks, splashes to mucous membranes, or contact with non-intact skin.","category":"Bloodborne Viruses"},{"id":"c22_fc08","question":"What are the three types of transmission-based precautions?","answer":"Contact precautions, droplet precautions, and airborne precautions.","category":"Transmission Precautions"},{"id":"c22_fc09","question":"When are contact precautions used?","answer":"For organisms spread by direct or indirect touch—use gloves and a gown.","category":"Transmission Precautions"},{"id":"c22_fc10","question":"When are droplet precautions used and what PPE is required?","answer":"For diseases spread by large respiratory droplets (e.g., influenza, meningococcus); wear a surgical mask and eye protection.","category":"Transmission Precautions"},{"id":"c22_fc11","question":"When are airborne precautions used and what respirator is required?","answer":"For small-particle airborne diseases (TB, measles, varicella); wear a fit-tested N95/respirator and place a surgical mask on the patient.","category":"Transmission Precautions"},{"id":"c22_fc12","question":"Which diseases require airborne precautions?","answer":"Tuberculosis, measles, and varicella (chickenpox).","category":"Transmission Precautions"},{"id":"c22_fc13","question":"What symptoms should make you suspect tuberculosis?","answer":"Chronic cough, fever, night sweats, and weight loss—apply airborne precautions.","category":"Tuberculosis"},{"id":"c22_fc14","question":"How can the BCG vaccine complicate TB screening?","answer":"BCG (used in some countries) can cause a positive TB skin test, so results must be interpreted with clinical context.","category":"Tuberculosis"},{"id":"c22_fc15","question":"What are the first steps after a needlestick or splash exposure?","answer":"Immediately wash the site with soap and water (flush mucous membranes with water/saline), then report the exposure per protocol and seek evaluation promptly.","category":"Exposure Response"},{"id":"c22_fc16","question":"What is post-exposure prophylaxis (PEP) for HIV and why is timing critical?","answer":"Medication started after a significant exposure to reduce HIV transmission risk; it is most effective when started as soon as possible (within hours).","category":"PEP"},{"id":"c22_fc17","question":"Is there PEP for hepatitis C?","answer":"No—there is no PEP for HCV, but early identification allows monitoring and effective treatment if infection occurs.","category":"PEP"},{"id":"c22_fc18","question":"How are HBV-vaccinated providers protected after exposure?","answer":"Vaccination provides strong protection; immune globulin/vaccination and follow-up testing are arranged as indicated based on status.","category":"PEP"},{"id":"c22_fc19","question":"Why apply standard precautions even to 'low-risk' patients?","answer":"Infection status is frequently unknown, so universal precautions protect against unrecognized infections.","category":"Standard Precautions"},{"id":"c22_fc20","question":"What is the correct mask for a suspected measles patient?","answer":"Airborne precautions—a fit-tested N95 respirator for the provider, with a surgical mask on the patient.","category":"Transmission Precautions"}]}},"quizzes":{"c01":{"chapter":"c01","questions":[{"id":"c01_q01","question":"What is the first step in performing a scene size-up according to the text?","options":["A. Assessing the patient","B. Determining the total number of patients","C. Evaluating the scene for dangers","D. Performing initial assessment"],"correct":2,"rationale":"The text states, 'Scene size-up includes taking standard precautions to prevent exposure to blood and other potentially infective material, evaluating the scene for dangers, determining the total number of patients, determining essential equipment needed for the particular scene, and identifying the mechanisms of injuries.' The first step is clearly stated as evaluating the scene for dangers.","difficulty":"Easy"},{"id":"c01_q02","question":"Which mechanism of injury involves a rapid forward deceleration in an MVC?","options":["A. Penetrating","B. Blunt","C. Lateral impact","D. Frontal impact"],"correct":3,"rationale":"The text mentions, 'Frontal-impact or head-on collision: In an MVC involving a frontal-impact collision, an unrestrained body is brought to a sudden halt. The energy transfer is capable of producing multiple injuries.' This describes the rapid forward deceleration mechanism.","difficulty":"Easy"},{"id":"c01_q03","question":"What type of injury can be caused by the steering wheel in an MVC, according to the text?","options":["A. Cervical spine fracture","B. Facial laceration","C. Both A and B","D. Pelvic fracture"],"correct":2,"rationale":"The text states, 'Steering-wheel injuries most often occur to an unrestrained driver of a vehicle in a head-on collision. The driver may subsequently impact with the windshield. The steering wheel is the vehicle’s most lethal weapon for the unrestrained driver, and any degree of steering-wheel deformity (check under collapsed airbags) must be treated with a high index of suspicion for face, neck, thoracic, or abdominal injury.' This indicates that facial lacerations can occur.","difficulty":"Medium"},{"id":"c01_q04","question":"What is the primary concern when assessing a patient involved in a rear-impact collision?","options":["A. Cervical spine injury","B. Pelvic fracture","C. Head injury","D. Abdominal trauma"],"correct":0,"rationale":"The text states, 'In rear-impact collisions, the potential exists for neck and back injury. The mechanism of cervical-spine injury in a rear-impact collision is explained.' This indicates that cervical spine injuries are the primary concern.","difficulty":"Easy"},{"id":"c01_q05","question":"What equipment should be carried to the scene according to the text?","options":["A. Personal protective equipment only","B. Patient transport device and trauma box","C. Only oxygen and airway equipment","D. All essential equipment"],"correct":3,"rationale":"The text states, 'If possible, carry all essential equipment to the scene. This prevents loss of time returning to the vehicle.' Essential equipment includes personal protective equipment, patient transport device, trauma box, and other necessary items.","difficulty":"Easy"},{"id":"c01_q06","question":"What is a key factor in determining the mechanism of injury for a penetrating wound?","options":["A. The size of the entry wound","B. The velocity and type of projectile","C. The distance from which it was fired","D. The angle at which it entered the body"],"correct":1,"rationale":"The text states, 'Bullet factors that contribute to tissue damage include the following: Missile size, Missile deformity, Semijacket, Tumbling, Yaw. The velocity and type of projectile are key factors in determining the mechanism of injury for a penetrating wound.'","difficulty":"Medium"},{"id":"c01_q07","question":"What is the primary concern when managing a patient with a blast injury?","options":["A. Airway compromise","B. Secondary shrapnel injuries","C. Tertiary impact injuries","D. Quaternary burn injuries"],"correct":0,"rationale":"The text states, 'Primary blast injury is less common in the civilian setting than in combat. Injuries due to the primary air blast are almost exclusive to the air-containing organs. The auditory system often involves ruptured tympanic membranes. Once thought of as a marker of exposure to blasts sufficient to cause primary injury, recent data suggests that this is not a good triage tool. Lung injuries resulting from primary blast injury can include pneumothorax, parenchymal hemorrhage, and especially alveolar rupture.' This indicates that airway compromise is the primary concern.","difficulty":"Hard"},{"id":"c01_q08","question":"What are two common forms of MVCs mentioned in the text?","options":["A. Frontal-impact and rear-impact","B. Rear-impact and rollover","C. Lateral-impact and frontal-impact","D. Rollover and rotational"],"correct":2,"rationale":"The text states, 'The five common forms of MVCs are the following: Frontal-impact or head-on collision, Lateral-impact or T-bone collision, Rear-impact collision, Rollover collision, Rotational collision.' This indicates that frontal-impact and lateral-impact are two common forms.","difficulty":"Easy"},{"id":"c01_q09","question":"What is the potential risk of a lap belt in a frontal deceleration crash?","options":["A. Head injury","B. Pelvic fracture","C. Abdominal injury","D. Cervical spine injury"],"correct":2,"rationale":"The text states, 'If the lap belt is in place and the victim is subjected to a frontal deceleration crash, the body tends to fold together like a clasp knife (Figure 1-11). The head may be thrown forward into the steering wheel or dashboard. Facial, head, or neck injuries are common. Abdominal injuries also occur if the lap belt is positioned improperly.' This indicates that abdominal injury can occur.","difficulty":"Medium"},{"id":"c01_q10","question":"What mechanism of motion injury involves a rapid vertical deceleration?","options":["A. Blunt","B. Penetrating","C. Fall","D. Rear impact"],"correct":2,"rationale":"The text states, 'Potential Injury Patterns: Frontal impact: Cervical-spine fracture, Flail chest, Myocardial contusion, Pneumothorax, Aortic disruption, Spleen or liver laceration, Posterior hip dislocation, Knee dislocation. These injuries are caused by rapid vertical deceleration.' This indicates that falls involve a rapid vertical deceleration.","difficulty":"Easy"},{"id":"c01_q11","question":"What is the primary concern when managing a patient involved in a tractor accident?","options":["A. Airway compromise","B. Crush injuries","C. Head injury","D. Pelvic fracture"],"correct":1,"rationale":"The text states, 'The primary mechanism of injury in a tractor accident is the crush injury. Severity depends on the part of the anatomy involved.' This indicates that crush injuries are the primary concern.","difficulty":"Easy"},{"id":"c01_q12","question":"What is the potential risk when managing a patient with a gunshot wound?","options":["A. Airway compromise","B. Secondary shrapnel injuries","C. Tertiary impact injuries","D. Quaternary burn injuries"],"correct":0,"rationale":"The text states, 'Injuries caused by the secondary factors may be penetrating or blunt. Fragments of shrapnel from an explosion may attain velocities of 14,000 feet (4,270 meters) per second. This is over four times the velocity of the most powerful high-velocity rifle bullets. A piece of shrapnel traveling at this velocity would impart more than 16 times the energy of a similarly sized high-velocity rifle bullet. Any shrapnel wound should be considered serious.' This indicates that airway compromise can occur.","difficulty":"Hard"},{"id":"c01_q13","question":"What is the first step in performing a scene size-up according to the chapter?","options":["A. Approach the patient immediately","B. Determine if the scene is safe","C. Assess the total number of patients","D. Identify the mechanism of injury"],"correct":1,"rationale":"The text states that 'Scene size-up includes taking standard precautions to prevent exposure to blood and other potentially infective material, evaluating the scene for dangers, determining the total number of patients, determining essential equipment needed for the particular scene, and identifying the mechanisms of injuries.' The first step is clearly stated as 'evaluating the scene for dangers'.","difficulty":"Easy"},{"id":"c01_q14","question":"Which of the following is NOT a form of MVC mentioned in the chapter?","options":["A. Frontal-impact collision","B. Rear-impact collision","C. Lateral-impact collision","D. Rotational collision involving only one vehicle"],"correct":3,"rationale":"The chapter lists five common forms of MVCs: frontal-impact, lateral-impact (T-bone), rear-impact, rollover, and rotational. A rotational collision involving only one vehicle is not mentioned as a form of MVC.","difficulty":"Easy"},{"id":"c01_q15","question":"What type of injuries are most commonly associated with the steering wheel in head-on collisions?","options":["A. Facial and neck injuries","B. Chest and abdominal injuries","C. Lower extremity fractures","D. Spinal cord injuries"],"correct":0,"rationale":"The text mentions that 'The driver may subsequently impact with the windshield. The steering wheel is the vehicle’s most lethal weapon for the unrestrained driver, and any degree of steering-wheel deformity (check under collapsed airbags) must be treated with a high index of suspicion for face, neck, thoracic, or abdominal injury.'","difficulty":"Medium"},{"id":"c01_q16","question":"What is the primary mechanism of injury in rear-impact collisions according to the chapter?","options":["A. Deceleration injuries","B. Compression injuries","C. Penetrating injuries","D. Axial loading"],"correct":0,"rationale":"The text states that 'The sudden increase in acceleration produces posterior displacement of the occupants and possible hyperextension of the cervical spine if the headrest is not properly adjusted.' This indicates deceleration injuries as a primary mechanism.","difficulty":"Medium"},{"id":"c01_q17","question":"Which of the following is NOT a potential injury associated with seat restraints in MVCs?","options":["A. Cervical spine fractures","B. Rib fractures","C. Pelvic fractures","D. Concussions"],"correct":3,"rationale":"The text mentions that 'In rear-impact collisions, the potential exists for neck and back injury.' It does not specifically mention concussions as a common injury from seat restraints.","difficulty":"Easy"},{"id":"c01_q18","question":"What is the significance of a deformed steering wheel in an MVC?","options":["A. It indicates the vehicle was not involved in any collision","B. It suggests potential injuries to the driver's face, neck, or thorax","C. It means the airbags did not deploy","D. It is irrelevant to patient assessment"],"correct":1,"rationale":"The text states that 'A deformed steering wheel is just as important a clue in an auto equipped with an air bag as in those that are not. This clue may be missed because the deflated air bag covers the steering wheel.'","difficulty":"Medium"},{"id":"c01_q19","question":"What is the primary cause of injuries in tractor accidents according to the chapter?","options":["A. Penetrating injuries","B. Crush injuries","C. Blast injuries","D. Fall-related injuries"],"correct":1,"rationale":"The text states that 'The primary mechanism of injury in a tractor accident is the crush injury.'","difficulty":"Easy"},{"id":"c01_q20","question":"What type of injuries are most common with motorcycle accidents according to the chapter?","options":["A. Head and neck injuries","B. Lower extremity fractures","C. Chest and abdominal injuries","D. Spinal cord injuries"],"correct":0,"rationale":"The text mentions that 'Injuries depend on the part of the anatomy subjected to kinetic energy. The lack of protective encasement leads to a higher frequency of head, neck, and extremity injuries.'","difficulty":"Medium"},{"id":"c01_q21","question":"What is the significance of the steering wheel in MVCs according to the chapter?","options":["A. It is a minor injury risk","B. It can cause severe injuries due to its design as a 'lethal weapon'","C. It only affects passengers, not drivers","D. It has no significant role in injury patterns"],"correct":1,"rationale":"The text states that 'The steering wheel is the vehicle’s most lethal weapon for the unrestrained driver, and any degree of steering-wheel deformity (check under collapsed airbags) must be treated with a high index of suspicion for face, neck, thoracic, or abdominal injury.'","difficulty":"Medium"},{"id":"c01_q22","question":"What is the primary concern when assessing a patient after a fall according to the chapter?","options":["A. Immediate pain management","B. Determining the height of the fall and surface struck","C. Checking for superficial abrasions","D. Ensuring the airway is clear"],"correct":1,"rationale":"The text states that 'The types of injuries sustained depend on the following three factors, which you must identify and relay to medical direction: • Distance of fall • Anatomic area impacted • Surface struck.'","difficulty":"Medium"},{"id":"c01_q23","question":"What is a key factor in determining the severity of a knife wound according to the chapter?","options":["A. The type of blade","B. The angle and depth of penetration","C. The presence of blood","D. The location on the body"],"correct":1,"rationale":"The text states that 'The severity of a knife wound depends on the anatomic area penetrated, length of the blade, and angle of penetration.'","difficulty":"Medium"},{"id":"c01_q24","question":"What is the primary mechanism of injury in blast explosions according to the chapter?","options":["A. Penetrating injuries","B. Crush injuries","C. Air blast overpressure on air-filled structures","D. Thermal burns"],"correct":2,"rationale":"The text states that 'Primary. Caused by the initial air blast, a primary blast injury is caused by the direct effect of blast overpressure on tissue.'","difficulty":"Easy"},{"id":"c01_q25","question":"What is the first step in the ITLS Primary Survey according to the chapter?","options":["A. Performing a rapid trauma survey","B. Conducting an initial assessment","C. Performing a scene size-up","D. Making critical interventions and transporting decision"],"correct":2,"rationale":"The correct answer is C. The ITLS Primary Survey begins with performing a scene size-up, as stated in the chapter: 'Scene size-up is the first step in the ItLs Primary survey (Table 1-1).'","difficulty":"Easy"},{"id":"c01_q26","question":"Which of the following is NOT a component of the scene safety assessment during scene size-up?","options":["A. Determining if it's safe to approach the patient","B. Evaluating for potential hazards such as fire or toxic substances","C. Checking for the presence of bystanders","D. Assessing the total number of patients"],"correct":3,"rationale":"The correct answer is D. Assessing the total number of patients is part of determining the total number of patients, not a component of scene safety.","difficulty":"Easy"},{"id":"c01_q27","question":"What type of injuries are primarily responsible for most deaths from trauma in most countries?","options":["A. Penetrating injuries","B. Blast injuries","C. Motion (mechanical) injuries","D. Fall-related injuries"],"correct":2,"rationale":"The correct answer is C. The chapter states: 'Motion (mechanical) injuries are by and large responsible for the majority of deaths from trauma in most countries.'","difficulty":"Easy"},{"id":"c01_q28","question":"What mechanism of injury involves a sudden stop that can result in multiple injuries, such as those seen in head-on collisions?","options":["A. Lateral impact","B. Rear impact","C. Frontal impact","D. Rotational collision"],"correct":2,"rationale":"The correct answer is C. The chapter explains that frontal-impact or head-on collisions involve rapid forward deceleration, which can result in multiple injuries.","difficulty":"Medium"},{"id":"c01_q29","question":"What type of injury is most likely to occur when a pedestrian is struck by a car at low speed?","options":["A. Head injury","B. Pelvic fracture","C. Femur fracture","D. Multiple fractures in the lower leg or knee"],"correct":4,"rationale":"The correct answer is D. The chapter states that a pedestrian struck by a car, even at low speed, almost always suffers severe internal injuries as well as fractures, with bilateral lower leg or knee fractures being common.","difficulty":"Medium"},{"id":"c01_q30","question":"What is the primary mechanism of injury in a tractor accident?","options":["A. Penetrating injuries","B. Crush injuries","C. Blast injuries","D. Fall-related injuries"],"correct":1,"rationale":"The correct answer is B. The chapter states: 'The primary mechanism of injury in a tractor accident is the crush injury.'","difficulty":"Easy"},{"id":"c01_q31","question":"What type of injuries are commonly associated with motorcycle accidents, according to the text?","options":["A. Head and neck injuries","B. Pelvic fractures","C. Upper arm and shoulder injuries","D. Lower leg and knee injuries"],"correct":0,"rationale":"The correct answer is A. The chapter mentions that motorcycle operators are much like ejected automobile occupants, with severe head and neck injuries being common.","difficulty":"Medium"},{"id":"c01_q32","question":"What type of injury can occur when a pedestrian falls from a height?","options":["A. Cervical spine injury","B. Pelvic fracture","C. Femur fracture","D. Axial loading to the lumbar and cervical spine"],"correct":3,"rationale":"The correct answer is D. The chapter describes that in a 'lover’s leap' fall, the victim typically impacts initially on the feet and then falls backward, landing on the buttocks and outstretched hands, resulting in axial loading to the lumbar and cervical spine.","difficulty":"Medium"},{"id":"c01_q33","question":"What is a key factor to consider when evaluating a gunshot wound?","options":["A. The type of weapon","B. The distance from which the weapon was fired","C. The size and construction of the bullet","D. All of the above"],"correct":3,"rationale":"The correct answer is D. The chapter states: 'Important factors to obtain, if possible, are the type of weapon, its caliber (size of bullet), and the distance from which the weapon was fired.'","difficulty":"Easy"},{"id":"c01_q34","question":"What is the primary mechanism of injury in a rear-impact collision according to the chapter?","options":["A. Deceleration injuries","B. Compression injuries","C. Axial loading","D. Blast injuries"],"correct":0,"rationale":"The correct answer is A. The chapter explains that in a rear-impact collision, there is an increase in acceleration and possible hyperextension of the cervical spine due to the headrest not being properly adjusted.","difficulty":"Medium"},{"id":"c01_q35","question":"What type of injuries are most commonly associated with a rollover collision?","options":["A. Crush injuries","B. Deceleration injuries","C. Axial loading to the spine","D. Blast injuries"],"correct":2,"rationale":"The correct answer is C. The chapter states that during a vehicle rollover, there is an increased chance for axial-loading injuries of the spine.","difficulty":"Easy"},{"id":"c01_q36","question":"What type of injury can be caused by a knife wound according to the text?","options":["A. Blast injury","B. Penetrating injury","C. Crush injury","D. Deceleration injury"],"correct":1,"rationale":"The correct answer is B. The chapter states that stab wounds are low-energy injuries, and tissue damage is confined to the direct path of the blade.","difficulty":"Easy"}]},"c02":{"chapter":"c02","questions":[{"id":"c02_q01","question":"What is the first step in the ITLS Primary Survey?","options":["A. Scene size-up","B. Initial assessment","C. Rapid trauma survey or focused exam","D. Airway evaluation"],"correct":0,"rationale":"The first step in the ITLS Primary Survey is to perform a scene size-up, which sets the stage for the rest of the assessment. The initial assessment and rapid trauma survey follow.","difficulty":"Easy"},{"id":"c02_q02","question":"Which scale is used to assess the patient's level of consciousness during the initial assessment?","options":["A. AVPU","B. Glasgow Coma Scale","C. SAMPLE history","D. DCAP-BLS"],"correct":0,"rationale":"The AVPU scale (alert, responds to verbal stimuli, responds to pain, unresponsive) is used to assess the patient's level of consciousness during the initial assessment.","difficulty":"Easy"},{"id":"c02_q03","question":"What should be done if a patient has an altered mental status (AVPU score < A)?","options":["A. Perform a rapid trauma survey","B. Immediately transport to the hospital","C. Conduct a focused exam on the area of injury","D. Systematically search for causes during the rapid trauma survey"],"correct":3,"rationale":"If an altered mental status is noted, it triggers a systematic search for the cause during the rapid trauma survey, as loss or decrease in LOC can be caused by various factors.","difficulty":"Medium"},{"id":"c02_q04","question":"Which of the following is NOT an indication to perform a rapid trauma survey?","options":["A. Dangerous generalized mechanism of injury","B. Unconscious patient with unknown mechanism of injury","C. Patient with localized isolated injury (e.g., stab wound)","D. Multiple patients in a mass casualty event"],"correct":2,"rationale":"The rapid trauma survey is not limited to only localized injuries; it should be performed for dangerous generalized mechanisms or unknown mechanisms of injury, even if the patient has an isolated injury.","difficulty":"Medium"},{"id":"c02_q05","question":"What is the primary purpose of the ITLS Ongoing Exam?","options":["A. To find all life-threatening conditions","B. To assess for changes in patient condition during transport","C. To perform a comprehensive head-to-toe exam","D. To determine initial treatment interventions"],"correct":1,"rationale":"The ITLS Ongoing Exam is meant to identify any changes in the patient's condition, particularly useful when transporting critically injured patients.","difficulty":"Easy"},{"id":"c02_q06","question":"Which of the following should be performed first during an initial assessment?","options":["A. Check for breathing","B. Apply a cervical collar","C. Control bleeding from lacerations","D. Perform a focused exam on the area of injury"],"correct":0,"rationale":"The primary focus in the initial assessment is to ensure airway, breathing, and circulation (ABCs), starting with checking for breathing.","difficulty":"Easy"},{"id":"c02_q07","question":"What should be done if a patient has an altered mental status during the initial assessment?","options":["A. Immediately transport to the hospital","B. Perform a focused exam on the area of injury","C. Conduct a brief neurologic exam","D. Ignore and continue with the rapid trauma survey"],"correct":2,"rationale":"If an altered mental status is noted, it should trigger a brief neurologic exam to identify possible increased intracranial pressure.","difficulty":"Medium"},{"id":"c02_q08","question":"Which of the following is NOT part of the ITLS Primary Survey?","options":["A. Scene size-up","B. Initial assessment","C. Rapid trauma survey or focused exam","D. Secondary survey"],"correct":3,"rationale":"The secondary survey is not part of the primary survey; it comes after and is a separate step in the patient assessment process.","difficulty":"Easy"},{"id":"c02_q09","question":"What should be done if you identify a critical condition during the ITLS Primary Survey?","options":["A. Continue with the rapid trauma survey","B. Immediately transport to the hospital","C. Perform a focused exam on the area of injury","D. Wait for medical direction before transporting"],"correct":1,"rationale":"If critical conditions are identified, immediate transportation should be performed.","difficulty":"Easy"},{"id":"c02_q10","question":"What is the purpose of the ITLS Secondary Survey?","options":["A. To find all life-threatening conditions","B. To assess for changes in patient condition during transport","C. To perform a comprehensive head-to-toe exam and establish baseline information","D. To determine initial treatment interventions"],"correct":2,"rationale":"The ITLS Secondary Survey is meant to pick up additional injuries that might have been missed in the brief ITLS Primary Survey, establishing a baseline for treatment decisions.","difficulty":"Medium"},{"id":"c02_q11","question":"Which of the following should be performed during an ongoing exam?","options":["A. Perform a rapid trauma survey","B. Conduct a comprehensive head-to-toe exam","C. Reassess ABCs, mental status, and vital signs","D. Determine initial treatment interventions"],"correct":2,"rationale":"The ongoing exam should reassess the patient's condition, including ABCs, mental status, and vital signs.","difficulty":"Easy"},{"id":"c02_q12","question":"What is the primary reason to interrupt the ITLS Primary Survey?","options":["A. The scene becomes unsafe","B. To perform a focused exam on the area of injury","C. The patient requests treatment","D. To obtain more information from bystanders"],"correct":0,"rationale":"The primary reasons to interrupt the ITLS Primary Survey are if the scene becomes unsafe, there is exsanguinating hemorrhage, an airway obstruction, or cardiac arrest.","difficulty":"Medium"},{"id":"c02_q13","question":"What is the first step in the ITLS Primary Survey?","options":["A. Scene size-up","B. Initial assessment","C. Rapid trauma survey or focused exam","D. Airway evaluation"],"correct":0,"rationale":"The first step in the ITLS Primary Survey is to perform a scene size-up, which involves assessing hazards and determining if it's safe to enter the scene before approaching the patient.","difficulty":"Easy"},{"id":"c02_q14","question":"Which of the following is NOT part of the initial assessment in the ITLS Primary Survey?","options":["A. Level of consciousness","B. Airway evaluation","C. Circulation check","D. Detailed history taking"],"correct":3,"rationale":"Detailed history taking is not performed during the initial assessment; it's part of the ITLS Secondary Survey or ongoing exam.","difficulty":"Easy"},{"id":"c02_q15","question":"What should be done if a patient has an altered mental status (AVPU) and is unresponsive to verbal stimuli?","options":["A. Perform a rapid trauma survey","B. Apply a cervical collar immediately","C. Use the AVPU scale to document their level of consciousness","D. Intubate the patient"],"correct":2,"rationale":"The AVPU scale is used to document the level of consciousness, and if the patient is unresponsive to verbal stimuli, they are classified as 'V' (responds to verbal stimuli).","difficulty":"Easy"},{"id":"c02_q16","question":"Which of the following interventions should be performed immediately during a load-and-go situation?","options":["A. Detailed history taking","B. Rapid trauma survey","C. Control major external bleeding","D. Full secondary survey"],"correct":2,"rationale":"In a load-and-go situation, the primary focus is on controlling life-threatening conditions and transporting the patient immediately.","difficulty":"Easy"},{"id":"c02_q17","question":"What does the term 'PE aRLS' stand for in the context of trauma assessment?","options":["A. Patient Evaluation and Rapid Life Support","B. Prehospital Emergency Assessment and Response Levels","C. Prehospital Emergency Resuscitation and Lifesaving Skills","D. Prehospital Emergency Rapid Life-Support"],"correct":0,"rationale":"PE aRLS stands for 'Patient Evaluation and Rapid Life Support', which is the systematic approach used in trauma assessment.","difficulty":"Easy"},{"id":"c02_q18","question":"Which of the following is NOT an indication to interrupt the ITLS Primary Survey?","options":["A. Exsanguinating hemorrhage","B. Airway obstruction","C. Cardiac arrest","D. Patient's chief complaint"],"correct":3,"rationale":"The patient's chief complaint is not an indication to interrupt the ITLS Primary Survey; it's part of the initial assessment.","difficulty":"Easy"},{"id":"c02_q19","question":"What is the purpose of the rapid trauma survey in the ITLS Primary Survey?","options":["A. To perform a detailed head-to-toe examination","B. To find all life-threatening conditions quickly","C. To document patient history","D. To provide definitive treatment"],"correct":1,"rationale":"The rapid trauma survey is designed to identify all life-threatening conditions in a brief, systematic manner.","difficulty":"Easy"},{"id":"c02_q20","question":"Which of the following is NOT part of the ITLS Ongoing Exam?","options":["A. Reassessing the airway","B. Performing a detailed head-to-toe examination","C. Monitoring vital signs","D. Checking interventions"],"correct":1,"rationale":"The ITLS Ongoing Exam does not include performing a detailed head-to-toe examination; it focuses on reassessing changes in the patient's condition.","difficulty":"Easy"},{"id":"c02_q21","question":"What is the primary goal of the ITLS Secondary Survey?","options":["A. To find all life-threatening conditions","B. To provide definitive treatment","C. To pick up additional injuries missed in the initial assessment","D. To document patient history"],"correct":2,"rationale":"The primary goal of the ITLS Secondary Survey is to identify any additional injuries that may have been missed during the initial assessment.","difficulty":"Easy"},{"id":"c02_q22","question":"Which of the following is NOT a component of the SAMPLE history?","options":["A. Symptoms","B. Allergies","C. Medications","D. Past medical history and events preceding the incident"],"correct":3,"rationale":"The 'P' in SAMPLE stands for past medical history, not 'Past medical history and events preceding the incident'.","difficulty":"Easy"},{"id":"c02_q23","question":"What is the first step to take if a patient has an altered mental status during the initial assessment?","options":["A. Perform a rapid trauma survey","B. Apply a cervical collar","C. Check for airway patency and breathing","D. Intubate the patient"],"correct":2,"rationale":"The first step is to check for airway patency and breathing, as this can quickly determine if the patient's altered mental status is due to respiratory or airway issues.","difficulty":"Easy"},{"id":"c02_q24","question":"What should be done immediately after completing the initial assessment in a load-and-go situation?","options":["A. Perform a detailed secondary survey","B. Control major external bleeding and transport","C. Document patient history","D. Apply a cervical collar"],"correct":1,"rationale":"In a load-and-go situation, the primary focus is on controlling major external bleeding and transporting the patient immediately.","difficulty":"Easy"},{"id":"c02_q25","question":"What is the first step in the ITLS Primary Survey?","options":["A. Scene size-up","B. Initial assessment","C. Rapid trauma survey or focused exam","D. Airway evaluation"],"correct":0,"rationale":"The correct answer is A. The first step in the ITLS Primary Survey is to perform a scene size-up, which sets the stage for the rest of the assessment.","difficulty":"Easy"},{"id":"c02_q26","question":"Which scale is used to assess the patient's level of consciousness during the initial assessment?","options":["A. AVPU","B. Glasgow Coma Scale","C. SAMPLE history","D. DCAP-BLS"],"correct":0,"rationale":"The correct answer is A. The AVPU scale (alert, responds to verbal stimuli, responds to pain, unresponsive) is used to assess the patient's level of consciousness.","difficulty":"Easy"},{"id":"c02_q27","question":"What should be done if a patient has an altered mental status during the initial assessment?","options":["A. Perform a rapid trauma survey","B. Immediately transport to the hospital","C. Check for signs of increased intracranial pressure (ICP)","D. Apply a cervical collar"],"correct":2,"rationale":"The correct answer is C. If a patient has an altered mental status, it's important to check for possible increased intracranial pressure using the Glasgow Coma Scale and other assessments.","difficulty":"Medium"},{"id":"c02_q28","question":"Which of the following is NOT a reason to interrupt the ITLS Primary Survey?","options":["A. Exsanguinating hemorrhage","B. Airway obstruction","C. Cardiac arrest","D. Patient's chief complaint"],"correct":3,"rationale":"The correct answer is D. The patient's chief complaint does not interrupt the ITLS Primary Survey, whereas exsanguinating hemorrhage, airway obstruction, and cardiac arrest do.","difficulty":"Easy"},{"id":"c02_q29","question":"What should be done if a patient has major external bleeding during the initial assessment?","options":["A. Control it immediately","B. Wait for medical direction","C. Perform a rapid trauma survey first","D. Transport to the hospital"],"correct":0,"rationale":"The correct answer is A. If a patient has major external bleeding, you should control it immediately as part of the initial assessment.","difficulty":"Easy"},{"id":"c02_q30","question":"Which of the following is NOT included in the ITLS Ongoing Exam?","options":["A. Reassessing airway","B. Checking vital signs","C. Performing a detailed head-to-toe exam","D. Monitoring interventions"],"correct":2,"rationale":"The correct answer is C. A detailed head-to-toe exam is not part of the ITLS Ongoing Exam, which focuses on reassessing changes in the patient's condition.","difficulty":"Medium"},{"id":"c02_q31","question":"What should be done if a patient has an unstable pelvis during transport?","options":["A. Transport immediately","B. Perform a rapid trauma survey","C. Apply a cervical collar","D. Wait for hospital arrival"],"correct":0,"rationale":"The correct answer is A. If a patient has an unstable pelvis, transport should be immediate as it can lead to shock and other complications.","difficulty":"Easy"},{"id":"c02_q32","question":"Which of the following is NOT part of the ITLS Secondary Survey?","options":["A. Repeating initial assessment","B. Performing a detailed head-to-toe exam","C. Checking vital signs again","D. Applying a cervical collar"],"correct":3,"rationale":"The correct answer is D. Applying a cervical collar is not part of the ITLS Secondary Survey, which focuses on finding additional injuries.","difficulty":"Medium"},{"id":"c02_q33","question":"What should be done if a patient has a suspected tension pneumothorax during the rapid trauma survey?","options":["A. Perform chest decompression","B. Apply a cervical collar","C. Wait for hospital arrival","D. Transport immediately without intervention"],"correct":0,"rationale":"The correct answer is A. If a patient has a suspected tension pneumothorax, immediate chest decompression should be performed.","difficulty":"Medium"},{"id":"c02_q34","question":"Which of the following is NOT a critical condition that requires immediate transport?","options":["A. Altered mental status","B. Abnormal breathing","C. Normal circulation","D. Penetrating wounds to the torso"],"correct":2,"rationale":"The correct answer is C. Normal circulation does not require immediate transport, whereas altered mental status, abnormal breathing, and penetrating wounds do.","difficulty":"Easy"},{"id":"c02_q35","question":"What should be done if a patient has bilateral femur fractures during the ITLS Primary Survey?","options":["A. Transport immediately","B. Perform a detailed head-to-toe exam","C. Apply traction splints","D. Wait for hospital arrival"],"correct":0,"rationale":"The correct answer is A. If a patient has bilateral femur fractures, transport should be immediate due to the risk of shock.","difficulty":"Easy"},{"id":"c02_q36","question":"What is the purpose of the ITLS Secondary Survey?","options":["A. To find all life-threatening conditions","B. To perform a brief exam from head to toe","C. To establish a baseline for treatment decisions","D. To assess changes in patient condition"],"correct":2,"rationale":"The correct answer is C. The ITLS Secondary Survey is meant to pick up additional injuries and establish the baseline from which treatment decisions will be made.","difficulty":"Medium"}]},"c03":{"chapter":"c03","questions":[{"id":"c03_q01","question":"What is the primary goal of the ITLS Primary Survey?","options":["Document a complete head-to-toe exam","Identify and treat immediate life threats and determine load-and-go status","Obtain a full SAMPLE history","Apply all splints before transport"],"correct":1,"rationale":"The Primary Survey is a rapid, prioritized assessment whose purpose is to find and treat immediate threats to life and to identify load-and-go patients within about two minutes.","difficulty":"Easy"},{"id":"c03_q02","question":"Within approximately how long should the Primary Survey identify a load-and-go patient?","options":["30 seconds","2 minutes","5 minutes","10 minutes"],"correct":1,"rationale":"ITLS sets the benchmark of identifying critical/load-and-go patients within about two minutes of patient contact.","difficulty":"Easy"},{"id":"c03_q03","question":"In the CABC approach, what is addressed first?","options":["Airway patency","Breathing adequacy","Control of catastrophic external bleeding","Circulation and pulse check"],"correct":2,"rationale":"The leading 'C' in CABC means control of catastrophic/life-threatening external bleeding takes priority, using direct pressure, tourniquet, or hemostatic agent.","difficulty":"Easy"},{"id":"c03_q04","question":"A patient opens his eyes only when you pinch his trapezius. What is his AVPU rating?","options":["Alert","Voice","Pain","Unresponsive"],"correct":2,"rationale":"Responding only to a painful stimulus corresponds to 'P' (Pain) on the AVPU scale.","difficulty":"Easy"},{"id":"c03_q05","question":"You hear stridor on the initial assessment. This finding most suggests:","options":["Fluid in the airway","Upper-airway narrowing/partial obstruction","Complete obstruction","Normal breathing"],"correct":1,"rationale":"Stridor is a high-pitched sound of upper-airway narrowing (e.g., edema, partial obstruction), distinct from gurgling (fluid) or snoring (tongue).","difficulty":"Medium"},{"id":"c03_q06","question":"Gurgling respirations are best managed initially by:","options":["Endotracheal intubation","Suction","Needle decompression","Bag-valve-mask ventilation"],"correct":1,"rationale":"Gurgling indicates fluid in the airway; suction is the immediate corrective action.","difficulty":"Easy"},{"id":"c03_q07","question":"A patient with a generalized/unknown mechanism of injury should receive which assessment?","options":["Focused exam only","Rapid trauma survey","No exam until the hospital","Only a SAMPLE history"],"correct":1,"rationale":"Generalized or unknown mechanisms warrant a head-to-toe rapid trauma survey; localized mechanisms warrant a focused exam.","difficulty":"Easy"},{"id":"c03_q08","question":"During the rapid trauma survey, you find distended neck veins, tracheal deviation, and absent breath sounds on the right. This suggests:","options":["Cardiac tamponade","Tension pneumothorax","Simple rib fracture","Hemothorax"],"correct":1,"rationale":"Distended neck veins, tracheal deviation (late sign), and unilateral absent breath sounds are the classic picture of tension pneumothorax requiring decompression.","difficulty":"Medium"},{"id":"c03_q09","question":"Breath sounds are diminished on the left. You percuss and hear dullness. This most likely indicates:","options":["Pneumothorax","Hemothorax","Tension pneumothorax","Normal lung"],"correct":1,"rationale":"Dullness to percussion with diminished breath sounds suggests fluid (blood) — a hemothorax. Hyperresonance would suggest pneumothorax.","difficulty":"Medium"},{"id":"c03_q10","question":"What does DCAP-BLS help you remember?","options":["Vital sign parameters","Inspection findings during the detailed exam","Steps of CPR","Components of the SAMPLE history"],"correct":1,"rationale":"DCAP-BLS (Deformities, Contusions, Abrasions, Punctures/Penetrations, Burns, Lacerations, Swelling) is the inspection checklist for the detailed exam.","difficulty":"Easy"},{"id":"c03_q11","question":"TIC, used while palpating a region, stands for:","options":["Tenderness, Instability, Crepitation","Trauma, Injury, Contusion","Tension, Inflammation, Cyanosis","Tenderness, Inflammation, Crackles"],"correct":0,"rationale":"TIC = Tenderness, Instability, Crepitation — what you palpate for over bony and chest-wall structures.","difficulty":"Easy"},{"id":"c03_q12","question":"When is the disability (pupils/GCS) assessment performed during the Primary Survey?","options":["Always before airway","Only if the patient has altered mental status","Never in the field","Only after splinting"],"correct":1,"rationale":"Disability is assessed during the Primary Survey only when the patient has altered mental status; otherwise it is postponed to the Secondary Survey.","difficulty":"Medium"},{"id":"c03_q13","question":"Which set of findings suggests cerebral herniation syndrome?","options":["Tachycardia, hypotension, pinpoint pupils","Unresponsiveness, dilated/unequal pupil, hypertension, bradycardia, posturing","Alert patient with equal reactive pupils","Fever, rash, neck stiffness"],"correct":1,"rationale":"Cerebral herniation presents with unresponsiveness, a dilated/unequal pupil, hypertension, bradycardia, and posturing.","difficulty":"Medium"},{"id":"c03_q14","question":"A patient has a GCS of 7 with a dilated, fixed left pupil and extensor posturing. What ventilatory strategy may be indicated?","options":["No supplemental oxygen","Controlled mild hyperventilation only for signs of herniation","Routine hyperventilation for all head injuries","Withhold ventilation"],"correct":1,"rationale":"Prophylactic hyperventilation is not recommended; it is reserved for head-injured patients showing signs of cerebral herniation (e.g., GCS <8 with posturing or pupillary asymmetry).","difficulty":"Hard"},{"id":"c03_q15","question":"When should the ITLS Ongoing Exam be repeated?","options":["Only once at the hospital","After condition changes, after interventions, and after moves","Only if the patient complains","Never during transport"],"correct":1,"rationale":"Repeat the Ongoing Exam whenever the condition changes, after any intervention, and after any move (scene to ambulance, ambulance to ED).","difficulty":"Easy"},{"id":"c03_q16","question":"Which is NOT a routine part of the Ongoing Exam intervention check?","options":["ET tube position","IV rate and fluid","Re-taking the patient's complete past surgical history","Decompression needle patency"],"correct":2,"rationale":"The Ongoing Exam rechecks interventions and monitors; a complete past surgical history is part of the SAMPLE history, not the intervention recheck.","difficulty":"Medium"},{"id":"c03_q17","question":"A critical (load-and-go) patient should receive the Secondary Survey:","options":["On scene before transport","En route, only if time permits","Never","Only after arrival at the hospital"],"correct":1,"rationale":"Critical patients receive the Secondary Survey en route if time allows; stable patients may receive it on scene.","difficulty":"Easy"},{"id":"c03_q18","question":"Battle's sign and raccoon eyes during the Secondary Survey suggest:","options":["Cervical spine fracture","Basilar skull fracture","Mandibular fracture","Orbital cellulitis"],"correct":1,"rationale":"Mastoid bruising (Battle's sign) and periorbital bruising (raccoon eyes), with CSF drainage from ears/nose, suggest a basilar skull fracture.","difficulty":"Medium"},{"id":"c03_q19","question":"PMS assessment of an extremity evaluates:","options":["Pain, Movement, Strength","Pulses, Motor function, Sensation","Position, Mobility, Skin","Pressure, Mass, Swelling"],"correct":1,"rationale":"PMS = distal Pulses, Motor function, and Sensation, checked in each extremity.","difficulty":"Easy"},{"id":"c03_q20","question":"Why should a critical trauma patient generally NOT have a traction splint applied on scene?","options":["It worsens bleeding","It takes too long and delays transport","It is contraindicated in all fractures","It requires medical direction"],"correct":1,"rationale":"Traction splinting is time-consuming; for load-and-go patients it delays transport and is deferred or done en route.","difficulty":"Medium"},{"id":"c03_q21","question":"When is the posterior exam typically performed?","options":["Never in the field","During the log roll onto or off the backboard","Before the airway is assessed","Only at the hospital"],"correct":1,"rationale":"The posterior is examined during the log roll for spinal motion restriction (onto the board) or when removing the patient from the board.","difficulty":"Easy"},{"id":"c03_q22","question":"For every patient with a decreased level of consciousness, you should also:","options":["Apply a traction splint","Obtain a blood glucose level and check for medical ID","Withhold oxygen","Hyperventilate routinely"],"correct":1,"rationale":"All patients with decreased LOC should have a finger-stick glucose obtained and be checked for medical identification devices.","difficulty":"Easy"},{"id":"c03_q23","question":"When should you communicate with medical direction and the receiving facility?","options":["Only after arrival","Early, when you identify a critical patient","Only for stable patients","Never from the field"],"correct":1,"rationale":"Early communication with medical direction and the receiving facility is emphasized for critical patients to mobilize resources.","difficulty":"Easy"},{"id":"c03_q24","question":"Which critical interventions may justifiably be done before transport even though they cost Golden Period time?","options":["Full secondary survey and documentation","Airway control, ventilation, control of serious bleeding, sealing open pneumothorax, decompressing tension pneumothorax, stabilizing impaled objects, packaging","Detailed neurologic exam","IV start for a stable patient"],"correct":1,"rationale":"Only essential life-saving interventions justify on-scene delay; ITLS lists airway, ventilation, oxygen, hemorrhage control, sealing open pneumothorax, decompressing tension pneumothorax, impaled-object stabilization, and packaging.","difficulty":"Hard"},{"id":"c03_q25","question":"The pregnant trauma patient should be transported:","options":["Flat and supine","Tilted slightly to the left","Sitting fully upright","Prone"],"correct":1,"rationale":"Tilting the pregnant patient slightly to the left (about 20–30 degrees) relieves aortocaval compression by the gravid uterus.","difficulty":"Medium"}]},"c04":{"chapter":"c04","questions":[{"id":"c04_q01","question":"Which field task is considered the single most important in trauma care?","options":["Splinting fractures","Airway control","Obtaining IV access","Documentation"],"correct":1,"rationale":"Airway control is paramount because hypoxia is rapidly fatal and cannot wait for hospital arrival.","difficulty":"Easy"},{"id":"c04_q02","question":"The preferred maneuver to open the airway in a trauma patient is:","options":["Head-tilt/chin-lift","Modified jaw thrust","Hyperextension of the neck","Sniffing position"],"correct":1,"rationale":"The modified jaw thrust opens the airway without moving the cervical spine, protecting a potential spinal injury.","difficulty":"Easy"},{"id":"c04_q03","question":"Minute volume is best described as:","options":["Air moved in one breath","Tidal volume multiplied by respiratory rate","Oxygen saturation over one minute","The volume of dead space"],"correct":1,"rationale":"Minute volume = tidal volume × respiratory rate, representing the total air moved per minute.","difficulty":"Medium"},{"id":"c04_q04","question":"An oropharyngeal airway (OPA) should be used only in patients who:","options":["Have an intact gag reflex","Have no gag reflex","Are fully alert","Have a suspected basilar skull fracture"],"correct":1,"rationale":"An OPA can stimulate the gag reflex and induce vomiting; it is reserved for patients with no gag reflex.","difficulty":"Easy"},{"id":"c04_q05","question":"A nasopharyngeal airway is relatively contraindicated when there is suspicion of:","options":["A femur fracture","A basilar skull fracture","A tension pneumothorax","Hypovolemic shock"],"correct":1,"rationale":"With basilar skull fracture, an NPA (or nasal intubation) risks passing into the cranial vault.","difficulty":"Medium"},{"id":"c04_q06","question":"What oxygen flow rate is used with a nonrebreather mask?","options":["2 L/min","6 L/min","15 L/min","25 L/min"],"correct":2,"rationale":"A nonrebreather is run at 15 L/min to keep the reservoir filled and deliver a high oxygen concentration.","difficulty":"Easy"},{"id":"c04_q07","question":"The recommended bag-valve-mask ventilation rate for an apneic adult is:","options":["4–6 breaths/min","8–10 breaths/min","12–16 breaths/min","20–24 breaths/min"],"correct":1,"rationale":"Adults are ventilated at 8–10 breaths per minute with oxygen, confirming chest rise to avoid hyperventilation.","difficulty":"Easy"},{"id":"c04_q08","question":"The most reliable method to confirm and monitor endotracheal tube placement is:","options":["Auscultation alone","Misting in the tube","Waveform capnography","Chest X-ray in the field"],"correct":2,"rationale":"Waveform capnography provides continuous confirmation of tube placement and ventilation; auscultation alone is unreliable.","difficulty":"Medium"},{"id":"c04_q09","question":"A blind insertion airway device (BIAD) is best described as:","options":["A device requiring direct cord visualization","A supraglottic airway placed without seeing the cords","A surgical airway","An oxygen delivery mask"],"correct":1,"rationale":"A BIAD is a supraglottic airway inserted blindly, useful as a primary or rescue airway.","difficulty":"Easy"},{"id":"c04_q10","question":"The mnemonic MMAP is used to predict:","options":["Shock severity","A difficult airway","Burn depth","Spinal injury"],"correct":1,"rationale":"MMAP (Mallampati/mouth opening, Mask seal/obstruction/obesity, Anatomy, Position) anticipates difficult mask ventilation and intubation.","difficulty":"Medium"},{"id":"c04_q11","question":"Apneic oxygenation refers to:","options":["Withholding all oxygen during intubation","Delivering oxygen (e.g., nasal cannula) during the apneic intubation attempt","Hyperventilating before intubation","Using a nonrebreather after intubation"],"correct":1,"rationale":"Apneic oxygenation keeps oxygen flowing during laryngoscopy to prolong safe apnea time and prevent desaturation.","difficulty":"Medium"},{"id":"c04_q12","question":"External laryngeal manipulation (ELM/BURP) is performed to:","options":["Decompress the chest","Improve the glottic view during intubation","Clear secretions","Stabilize the cervical spine"],"correct":1,"rationale":"ELM applies backward, upward, rightward pressure on the larynx to bring the cords into view and improve first-pass success.","difficulty":"Medium"},{"id":"c04_q13","question":"A major hazard of ventilating too fast or with excessive volume is:","options":["Improved cardiac output","Gastric insufflation and decreased venous return","Hyperoxia of the brain","Lower aspiration risk"],"correct":1,"rationale":"Over-aggressive ventilation distends the stomach (aspiration risk) and raises intrathoracic pressure, reducing venous return and cardiac output.","difficulty":"Hard"},{"id":"c04_q14","question":"Rapid sequence intubation (RSI) differs from rapid sequence airway (RSA) in that RSA:","options":["Uses no medications","Places a supraglottic device instead of an ET tube","Is only for pediatrics","Requires a surgical airway"],"correct":1,"rationale":"RSA uses the same sedation/paralysis approach but places a supraglottic (BIAD) airway rather than an endotracheal tube.","difficulty":"Hard"},{"id":"c04_q15","question":"Adequate tidal volume during BVM ventilation is best confirmed by:","options":["Squeezing the bag faster","Visible, symmetric chest rise","A loud bag sound","Patient color alone"],"correct":1,"rationale":"Visible, symmetric chest rise and fall confirms adequate tidal volume; rate and force of squeezing do not.","difficulty":"Easy"},{"id":"c04_q16","question":"An unrecognized esophageal intubation is dangerous primarily because:","options":["It causes mild discomfort","It is rapidly fatal from lack of ventilation/oxygenation","It improves oxygenation","It only delays care slightly"],"correct":1,"rationale":"An esophageal tube delivers no ventilation; if unrecognized it is rapidly fatal—hence mandatory capnographic confirmation.","difficulty":"Medium"},{"id":"c04_q17","question":"Routine hyperventilation of the head-injured patient is:","options":["Always recommended","Not recommended except for signs of cerebral herniation","Required for all trauma patients","Beneficial for shock"],"correct":1,"rationale":"Hyperventilation reduces cerebral perfusion; it is reserved only for patients showing signs of cerebral herniation.","difficulty":"Medium"},{"id":"c04_q18","question":"Before the first intubation attempt, the provider should always:","options":["Skip pre-oxygenation to save time","Have a backup airway plan and stocked airway kit","Remove the cervical collar permanently","Hyperventilate the patient"],"correct":1,"rationale":"Preparation—including a backup plan and a complete airway kit—is essential before any attempt.","difficulty":"Easy"},{"id":"c04_q19","question":"Pulse oximetry and capnography respectively measure:","options":["Both measure oxygenation","Oxygenation and ventilation","Ventilation and perfusion","Both measure ventilation"],"correct":1,"rationale":"Pulse oximetry reflects oxygenation (SpO2); capnography reflects ventilation (end-tidal CO2) and confirms tube placement.","difficulty":"Medium"},{"id":"c04_q20","question":"When repeated intubation attempts fail and the patient is hypoxic, the immediate priority is to:","options":["Keep attempting intubation","Ventilate with BVM or insert a BIAD","Withhold oxygen","Transport without ventilation"],"correct":1,"rationale":"Failed intubation in a hypoxic patient demands a return to effective oxygenation/ventilation via BVM or a rescue BIAD.","difficulty":"Medium"}]},"c05":{"chapter":"c05","questions":[{"id":"c05_q01","question":"A single suction attempt in an adult should generally not exceed:","options":["5 seconds","15 seconds","30 seconds","60 seconds"],"correct":1,"rationale":"Suctioning removes oxygen along with secretions; limit each attempt to about 15 seconds and reoxygenate between passes.","difficulty":"Easy"},{"id":"c05_q02","question":"When should suction be applied during airway suctioning?","options":["During insertion","Only while withdrawing the catheter","Continuously throughout","Never"],"correct":1,"rationale":"Insert the catheter without suction; apply suction only on withdrawal to avoid prolonged oxygen removal and mucosal trauma.","difficulty":"Easy"},{"id":"c05_q03","question":"An oropharyngeal airway is correctly sized from:","options":["Nostril to earlobe","Corner of the mouth to the earlobe/angle of jaw","Chin to sternum","Lip to lip"],"correct":1,"rationale":"The OPA is measured from the corner of the mouth to the earlobe or angle of the jaw.","difficulty":"Easy"},{"id":"c05_q04","question":"The chief advantage of two-rescuer BVM ventilation is:","options":["It needs less oxygen","A better mask seal and more effective ventilation","It is faster to set up","It avoids the need for adjuncts"],"correct":1,"rationale":"With one rescuer sealing the mask two-handed and another ventilating, the seal and tidal volume delivery improve markedly.","difficulty":"Easy"},{"id":"c05_q05","question":"A supraglottic airway device functions by:","options":["Passing through the cords under direct vision","Sealing over the glottic opening after blind insertion","Replacing the need for oxygen","Providing a surgical airway"],"correct":1,"rationale":"Supraglottic (BIAD) devices are inserted blindly and seal over the glottis, allowing ventilation without cord visualization.","difficulty":"Easy"},{"id":"c05_q06","question":"During trauma intubation, the cervical spine should be managed by:","options":["Hyperextension","Manual in-line stabilization","Full flexion","No precautions"],"correct":1,"rationale":"Manual in-line stabilization is maintained throughout intubation to protect a potential cervical injury.","difficulty":"Medium"},{"id":"c05_q07","question":"The most reliable confirmation of endotracheal tube placement is:","options":["Epigastric sounds","Waveform capnography","Pulse oximetry alone","Patient cough"],"correct":1,"rationale":"Waveform capnography is the standard for confirming and continuously monitoring tube placement.","difficulty":"Medium"},{"id":"c05_q08","question":"Nasotracheal intubation is contraindicated when there is suspicion of:","options":["A femur fracture","A basilar skull fracture","A clavicle fracture","Hypovolemia"],"correct":1,"rationale":"Nasotracheal intubation (and NPAs) risk intracranial passage with basilar skull fracture and require spontaneous breathing.","difficulty":"Medium"},{"id":"c05_q09","question":"Why is preoxygenation performed before intubation?","options":["To slow the heart rate","To build an oxygen reserve and prolong safe apnea time","To paralyze the patient","To reduce secretions"],"correct":1,"rationale":"Preoxygenation fills the functional reserve with oxygen, delaying desaturation during the apneic attempt.","difficulty":"Medium"},{"id":"c05_q10","question":"Before administering a paralytic for RSI, the provider must ensure:","options":["The patient is fully alert","The ability to ventilate and a rescue airway plan are in place","No monitoring is needed","The collar is removed"],"correct":1,"rationale":"Paralysis removes the patient's own breathing; you must be able to ventilate and have a rescue airway and monitoring ready.","difficulty":"Hard"},{"id":"c05_q11","question":"External laryngeal manipulation (BURP) improves intubation by:","options":["Decompressing the stomach","Bringing the glottis into the laryngoscopic view","Sealing the mask","Suctioning the airway"],"correct":1,"rationale":"BURP/ELM applies backward-upward-rightward pressure on the larynx to optimize the view of the cords.","difficulty":"Medium"},{"id":"c05_q12","question":"A pulse oximeter reading of 90% on a trauma patient indicates:","options":["Normal oxygenation, no action","Hypoxemia requiring supplemental oxygen and reassessment","A faulty device only","The need to stop oxygen"],"correct":1,"rationale":"An SpO2 of 90% is hypoxemic; provide oxygen, reassess ventilation, and look for a treatable cause.","difficulty":"Easy"},{"id":"c05_q13","question":"A frequent cause of ineffective bag-valve-mask ventilation is:","options":["Excess oxygen","A poor mask seal","Too slow a rate","Using an adjunct"],"correct":1,"rationale":"Poor mask seal is the most common reason for inadequate BVM ventilation; correct with two-handed technique and adjuncts.","difficulty":"Easy"},{"id":"c05_q14","question":"After moving an intubated patient from the ground to the stretcher, you should:","options":["Assume the tube is fine","Reconfirm tube placement with capnography and breath sounds","Remove the tube","Stop ventilating"],"correct":1,"rationale":"Tube position must be reconfirmed after every move because movement is a common cause of dislodgement.","difficulty":"Medium"},{"id":"c05_q15","question":"A rigid (Yankauer) suction tip is most useful for:","options":["Deep tracheal suctioning","Clearing thick blood and debris from the mouth","Ventilation","Oxygen delivery"],"correct":1,"rationale":"The rigid Yankauer is designed to rapidly clear large volumes of blood, vomitus, and debris from the oropharynx.","difficulty":"Easy"},{"id":"c05_q16","question":"If a paralyzed patient cannot be intubated or ventilated by BVM or BIAD, the next step is:","options":["Keep trying to intubate","Surgical airway per protocol","Withhold oxygen","Transport without an airway"],"correct":1,"rationale":"A 'cannot intubate, cannot ventilate' situation requires a surgical airway as the final rescue, per protocol.","difficulty":"Hard"},{"id":"c05_q17","question":"The OPA is appropriate only when the patient:","options":["Is awake and talking","Has no gag reflex","Has a basilar skull fracture","Is breathing normally"],"correct":1,"rationale":"An OPA can trigger gagging/vomiting; it is used only in patients without a gag reflex.","difficulty":"Easy"},{"id":"c05_q18","question":"Apneic oxygenation during intubation is achieved by:","options":["Removing all oxygen","Leaving a nasal cannula running during the attempt","Hyperventilating with the BVM","Suctioning continuously"],"correct":1,"rationale":"Oxygen delivered by nasal cannula during laryngoscopy maintains oxygenation and extends safe apnea time.","difficulty":"Medium"},{"id":"c05_q19","question":"Effective trauma airway management most depends on:","options":["Working alone quickly","Clear team communication and preparation","Skipping confirmation","Using force"],"correct":1,"rationale":"ITLS stresses that clear communication, role assignment, and preparation drive successful airway outcomes.","difficulty":"Easy"},{"id":"c05_q20","question":"The mnemonic SOAP-ME is used to:","options":["Assess shock","Prepare equipment for intubation","Score the GCS","Grade burns"],"correct":1,"rationale":"SOAP-ME (Suction, Oxygen, Airways, Pharmacology, Monitoring, Equipment) is an intubation preparation checklist.","difficulty":"Medium"}]},"c06":{"chapter":"c06","questions":[{"id":"c06_q01","question":"Which of the following is an immediately life-threatening thoracic injury?","options":["Simple rib fracture","Tension pneumothorax","Clavicle fracture","Sternal bruise"],"correct":1,"rationale":"Tension pneumothorax is one of the six immediate life threats (ATOM-FC) that must be identified in the Primary Survey.","difficulty":"Easy"},{"id":"c06_q02","question":"A patient has absent breath sounds and hyperresonance on the right, distended neck veins, and hypotension. The diagnosis is:","options":["Massive hemothorax","Tension pneumothorax","Cardiac tamponade","Flail chest"],"correct":1,"rationale":"Hyperresonance with absent breath sounds, JVD, and hypotension is the classic tension pneumothorax picture.","difficulty":"Medium"},{"id":"c06_q03","question":"The definitive field treatment for tension pneumothorax is:","options":["Occlusive dressing","Needle chest decompression","IV fluids","Pericardiocentesis"],"correct":1,"rationale":"Tension pneumothorax requires immediate needle decompression to release trapped pleural air.","difficulty":"Easy"},{"id":"c06_q04","question":"An open (sucking) chest wound is best managed with:","options":["A fully sealed airtight dressing","A vented occlusive dressing with monitoring for tension pneumothorax","Needle decompression","No dressing at all"],"correct":1,"rationale":"A vented occlusive dressing lets trapped air escape, reducing the risk of converting to a tension pneumothorax.","difficulty":"Medium"},{"id":"c06_q05","question":"Why is a completely airtight dressing on an open chest wound risky?","options":["It causes infection","It can convert an open pneumothorax into a tension pneumothorax","It is uncomfortable","It blocks oxygen"],"correct":1,"rationale":"Sealing all sides can trap accumulating air in the pleural space, producing a tension pneumothorax.","difficulty":"Medium"},{"id":"c06_q06","question":"A trauma patient has dullness to percussion, diminished breath sounds, flat neck veins, and shock. This best fits:","options":["Tension pneumothorax","Massive hemothorax","Cardiac tamponade","Pneumonia"],"correct":1,"rationale":"Dullness, diminished sounds, FLAT neck veins, and hypovolemic shock indicate massive hemothorax.","difficulty":"Medium"},{"id":"c06_q07","question":"Massive hemothorax causes shock primarily through:","options":["Air trapping","Blood loss into the chest (hypovolemia)","Pericardial compression","Spinal cord injury"],"correct":1,"rationale":"Large-volume blood loss into the pleural cavity produces hypovolemic shock plus respiratory compromise.","difficulty":"Easy"},{"id":"c06_q08","question":"Flail chest is defined as:","options":["A single rib fracture","Two or more adjacent ribs each broken in two or more places","A fractured sternum only","A collapsed lung"],"correct":1,"rationale":"Flail chest requires two or more adjacent ribs each fractured in two or more places, creating a free-moving segment.","difficulty":"Easy"},{"id":"c06_q09","question":"The greatest threat to life in flail chest is:","options":["The paradoxical wall motion","The underlying pulmonary contusion and hypoventilation","Skin bruising","Rib pain"],"correct":1,"rationale":"The associated pulmonary contusion and impaired ventilation cause the morbidity, not the paradoxical motion itself.","difficulty":"Medium"},{"id":"c06_q10","question":"Beck's triad consists of:","options":["Tachycardia, fever, rash","Hypotension, distended neck veins, muffled heart tones","Bradycardia, hypertension, irregular breathing","Cyanosis, stridor, drooling"],"correct":1,"rationale":"Beck's triad—hypotension, JVD, and muffled heart tones—indicates pericardial tamponade.","difficulty":"Easy"},{"id":"c06_q11","question":"Definitive treatment of cardiac tamponade requires:","options":["Needle chest decompression","Pericardiocentesis or surgery—rapid transport","Occlusive dressing","Traction splinting"],"correct":1,"rationale":"Tamponade needs pericardiocentesis or surgical decompression; the field priority is rapid transport with supportive care.","difficulty":"Medium"},{"id":"c06_q12","question":"Which finding helps distinguish tension pneumothorax from massive hemothorax?","options":["Both have flat neck veins","Tension pneumothorax has distended neck veins and hyperresonance; hemothorax has flat veins and dullness","Both are dull to percussion","Neither causes shock"],"correct":1,"rationale":"JVD + hyperresonance points to tension pneumothorax; flat veins + dullness points to hemothorax.","difficulty":"Hard"},{"id":"c06_q13","question":"Distended neck veins with shock should make you suspect:","options":["Hypovolemia","An obstructive cause such as tension pneumothorax or tamponade","Dehydration","Simple fainting"],"correct":1,"rationale":"JVD with shock indicates obstruction to venous return—tension pneumothorax or cardiac tamponade—rather than hypovolemia.","difficulty":"Medium"},{"id":"c06_q14","question":"Indications for emergency chest decompression include signs of tension pneumothorax PLUS more than one of:","options":["Mild chest pain only","Respiratory distress/cyanosis, loss of radial pulse, or decreasing LOC","A normal blood pressure","A simple rib fracture"],"correct":1,"rationale":"ITLS requires tension-pneumothorax signs plus more than one of: respiratory distress/cyanosis, lost radial pulse (shock), or decreasing/loss of consciousness.","difficulty":"Hard"},{"id":"c06_q15","question":"After significant blunt chest trauma, you should apply early:","options":["A traction splint","Cardiac monitoring to detect dysrhythmias","A tourniquet","A cervical collar only"],"correct":1,"rationale":"Blunt cardiac injury can cause dysrhythmias; early cardiac monitoring helps detect and manage them.","difficulty":"Easy"},{"id":"c06_q16","question":"Aggressive crystalloid resuscitation in pulmonary contusion is discouraged because it:","options":["Raises blood pressure too slowly","Worsens oxygenation of the contused lung","Has no effect","Prevents shock entirely"],"correct":1,"rationale":"Excess fluid worsens the contused lung's gas exchange; controlled resuscitation is preferred.","difficulty":"Hard"},{"id":"c06_q17","question":"A patient with a penetrating chest wound suddenly develops worsening dyspnea, rising JVD, and falling pressure after you applied a chest seal. You should:","options":["Add more tape to fully seal it","Lift/burp the dressing or decompress for a possible tension pneumothorax","Remove the dressing and leave the wound open","Do nothing"],"correct":1,"rationale":"These signs suggest a tension pneumothorax developing under the seal; burp the dressing and prepare to decompress.","difficulty":"Hard"},{"id":"c06_q18","question":"The most common general symptoms of serious thoracic trauma are:","options":["Abdominal pain and vomiting","Chest pain, dyspnea, and anxiety/impending doom","Headache and dizziness","Leg numbness"],"correct":1,"rationale":"Chest pain, shortness of breath, and a sense of impending doom are hallmark symptoms of significant chest injury.","difficulty":"Easy"},{"id":"c06_q19","question":"Tracheal deviation in tension pneumothorax is best described as:","options":["An early, reliable sign","A late sign that should not delay treatment","Diagnostic of hemothorax","Always absent"],"correct":1,"rationale":"Tracheal deviation is a late finding; decompression should not be delayed waiting for it.","difficulty":"Medium"},{"id":"c06_q20","question":"Which injury is treated by decompression rather than a dressing or fluids?","options":["Open pneumothorax","Tension pneumothorax","Massive hemothorax","Cardiac tamponade"],"correct":1,"rationale":"Tension pneumothorax is relieved by needle decompression; the others require dressings, transport, or surgical care.","difficulty":"Easy"}]},"c07":{"chapter":"c07","questions":[{"id":"c07_q01","question":"Needle chest decompression converts a tension pneumothorax into:","options":["A hemothorax","A simple pneumothorax","Cardiac tamponade","A flail chest"],"correct":1,"rationale":"Releasing trapped air relieves the tension and leaves a simple pneumothorax, restoring venous return.","difficulty":"Easy"},{"id":"c07_q02","question":"The anterior decompression landmark is the:","options":["5th ICS, midaxillary line","2nd or 3rd ICS, midclavicular line","4th ICS, sternal border","Xiphoid process"],"correct":1,"rationale":"The traditional anterior site is the 2nd–3rd intercostal space at the midclavicular line.","difficulty":"Easy"},{"id":"c07_q03","question":"The lateral decompression landmark is the:","options":["2nd ICS midclavicular line","4th or 5th ICS at the anterior axillary line","Subxiphoid area","Suprasternal notch"],"correct":1,"rationale":"The lateral approach uses the 4th–5th intercostal space at the anterior axillary line.","difficulty":"Easy"},{"id":"c07_q04","question":"The needle is inserted just over the TOP of the rib to avoid:","options":["The lung","The intercostal neurovascular bundle on the rib's underside","The sternum","The diaphragm"],"correct":1,"rationale":"The nerve, artery, and vein run along the inferior margin of each rib; entering over the top avoids them.","difficulty":"Medium"},{"id":"c07_q05","question":"A recommended anterior decompression catheter is approximately:","options":["22 gauge, 1 cm","14 gauge, 6–9 cm long","18 gauge, 2 cm","16 gauge, 1.5 cm"],"correct":1,"rationale":"A large-bore (about 14 gauge/8 French) catheter 6–9 cm long is recommended to reliably reach the pleural space.","difficulty":"Medium"},{"id":"c07_q06","question":"Which is an indication for emergency chest decompression?","options":["Mild rib pain","Tension pneumothorax signs plus loss of radial pulse","Stable vitals with a small simple pneumothorax","An isolated clavicle fracture"],"correct":1,"rationale":"Decompress with tension signs plus more than one of distress/cyanosis, lost radial pulse, or decreasing LOC.","difficulty":"Medium"},{"id":"c07_q07","question":"A common cause of failed anterior needle decompression is:","options":["Too long a catheter","A catheter too short to reach the pleural space","Using oxygen","Inserting over the rib"],"correct":1,"rationale":"Studies show many standard catheters are too short for the anterior chest wall, causing failure.","difficulty":"Medium"},{"id":"c07_q08","question":"A key advantage of the lateral approach in tactical care is:","options":["It requires removing body armor","It can be done without removing body armor","It treats hemothorax","It is the only sterile option"],"correct":1,"rationale":"The lateral site allows decompression without removing body armor and may more reliably reach the pleura.","difficulty":"Easy"},{"id":"c07_q09","question":"Successful decompression is suggested by:","options":["No change in the patient","An audible rush of air and clinical improvement","Increasing JVD","Loss of the radial pulse"],"correct":1,"rationale":"A rush of air and improvement (better breathing, returning pulse, improved LOC) indicate success.","difficulty":"Easy"},{"id":"c07_q10","question":"Needle decompression will NOT help which condition?","options":["Tension pneumothorax","Massive hemothorax","Simple pneumothorax under tension","Air trapped in the pleural space"],"correct":1,"rationale":"Decompression releases air, not blood; a hemothorax requires shock care and surgical management.","difficulty":"Medium"},{"id":"c07_q11","question":"After decompression you should:","options":["Remove the catheter immediately","Secure the catheter and monitor for re-accumulation","Stop reassessing the patient","Apply a traction splint"],"correct":1,"rationale":"Decompression is temporary; secure the catheter, reassess frequently, and repeat if tension recurs.","difficulty":"Easy"},{"id":"c07_q12","question":"Definitive treatment of a tension pneumothorax is:","options":["A second needle","A chest tube (tube thoracostomy) at the hospital","IV fluids","A chest seal"],"correct":1,"rationale":"Needle decompression is a bridge; the chest tube provides definitive drainage.","difficulty":"Easy"},{"id":"c07_q13","question":"Prehospital ultrasound can assist by:","options":["Replacing decompression","Confirming a pneumothorax before the procedure","Treating hemorrhage","Measuring blood pressure"],"correct":1,"rationale":"Ultrasound improves diagnostic accuracy by confirming the pneumothorax before needle placement.","difficulty":"Medium"},{"id":"c07_q14","question":"Are decompression indications different in tactical versus civilian environments?","options":["Yes, tactical needs fewer signs","No, the indications are the same","Yes, civilian needs more signs","Decompression is tactical-only"],"correct":1,"rationale":"The indications for needle decompression are identical regardless of the care environment.","difficulty":"Easy"},{"id":"c07_q15","question":"A complication of placing the needle below the rib margin is:","options":["Faster relief","Laceration of the intercostal nerve, artery, or vein","Better catheter seating","No risk at all"],"correct":1,"rationale":"The neurovascular bundle lies under the rib; entry below the rib can lacerate these structures.","difficulty":"Medium"},{"id":"c07_q16","question":"The catheter direction during insertion should be:","options":["Angled toward the heart","Perpendicular to the chest wall at the landmark","Toward the abdomen","Parallel to the skin"],"correct":1,"rationale":"Insert perpendicular to the chest wall at the chosen interspace, over the top of the rib, into the pleural space.","difficulty":"Medium"},{"id":"c07_q17","question":"A theoretical benefit of the 3rd intercostal lateral site is:","options":["Closer to the heart","Less risk of injuring the liver or spleen","No need for a catheter","Guaranteed success"],"correct":1,"rationale":"A higher lateral site reduces the risk of solid-organ injury and may be more quickly accessible in combat.","difficulty":"Hard"},{"id":"c07_q18","question":"If the patient re-deteriorates after an initially successful decompression, you should:","options":["Assume the device failed permanently and stop","Reassess and repeat decompression for re-accumulation","Give insulin","Apply a cervical collar"],"correct":1,"rationale":"A re-tensioning pneumothorax (kinked/clotted catheter) requires reassessment and repeat decompression.","difficulty":"Medium"}]},"c08":{"chapter":"c08","questions":[{"id":"c08_q01","question":"Shock is best defined as:","options":["Low blood pressure","Inadequate tissue perfusion","A fast heart rate","Loss of consciousness"],"correct":1,"rationale":"Shock is inadequate tissue perfusion—cells fail to receive enough oxygen—of which hypotension is only a late manifestation.","difficulty":"Easy"},{"id":"c08_q02","question":"Which is NOT one of the four components required for normal perfusion?","options":["An intact pump","Adequate blood volume","Intact blood vessels","Normal body temperature"],"correct":3,"rationale":"The four components are pump, volume, vessels (pipes), and oxygen-carrying capacity; temperature is important but not one of the four.","difficulty":"Medium"},{"id":"c08_q03","question":"An early sign of compensated shock is:","options":["Hypotension","Tachycardia with cool, pale skin","Bradycardia with warm skin","Bounding pulses"],"correct":1,"rationale":"Early shock shows tachycardia, cool/pale skin, anxiety, delayed cap refill, and narrowing pulse pressure—before pressure falls.","difficulty":"Easy"},{"id":"c08_q04","question":"Falling blood pressure in shock is considered:","options":["An early sign","A late sign","Always neurogenic","Insignificant"],"correct":1,"rationale":"Hypotension is late; significant blood volume is often already lost by the time pressure drops.","difficulty":"Easy"},{"id":"c08_q05","question":"The most common type of shock in trauma is:","options":["Cardiogenic","Hemorrhagic (hypovolemic)","Neurogenic","Septic"],"correct":1,"rationale":"Blood loss makes hemorrhagic shock the most common shock state in trauma.","difficulty":"Easy"},{"id":"c08_q06","question":"A spinal-injury patient is hypotensive with a heart rate of 56 and warm, dry skin. This suggests:","options":["Hemorrhagic shock","Neurogenic shock","Tension pneumothorax","Cardiac tamponade"],"correct":1,"rationale":"Hypotension with bradycardia and warm, dry skin from loss of sympathetic tone is classic neurogenic shock.","difficulty":"Medium"},{"id":"c08_q07","question":"Distended neck veins in a hypotensive trauma patient point to:","options":["Hypovolemia","An obstructive cause (tension pneumothorax or tamponade)","Dehydration","Neurogenic shock"],"correct":1,"rationale":"JVD with shock indicates obstruction to venous return/cardiac filling rather than volume loss.","difficulty":"Medium"},{"id":"c08_q08","question":"The first-line method to control life-threatening extremity hemorrhage when direct pressure fails is:","options":["IV fluids","A tourniquet","Elevation only","A cold pack"],"correct":1,"rationale":"A tourniquet rapidly controls extremity hemorrhage that direct pressure cannot.","difficulty":"Easy"},{"id":"c08_q09","question":"Hemostatic dressings are most appropriate for:","options":["Minor abrasions","Junctional or deep wounds where a tourniquet cannot be applied","Closed fractures","Stable patients with no bleeding"],"correct":1,"rationale":"Hemostatic agents are packed into junctional/deep wounds (e.g., groin, axilla) not amenable to tourniquets.","difficulty":"Medium"},{"id":"c08_q10","question":"For uncontrolled internal hemorrhage, the most life-saving field action is:","options":["Large-volume crystalloid infusion","Rapid transport to surgical care","Applying a tourniquet","Withholding all treatment"],"correct":1,"rationale":"Internal bleeding requires surgical control; rapid transport with supportive care is the priority.","difficulty":"Medium"},{"id":"c08_q11","question":"Permissive (controlled) hypotension aims to:","options":["Normalize blood pressure quickly","Maintain minimal adequate perfusion without dislodging clots","Maximize fluid volume","Raise pressure above normal"],"correct":1,"rationale":"Targeting a palpable radial pulse / modest systolic pressure preserves perfusion while avoiding clot disruption and dilution.","difficulty":"Hard"},{"id":"c08_q12","question":"A harm of over-aggressive crystalloid resuscitation in active hemorrhage is:","options":["Improved clotting","Clot disruption and dilution of clotting factors","Increased oxygen-carrying capacity","Reduced bleeding"],"correct":1,"rationale":"Excess fluids raise pressure enough to pop clots and dilute clotting factors and red cells, worsening hemorrhage.","difficulty":"Hard"},{"id":"c08_q13","question":"Tranexamic acid (TXA) is most beneficial when given:","options":["After 6 hours","Early, ideally within 3 hours of injury","Only at the hospital after surgery","Never in trauma"],"correct":1,"rationale":"Evidence (e.g., CRASH-2) shows TXA reduces mortality when given early—within about 3 hours of injury.","difficulty":"Medium"},{"id":"c08_q14","question":"The lethal triad of trauma consists of:","options":["Hypoxia, hypotension, hyperglycemia","Hypothermia, acidosis, coagulopathy","Fever, tachycardia, anxiety","Hyperkalemia, hypocalcemia, anemia"],"correct":1,"rationale":"Hypothermia, acidosis, and coagulopathy reinforce one another and markedly increase mortality.","difficulty":"Medium"},{"id":"c08_q15","question":"Keeping a hemorrhaging trauma patient warm is important because hypothermia:","options":["Improves clotting","Impairs clotting and worsens the lethal triad","Has no effect","Raises blood pressure"],"correct":1,"rationale":"Hypothermia impairs the clotting cascade, contributing to coagulopathy and the lethal triad.","difficulty":"Easy"},{"id":"c08_q16","question":"In a head-injured patient, blood pressure should be:","options":["Allowed to fall to reduce bleeding","Maintained to preserve cerebral perfusion","Ignored","Lowered with medication"],"correct":1,"rationale":"Hypotension worsens secondary brain injury; maintain adequate pressure for cerebral perfusion.","difficulty":"Medium"},{"id":"c08_q17","question":"A narrowing pulse pressure in early shock reflects:","options":["Falling diastolic pressure","Rising diastolic pressure from compensatory vasoconstriction","Bradycardia","Improved perfusion"],"correct":1,"rationale":"Compensatory vasoconstriction raises diastolic pressure, narrowing the pulse pressure as an early warning.","difficulty":"Hard"},{"id":"c08_q18","question":"Why should hypotension in a spinal-injured patient not be assumed neurogenic?","options":["Neurogenic shock never occurs","Concurrent hemorrhage is common and must be excluded first","Blood pressure is unimportant","Spinal injuries do not cause shock"],"correct":1,"rationale":"Neurogenic shock is a diagnosis of exclusion; rule out and treat hemorrhage before attributing shock to neurogenic causes.","difficulty":"Hard"},{"id":"c08_q19","question":"Cardiogenic shock results from:","options":["Loss of blood volume","Failure of the heart as a pump","Spinal cord injury","Vasodilation from sepsis"],"correct":1,"rationale":"Cardiogenic shock is pump failure (e.g., from cardiac contusion or pre-existing cardiac disease).","difficulty":"Medium"},{"id":"c08_q20","question":"The correct sequence for controlling severe external bleeding is:","options":["Tourniquet, then nothing","Direct pressure → tourniquet → hemostatic dressing","Hemostatic dressing only","Elevation → ice → rest"],"correct":1,"rationale":"Escalate hemorrhage control: direct pressure first, tourniquet for uncontrolled extremity bleeding, hemostatic agents for junctional/deep wounds.","difficulty":"Easy"}]},"c09":{"chapter":"c09","questions":[{"id":"c09_q01","question":"In a critical trauma patient, IV access should generally be obtained:","options":["On scene before moving","En route to the hospital","Only at the hospital","Never"],"correct":1,"rationale":"Access should not delay transport; start IVs en route whenever possible.","difficulty":"Easy"},{"id":"c09_q02","question":"The external jugular vein runs from the angle of the jaw to:","options":["The sternal notch","The junction of the medial and middle third of the clavicle","The mastoid process","The acromion"],"correct":1,"rationale":"The EJ courses to the junction of the medial and middle third of the clavicle, draining into the subclavian vein.","difficulty":"Medium"},{"id":"c09_q03","question":"To make the external jugular more prominent before cannulation, you should:","options":["Elevate the head of the bed","Press just above the clavicle","Apply a tourniquet to the arm","Have the patient cough"],"correct":1,"rationale":"Pressure just above the clavicle occludes outflow and distends the vein.","difficulty":"Medium"},{"id":"c09_q04","question":"The indication for EJ cannulation is:","options":["Any stable patient","A patient needing IV access with no suitable peripheral vein","Cardiac arrest only","Pediatric patients only"],"correct":1,"rationale":"EJ cannulation is used when no suitable peripheral vein is found in an adult or child needing access.","difficulty":"Easy"},{"id":"c09_q05","question":"Intraosseous infusion delivers fluids and drugs into the:","options":["Pleural space","Bone marrow cavity","Subcutaneous tissue","Peritoneum"],"correct":1,"rationale":"IO access uses the marrow cavity, which behaves as a non-collapsible vein with rapid central circulation.","difficulty":"Easy"},{"id":"c09_q06","question":"A common drill IO site is the:","options":["Distal radius","Proximal tibia","Iliac crest","Calcaneus"],"correct":1,"rationale":"The proximal tibia (medial flat surface below the tuberosity) is a standard drill IO site, along with the proximal humerus.","difficulty":"Easy"},{"id":"c09_q07","question":"A sternal IO device places the catheter in the:","options":["Xiphoid","Manubrium","Clavicle","Costal margin"],"correct":1,"rationale":"Sternal IO devices are placed in the manubrium of the sternum.","difficulty":"Medium"},{"id":"c09_q08","question":"Which finding confirms correct IO placement?","options":["The needle wobbles loosely","Free flow without soft-tissue swelling and ability to aspirate marrow","Immediate extravasation","Resistance to flushing with swelling"],"correct":1,"rationale":"A stable needle, marrow aspiration, and free flow without extravasation confirm correct placement.","difficulty":"Medium"},{"id":"c09_q09","question":"In a conscious patient, before flushing an IO you should consider giving:","options":["Epinephrine","Slow IO lidocaine for pain","A paralytic","Dextrose"],"correct":1,"rationale":"IO infusion is painful; slow IO lidocaine per protocol blunts the pain before the flush and fluids.","difficulty":"Medium"},{"id":"c09_q10","question":"Why should the IO be flushed briskly after insertion?","options":["To test the patient's pain","To open the marrow channel and establish free flow","To remove the needle","To cause extravasation"],"correct":1,"rationale":"A rapid flush opens the intramedullary channel so fluids and drugs can run freely.","difficulty":"Medium"},{"id":"c09_q11","question":"Which is a contraindication to IO placement in a given bone?","options":["A patient in shock","A fracture of that bone or a recent IO attempt in it","An unconscious patient","Pediatric age"],"correct":1,"rationale":"A fractured bone or one with a recent prior IO attempt will leak (extravasate) and should be avoided.","difficulty":"Medium"},{"id":"c09_q12","question":"A length-based resuscitation tape estimates a child's:","options":["Age only","Weight, with corresponding doses and equipment sizes","Blood type","Temperature"],"correct":1,"rationale":"The tape estimates weight from length and provides matched drug doses, fluid volumes, and equipment sizes.","difficulty":"Easy"},{"id":"c09_q13","question":"The child is measured with a length-based tape from:","options":["Shoulder to hip","Head to heel","Wrist to elbow","Knee to ankle"],"correct":1,"rationale":"Measure head to heel and read the corresponding color zone for weight and reference values.","difficulty":"Easy"},{"id":"c09_q14","question":"Why is the marrow cavity reliable for access in shock?","options":["It collapses like peripheral veins","It is a non-collapsible space that stays patent even in profound shock","It has no blood supply","It is only present in children"],"correct":1,"rationale":"The bony marrow network stays open when peripheral veins collapse, making IO dependable in shock.","difficulty":"Medium"},{"id":"c09_q15","question":"A complication of external jugular cannulation is:","options":["Compartment syndrome","Air embolism or infiltration","Pelvic fracture","Spinal cord injury"],"correct":1,"rationale":"EJ cannulation risks air embolism, infiltration, and hematoma; secure the line and monitor the site.","difficulty":"Medium"},{"id":"c09_q16","question":"Which patient is the best candidate for immediate IO access?","options":["A stable patient with good arm veins","A critically injured shock patient with collapsed peripheral veins","A patient refusing care","A patient with a minor laceration"],"correct":1,"rationale":"IO is ideal when rapid access is needed and peripheral veins are collapsed or inaccessible.","difficulty":"Easy"},{"id":"c09_q17","question":"Spending several minutes on scene to obtain access in a load-and-go patient is:","options":["Recommended","A common mistake that delays definitive care","Required by protocol","Harmless"],"correct":1,"rationale":"Delaying transport for access is a common error; obtain access en route for critical patients.","difficulty":"Easy"},{"id":"c09_q18","question":"If fluid infused through an IO causes soft-tissue swelling, you should suspect:","options":["Correct placement","Extravasation/infiltration from a misplaced or dislodged needle","Air embolism","Normal function"],"correct":1,"rationale":"Soft-tissue swelling indicates the fluid is leaking outside the marrow—remove and choose another site.","difficulty":"Medium"}]},"c10":{"chapter":"c10","questions":[{"id":"c10_q01","question":"The Monro-Kellie Doctrine explains why:","options":["The skull can expand to accommodate swelling","A rise in one intracranial component must be offset, or ICP rises sharply","CSF is unimportant","Brain injury is always reversible"],"correct":1,"rationale":"Because the skull is rigid, increases in brain, blood, or CSF must be compensated; once compensation fails, ICP climbs rapidly.","difficulty":"Medium"},{"id":"c10_q02","question":"Primary brain injury is:","options":["Preventable in the field","The damage occurring at the moment of impact","Caused by hypoxia after the event","Always survivable"],"correct":1,"rationale":"Primary injury happens at impact and cannot be reversed prehospitally; the focus is preventing secondary injury.","difficulty":"Easy"},{"id":"c10_q03","question":"Which is a cause of secondary brain injury?","options":["The initial contusion","Hypoxia and hypotension","The mechanism of impact","The skull fracture itself"],"correct":1,"rationale":"Secondary injury results from hypoxia, hypotension, abnormal glucose/CO2, raised ICP, and edema—all targets of prehospital care.","difficulty":"Easy"},{"id":"c10_q04","question":"Cerebral perfusion pressure (CPP) equals:","options":["MAP + ICP","MAP − ICP","ICP − MAP","Systolic − diastolic"],"correct":1,"rationale":"CPP = MAP − ICP; as ICP rises or MAP falls, perfusion to the brain decreases.","difficulty":"Medium"},{"id":"c10_q05","question":"The two greatest threats to the injured brain are:","options":["Fever and pain","Hypoxia and hypotension","Tachycardia and anxiety","Hyperglycemia and nausea"],"correct":1,"rationale":"Hypoxia and hypotension are the leading preventable causes of secondary brain injury.","difficulty":"Easy"},{"id":"c10_q06","question":"Cushing's reflex consists of:","options":["Hypotension, tachycardia, rapid breathing","Hypertension, bradycardia, irregular respirations","Fever, rash, stiff neck","Hyperglycemia, sweating, tremor"],"correct":1,"rationale":"Cushing's triad (hypertension, bradycardia, irregular respirations) is a late sign of raised ICP.","difficulty":"Medium"},{"id":"c10_q07","question":"A GCS of 8 or less indicates:","options":["A minor injury","Severe TBI and inability to protect the airway","Normal neurologic status","Spinal shock"],"correct":1,"rationale":"GCS ≤ 8 defines severe TBI; these patients cannot protect their airway and need it secured.","difficulty":"Easy"},{"id":"c10_q08","question":"Routine hyperventilation of a head-injured patient is harmful because it:","options":["Raises blood pressure","Causes cerebral vasoconstriction and lowers CPP","Improves oxygenation","Reduces ICP safely in all cases"],"correct":1,"rationale":"Hyperventilation constricts cerebral vessels, reducing perfusion and worsening ischemia—avoid unless herniating.","difficulty":"Hard"},{"id":"c10_q09","question":"Hyperventilation is appropriate ONLY when the patient shows:","options":["Any head injury","Signs of cerebral herniation","A normal GCS","Mild headache"],"correct":1,"rationale":"Controlled mild hyperventilation (ETCO2 ~30–35) is reserved for active herniation signs.","difficulty":"Medium"},{"id":"c10_q10","question":"Signs of cerebral herniation include:","options":["Improving GCS and equal pupils","Decreasing GCS, a dilated/fixed pupil, and posturing","Warm dry skin and bradycardia only","A normal exam"],"correct":1,"rationale":"Herniation presents with declining GCS, a blown pupil, abnormal posturing, and Cushing's signs.","difficulty":"Medium"},{"id":"c10_q11","question":"For a head-injured patient WITHOUT herniation, ventilate to an ETCO2 of:","options":["20–25 mmHg","35–45 mmHg","55–60 mmHg","It does not matter"],"correct":1,"rationale":"Maintain normal ventilation (ETCO2 ~35–45) and avoid both hyper- and hypoventilation.","difficulty":"Medium"},{"id":"c10_q12","question":"Maintaining systolic blood pressure around 110–120 mmHg in TBI is intended to:","options":["Reduce bleeding","Preserve cerebral perfusion and avoid secondary injury","Lower ICP directly","Slow the heart rate"],"correct":1,"rationale":"Avoiding hypotension preserves CPP; a single hypotensive episode markedly worsens TBI outcome.","difficulty":"Medium"},{"id":"c10_q13","question":"Coup injury refers to brain injury:","options":["On the opposite side of impact","At the site of impact","In the spinal cord","Only in children"],"correct":1,"rationale":"Coup injury is at the impact site; contrecoup is on the opposite side from rebound.","difficulty":"Easy"},{"id":"c10_q14","question":"Raccoon eyes and Battle's sign indicate:","options":["A cervical fracture","A basilar skull fracture","Increased glucose","Neurogenic shock"],"correct":1,"rationale":"Periorbital and mastoid bruising with CSF leakage suggest a basilar skull fracture.","difficulty":"Medium"},{"id":"c10_q15","question":"Blood glucose should be checked in head injury because:","options":["It is irrelevant","Both hypo- and hyperglycemia worsen brain injury","Only hyperglycemia matters","Glucose causes herniation"],"correct":1,"rationale":"Abnormal glucose in either direction worsens secondary injury; measure and correct it.","difficulty":"Easy"},{"id":"c10_q16","question":"Hypotension in a patient with an isolated head injury should prompt you to:","options":["Attribute it to the brain injury","Search for another source of hemorrhage","Ignore it","Hyperventilate"],"correct":1,"rationale":"Isolated brain injury rarely causes hypotension except terminally; suspect bleeding elsewhere.","difficulty":"Hard"},{"id":"c10_q17","question":"Elevating the head ~30 degrees (if not contraindicated) helps by:","options":["Raising ICP","Promoting cerebral venous drainage to lower ICP","Increasing bleeding","Lowering oxygenation"],"correct":1,"rationale":"Modest head elevation with a midline neck position improves venous outflow and can lower ICP.","difficulty":"Medium"},{"id":"c10_q18","question":"Target SpO2 for the head-injured patient is at least:","options":["85%","90%","94%","It does not matter"],"correct":2,"rationale":"Keep SpO2 ≥ 94% to avoid hypoxic secondary injury.","difficulty":"Easy"},{"id":"c10_q19","question":"A newly dilated pupil with a dropping GCS during transport indicates:","options":["Improvement","Possible expanding lesion/herniation requiring immediate action","Eye injury only","Normal variation"],"correct":1,"rationale":"These are ominous signs of an expanding intracranial process or herniation—reassess and intervene.","difficulty":"Medium"},{"id":"c10_q20","question":"The single most important prehospital goal in TBI is to:","options":["Reverse the primary injury","Prevent secondary brain injury","Apply a traction splint","Lower the blood pressure"],"correct":1,"rationale":"Primary injury is fixed at impact; prehospital care focuses on preventing secondary injury (hypoxia, hypotension, etc.).","difficulty":"Easy"}]},"c11":{"chapter":"c11","questions":[{"id":"c11_q01","question":"The primary goal of spinal motion restriction is to:","options":["Treat the primary cord injury","Prevent secondary spinal-cord injury from movement","Reduce a fracture","Speed transport in all cases"],"correct":1,"rationale":"SMR limits movement of a potentially unstable spine to prevent secondary cord injury; primary injury cannot be reversed.","difficulty":"Easy"},{"id":"c11_q02","question":"Which spinal region is most mobile and most often injured?","options":["Thoracic","Lumbar","Cervical","Sacral"],"correct":2,"rationale":"The cervical spine is the most mobile and most vulnerable region.","difficulty":"Easy"},{"id":"c11_q03","question":"Which finding indicates a patient needs SMR?","options":["Alert with no midline tenderness","Midline cervical tenderness or a neurologic deficit","No distracting injury","Sober and reliable exam"],"correct":1,"rationale":"Midline tenderness/deformity or any neurologic deficit (with a concerning mechanism) indicates SMR.","difficulty":"Easy"},{"id":"c11_q04","question":"A reliable patient who may NOT require SMR is one who is:","options":["Intoxicated with neck pain","Alert, sober, with no midline tenderness, no neuro deficit, and no distracting injury","Has numbness in the arms","Has an altered mental status"],"correct":1,"rationale":"Selective criteria allow withholding SMR when the patient is reliable and has no concerning findings.","difficulty":"Medium"},{"id":"c11_q05","question":"Routine spinal immobilization is generally NOT recommended for:","options":["A rollover MVC with neck pain","Isolated penetrating trauma without neurologic deficit","A fall with leg weakness","An unconscious trauma patient"],"correct":1,"rationale":"Immobilizing isolated penetrating trauma without deficit delays transport and is associated with higher mortality.","difficulty":"Hard"},{"id":"c11_q06","question":"Neurogenic shock typically presents with:","options":["Tachycardia and cool, clammy skin","Hypotension with normal/slow heart rate and warm, dry skin","Hypertension and bradycardia","Fever and rash"],"correct":1,"rationale":"Loss of sympathetic tone causes hypotension with a normal/slow pulse and warm, dry skin below the lesion.","difficulty":"Medium"},{"id":"c11_q07","question":"Hemorrhagic shock is distinguished from neurogenic shock by:","options":["Warm dry skin","Tachycardia with cool, pale, clammy skin","Bradycardia","Pink, warm skin"],"correct":1,"rationale":"Hemorrhagic shock shows tachycardia and cool, clammy skin, unlike the warm, dry skin of neurogenic shock.","difficulty":"Medium"},{"id":"c11_q08","question":"In a hypotensive spine-injured patient, you should first assume:","options":["Neurogenic shock","Hemorrhage until proven otherwise","Anxiety","Dehydration"],"correct":1,"rationale":"Neurogenic shock is a diagnosis of exclusion; treat for hemorrhage and rule it out first.","difficulty":"Medium"},{"id":"c11_q09","question":"Emergency Rescue is performed when:","options":["The patient is stable and the scene is safe","The scene is immediately dangerous (fire, drowning) and life takes priority over spine","A short device is available","The patient refuses care"],"correct":1,"rationale":"Emergency Rescue is immediate removal from an unsafe scene—life over spine.","difficulty":"Easy"},{"id":"c11_q10","question":"Rapid extrication is indicated for:","options":["A stable patient in a stable vehicle","A critical/load-and-go patient or an unstable scene","Any patient with neck pain","Minor injuries only"],"correct":1,"rationale":"Rapid extrication uses manual stabilization for critical patients or unstable scenes, faster than standard extrication.","difficulty":"Medium"},{"id":"c11_q11","question":"Primary spinal-cord injury occurs:","options":["From hypoxia after the event","At the moment of trauma","Only during transport","From immobilization"],"correct":1,"rationale":"Primary injury happens at impact; secondary injury arises later from movement, hypoxia, and hypotension.","difficulty":"Easy"},{"id":"c11_q12","question":"Which is a harm of unnecessary full immobilization?","options":["Improved breathing","Pressure sores, pain, and aspiration risk","Lower mortality","Faster transport"],"correct":1,"rationale":"Rigid immobilization can cause pressure injury, pain, agitation, impaired ventilation, and aspiration risk.","difficulty":"Medium"},{"id":"c11_q13","question":"If achieving neutral in-line alignment causes increased pain or new neurologic symptoms, you should:","options":["Force the head into alignment","Stop and immobilize in the position found","Remove all immobilization","Apply traction to the neck"],"correct":1,"rationale":"Do not force alignment that worsens pain or neuro status—immobilize in the position found.","difficulty":"Medium"},{"id":"c11_q14","question":"Paresthesia in the extremities after trauma is significant because it:","options":["Is always benign","Suggests possible spinal-cord involvement and warrants SMR","Indicates a fracture only","Rules out spine injury"],"correct":1,"rationale":"Tingling/numbness (paresthesia) is a neurologic deficit suggesting cord involvement—apply SMR.","difficulty":"Easy"},{"id":"c11_q15","question":"Why pad under the torso of a small child during SMR?","options":["To raise the legs","Because the large head would otherwise flex the neck forward","To increase pressure on the chest","It is never needed"],"correct":1,"rationale":"A child's proportionally large head flexes the neck on a flat board; torso padding restores neutral alignment.","difficulty":"Medium"},{"id":"c11_q16","question":"Secondary spinal-cord injury can be caused by:","options":["Only the initial impact","Movement of an unstable spine, hypoxia, and hypotension","Proper SMR","Oxygen therapy"],"correct":1,"rationale":"Secondary injury arises from unstable-spine movement plus systemic insults like hypoxia and hypotension.","difficulty":"Easy"},{"id":"c11_q17","question":"An intoxicated trauma patient with neck pain should:","options":["Be cleared without SMR","Receive SMR because intoxication makes the exam unreliable","Be discharged","Be told to self-immobilize"],"correct":1,"rationale":"Intoxication is a criterion that makes the spinal exam unreliable—apply SMR.","difficulty":"Easy"},{"id":"c11_q18","question":"An elderly kyphotic patient on a flat board should be managed by:","options":["Forcing the spine flat","Padding voids to maintain neutral, comfortable alignment","Skipping all padding","Applying neck traction"],"correct":1,"rationale":"Kyphosis creates gaps; pad voids behind the head and back to support the spine in its baseline neutral position.","difficulty":"Medium"},{"id":"c11_q19","question":"Loss of vascular tone causing warm, dry skin below the injury reflects:","options":["Hemorrhage","Interruption of sympathetic pathways in the cord (neurogenic shock)","Fever","Hypoglycemia"],"correct":1,"rationale":"Cord injury interrupts sympathetic tone, dilating vessels below the lesion and producing warm, dry skin.","difficulty":"Medium"},{"id":"c11_q20","question":"The decision to apply SMR is best described as:","options":["All trauma patients always","Patient-centered/selective based on mechanism, mental status, exam, and deficits","Only for penetrating trauma","Based solely on age"],"correct":1,"rationale":"Modern SMR is selective—applied based on mechanism, reliability of exam, tenderness, and neurologic findings.","difficulty":"Easy"}]},"c12":{"chapter":"c12","questions":[{"id":"c12_q01","question":"When securing a patient to a long backboard, you should secure:","options":["The head first, then the torso","The torso first, then the head last","Only the head","Only the legs"],"correct":1,"rationale":"Secure the torso before the head so the head is never the anchor point; otherwise torso shift loads the neck.","difficulty":"Easy"},{"id":"c12_q02","question":"Manual in-line stabilization should be maintained:","options":["Only during the log roll","From first contact until the patient is fully secured","Only after the collar is applied","Only during transport"],"correct":1,"rationale":"Continuous manual stabilization is held from first contact until full securing to the device.","difficulty":"Easy"},{"id":"c12_q03","question":"The long backboard is best understood as:","options":["The required transport surface for all patients","Primarily an extrication and transfer tool","A splinting device for fractures","Unnecessary in all cases"],"correct":1,"rationale":"The board is mainly for extrication/transfer; patients can often be transported on a padded stretcher with collar and straps.","difficulty":"Medium"},{"id":"c12_q04","question":"During a log roll, who directs the team and gives commands?","options":["The driver","The rescuer holding head/neck stabilization","The patient","Any bystander"],"correct":1,"rationale":"The provider maintaining head stabilization coordinates and commands the roll.","difficulty":"Easy"},{"id":"c12_q05","question":"A key purpose of the log roll, besides moving the patient, is to:","options":["Apply a traction splint","Inspect and palpate the posterior for injuries","Remove the collar","Start an IV"],"correct":1,"rationale":"The roll allows examination of the posterior (DCAP-BLS, TIC) and placement of the board.","difficulty":"Easy"},{"id":"c12_q06","question":"A short extrication (vest-type) device is indicated for:","options":["A critical load-and-go patient","A seated, stable patient before vehicle extrication","An apneic patient","Any standing patient"],"correct":1,"rationale":"The short device provides SMR to seated, stable patients prior to extrication.","difficulty":"Medium"},{"id":"c12_q07","question":"An advantage of the scoop stretcher is that it:","options":["Replaces the cervical collar","Splits to slide under the patient with minimal movement","Provides traction","Is only for pediatric patients"],"correct":1,"rationale":"The scoop splits in two to slide under the patient from each side, minimizing movement during transfer.","difficulty":"Easy"},{"id":"c12_q08","question":"A vacuum mattress is beneficial because it:","options":["Increases pressure points","Conforms to the body and distributes pressure while maintaining alignment","Cannot be used in transport","Forces hyperextension"],"correct":1,"rationale":"The vacuum mattress molds to the patient, reducing pressure injury and maintaining neutral alignment comfortably.","difficulty":"Medium"},{"id":"c12_q09","question":"Emergency Rescue is performed when:","options":["The patient is stable","There is immediate danger to life (fire, drowning)","A scoop stretcher is available","The patient has neck pain only"],"correct":1,"rationale":"Emergency Rescue prioritizes life over spine when the scene poses immediate danger.","difficulty":"Easy"},{"id":"c12_q10","question":"A helmet should be removed when:","options":["It fits snugly and the airway is accessible","It prevents airway access/assessment or fits poorly","The patient prefers it on","Never"],"correct":1,"rationale":"Remove a helmet that blocks airway/assessment, fits loosely (allowing head movement), or impairs immobilization.","difficulty":"Medium"},{"id":"c12_q11","question":"Helmet removal in a trauma patient requires:","options":["One rescuer","Two rescuers maintaining in-line stabilization","No stabilization","Traction on the neck"],"correct":1,"rationale":"Two rescuers are needed—one stabilizes from below while the other removes the helmet to prevent movement.","difficulty":"Medium"},{"id":"c12_q12","question":"A well-fitting helmet may be left in place if:","options":["The airway is inaccessible","The airway is accessible and the head can be securely immobilized","It interferes with the collar","The patient is apneic"],"correct":1,"rationale":"A snug helmet with an accessible airway and secure head immobilization can be left on, with padding as needed.","difficulty":"Medium"},{"id":"c12_q13","question":"Before and after packaging a spine-injured patient, you must reassess:","options":["Blood glucose only","Distal pulses, motor function, and sensation (PMS)","Pupil size","Lung sounds only"],"correct":1,"rationale":"Distal neurovascular status (PMS) is checked before and after any movement or packaging.","difficulty":"Easy"},{"id":"c12_q14","question":"To maintain neutral alignment in a small child on a board, you should:","options":["Pad under the head","Pad under the torso to offset the large head","Apply traction","Use no padding"],"correct":1,"rationale":"A child's large head flexes the neck on a flat board; padding under the torso restores neutral alignment.","difficulty":"Medium"},{"id":"c12_q15","question":"A hazard of leaving a patient on a rigid backboard for a long transport is:","options":["Improved comfort","Pressure sores and respiratory compromise","Lower mortality","Better alignment always"],"correct":1,"rationale":"Prolonged rigid-board time causes pressure injury and can impair breathing—transfer to a padded surface when possible.","difficulty":"Medium"},{"id":"c12_q16","question":"If neutral in-line position cannot be safely achieved, you should:","options":["Force the head into alignment","Stabilize and immobilize the head/neck in the position found","Remove all immobilization","Apply heavy traction"],"correct":1,"rationale":"Do not force movement that causes pain or neuro change—immobilize in the position found.","difficulty":"Medium"},{"id":"c12_q17","question":"Rapid extrication differs from standard extrication in that it:","options":["Uses a full short device","Uses manual stabilization to move a critical patient quickly","Is slower","Is for stable patients only"],"correct":1,"rationale":"Rapid extrication trades the short device for speed using manual stabilization in critical or unstable situations.","difficulty":"Medium"},{"id":"c12_q18","question":"An ill-fitting cervical collar can:","options":["Improve alignment","Force flexion or extension of the neck","Replace head blocks","Eliminate the need for stabilization"],"correct":1,"rationale":"Wrong collar size can push the neck into flexion or extension; correct sizing maintains neutral alignment.","difficulty":"Easy"}]},"c13":{"chapter":"c13","questions":[{"id":"c13_q01","question":"The intrathoracic abdomen contains organs that are:","options":["Below the umbilicus","Protected by the lower ribs (liver, spleen, stomach, diaphragm)","Only in the pelvis","Outside the body cavity"],"correct":1,"rationale":"The intrathoracic abdomen lies under the lower ribs, linking chest and abdominal injuries.","difficulty":"Medium"},{"id":"c13_q02","question":"Blunt abdominal trauma most commonly injures which organs?","options":["Hollow organs only","Solid organs such as the liver and spleen","The skin only","The lungs"],"correct":1,"rationale":"Blunt force compresses and shears solid organs like the liver and spleen, causing internal hemorrhage.","difficulty":"Easy"},{"id":"c13_q03","question":"A characteristic risk of penetrating abdominal trauma is:","options":["Compartment syndrome","Hollow-organ perforation with contamination and peritonitis","Pulmonary contusion","Neurogenic shock"],"correct":1,"rationale":"Penetrating injury can perforate bowel, causing bleeding plus contamination and delayed peritonitis/sepsis.","difficulty":"Medium"},{"id":"c13_q04","question":"A seat-belt sign across the abdomen should raise concern for:","options":["Only skin bruising","Underlying bowel, mesenteric, or solid-organ injury","A femur fracture","A simple contusion with no risk"],"correct":1,"rationale":"The seat-belt sign is associated with significant intra-abdominal injuries despite a benign exterior.","difficulty":"Easy"},{"id":"c13_q05","question":"Serious intra-abdominal hemorrhage may present as:","options":["Always a rigid abdomen","Developing shock with few external signs","Obvious external bleeding","A normal blood pressure indefinitely"],"correct":1,"rationale":"The abdomen can hide large blood loss; unexplained/developing shock may be the only sign.","difficulty":"Medium"},{"id":"c13_q06","question":"The abdominal exam is least reliable in:","options":["An alert, sober patient","An intoxicated or head-injured patient","A cooperative patient","A patient with isolated arm pain"],"correct":1,"rationale":"Altered mental status from intoxication or head injury masks abdominal tenderness, making the exam unreliable.","difficulty":"Easy"},{"id":"c13_q07","question":"Management of an abdominal evisceration includes:","options":["Pushing the organs back inside","Covering with a moist sterile dressing and an occlusive layer","Applying a dry pressure dressing only","Leaving the organs exposed"],"correct":1,"rationale":"Do not replace the organs; cover with moist sterile then occlusive dressing to retain warmth/moisture and prevent contamination.","difficulty":"Easy"},{"id":"c13_q08","question":"Why should eviscerated organs not be pushed back in?","options":["It saves time","It risks further injury, contamination, and infection","It stops bleeding","It is required by protocol"],"correct":1,"rationale":"Replacing organs can cause additional injury and introduce contamination/infection.","difficulty":"Easy"},{"id":"c13_q09","question":"An unstable pelvic fracture is life-threatening primarily because of:","options":["Nerve damage","Massive hemorrhage from the pelvic vessels","Skin loss","Joint stiffness"],"correct":1,"rationale":"Disruption of the pelvic ring lacerates the venous plexus and arteries, causing major hemorrhage.","difficulty":"Easy"},{"id":"c13_q10","question":"A pelvic binder should be applied at the level of the:","options":["Umbilicus","Greater trochanters","Iliac crests only","Knees"],"correct":1,"rationale":"Binding at the greater trochanters closes the pelvic ring volume to tamponade bleeding.","difficulty":"Medium"},{"id":"c13_q11","question":"How should a suspected unstable pelvis be physically assessed?","options":["Spring it repeatedly to confirm","Gently and only once","Rock it side to side","Never touch it"],"correct":1,"rationale":"Assess gently a single time; repeated manipulation can dislodge clots and worsen hemorrhage.","difficulty":"Medium"},{"id":"c13_q12","question":"An object impaled in the abdomen should be:","options":["Removed immediately","Stabilized in place and left for surgical removal","Pushed in further","Twisted to assess depth"],"correct":1,"rationale":"Stabilize impaled objects; removal can cause uncontrollable hemorrhage and further injury.","difficulty":"Easy"},{"id":"c13_q13","question":"The most life-saving field action for major intra-abdominal hemorrhage is:","options":["High-volume crystalloid on scene","Rapid transport to surgical care","Applying a tourniquet to the abdomen","Pelvic springing"],"correct":1,"rationale":"Internal abdominal bleeding requires surgery; rapid transport with supportive care is the priority.","difficulty":"Medium"},{"id":"c13_q14","question":"Abdominal rigidity and guarding indicate:","options":["Normal findings","Peritoneal irritation from blood or spilled contents","Dehydration","A musculoskeletal strain only"],"correct":1,"rationale":"Rigidity/guarding reflect peritoneal irritation, signaling significant intra-abdominal injury.","difficulty":"Medium"},{"id":"c13_q15","question":"Retroperitoneal bleeding is easily missed because it:","options":["Always causes obvious distention","May present only as shock without peritoneal signs","Is never serious","Causes immediate rigidity"],"correct":1,"rationale":"The retroperitoneal space can bleed substantially without distention or peritoneal signs—shock may be the only clue.","difficulty":"Hard"},{"id":"c13_q16","question":"A patient with a tender, distended abdomen and unexplained tachycardia after a high-speed MVC should be treated as having:","options":["A minor bruise","Potential intra-abdominal hemorrhage—treat for shock and transport rapidly","Neurogenic shock","An anxiety attack"],"correct":1,"rationale":"These findings with a significant mechanism point to intra-abdominal bleeding requiring shock care and rapid surgical transport.","difficulty":"Medium"},{"id":"c13_q17","question":"Which intervention is appropriate for the abdominal-trauma patient?","options":["Remove impaled objects","Keep the patient warm and provide judicious fluids/TXA per protocol","Push eviscerated bowel back in","Spring the pelvis repeatedly"],"correct":1,"rationale":"Supportive care includes warmth, controlled fluids/TXA per protocol, pelvic stabilization, and rapid transport.","difficulty":"Easy"},{"id":"c13_q18","question":"The lower ribs overlying the upper abdomen mean that:","options":["Abdominal injury is impossible","Lower chest trauma can injure the liver, spleen, or diaphragm","Only the lungs can be injured","The pelvis is involved"],"correct":1,"rationale":"Because the lower ribs cover upper-abdominal organs, lower chest trauma frequently produces abdominal injury.","difficulty":"Easy"}]},"c14":{"chapter":"c14","questions":[{"id":"c14_q01","question":"The overarching principle in managing extremity trauma is:","options":["Limb before life","Life before limb","Splint everything first","Ignore distal pulses"],"correct":1,"rationale":"Address life threats (ABCs and major hemorrhage) before treating dramatic but rarely fatal extremity injuries.","difficulty":"Easy"},{"id":"c14_q02","question":"Which extremity issue is managed during the Primary Survey?","options":["A closed wrist fracture","Life-threatening extremity hemorrhage","A minor sprain","An isolated dislocation with pulses"],"correct":1,"rationale":"Only life-threatening extremity bleeding (pressure/tourniquet) is addressed in the Primary Survey.","difficulty":"Easy"},{"id":"c14_q03","question":"An open fracture is distinguished by:","options":["Intact overlying skin","A wound communicating with the fractured bone","No deformity","Absent pain"],"correct":1,"rationale":"Open fractures have a skin wound exposing the fracture, increasing infection risk.","difficulty":"Easy"},{"id":"c14_q04","question":"Before and after splinting, you must assess:","options":["Blood glucose","Distal pulses, motor, and sensation (PMS)","Pupil size","Lung sounds"],"correct":1,"rationale":"Distal neurovascular status (PMS) is checked before and after splinting/movement.","difficulty":"Easy"},{"id":"c14_q05","question":"Approximate blood loss from a closed femur fracture is:","options":["100–200 mL","1–1.5 liters","5 liters","Negligible"],"correct":1,"rationale":"A closed femur fracture can lose roughly 1–1.5 liters into the thigh, contributing to shock.","difficulty":"Medium"},{"id":"c14_q06","question":"An amputated part should be:","options":["Placed directly on ice","Wrapped moist, sealed in a bag, and kept cool (not frozen)","Frozen solid","Left dry and warm"],"correct":1,"rationale":"Keep the part moist, bagged, and cool—direct ice or freezing damages tissue and harms replantation chances.","difficulty":"Medium"},{"id":"c14_q07","question":"Crush syndrome after release of prolonged compression can cause:","options":["Hypoglycemia","Hyperkalemia, dysrhythmias, and renal failure","Hypertension only","No systemic effects"],"correct":1,"rationale":"Rhabdomyolysis releases potassium and myoglobin, risking lethal hyperkalemia and renal failure.","difficulty":"Hard"},{"id":"c14_q08","question":"The earliest sign of compartment syndrome is:","options":["Pulselessness","Pain out of proportion, worsened by passive stretch","Paralysis","Pallor"],"correct":1,"rationale":"Pain out of proportion and pain on passive stretch are early; pulselessness and paralysis are late.","difficulty":"Medium"},{"id":"c14_q09","question":"The 6 P's of limb ischemia/compartment syndrome include all EXCEPT:","options":["Pain","Paresthesia","Pyrexia (fever)","Pulselessness"],"correct":2,"rationale":"The 6 P's are Pain, Paresthesia, Pallor, Pulselessness, Paralysis, Poikilothermia—not fever.","difficulty":"Medium"},{"id":"c14_q10","question":"Compartment syndrome most commonly develops in the:","options":["Skull","Lower leg or forearm after fractures/crush","Abdomen","Chest"],"correct":1,"rationale":"Closed compartments of the lower leg (tibia) and forearm are most prone, especially with fractures, crush, or tight splints.","difficulty":"Medium"},{"id":"c14_q11","question":"An angulated long-bone fracture with NO distal pulse should be:","options":["Splinted exactly as found","Gently realigned with traction to restore circulation, then splinted, and the pulse rechecked","Left untreated","Forced rapidly into position"],"correct":1,"rationale":"Gentle in-line traction can restore distal perfusion before splinting; recheck the pulse after.","difficulty":"Medium"},{"id":"c14_q12","question":"A dislocation with an intact distal pulse should be:","options":["Forcefully reduced in the field","Splinted in the position found","Left unsplinted","Realigned rapidly"],"correct":1,"rationale":"If perfusion is intact, splint a dislocation in the position found rather than forcing realignment.","difficulty":"Medium"},{"id":"c14_q13","question":"The rule for splinting a long-bone fracture is to immobilize:","options":["Only the fracture site","The joint above and the joint below","The entire body","Nothing"],"correct":1,"rationale":"Effective splinting immobilizes the joints above and below the fracture.","difficulty":"Easy"},{"id":"c14_q14","question":"An object impaled in an extremity should be:","options":["Removed in the field","Stabilized in place","Pushed through","Twisted to assess depth"],"correct":1,"rationale":"Impaled objects are stabilized in place; removal risks hemorrhage and further injury.","difficulty":"Easy"},{"id":"c14_q15","question":"After splinting, the distal pulse is now absent. You should:","options":["Tighten the splint further","Loosen/readjust the splint and reassess circulation","Ignore it","Apply a tourniquet"],"correct":1,"rationale":"A too-tight splint can compromise circulation; readjust and reassess PMS immediately.","difficulty":"Medium"},{"id":"c14_q16","question":"A traction splint on a critical load-and-go patient should be:","options":["Always applied on scene","Deferred or applied en route to avoid delaying transport","Applied to the chest","Used for dislocations"],"correct":1,"rationale":"Traction splinting is time-consuming; for load-and-go patients, package and transport, deferring the splint.","difficulty":"Medium"},{"id":"c14_q17","question":"A sprain involves injury to a ____, while a strain involves injury to a ____.","options":["muscle; ligament","ligament; muscle or tendon","bone; nerve","nerve; vessel"],"correct":1,"rationale":"A sprain injures a ligament; a strain injures a muscle or tendon.","difficulty":"Easy"},{"id":"c14_q18","question":"Why is a joint dislocation a neurovascular concern?","options":["It never affects vessels","Nerves and vessels cross the joint and can be compromised","It only affects skin","It causes fever"],"correct":1,"rationale":"Dislocations can stretch or compress the nerves and arteries crossing the joint, threatening the limb.","difficulty":"Medium"},{"id":"c14_q19","question":"Open fractures and wounds should be:","options":["Left exposed","Covered with sterile dressings, with bleeding controlled and the limb immobilized","Scrubbed vigorously","Packed tightly into the bone"],"correct":1,"rationale":"Cover open wounds with sterile dressings to limit contamination, control bleeding, and immobilize.","difficulty":"Easy"},{"id":"c14_q20","question":"Becoming fixated on a dramatic open fracture and missing a developing tension pneumothorax illustrates:","options":["Good prioritization","The danger of distraction from life threats","Proper assessment","Correct triage"],"correct":1,"rationale":"Dramatic extremity injuries can distract from life threats—maintain the life-before-limb discipline.","difficulty":"Easy"}]},"c15":{"chapter":"c15","questions":[{"id":"c15_q01","question":"A traction splint is indicated for:","options":["A lower-leg fracture","A mid-shaft femur fracture","A pelvic fracture","A knee dislocation"],"correct":1,"rationale":"Traction splints immobilize mid-shaft femur fractures only.","difficulty":"Easy"},{"id":"c15_q02","question":"Traction splints should NOT be used with:","options":["An isolated mid-shaft femur fracture","A suspected pelvic, hip, knee, or lower-leg injury","A stable patient","An adult patient"],"correct":1,"rationale":"Hip, knee, lower-leg, ankle, and pelvic injuries contraindicate traction splinting.","difficulty":"Easy"},{"id":"c15_q03","question":"Applying traction across a fractured/dislocated knee risks:","options":["Improved alignment","Tearing the popliteal blood vessels","Faster healing","No harm"],"correct":1,"rationale":"Traction at the knee can lacerate the popliteal vessels behind the joint.","difficulty":"Medium"},{"id":"c15_q04","question":"Benefits of a femur traction splint include all EXCEPT:","options":["Reduced pain","Decreased thigh blood loss","Realignment of the fracture","Reduction of a hip dislocation"],"correct":3,"rationale":"Traction splints realign femur fractures and reduce pain/blood loss but are not for hip dislocations.","difficulty":"Medium"},{"id":"c15_q05","question":"Which is a low-profile splint that applies traction from a single bar between the legs?","options":["Hare splint","Thomas splint","Sager splint","Vacuum splint"],"correct":2,"rationale":"The Sager splint uses a single medial bar, is lower-profile, and can splint both legs.","difficulty":"Medium"},{"id":"c15_q06","question":"Before and after applying a traction splint, assess:","options":["Blood glucose","Distal pulses, motor, and sensation","Lung sounds","Pupils"],"correct":1,"rationale":"Distal PMS is documented before and after splinting to detect neurovascular compromise.","difficulty":"Easy"},{"id":"c15_q07","question":"How much traction should be applied with a traction splint?","options":["As much as possible","Only enough to realign and relieve pain","None","Until the leg lengthens 4 inches"],"correct":1,"rationale":"Apply only enough traction to realign and reduce pain; excessive traction harms neurovascular structures.","difficulty":"Medium"},{"id":"c15_q08","question":"A pelvic binder is correctly centered over the:","options":["Iliac crests","Greater trochanters","Umbilicus","Lower ribs"],"correct":1,"rationale":"Binding at the greater trochanters closes the pelvic ring to control hemorrhage.","difficulty":"Medium"},{"id":"c15_q09","question":"A suspected unstable pelvis should be assessed:","options":["Repeatedly to confirm","Gently and only once","By springing forcefully","Never"],"correct":1,"rationale":"Assess once, gently; repeated manipulation can worsen hemorrhage.","difficulty":"Easy"},{"id":"c15_q10","question":"A tourniquet should be placed:","options":["Directly over the wound","2–3 inches proximal to the wound, not over a joint","Distal to the wound","Over the nearest joint"],"correct":1,"rationale":"Place the tourniquet 2–3 inches proximal to the wound, avoiding joints.","difficulty":"Easy"},{"id":"c15_q11","question":"A correctly applied tourniquet should be tightened until:","options":["The patient is comfortable","Bleeding stops and the distal pulse is eliminated","It feels snug only","The skin turns blue"],"correct":1,"rationale":"Tighten until bleeding stops and the distal pulse disappears; a partial (venous) tourniquet increases bleeding.","difficulty":"Medium"},{"id":"c15_q12","question":"When applying a tourniquet, you must always:","options":["Loosen it every 10 minutes","Record the time of application","Apply it loosely","Cover it from view"],"correct":1,"rationale":"Document the application time; periodic loosening is not done and the device should remain visible.","difficulty":"Easy"},{"id":"c15_q13","question":"Periodically loosening a properly applied tourniquet is:","options":["Recommended","Harmful and should not be done","Required hourly","Standard practice"],"correct":1,"rationale":"Loosening a tourniquet can worsen hemorrhage and is not recommended in the field.","difficulty":"Medium"},{"id":"c15_q14","question":"Hemostatic agents are best used for:","options":["Minor abrasions","Junctional/deep wounds where a tourniquet cannot be applied","Closed fractures","Stable patients with no bleeding"],"correct":1,"rationale":"Hemostatic dressings are packed into junctional or deep wounds and held with sustained pressure.","difficulty":"Medium"},{"id":"c15_q15","question":"A complication of excessive traction with a traction splint is:","options":["Better perfusion","Neurovascular compromise","Reduced pain only","Faster transport"],"correct":1,"rationale":"Too much traction can damage nerves and vessels—apply only enough to realign and relieve pain.","difficulty":"Medium"},{"id":"c15_q16","question":"Why is a traction splint deferred for a critical load-and-go patient?","options":["It is illegal","It is time-consuming and delays transport","It worsens femur fractures","It is only for children"],"correct":1,"rationale":"Traction splinting takes time; for load-and-go patients, package and transport, applying it en route if at all.","difficulty":"Easy"},{"id":"c15_q17","question":"A pelvic binder placed too high over the iliac crests will:","options":["Work better","Fail to effectively close the pelvic ring","Stop all bleeding","Reduce a femur fracture"],"correct":1,"rationale":"Only binding at the trochanters effectively compresses the pelvic ring; placement over the crests is ineffective.","difficulty":"Hard"},{"id":"c15_q18","question":"Which device minimizes movement when transferring a pelvic-fracture patient?","options":["Long backboard with a log roll","Scoop stretcher","Traction splint","Stair chair"],"correct":1,"rationale":"A scoop stretcher slides under the patient from both sides, minimizing pelvic manipulation.","difficulty":"Medium"}]},"c16":{"chapter":"c16","questions":[{"id":"c16_q01","question":"The two main layers of skin are the:","options":["Cortex and medulla","Epidermis and dermis","Mucosa and serosa","Intima and adventitia"],"correct":1,"rationale":"Skin consists of the outer epidermis and the deeper dermis.","difficulty":"Easy"},{"id":"c16_q02","question":"A burn that is red, blistered, moist, and very painful is:","options":["Superficial (first-degree)","Partial-thickness (second-degree)","Full-thickness (third-degree)","Fourth-degree"],"correct":1,"rationale":"Blistering, moist, painful burns extending into the dermis are partial-thickness (second-degree).","difficulty":"Easy"},{"id":"c16_q03","question":"A dry, leathery, white/charred, painless burn is:","options":["Superficial","Partial-thickness","Full-thickness","A sunburn"],"correct":2,"rationale":"Full-thickness burns destroy the dermis and nerves, appearing leathery/charred and painless in the burned area.","difficulty":"Easy"},{"id":"c16_q04","question":"Using the adult rule of nines, an entire anterior trunk equals:","options":["9%","18%","27%","36%"],"correct":1,"rationale":"The anterior trunk is 18% TBSA in the adult rule of nines.","difficulty":"Medium"},{"id":"c16_q05","question":"Using the adult rule of nines, one entire leg equals:","options":["9%","14%","18%","27%"],"correct":2,"rationale":"Each leg is 18% TBSA in the adult rule of nines.","difficulty":"Medium"},{"id":"c16_q06","question":"The patient's palm (with fingers) represents approximately what TBSA?","options":["1%","5%","9%","18%"],"correct":0,"rationale":"The palmar surface including fingers is about 1% TBSA, useful for scattered burns.","difficulty":"Easy"},{"id":"c16_q07","question":"When estimating TBSA, you should count:","options":["All burns including superficial","Only partial- and full-thickness burns","Only full-thickness burns","Only superficial burns"],"correct":1,"rationale":"Superficial (first-degree) burns are not included; count partial- and full-thickness only.","difficulty":"Medium"},{"id":"c16_q08","question":"Which finding most suggests inhalation/airway injury?","options":["A burn to the forearm","Singed nasal hairs, soot in the mouth, and hoarseness after an enclosed-space fire","A normal voice","A small hand burn"],"correct":1,"rationale":"Facial soot, singed hairs, hoarseness, and enclosed-space fire strongly suggest thermal airway injury.","difficulty":"Medium"},{"id":"c16_q09","question":"The airway in inhalation injury should be:","options":["Observed only","Secured early before edema closes it","Ignored if the patient is talking","Managed only at the hospital"],"correct":1,"rationale":"Rapidly progressive edema can make later intubation impossible; secure the airway early.","difficulty":"Hard"},{"id":"c16_q10","question":"Carbon monoxide causes hypoxia because it:","options":["Increases oxygen delivery","Binds hemoglobin far more strongly than oxygen, forming carboxyhemoglobin","Dilates the airways","Raises hemoglobin levels"],"correct":1,"rationale":"CO binds hemoglobin ~250x more avidly than oxygen, blocking oxygen transport and causing tissue hypoxia.","difficulty":"Medium"},{"id":"c16_q11","question":"In suspected CO poisoning, the pulse oximeter:","options":["Reliably detects it","May read falsely normal","Reads zero","Is the best test"],"correct":1,"rationale":"Standard pulse oximeters cannot distinguish carboxyhemoglobin, giving a falsely reassuring reading.","difficulty":"Medium"},{"id":"c16_q12","question":"The initial treatment for carbon monoxide poisoning is:","options":["Low-flow oxygen","100% high-flow oxygen","Withhold oxygen","Hyperventilation only"],"correct":1,"rationale":"High-flow 100% oxygen accelerates CO elimination from hemoglobin.","difficulty":"Easy"},{"id":"c16_q13","question":"A dry chemical burn should first be:","options":["Irrigated immediately","Brushed off, then irrigated copiously","Covered without cleaning","Neutralized with acid/base"],"correct":1,"rationale":"Brush dry chemical off first to avoid activating it with water, then irrigate copiously.","difficulty":"Medium"},{"id":"c16_q14","question":"Electrical burns require special attention to:","options":["Only the skin entry wound","Deep tissue injury and cardiac dysrhythmias—apply monitoring","Nothing beyond the visible burn","Traction splinting"],"correct":1,"rationale":"Electrical current causes deep tissue damage and dysrhythmias far beyond visible skin injury; monitor the heart.","difficulty":"Medium"},{"id":"c16_q15","question":"Field dressing of burns should use:","options":["Wet, cold dressings for prolonged cooling","Clean, dry dressings while keeping the patient warm","No dressing","Greasy ointment and tight wraps"],"correct":1,"rationale":"Cover with clean dry dressings and keep warm; prolonged wet cooling risks hypothermia.","difficulty":"Easy"},{"id":"c16_q16","question":"Which patient meets burn-center criteria?","options":["A small superficial sunburn","A patient with burns to the hands, face, and an inhalation injury","A minor first-degree forearm burn","A scraped knee"],"correct":1,"rationale":"Burns of the face/hands and inhalation injury are clear burn-center referral criteria.","difficulty":"Medium"},{"id":"c16_q17","question":"A circumferential full-thickness burn of the chest is dangerous because it can:","options":["Improve breathing","Restrict chest expansion and impair ventilation","Lower infection risk","Reduce fluid loss"],"correct":1,"rationale":"A constricting circumferential burn limits chest wall movement, impairing ventilation and possibly needing escharotomy.","difficulty":"Hard"},{"id":"c16_q18","question":"The very first action at a burn scene is to:","options":["Estimate TBSA","Ensure scene safety and stop the burning process","Start an IV","Apply a dressing"],"correct":1,"rationale":"Ensure safety and stop the burning (remove from source, remove smoldering clothing/jewelry) before other care.","difficulty":"Easy"},{"id":"c16_q19","question":"Over-cooling a large burn risks:","options":["Hyperthermia","Hypothermia","Improved outcomes","Higher blood pressure"],"correct":1,"rationale":"Large burns impair thermoregulation; prolonged cooling causes harmful hypothermia.","difficulty":"Medium"},{"id":"c16_q20","question":"Children differ from adults in burn assessment because they have:","options":["Smaller heads proportionally","Proportionally larger heads requiring a modified rule of nines","Thicker skin","No risk of airway injury"],"correct":1,"rationale":"Children's proportionally larger heads (and smaller legs) require a modified pediatric rule of nines.","difficulty":"Medium"}]},"c17":{"chapter":"c17","questions":[{"id":"c17_q01","question":"Compared with adults, children have:","options":["Smaller heads proportionally","Proportionally larger heads and smaller airways","Stiffer ribs","Smaller body surface area relative to mass"],"correct":1,"rationale":"Children have proportionally larger heads, smaller/more easily obstructed airways, flexible ribs, and larger relative BSA.","difficulty":"Easy"},{"id":"c17_q02","question":"The earliest sign of shock in a child is:","options":["Hypotension","Tachycardia","Bradycardia","Warm, dry skin"],"correct":1,"rationale":"Children compensate with tachycardia and vasoconstriction; hypotension appears late.","difficulty":"Easy"},{"id":"c17_q03","question":"Hypotension in an injured child indicates:","options":["A minor injury","A late, pre-arrest sign of decompensation","Normal physiology","Improvement"],"correct":1,"rationale":"Because children compensate so well, hypotension is a late and ominous sign of impending collapse.","difficulty":"Medium"},{"id":"c17_q04","question":"The most common path to pediatric cardiac arrest is:","options":["Primary cardiac disease","Respiratory failure/hypoxia","Hemorrhage only","Electrocution"],"correct":1,"rationale":"Respiratory failure leading to hypoxia is the usual route to pediatric arrest—support breathing early.","difficulty":"Medium"},{"id":"c17_q05","question":"To maintain neutral airway/spinal alignment in a small child, pad:","options":["Under the head","Under the torso/shoulders","Under the hips","Under the feet"],"correct":1,"rationale":"The large occiput flexes the neck on a flat surface; padding under the torso restores neutral position.","difficulty":"Medium"},{"id":"c17_q06","question":"A length-based resuscitation tape provides:","options":["Only the child's age","Estimated weight, drug doses, fluid volumes, and equipment sizes","Blood type","Burn percentage"],"correct":1,"rationale":"The tape estimates weight and supplies matched doses, volumes, and equipment sizes.","difficulty":"Easy"},{"id":"c17_q07","question":"A typical pediatric fluid bolus for decompensated shock is:","options":["5 mL/kg","20 mL/kg of warmed isotonic crystalloid","100 mL/kg","A fixed 1 liter"],"correct":1,"rationale":"About 20 mL/kg of warmed isotonic crystalloid is given and reassessed/repeated per protocol.","difficulty":"Medium"},{"id":"c17_q08","question":"SCIWORA refers to:","options":["A type of burn","Spinal Cord Injury Without Radiographic Abnormality","A pediatric airway device","A fluid formula"],"correct":1,"rationale":"A child's elastic spine can injure the cord without a visible fracture—maintain suspicion based on mechanism.","difficulty":"Medium"},{"id":"c17_q09","question":"Why can children sustain a pulmonary contusion without rib fractures?","options":["Their ribs are very brittle","Their flexible ribs transmit force to the lung without breaking","They have no ribs","Their lungs are protected by fat"],"correct":1,"rationale":"Compliant pediatric ribs bend and transmit energy to the lung, causing contusion without fracture.","difficulty":"Medium"},{"id":"c17_q10","question":"Children lose heat rapidly because of their:","options":["Thick subcutaneous fat","Large body surface area relative to mass","Slow metabolism","Small heads"],"correct":1,"rationale":"A high surface-area-to-mass ratio promotes rapid heat loss; keep injured children warm.","difficulty":"Easy"},{"id":"c17_q11","question":"For a critically injured child without a parent present, you should:","options":["Wait for consent before any care","Provide immediate life-saving care under implied consent","Refuse to treat","Only transport"],"correct":1,"rationale":"Emergency (implied) consent allows immediate life-saving treatment regardless of parental availability.","difficulty":"Easy"},{"id":"c17_q12","question":"Which finding suggests non-accidental trauma (abuse)?","options":["A single bruise from a witnessed fall","Injuries inconsistent with the history or in different healing stages","An age-appropriate scrape","A clear, consistent account"],"correct":1,"rationale":"Inconsistent histories, patterned injuries, and injuries in different healing stages are red flags for abuse.","difficulty":"Medium"},{"id":"c17_q13","question":"EMS providers regarding suspected child abuse are:","options":["Forbidden to report","Mandated reporters who document and report per protocol","Required to confront the caregiver","Not involved"],"correct":1,"rationale":"EMS providers are mandated reporters; document objectively and report per protocol.","difficulty":"Easy"},{"id":"c17_q14","question":"When peripheral IV access fails in a critical child, the alternative is:","options":["Oral fluids","Intraosseous access (often proximal tibia)","No access","Subcutaneous fluids"],"correct":1,"rationale":"IO access provides rapid, reliable delivery when peripheral access fails.","difficulty":"Easy"},{"id":"c17_q15","question":"A normal blood pressure in a tachycardic, injured child should be interpreted as:","options":["Reassuring—no shock","Compensated shock that can suddenly decompensate","Evidence of overhydration","A reason to stop monitoring"],"correct":1,"rationale":"Normal pressure with tachycardia reflects compensation; deterioration can be abrupt—treat and monitor closely.","difficulty":"Hard"},{"id":"c17_q16","question":"Multisystem injury is common in children because:","options":["Their organs are far apart","Their organs are close together and less protected","They have thick muscle layers","They rarely fall"],"correct":1,"rationale":"Closely packed, less-protected organs mean a single force often injures multiple systems.","difficulty":"Medium"},{"id":"c17_q17","question":"Building rapport with an injured child is best done by:","options":["Speaking loudly from above","Getting to eye level, staying calm, and keeping a caregiver near when possible","Separating the child from all family","Ignoring the child"],"correct":1,"rationale":"A calm, eye-level, honest approach with a caregiver nearby reduces fear and improves cooperation.","difficulty":"Easy"},{"id":"c17_q18","question":"The leading principle of pediatric resuscitation equipment selection is to:","options":["Use adult sizes","Use a length-based tape or pediatric reference for correct sizing","Guess from age only","Use the smallest available"],"correct":1,"rationale":"A length-based tape ensures correctly sized airway, vascular, and immobilization equipment.","difficulty":"Easy"}]},"c18":{"chapter":"c18","questions":[{"id":"c18_q01","question":"The central principle of geriatric trauma physiology is:","options":["Increased reserve","Decreased physiologic reserve in every system","Faster healing","Resistance to shock"],"correct":1,"rationale":"Aging reduces reserve everywhere, so older patients tolerate injury poorly and decompensate quickly.","difficulty":"Easy"},{"id":"c18_q02","question":"A beta-blocker in a bleeding elderly patient may cause:","options":["Exaggerated tachycardia","A blunted heart-rate response that masks shock","Hypertension","No effect on assessment"],"correct":1,"rationale":"Beta-blockers prevent compensatory tachycardia, masking the usual sign of shock.","difficulty":"Medium"},{"id":"c18_q03","question":"A pacemaker affects shock assessment by:","options":["Raising blood pressure","Fixing the heart rate so tachycardia cannot signal shock","Causing fever","Improving perfusion"],"correct":1,"rationale":"A fixed paced rate removes the tachycardic warning sign of shock.","difficulty":"Medium"},{"id":"c18_q04","question":"Anticoagulants in an elderly head-injury patient most increase the risk of:","options":["Pneumonia","Intracranial hemorrhage","Hyperglycemia","Compartment syndrome"],"correct":1,"rationale":"Blood thinners dramatically increase intracranial bleeding risk after head trauma.","difficulty":"Easy"},{"id":"c18_q05","question":"A 'normal' blood pressure in a chronically hypertensive elder may actually represent:","options":["Overhydration","Relative hypotension (shock)","Excellent perfusion","Hypertensive crisis"],"correct":1,"rationale":"Because their baseline is high, a 'normal' reading can be relative hypotension indicating shock.","difficulty":"Medium"},{"id":"c18_q06","question":"Subdural hematomas develop slowly in the elderly because:","options":["Their skulls are thicker","Brain atrophy stretches bridging veins that tear and bleed slowly","They never get head injuries","They have more CSF"],"correct":1,"rationale":"Atrophy stretches the bridging veins, which bleed slowly, causing delayed symptoms after minor trauma.","difficulty":"Hard"},{"id":"c18_q07","question":"A kyphotic spine on a backboard should be managed by:","options":["Forcing it flat","Padding the voids for comfortable neutral alignment","Leaving large gaps","Applying neck traction"],"correct":1,"rationale":"Pad the natural curves rather than forcing the spine flat, which can cause injury and pain.","difficulty":"Medium"},{"id":"c18_q08","question":"Why can a ground-level fall cause major injury in an older adult?","options":["They fall harder","Osteoporosis makes bones fragile (hip, pelvis, ribs)","They are heavier","They have stronger bones"],"correct":1,"rationale":"Fragile osteoporotic bones fracture from low-energy mechanisms like simple falls.","difficulty":"Easy"},{"id":"c18_q09","question":"Rib fractures in the elderly are dangerous because they:","options":["Heal too fast","Impair ventilation and increase pneumonia risk and mortality","Have no consequences","Prevent shock"],"correct":1,"rationale":"Painful rib fractures limit breathing and markedly raise the risk of pneumonia and death in older patients.","difficulty":"Medium"},{"id":"c18_q10","question":"Fluid resuscitation in the elderly must be cautious to avoid:","options":["Hypoglycemia","Pulmonary edema and heart failure","Hypothermia only","Hypertension"],"correct":1,"rationale":"Reduced cardiac/renal reserve makes the elderly prone to fluid overload and heart failure.","difficulty":"Medium"},{"id":"c18_q11","question":"Older patients desaturate faster because of:","options":["Increased lung reserve","Decreased respiratory reserve and lung elasticity","Larger lungs","More hemoglobin"],"correct":1,"rationale":"Reduced respiratory reserve and lung elasticity cause faster desaturation—support breathing early.","difficulty":"Easy"},{"id":"c18_q12","question":"To interpret a geriatric patient's mental status, you should:","options":["Assume any confusion is baseline","Obtain the patient's baseline from caregivers","Ignore mental status","Assume it is always abnormal"],"correct":1,"rationale":"Knowing the baseline (from caregivers) helps distinguish acute changes from chronic dementia.","difficulty":"Medium"},{"id":"c18_q13","question":"Why handle elderly patients gently and pad prominences?","options":["They prefer it","Thin skin and fragile bones injure easily","It speeds transport","It is optional"],"correct":1,"rationale":"Fragile skin and bones are easily injured; gentle handling and padding prevent harm.","difficulty":"Easy"},{"id":"c18_q14","question":"In a geriatric head injury, you should always ask about:","options":["Diet","Anticoagulant/antiplatelet medication use","Exercise habits","Family history only"],"correct":1,"rationale":"Blood thinners greatly increase intracranial bleeding risk and change the urgency of evaluation.","difficulty":"Easy"},{"id":"c18_q15","question":"The threshold for trauma-center transport in the elderly should be:","options":["High—rarely transport","Low—they benefit from higher-level care even after minor trauma","Based only on age","Never"],"correct":1,"rationale":"Limited reserve and occult-injury risk justify a low threshold for trauma-center transport.","difficulty":"Medium"},{"id":"c18_q16","question":"Reduced kidney function in the elderly increases the risk of:","options":["Better drug clearance","Fluid overload and altered drug effects","Hypoglycemia only","Faster recovery"],"correct":1,"rationale":"Impaired renal function affects fluid and drug handling, raising overload and toxicity risks.","difficulty":"Medium"},{"id":"c18_q17","question":"Trusting normal-appearing vital signs in an elderly trauma patient is risky because:","options":["Vitals are always accurate","Medications and baseline hypertension can mask serious injury and shock","Older patients never have shock","Vitals do not matter"],"correct":1,"rationale":"Masked compensation and high baselines mean normal vitals can conceal significant injury.","difficulty":"Medium"},{"id":"c18_q18","question":"A 78-year-old on warfarin has a minor head bump and a normal exam. The best approach is:","options":["Reassure and refuse transport","Recognize high bleeding risk, monitor closely, and transport for evaluation","Ignore the mechanism","Give a fluid bolus"],"correct":1,"rationale":"Anticoagulation makes even minor head trauma high-risk for delayed intracranial bleeding—transport for evaluation.","difficulty":"Hard"}]},"c19":{"chapter":"c19","questions":[{"id":"c19_q01","question":"The best way to protect the fetus in trauma is to:","options":["Focus only on the fetus","Aggressively resuscitate the mother","Deliver immediately","Withhold fluids"],"correct":1,"rationale":"What is good for the mother is good for the fetus—resuscitating the mother optimizes fetal outcome.","difficulty":"Easy"},{"id":"c19_q02","question":"Blood volume in pregnancy increases by approximately:","options":["5–10%","40–50%","100%","It decreases"],"correct":1,"rationale":"A 40–50% increase in blood volume lets the mother lose much blood before showing shock.","difficulty":"Medium"},{"id":"c19_q03","question":"Because of increased blood volume, a pregnant trauma patient may:","options":["Show shock immediately","Lose a large volume before showing signs of shock","Never develop shock","Have a falsely high blood pressure"],"correct":1,"rationale":"Expanded volume masks early shock; maternal vitals can be falsely reassuring while the fetus suffers.","difficulty":"Medium"},{"id":"c19_q04","question":"Supine hypotension syndrome is caused by:","options":["The fetus pressing on the lungs","The gravid uterus compressing the inferior vena cava when supine","Low blood sugar","Anxiety"],"correct":1,"rationale":"After ~20 weeks the uterus compresses the IVC in the supine position, reducing venous return.","difficulty":"Medium"},{"id":"c19_q05","question":"Supine hypotension is best prevented by:","options":["Sitting the patient fully upright","Tilting the patient (and board) 15–30 degrees to the left","Placing the patient prone","Elevating the legs only"],"correct":1,"rationale":"Left tilt or manual leftward uterine displacement relieves aortocaval compression while maintaining SMR.","difficulty":"Easy"},{"id":"c19_q06","question":"Abruptio placenta classically presents with:","options":["Painless heavy bleeding only","Vaginal bleeding, abdominal pain, a tender/rigid uterus, and fetal distress","Chest pain and dyspnea","Leg swelling"],"correct":1,"rationale":"Placental separation causes bleeding, pain, uterine tenderness/rigidity, and fetal distress.","difficulty":"Medium"},{"id":"c19_q07","question":"Why does maternal hypotension endanger the fetus?","options":["It does not affect the fetus","The fetus depends on maternal perfusion of the uterus","It improves fetal oxygenation","It only affects the mother"],"correct":1,"rationale":"Reduced maternal blood pressure lowers uterine blood flow, compromising the fetus.","difficulty":"Easy"},{"id":"c19_q08","question":"Fluid and oxygen for the pregnant trauma patient should be:","options":["Withheld","Given generously to support maternal volume and fetal perfusion","Minimized","Given only after delivery"],"correct":1,"rationale":"Generous oxygen and fluids support the mother's increased volume needs and fetal perfusion.","difficulty":"Medium"},{"id":"c19_q09","question":"Aspiration risk is increased in pregnancy due to:","options":["Faster gastric emptying","Slowed gastric emptying and uterine pressure on the stomach","Decreased saliva","Smaller stomach"],"correct":1,"rationale":"Delayed gastric emptying and upward uterine pressure raise vomiting and aspiration risk.","difficulty":"Medium"},{"id":"c19_q10","question":"A fetus can be in distress while maternal vital signs appear normal because:","options":["The fetus is unaffected by maternal status","The mother shunts blood away from the uterus to compensate","Fetal monitoring is unnecessary","Maternal vitals always reflect fetal status"],"correct":1,"rationale":"Maternal compensation diverts blood from the uterus, so the fetus suffers before the mother shows shock.","difficulty":"Hard"},{"id":"c19_q11","question":"Even after minor trauma, a pregnant patient should be evaluated because:","options":["It is never necessary","Placental abruption/fetal compromise can occur with few external signs","Minor trauma is always harmless","Only major trauma matters"],"correct":1,"rationale":"Abruption and fetal compromise can occur without obvious external injury, warranting evaluation.","difficulty":"Medium"},{"id":"c19_q12","question":"An important and under-recognized cause of trauma in pregnancy is:","options":["Sports injuries only","Domestic (intimate partner) violence","Workplace falls only","Animal bites"],"correct":1,"rationale":"Domestic violence is a significant, often missed cause—screen and document carefully.","difficulty":"Medium"},{"id":"c19_q13","question":"The correct transport position for a late-pregnancy trauma patient requiring SMR is:","options":["Flat supine","Whole board tilted 15–30 degrees to the left","Prone","Fully upright"],"correct":1,"rationale":"Tilt the entire board left to relieve aortocaval compression while keeping spinal alignment.","difficulty":"Easy"},{"id":"c19_q14","question":"Besides abruption, abdominal trauma in pregnancy can cause:","options":["Uterine rupture and preterm labor","Only skin bruising","No internal injury","Improved fetal status"],"correct":0,"rationale":"Uterine rupture and preterm labor are additional pregnancy-specific complications of abdominal trauma.","difficulty":"Medium"},{"id":"c19_q15","question":"The elevated diaphragm in late pregnancy causes:","options":["Increased lung volume","Reduced functional lung volume and faster desaturation","No respiratory change","Slower breathing"],"correct":1,"rationale":"The gravid uterus elevates the diaphragm, reducing lung volume and increasing desaturation risk.","difficulty":"Medium"},{"id":"c19_q16","question":"During transport you should monitor the pregnant trauma patient for:","options":["Only blood pressure","Vaginal bleeding, abdominal pain, uterine rigidity, and contractions","Only heart rate","Nothing additional"],"correct":1,"rationale":"Watch for signs of abruption and preterm labor in addition to maternal vital signs.","difficulty":"Easy"},{"id":"c19_q17","question":"A significantly injured pregnant patient should be transported to a facility that can provide:","options":["Only adult trauma care","Both maternal trauma and fetal/obstetric care","Only obstetric care","Outpatient care"],"correct":1,"rationale":"Optimal care requires capability for both maternal trauma and fetal/obstetric management.","difficulty":"Easy"},{"id":"c19_q18","question":"Transporting a 30-week pregnant patient flat and supine risks:","options":["Improved circulation","Supine hypotension from caval compression","Better fetal oxygenation","Nothing"],"correct":1,"rationale":"Supine positioning after 20 weeks compresses the vena cava, causing hypotension—always tilt left.","difficulty":"Easy"}]},"c20":{"chapter":"c20","questions":[{"id":"c20_q01","question":"Altered behavior in a trauma patient should be assumed to be due to:","options":["Intoxication alone","A treatable medical/traumatic cause until proven otherwise","Anxiety only","Faking"],"correct":1,"rationale":"Assume head injury, hypoglycemia, hypoxia, or shock first—do not blame intoxication and miss a treatable cause.","difficulty":"Easy"},{"id":"c20_q02","question":"Opioid intoxication characteristically causes:","options":["Tachycardia and dilated pupils","Sedation, pinpoint pupils, and respiratory depression","Hyperthermia and agitation","Hypertension and tremor"],"correct":1,"rationale":"Opioids produce sedation, pinpoint pupils, and dangerous respiratory depression.","difficulty":"Medium"},{"id":"c20_q03","question":"Stimulant intoxication typically causes:","options":["Bradycardia and sedation","Tachycardia, agitation, dilated pupils, and hyperthermia","Pinpoint pupils","Respiratory depression"],"correct":1,"rationale":"Stimulants drive tachycardia, agitation, mydriasis, and hyperthermia.","difficulty":"Medium"},{"id":"c20_q04","question":"Every impaired patient should have a check of:","options":["Only blood pressure","Blood glucose and oxygen saturation","Temperature only","Nothing"],"correct":1,"rationale":"Glucose and SpO2 identify hypoglycemia and hypoxia that mimic or worsen impairment.","difficulty":"Easy"},{"id":"c20_q05","question":"The best interactive style with an impaired patient is:","options":["Confrontational and loud","Calm, nonjudgmental, and reassuring","Silent and distant","Threatening"],"correct":1,"rationale":"A calm, nonjudgmental approach de-escalates and improves cooperation.","difficulty":"Easy"},{"id":"c20_q06","question":"Closed-ended questions are useful with a difficult patient because they:","options":["Take longer","Are easier to answer and reduce confrontation","Require detailed answers","Confuse the patient"],"correct":1,"rationale":"Simple yes/no questions are easier for an impaired patient and lower conflict.","difficulty":"Easy"},{"id":"c20_q07","question":"Excited delirium is best described as:","options":["Mild confusion","Extreme agitation, hyperthermia, and aggression that can cause sudden death","A type of seizure","Simple intoxication"],"correct":1,"rationale":"Excited delirium is a life-threatening hyperadrenergic state that can progress to collapse and death.","difficulty":"Medium"},{"id":"c20_q08","question":"Excited delirium should be managed by:","options":["Prolonged physical struggle only","Rapid control, sedation per protocol, cooling, and continuous monitoring","Ignoring it","Leaving the patient prone and restrained"],"correct":1,"rationale":"It is a medical emergency needing rapid control, chemical sedation, cooling, and monitoring—not prolonged restraint.","difficulty":"Hard"},{"id":"c20_q09","question":"Which restraint position must be avoided?","options":["Lateral recovery position","Prone/hog-tie position (risk of positional asphyxia)","Semi-sitting","Supine with tilt"],"correct":1,"rationale":"Prone/hog-tie restraint can cause positional asphyxia and death and must be avoided.","difficulty":"Medium"},{"id":"c20_q10","question":"After restraining a patient, you must:","options":["Stop monitoring","Continuously reassess breathing, circulation, and condition","Place them prone","Leave them alone"],"correct":1,"rationale":"Restrained patients require continuous monitoring to detect deterioration and asphyxia.","difficulty":"Easy"},{"id":"c20_q11","question":"A patient's capacity to refuse care may be lost when:","options":["They are calm","They are significantly impaired by drugs/alcohol or altered mental status","They disagree with you","They are elderly"],"correct":1,"rationale":"Impairment can remove decision-making capacity; involve medical direction and follow protocol/law.","difficulty":"Medium"},{"id":"c20_q12","question":"An impaired patient with a declining mental status should make you suspect:","options":["Only deeper intoxication","A possible expanding intracranial hemorrhage or other treatable cause","Nothing","Improvement"],"correct":1,"rationale":"Worsening mental status can reflect intracranial bleeding or other emergencies, not just intoxication.","difficulty":"Medium"},{"id":"c20_q13","question":"Opioid-impaired patients require close attention to:","options":["Blood sugar only","Respiratory depression—support ventilation and consider naloxone","Skin color only","Pupil size only"],"correct":1,"rationale":"Respiratory depression is the lethal threat in opioid intoxication; support ventilation and consider naloxone.","difficulty":"Medium"},{"id":"c20_q14","question":"Before approaching an agitated impaired patient, the priority is:","options":["Starting an IV","Ensuring scene and personal safety","Taking a full history","Applying a splint"],"correct":1,"rationale":"Scene and provider safety come first when approaching an agitated patient.","difficulty":"Easy"},{"id":"c20_q15","question":"Why perform a careful, systematic exam on an impaired patient?","options":["It is unnecessary","Drugs and alcohol mask pain, hiding significant injuries","They never have injuries","To save time"],"correct":1,"rationale":"Masked pain can conceal serious injury; a diligent exam prevents missed injuries.","difficulty":"Easy"},{"id":"c20_q16","question":"Restraint should be used:","options":["Routinely on all impaired patients","Only when necessary for safety, applied humanely","As punishment","Without monitoring"],"correct":1,"rationale":"Restraint is reserved for safety, applied humanely, and the patient is continuously monitored.","difficulty":"Easy"},{"id":"c20_q17","question":"Trusted bystanders or family can help by:","options":["Increasing agitation","Calming the patient and providing history","Restraining the patient","Refusing care"],"correct":1,"rationale":"Familiar, trusted people can reassure the patient and provide useful history.","difficulty":"Easy"},{"id":"c20_q18","question":"A hyperthermic, violently agitated patient with stimulant use is showing signs of:","options":["Simple drunkenness","Excited delirium—a medical emergency","Hypoglycemia only","Neurogenic shock"],"correct":1,"rationale":"Hyperthermia plus extreme agitation after stimulant use suggests excited delirium requiring urgent treatment.","difficulty":"Medium"}]},"c21":{"chapter":"c21","questions":[{"id":"c21_q01","question":"Traumatic cardiac arrest differs from medical arrest mainly because:","options":["It is always due to a dysrhythmia","Its cause is usually a mechanical/reversible problem","It cannot be treated","It requires only defibrillation"],"correct":1,"rationale":"TCPA usually stems from reversible mechanical causes (hypovolemia, hypoxia, obstruction), not a primary dysrhythmia.","difficulty":"Easy"},{"id":"c21_q02","question":"Which is a treatable cause of traumatic cardiopulmonary arrest?","options":["Chronic hypertension","Tension pneumothorax","Diabetes","Osteoporosis"],"correct":1,"rationale":"Tension pneumothorax is a reversible cause of TCPA, along with hypoxia, tamponade, and hypovolemia.","difficulty":"Easy"},{"id":"c21_q03","question":"Why are compressions alone often ineffective in trauma arrest?","options":["They are too fast","The mechanical cause (e.g., hypovolemia) must be corrected first","Compressions are contraindicated","The heart is uninjured"],"correct":1,"rationale":"Without correcting hypovolemia, tension pneumothorax, or hypoxia, there is nothing for compressions to circulate.","difficulty":"Medium"},{"id":"c21_q04","question":"In a traumatic arrest with chest trauma, you should:","options":["Apply a traction splint","Perform bilateral chest decompression for possible tension pneumothorax","Withhold oxygen","Give only chest compressions"],"correct":1,"rationale":"Bilateral needle decompression addresses a tension pneumothorax that may be causing the arrest.","difficulty":"Medium"},{"id":"c21_q05","question":"Hemorrhage in trauma arrest is managed by:","options":["Ignoring external bleeding","Aggressive control (pressure, tourniquet, hemostatic, pelvic binder) and rapid surgical transport","Only IV fluids on scene","Defibrillation"],"correct":1,"rationale":"Control the bleeding source and transport rapidly for surgery and blood—volume loss is a key reversible cause.","difficulty":"Medium"},{"id":"c21_q06","question":"A penetrating-trauma arrest with recent signs of life calls for:","options":["Prolonged on-scene resuscitation","Immediate rapid transport for possible surgical intervention","Termination of efforts","Splinting"],"correct":1,"rationale":"Penetrating arrest with recent signs of life is potentially survivable—transport immediately for surgery.","difficulty":"Hard"},{"id":"c21_q07","question":"Which finding warrants withholding resuscitation?","options":["A weak pulse","Decapitation or injuries obviously incompatible with life","A single gunshot wound with a pulse","Mild hypotension"],"correct":1,"rationale":"Injuries incompatible with life (decapitation, incineration, etc.) justify withholding resuscitation per protocol.","difficulty":"Medium"},{"id":"c21_q08","question":"Reliable signs of death that support withholding resuscitation include:","options":["Tachycardia","Rigor mortis and dependent lividity","A faint pulse","Agonal breathing"],"correct":1,"rationale":"Rigor mortis, dependent lividity, and decomposition indicate irreversible death.","difficulty":"Medium"},{"id":"c21_q09","question":"Foreign-body airway obstruction (FBAO) is important because it:","options":["Cannot be treated","Causes a hypoxic arrest that is rapidly reversible","Only affects adults","Requires defibrillation"],"correct":1,"rationale":"Relieving the obstruction can immediately reverse a hypoxic arrest.","difficulty":"Easy"},{"id":"c21_q10","question":"A conscious adult with a severe FBAO is treated with:","options":["Back slaps only","Abdominal thrusts (chest thrusts if pregnant/obese)","Chest compressions","A finger sweep"],"correct":1,"rationale":"Abdominal thrusts are used for the conscious severely obstructed adult; chest thrusts for pregnant/obese patients.","difficulty":"Easy"},{"id":"c21_q11","question":"An unconscious choking patient should receive:","options":["Abdominal thrusts while standing","CPR with removal of a visualized object, considering Magill forceps","No intervention","Only oxygen by mask"],"correct":1,"rationale":"Begin CPR, remove a seen object, and consider laryngoscopy with Magill forceps for the unconscious FBAO patient.","difficulty":"Medium"},{"id":"c21_q12","question":"The overarching priority in TCPA is to:","options":["Administer antiarrhythmics","Identify and correct the reversible mechanical cause and transport for definitive care","Apply a cardiac monitor only","Document the rhythm"],"correct":1,"rationale":"Survival hinges on fixing the mechanical cause and reaching surgical/blood resources quickly.","difficulty":"Medium"},{"id":"c21_q13","question":"Treating trauma arrest like a medical arrest is a mistake because it:","options":["Saves time","Focuses on rhythm/drugs instead of the mechanical causes that must be fixed","Is the recommended approach","Ignores compressions"],"correct":1,"rationale":"Trauma arrest requires correcting hemorrhage, tension pneumothorax, tamponade, and hypoxia—not a rhythm-first approach.","difficulty":"Medium"},{"id":"c21_q14","question":"Airway management in trauma arrest includes:","options":["Only chest compressions","Opening/securing the airway, oxygenating, and relieving any obstruction","Withholding ventilation","A traction splint"],"correct":1,"rationale":"Securing the airway, oxygenation/ventilation, and relieving FBAO are core to TCPA management.","difficulty":"Easy"},{"id":"c21_q15","question":"For a salvageable trauma-arrest patient, prolonged on-scene resuscitation is:","options":["Preferred","Discouraged—rapid transport to surgical/blood resources is critical","Required","Always best"],"correct":1,"rationale":"After addressing reversible causes, rapid transport to definitive care is essential—do not linger on scene.","difficulty":"Medium"},{"id":"c21_q16","question":"Blood products in hemorrhagic trauma arrest serve to:","options":["Increase clot breakdown","Replace volume and oxygen-carrying capacity","Slow the heart","Treat infection"],"correct":1,"rationale":"Blood restores volume and oxygen-carrying capacity while hemorrhage control and surgery proceed.","difficulty":"Medium"},{"id":"c21_q17","question":"When withholding/termination criteria are unclear, the provider should:","options":["Always continue indefinitely","Involve medical direction and follow local protocol","Never resuscitate","Decide alone without guidance"],"correct":1,"rationale":"Consult medical direction and follow protocol when criteria for withholding/terminating are uncertain.","difficulty":"Easy"},{"id":"c21_q18","question":"The classic reversible causes of TCPA can be summarized as:","options":["Only hypovolemia","Hypoxia, tension pneumothorax, tamponade, and hypovolemia","Only dysrhythmias","Infection and fever"],"correct":1,"rationale":"Trauma-arrest reversible causes are hypoxia (airway/FBAO), tension pneumothorax, cardiac tamponade, and hypovolemia.","difficulty":"Easy"}]},"c22":{"chapter":"c22","questions":[{"id":"c22_q01","question":"The principle of standard precautions is to:","options":["Use PPE only for known infections","Treat all patients' blood and body fluids as potentially infectious","Use gloves only for surgery","Avoid hand hygiene"],"correct":1,"rationale":"Standard precautions apply universally because infection status is often unknown.","difficulty":"Easy"},{"id":"c22_q02","question":"Which is a component of standard precautions?","options":["Fit-tested N95 for every patient","Hand hygiene and gloves, with eye/face/gown protection when splashing is possible","Negative-pressure rooms always","No PPE for stable patients"],"correct":1,"rationale":"Hand hygiene and gloves are baseline, with added barriers when splash exposure is possible.","difficulty":"Easy"},{"id":"c22_q03","question":"The three most important bloodborne viral illnesses for providers are:","options":["Influenza, TB, measles","HBV, HCV, and HIV","COVID, RSV, mumps","Tetanus, rabies, malaria"],"correct":1,"rationale":"Hepatitis B, hepatitis C, and HIV are the key bloodborne viral risks.","difficulty":"Easy"},{"id":"c22_q04","question":"Which bloodborne virus is vaccine-preventable?","options":["HIV","Hepatitis C","Hepatitis B","None of them"],"correct":2,"rationale":"Hepatitis B has an effective vaccine; HCV and HIV do not.","difficulty":"Easy"},{"id":"c22_q05","question":"Of HBV, HCV, and HIV, which is the most transmissible?","options":["HIV","Hepatitis C","Hepatitis B","They are equal"],"correct":2,"rationale":"Hepatitis B is the most readily transmitted of the three.","difficulty":"Medium"},{"id":"c22_q06","question":"Bloodborne viruses are transmitted to providers primarily by:","options":["Casual conversation","Needlesticks, mucous-membrane splashes, and non-intact skin contact","Shaking hands","Airborne particles"],"correct":1,"rationale":"Transmission occurs via blood/fluids through needlesticks, mucous membranes, or broken skin.","difficulty":"Medium"},{"id":"c22_q07","question":"Droplet precautions (surgical mask) are used for:","options":["Tuberculosis","Influenza and meningococcus","Measles","MRSA wound colonization"],"correct":1,"rationale":"Large-droplet diseases like influenza and meningococcus require a surgical mask.","difficulty":"Medium"},{"id":"c22_q08","question":"Airborne precautions with a fit-tested N95 are required for:","options":["Influenza","Tuberculosis, measles, and varicella","Contact-spread organisms","All patients"],"correct":1,"rationale":"Small-particle airborne diseases (TB, measles, varicella) require N95 respirators.","difficulty":"Medium"},{"id":"c22_q09","question":"Contact precautions involve:","options":["N95 respirator","Gown and gloves for touch-spread organisms","Surgical mask only","No additional PPE"],"correct":1,"rationale":"Contact precautions add a gown and gloves for organisms spread by touch.","difficulty":"Easy"},{"id":"c22_q10","question":"Symptoms suggesting tuberculosis include:","options":["Sudden chest pain","Chronic cough, fever, night sweats, and weight loss","Localized rash only","Acute abdominal pain"],"correct":1,"rationale":"Chronic cough with fever, night sweats, and weight loss should prompt airborne precautions for possible TB.","difficulty":"Medium"},{"id":"c22_q11","question":"The BCG vaccine can complicate TB screening because it:","options":["Prevents all TB","Can cause a positive TB skin test","Is a bloodborne virus","Requires airborne precautions"],"correct":1,"rationale":"BCG, used in some countries, can produce a positive skin test, requiring clinical interpretation.","difficulty":"Hard"},{"id":"c22_q12","question":"The first action after a needlestick exposure is to:","options":["Ignore it if the patient looks healthy","Wash the site immediately with soap and water","Apply a tourniquet","Wait until the end of shift"],"correct":1,"rationale":"Immediately wash the site (flush mucous membranes), then report and seek evaluation.","difficulty":"Easy"},{"id":"c22_q13","question":"HIV post-exposure prophylaxis (PEP) is most effective when:","options":["Started a week later","Started as soon as possible after exposure","Never started","Only given orally at home"],"correct":1,"rationale":"PEP is time-sensitive and most effective when begun within hours of exposure.","difficulty":"Medium"},{"id":"c22_q14","question":"Regarding hepatitis C after exposure:","options":["There is effective PEP","There is no PEP, but early identification allows monitoring and treatment","It is vaccine-preventable","It cannot be treated"],"correct":1,"rationale":"No PEP exists for HCV, but early detection enables monitoring and curative treatment if infection occurs.","difficulty":"Medium"},{"id":"c22_q15","question":"Why apply standard precautions to apparently 'low-risk' patients?","options":["It wastes resources","Infection status is frequently unknown","It is not necessary","Only high-risk patients transmit disease"],"correct":1,"rationale":"Because many infections are unrecognized, universal precautions protect against unknown risks.","difficulty":"Easy"},{"id":"c22_q16","question":"After an exposure, the provider should:","options":["Keep it private and do nothing","Report it per protocol and seek prompt evaluation","Wait several days","Self-prescribe antibiotics"],"correct":1,"rationale":"Reporting and prompt evaluation enable timely PEP and follow-up testing.","difficulty":"Easy"},{"id":"c22_q17","question":"The correct PPE for a suspected measles patient is:","options":["Surgical mask only","Fit-tested N95 for the provider and a surgical mask on the patient","Gloves only","No PPE"],"correct":1,"rationale":"Measles is airborne—use an N95 and place a surgical mask on the patient.","difficulty":"Medium"},{"id":"c22_q18","question":"Hepatitis B-vaccinated providers exposed to blood are:","options":["Unprotected","Strongly protected, with follow-up testing/prophylaxis as indicated","Required to start HIV PEP only","Immune to all viruses"],"correct":1,"rationale":"HBV vaccination provides strong protection; follow-up and any needed prophylaxis are arranged based on status.","difficulty":"Medium"}]}},"scenarios":{"c01":{"chapter":"c01","cases":[{"id":"c01_s01","title":"Multiple Patient Scene with Potential Hazards","presentation":"Upon arrival at a road traffic accident scene, you find a slight fuel odor and no fire danger. The senior fire officer reports that the driver is uninjured but the pedestrian appears to be unresponsive with an airway compromise. You have donned gloves and are proceeding to assess the pedestrian.","vitals":{"hr":"108 bpm","bp":"95/62 mmHg","rr":"24 bpm","spo2":"93%","temp":"97.8 F"},"question":"What is the most appropriate next action?","options":["A: Perform a focused exam on the driver.","B: Secure the scene and initiate primary survey on the pedestrian.","C: Request additional resources for the vehicle spill.","D: Conduct a rapid trauma survey of both patients."],"correct":1,"explanation":"The most appropriate next action is to secure the scene and initiate a primary survey on the pedestrian. The patient's unresponsiveness and airway compromise are critical concerns that require immediate attention, even though the driver appears uninjured.","clinicalPearl":"In multiple patient scenes, prioritize patients based on their level of consciousness and airway status."},{"id":"c01_s02","title":"Head-on Collision with Potential Cervical Spine Injury","presentation":"You arrive at the scene of a head-on collision where an ambulance is staged approximately one-half mile upwind. Upon arrival, you smell diesel fuel and see a four-door sedan damaged in the front and left fender with a starred windshield. A man on the ground 30 feet behind the car is not moving.","vitals":{"hr":"120 bpm","bp":"85/60 mmHg","rr":"28 bpm","spo2":"94%","temp":"97.3 F"},"question":"What should be your initial assessment focus?","options":["A: Check for consciousness and airway.","B: Perform a rapid trauma survey of the vehicle's interior.","C: Look for signs of cervical spine injury in the driver.","D: Assess the fuel spill and potential hazards."],"correct":0,"explanation":"The initial assessment should focus on checking for consciousness and airway. The patient is unresponsive, which requires immediate attention.","clinicalPearl":"In head-on collisions, maintain a high index of suspicion for cervical spine injuries due to the rapid forward deceleration mechanism."},{"id":"c01_s03","title":"Rear-impact Collision with Potential Spinal Injury","presentation":"You are dispatched to a rear-end collision where two vehicles are involved. The driver of the rear vehicle is complaining of neck pain and tingling in his right arm. He states that he was hit from behind while driving.","vitals":{"hr":"105 bpm","bp":"120/80 mmHg","rr":"16 bpm","spo2":"98%","temp":"98.7 F"},"question":"What is the most appropriate next step?","options":["A: Perform a focused exam on the driver.","B: Conduct a rapid trauma survey of both vehicles.","C: Check for seat belt usage and airbag deployment in the rear vehicle.","D: Assess the potential for spinal injury based on the mechanism of injury."],"correct":3,"explanation":"The most appropriate next step is to assess the potential for spinal injury based on the mechanism of injury. Rear-impact collisions can cause significant cervical spine injuries, especially if the driver was not properly restrained.","clinicalPearl":"In rear-end collisions, consider the possibility of cervical spine injury due to the rapid forward deceleration and hyperextension mechanisms."}]},"c02":{"chapter":"c02","cases":[{"id":"c02_s01","title":"Pedestrian Hit by Car with Suspected Spinal Injury","presentation":"A pedestrian was struck by a car in the middle of a road. Fire service has contained hazards, and the scene is safe to enter. The patient is unresponsive and lying on their back. You approach the scene and find that the patient has a large hematoma over the right eye and a contusion at the front of the neck. There are no obvious open wounds or penetrating injuries.","vitals":{"hr":"105 bpm","bp":"98/62 mmHg","rr":"24 bpm","spo2":"96%","temp":"98.3 F"},"question":"What is the most appropriate next action?","options":["A: Perform a rapid trauma survey.","B: Apply a cervical collar and begin an ongoing assessment.","C: Transport immediately to the hospital.","D: Check for signs of internal bleeding."],"correct":1,"explanation":"Given that the patient is unresponsive, has a large hematoma over the right eye, and a contusion at the front of the neck, which could indicate spinal injury, the most appropriate next action is to apply a cervical collar and begin an ongoing assessment. This ensures proper immobilization while assessing for any changes in condition.","clinicalPearl":"Always prioritize spinal immobilization when there are signs of potential spinal injury."},{"id":"c02_s02","title":"Multiple Casualties from a Vehicle Collision","presentation":"You arrive at the scene of a vehicle collision with multiple casualties. The fire service has contained hazards, and the scene is safe to enter. You identify two patients: one patient is lying on their back with no obvious external injuries but is unresponsive; the other patient is conscious and complaining of chest pain.","vitals":{"hr":"120 bpm","bp":"85/60 mmHg","rr":"30 bpm","spo2":"94%","temp":"97.8 F"},"question":"What is the most appropriate initial action?","options":["A: Perform a rapid trauma survey on both patients.","B: Prioritize the patient with chest pain and perform an ongoing assessment.","C: Transport the unresponsive patient immediately to the hospital.","D: Apply a cervical collar to the conscious patient."],"correct":0,"explanation":"The most appropriate initial action is to prioritize the patient who is unresponsive, as they are at higher risk for life-threatening conditions. Perform an initial assessment on this patient first before moving on to the other.","clinicalPearl":"In multiple casualty situations, prioritize patients based on their level of consciousness and potential for immediate life-threatening injuries."},{"id":"c02_s03","title":"Patient with Suspected Internal Bleeding from a Fall","presentation":"You are called to the scene of a fall from a height. The patient is lying on their back and appears pale, with cold extremities. There is no obvious external bleeding, but the patient is unresponsive.","vitals":{"hr":"130 bpm","bp":"78/52 mmHg","rr":"26 bpm","spo2":"92%","temp":"97.4 F"},"question":"What is the most appropriate next step?","options":["A: Perform a rapid trauma survey.","B: Apply a cervical collar and begin an ongoing assessment.","C: Transport immediately to the hospital.","D: Check for signs of internal bleeding."],"correct":3,"explanation":"Given the patient's pale appearance, cold extremities, unresponsiveness, and history of a fall from height, it is most appropriate to check for signs of internal bleeding. This can be done during an ongoing assessment while ensuring spinal immobilization.","clinicalPearl":"In cases with potential internal bleeding, always perform a thorough ongoing assessment to monitor for changes in condition."}]},"c03":{"chapter":"c03","cases":[{"id":"c03_s01","title":"Rollover MVC — Sequencing the Primary Survey","presentation":"You arrive at a single-vehicle rollover. A restrained 28-year-old male is still in the driver's seat, awake but confused, with noisy breathing and a bleeding scalp laceration that is soaking his collar. The scene is secured by fire.","vitals":{"hr":"118 bpm","bp":"104/70 mmHg","rr":"26/min noisy","spo2":"92%","gcs":"13"},"question":"After scene size-up, what is the correct first action in the initial assessment?","options":["Apply a traction splint to the legs","Control the actively bleeding scalp laceration, then assess LOC and airway","Obtain a full SAMPLE history","Perform a detailed neurologic exam"],"correct":1,"explanation":"Using CABC, life-threatening external bleeding is controlled first (direct pressure to the scalp), then you assess level of consciousness and immediately address the noisy airway. The generalized mechanism warrants a rapid trauma survey to follow.","clinicalPearl":"Noisy breathing is obstructed breathing—address airway sounds the moment you hear them rather than waiting to finish the survey."},{"id":"c03_s02","title":"Deciding Load-and-Go","presentation":"A 45-year-old struck by a car is found supine. During the rapid trauma survey you note a tender, rigid abdomen and an unstable pelvis. He is pale and diaphoretic with a thready radial pulse.","vitals":{"hr":"132 bpm","bp":"86/58 mmHg","rr":"24/min","spo2":"94%","skin":"pale, cool, clammy"},"question":"What is the most appropriate decision at this point?","options":["Complete a full secondary survey on scene before moving","Declare load-and-go, package, and transport immediately with IV access en route","Apply bilateral traction splints first","Stay on scene to start two large-bore IVs and infuse 2 liters"],"correct":1,"explanation":"A tender/rigid abdomen and unstable pelvis with signs of shock indicate internal hemorrhage—a critical trauma situation. This patient is load-and-go: transport immediately, begin IV fluid therapy en route, and notify the trauma center early.","clinicalPearl":"Unstable pelvis plus bilateral femur fractures or a rigid abdomen should make you anticipate and treat for hemorrhagic shock."},{"id":"c03_s03","title":"Ongoing Exam Catches a Deteriorating Patient","presentation":"En route, your previously stable chest-trauma patient becomes increasingly anxious and short of breath. On your Ongoing Exam, breath sounds are now absent on the right and his neck veins appear more distended than before.","vitals":{"hr":"128 bpm","bp":"92/64 mmHg","rr":"30/min labored","spo2":"88%","skin":"pale"},"question":"What does the Ongoing Exam most likely reveal, and what is indicated?","options":["Hyperglycemia — give insulin","Developing tension pneumothorax — prepare for needle decompression","Normal progression — no action","Simple anxiety — administer a sedative"],"correct":1,"explanation":"New absent breath sounds on one side with rising JVD, hypoxia, and hypotension indicate a developing tension pneumothorax. The Ongoing Exam exists precisely to catch this evolution so you can decompress promptly.","clinicalPearl":"Repeat the Ongoing Exam after every condition change—deterioration during transport is common and treatable when caught early."}]},"c04":{"chapter":"c04","cases":[{"id":"c04_s01","title":"Facial Trauma with Bloody Airway","presentation":"A 32-year-old male struck in the face during an assault is semi-conscious with blood and broken teeth in his mouth. He has gurgling respirations and is maintaining his own airway poorly. The cervical spine is being held in line.","vitals":{"hr":"104 bpm","bp":"128/80 mmHg","rr":"22/min gurgling","spo2":"90%","gcs":"11"},"question":"What is the most appropriate immediate airway action?","options":["Insert a nasopharyngeal airway","Suction the airway and open it with a modified jaw thrust","Perform immediate surgical cricothyrotomy","Place the patient supine and apply a nonrebreather only"],"correct":1,"explanation":"Gurgling means fluid in the airway—suction first, and open the airway with a modified jaw thrust to protect the cervical spine. Definitive airway management follows once the airway is cleared and the patient is preoxygenated.","clinicalPearl":"Suction before you visualize. You cannot intubate or ventilate effectively through a mouth full of blood and debris."},{"id":"c04_s02","title":"Hypoventilating Head-Injured Patient","presentation":"An 18-year-old fell from a roof. He is unresponsive with slow, shallow breathing at 6 per minute and snoring respirations. SpO2 is dropping.","vitals":{"hr":"58 bpm","bp":"168/96 mmHg","rr":"6/min shallow","spo2":"85%","gcs":"6"},"question":"What is the priority intervention?","options":["Hyperventilate at 24 breaths/min routinely","Open the airway, then assist ventilations with BVM and oxygen at 8–10/min confirming chest rise","Apply a nonrebreather and reassess in 5 minutes","Withhold ventilation until intubation equipment arrives"],"correct":1,"explanation":"Snoring indicates the tongue obstructing the airway—open it (jaw thrust/adjunct). A rate of 6/min with hypoxia is inadequate ventilation, so assist with BVM and oxygen at 8–10/min. The bradycardia and hypertension hint at rising intracranial pressure; avoid routine hyperventilation unless herniation signs appear.","clinicalPearl":"Hypoventilation worsens secondary brain injury. Support ventilation to normal rates and oxygenation—do not over-ventilate."},{"id":"c04_s03","title":"Anticipating a Difficult Airway","presentation":"A 60-year-old obese patient with a short, thick neck is in a cervical collar after a motorcycle crash. He is breathing but tiring, with SpO2 92% on a nonrebreather. Your protocol allows drug-assisted intubation.","vitals":{"hr":"110 bpm","bp":"138/84 mmHg","rr":"24/min","spo2":"92%","gcs":"13"},"question":"Which step best optimizes a safe first intubation attempt?","options":["Remove the collar and hyperextend the neck","Apply apneic oxygenation by nasal cannula and prepare external laryngeal manipulation plus a backup BIAD","Skip preoxygenation to save time","Attempt intubation repeatedly regardless of saturation"],"correct":1,"explanation":"Obesity, short neck, and in-line immobilization predict a difficult airway (MMAP). Apneic oxygenation prolongs safe apnea, ELM improves the glottic view, and a backup BIAD/plan must be ready. The collar/in-line stabilization is maintained, not removed.","clinicalPearl":"Predict difficulty before you act: optimize position, preoxygenate, use apneic oxygenation and ELM, and always have a rescue device ready."}]},"c05":{"chapter":"c05","cases":[{"id":"c05_s01","title":"Vomiting Unresponsive Patient","presentation":"An unresponsive 50-year-old ejected from a vehicle suddenly vomits. You hear loud gurgling. Your partner is maintaining in-line cervical stabilization.","vitals":{"hr":"112 bpm","bp":"118/76 mmHg","rr":"10/min","spo2":"89%","gcs":"5"},"question":"What is the immediate priority?","options":["Insert an OPA without suctioning","Suction with a rigid tip, then ventilate with BVM and oxygen","Attempt nasotracheal intubation immediately","Apply a nonrebreather and reassess"],"correct":1,"explanation":"Active vomiting and gurgling require immediate suctioning with a rigid (Yankauer) tip to protect the airway from aspiration, followed by assisted ventilation with BVM and oxygen. Definitive airway management follows once the airway is clear.","clinicalPearl":"Keep a working rigid suction within arm's reach for every obtunded trauma patient—aspiration can occur in seconds."},{"id":"c05_s02","title":"Failed Intubation, Rescue Plan","presentation":"You are managing a difficult trauma airway. After one intubation attempt the SpO2 falls from 96% to 84% and you could not visualize the cords.","vitals":{"hr":"124 bpm","bp":"126/82 mmHg","rr":"assisted","spo2":"84%","gcs":"3T attempt"},"question":"What is the best next action?","options":["Immediately reattempt intubation","Stop, ventilate with BVM to reoxygenate, then place a supraglottic rescue airway","Perform a surgical airway right away","Withhold ventilation and transport"],"correct":1,"explanation":"When an attempt fails and the patient desaturates, the priority is reoxygenation by BVM. A supraglottic (BIAD) rescue airway is the appropriate next device. A surgical airway is reserved for true cannot-intubate, cannot-ventilate situations.","clinicalPearl":"Oxygenation, not tube placement, is the goal. Reoxygenate between attempts and move to a rescue device early."},{"id":"c05_s03","title":"Confirming the Tube After a Move","presentation":"You intubated a crash patient on the ground and confirmed placement with capnography. After lifting him onto the stretcher and into the ambulance, the capnography waveform suddenly flattens and breath sounds are now absent.","vitals":{"hr":"130 bpm","bp":"104/70 mmHg","rr":"assisted","spo2":"falling","gcs":"3T"},"question":"What is the most likely problem and action?","options":["Equipment artifact — ignore it","Tube dislodgement during the move — reassess placement and re-intubate or rescue-ventilate","Normal finding after transport","Hyperglycemia — give insulin"],"correct":1,"explanation":"A sudden loss of waveform and breath sounds after moving the patient signals tube dislodgement (a leading cause of airway disaster). Reassess immediately: visualize/re-confirm, re-intubate, or ventilate with BVM/BIAD while reoxygenating.","clinicalPearl":"Reconfirm tube placement with capnography after every move—the flat waveform is your early-warning system."}]},"c06":{"chapter":"c06","cases":[{"id":"c06_s01","title":"Stabbing with Deteriorating Vitals","presentation":"A 24-year-old male was stabbed in the right anterior chest. He is anxious and severely short of breath. Breath sounds are absent on the right, the right chest is hyperresonant, and his neck veins are distended.","vitals":{"hr":"138 bpm","bp":"82/54 mmHg","rr":"34/min labored","spo2":"84%","skin":"cyanotic"},"question":"What is the most appropriate immediate intervention?","options":["Apply a fully airtight occlusive dressing only","Perform needle chest decompression of the right side","Start two liters of IV fluid before any other action","Apply a traction splint"],"correct":1,"explanation":"Absent breath sounds and hyperresonance on the right with JVD, hypotension, cyanosis, and respiratory distress are a tension pneumothorax. With signs plus respiratory distress/cyanosis and shock, emergency needle decompression is indicated immediately.","clinicalPearl":"Tension pneumothorax is a clinical diagnosis—decompress on signs and shock; do not wait for tracheal deviation."},{"id":"c06_s02","title":"Distinguishing Hemothorax from Tension","presentation":"A 40-year-old was shot in the left chest. He is pale and diaphoretic. The left chest is dull to percussion with decreased breath sounds, and his neck veins are flat.","vitals":{"hr":"130 bpm","bp":"78/50 mmHg","rr":"28/min","spo2":"90%","skin":"pale, cool"},"question":"What is the most likely injury and the correct management?","options":["Tension pneumothorax — needle decompression","Massive hemothorax — treat shock, give oxygen, rapid transport","Cardiac tamponade — pericardiocentesis on scene","Flail chest — tape the segment"],"correct":1,"explanation":"Dullness to percussion, decreased breath sounds, FLAT neck veins, and hypovolemic shock indicate massive hemothorax. Decompression does not relieve blood; manage shock, oxygenate, and transport rapidly to surgical care.","clinicalPearl":"Flat neck veins + dullness = blood (hemothorax). Distended neck veins + hyperresonance = air (tension pneumothorax)."},{"id":"c06_s03","title":"Beck's Triad After Blunt Trauma","presentation":"A restrained driver struck the steering wheel. He is confused and dusky. You note distended neck veins, muffled heart tones, and a narrowing pulse pressure. Breath sounds are equal bilaterally.","vitals":{"hr":"126 bpm","bp":"88/72 mmHg","rr":"26/min","spo2":"93%","skin":"dusky"},"question":"What condition does this presentation indicate?","options":["Tension pneumothorax","Cardiac (pericardial) tamponade","Simple pneumothorax","Pulmonary contusion"],"correct":1,"explanation":"Hypotension with a narrow pulse pressure, distended neck veins, and muffled heart tones (Beck's triad) with EQUAL breath sounds points to pericardial tamponade rather than a tension pneumothorax. Provide supportive care and transport rapidly for pericardiocentesis/surgery.","clinicalPearl":"Equal breath sounds with Beck's triad favor tamponade; absent unilateral breath sounds with hyperresonance favor tension pneumothorax."}]},"c07":{"chapter":"c07","cases":[{"id":"c07_s01","title":"Tactical Casualty Behind Cover","presentation":"A casualty wearing body armor was shot in the left chest. He has severe respiratory distress, cyanosis, and you cannot palpate a radial pulse. Breath sounds are absent on the left with hyperresonance. You are still in a tactical environment.","vitals":{"hr":"140 bpm","bp":"unobtainable radial","rr":"36/min labored","spo2":"80%","skin":"cyanotic"},"question":"What is the best approach to decompression here?","options":["Remove the body armor to use the anterior site","Use the lateral approach (4th–5th ICS anterior axillary line) without removing armor","Apply a chest seal and wait","Start IV fluids only"],"correct":1,"explanation":"This is a tension pneumothorax with shock and respiratory distress—decompression is indicated. In a tactical setting the lateral approach can be performed without removing body armor and may more reliably reach the pleural space.","clinicalPearl":"Know both approaches: the lateral site is invaluable when armor or positioning makes the anterior site impractical."},{"id":"c07_s02","title":"Failed First Attempt — Catheter Too Short","presentation":"You decompress a muscular 110-kg patient anteriorly with a short 3-cm catheter, but there is no air rush and no improvement. He remains in extremis with absent left breath sounds and JVD.","vitals":{"hr":"136 bpm","bp":"84/60 mmHg","rr":"34/min","spo2":"82%","skin":"dusky"},"question":"What is the most likely problem and the fix?","options":["The diagnosis is wrong — stop decompression","The catheter was too short to reach the pleural space — repeat with a 6–9 cm catheter","He needs a traction splint","Give insulin for hyperglycemia"],"correct":1,"explanation":"A short catheter frequently fails to reach the pleural space in muscular or obese patients. Repeat the decompression with an adequately long large-bore catheter (6–9 cm), or use the lateral approach.","clinicalPearl":"Match catheter length to chest-wall thickness—the most common reason for a 'failed' decompression is a catheter that never reached the pleura."},{"id":"c07_s03","title":"Re-accumulation En Route","presentation":"A blunt-trauma patient improved dramatically after needle decompression, with a returning radial pulse. Twenty minutes later en route he again becomes hypoxic and hypotensive with rising JVD and absent breath sounds on the same side.","vitals":{"hr":"128 bpm","bp":"90/64 mmHg","rr":"30/min","spo2":"86%","skin":"pale"},"question":"What is the appropriate action?","options":["Assume the original device fixed it permanently","Reassess and repeat decompression for a re-accumulating tension pneumothorax","Remove the original catheter and do nothing","Hyperventilate aggressively"],"correct":1,"explanation":"The catheter can kink, clot, or dislodge, allowing the tension pneumothorax to re-accumulate. Recurrent signs warrant reassessment and repeat decompression, with continued transport for definitive chest tube placement.","clinicalPearl":"Decompression is temporary—reassess frequently and be ready to decompress again if tension returns."}]},"c08":{"chapter":"c08","cases":[{"id":"c08_s01","title":"Early Shock, Normal Pressure","presentation":"A 30-year-old motorcyclist with a deformed thigh is anxious and restless. His skin is cool and pale, capillary refill is 3 seconds, and his pulse is rapid—but his blood pressure is 118/96.","vitals":{"hr":"124 bpm","bp":"118/96 mmHg","rr":"22/min","spo2":"97%","skin":"cool, pale"},"question":"How should you interpret and act on these findings?","options":["He is stable because his blood pressure is normal — no urgency","He is in compensated (early) shock — treat aggressively and transport promptly","He has neurogenic shock — give a vasopressor","He is simply anxious — reassure and release"],"correct":1,"explanation":"Tachycardia, anxiety, cool/pale skin, delayed capillary refill, and a NARROW pulse pressure (118/96) are early compensated shock. A 'normal' systolic pressure is reassuring but misleading—treat now and transport rather than waiting for hypotension.","clinicalPearl":"A narrowing pulse pressure with tachycardia is an early red flag—do not be falsely reassured by a normal systolic reading."},{"id":"c08_s02","title":"Uncontrolled Extremity Hemorrhage","presentation":"A construction worker has a mangled forearm with pulsatile bright-red bleeding that soaks through gauze despite firm direct pressure. He is pale and lightheaded.","vitals":{"hr":"130 bpm","bp":"94/70 mmHg","rr":"24/min","spo2":"96%","skin":"pale, diaphoretic"},"question":"What is the next best action?","options":["Continue direct pressure indefinitely","Apply a tourniquet proximal to the wound and note the time","Elevate the limb and apply ice","Start a large fluid bolus before controlling bleeding"],"correct":1,"explanation":"Arterial extremity hemorrhage not controlled by direct pressure requires prompt tourniquet application proximal to the wound, tightened until bleeding stops, with the time recorded. Controlling the source precedes fluid resuscitation.","clinicalPearl":"Stop the bleeding first. A tourniquet applied early is fast, effective, and life-saving for extremity hemorrhage."},{"id":"c08_s03","title":"Hypotension After a Diving Injury","presentation":"A young man dove into shallow water and cannot move his legs. He is hypotensive but his skin is warm and dry and his heart rate is slow. There is no external bleeding and the abdomen is soft.","vitals":{"hr":"52 bpm","bp":"82/60 mmHg","rr":"18/min","spo2":"98%","skin":"warm, dry"},"question":"What is the most likely cause of his hypotension and the appropriate first consideration?","options":["Hemorrhagic shock — give a rapid 2-liter bolus and search for bleeding","Neurogenic shock from spinal cord injury — support BP per protocol while still excluding hemorrhage","Cardiac tamponade — perform pericardiocentesis","Simple fainting — no treatment needed"],"correct":1,"explanation":"Hypotension with bradycardia and warm, dry skin after a cervical mechanism suggests neurogenic shock from loss of sympathetic tone. Support perfusion (judicious fluids ± vasopressor per protocol), maintain spinal motion restriction, and keep warm—while still excluding occult hemorrhage, since neurogenic shock is a diagnosis of exclusion.","clinicalPearl":"Warm, dry skin with bradycardic hypotension after a spinal mechanism suggests neurogenic shock—but always rule out bleeding first."}]},"c09":{"chapter":"c09","cases":[{"id":"c09_s01","title":"No Veins in a Crashing Patient","presentation":"A 55-year-old with severe internal bleeding is profoundly hypotensive. After two failed peripheral attempts and a failed external jugular attempt, he urgently needs access for fluids.","vitals":{"hr":"138 bpm","bp":"70/40 mmHg","rr":"26/min","spo2":"93%","skin":"cold, mottled"},"question":"What is the best next step for access?","options":["Keep attempting peripheral IVs on scene","Place an intraosseous line (proximal tibia or humerus)","Delay all access until the hospital","Give oral fluids"],"correct":1,"explanation":"Peripheral veins collapse in profound shock. After failed peripheral and EJ attempts, intraosseous access provides rapid, reliable delivery via the non-collapsible marrow. Obtain it en route—do not delay transport.","clinicalPearl":"When veins collapse in shock, go to the bone early—IO is fast and dependable, and the marrow stays patent."},{"id":"c09_s02","title":"Painful IO in an Awake Patient","presentation":"You successfully place a proximal tibial IO in an awake, talking trauma patient. As you begin to flush saline, he cries out in severe pain at the site.","vitals":{"hr":"120 bpm","bp":"96/62 mmHg","rr":"22/min","spo2":"96%","skin":"pale"},"question":"What is the appropriate management?","options":["Remove the IO immediately—it must be misplaced","Administer slow IO lidocaine per protocol before continuing the flush","Flush faster to get it over with","Stop all fluids permanently"],"correct":1,"explanation":"IO infusion is intensely painful in conscious patients because of pressure in the marrow. Provided placement is confirmed (stable needle, free flow, no swelling), give slow IO lidocaine per protocol before flushing and infusing.","clinicalPearl":"Pain on flushing a confirmed IO is expected—pretreat the awake patient with slow IO lidocaine, not removal."},{"id":"c09_s03","title":"Sizing a Pediatric Trauma Patient","presentation":"A 4-year-old was struck by a car and is unresponsive. The team needs medication doses, fluid volumes, and equipment sizes quickly, and no reliable weight is available.","vitals":{"hr":"150 bpm","bp":"80/50 mmHg","rr":"30/min","spo2":"94%","skin":"pale"},"question":"What tool best supports rapid, accurate dosing?","options":["Guess the weight from age alone","Use a length-based resuscitation tape measured head to heel","Use adult doses","Wait for a scale at the hospital"],"correct":1,"explanation":"A length-based resuscitation tape estimates the child's weight from length and provides corresponding drug doses, fluid volumes, and equipment sizes—reducing the dosing errors common in pediatric resuscitation.","clinicalPearl":"In pediatric emergencies, the length-based tape replaces guesswork—measure head to heel and read the color zone."}]},"c10":{"chapter":"c10","cases":[{"id":"c10_s01","title":"The Talk-and-Deteriorate Patient","presentation":"A 22-year-old fell from a ladder, was briefly knocked out, then woke and talked normally. Twenty minutes later he becomes increasingly drowsy and confused, and his right pupil is now larger than the left.","vitals":{"hr":"54 bpm","bp":"178/100 mmHg","rr":"12/min irregular","spo2":"96%","gcs":"9 and falling"},"question":"What is happening and what is the priority?","options":["Simple intoxication — let him sleep it off","Expanding intracranial hematoma with early herniation — secure airway, maintain BP/oxygenation, rapid neurosurgical transport, controlled hyperventilation for herniation signs","Neurogenic shock — give fluids only","Hyperglycemia — administer insulin"],"correct":1,"explanation":"A lucid interval followed by deterioration with a dilated pupil, bradycardia, hypertension, and irregular respirations (Cushing's reflex) signals an expanding hematoma and herniation. Protect the airway, maintain oxygenation and blood pressure, apply controlled mild hyperventilation (ETCO2 30–35) for herniation signs, and transport emergently to neurosurgery.","clinicalPearl":"A lucid interval that ends in deterioration is the classic epidural hematoma course—every minute to the operating room counts."},{"id":"c10_s02","title":"Don't Let the Brain Get Hypoxic or Hypotensive","presentation":"An unrestrained driver has a severe head injury (GCS 6) and a femur fracture. SpO2 reads 88% and systolic pressure is 84.","vitals":{"hr":"120 bpm","bp":"84/56 mmHg","rr":"8/min shallow","spo2":"88%","gcs":"6"},"question":"Which combination best protects this brain?","options":["Hyperventilate to ETCO2 of 25 and withhold fluids","Secure the airway, oxygenate to ≥94%, ventilate to normal ETCO2, and restore blood pressure","Focus only on the femur","Allow permissive hypotension to a systolic of 70"],"correct":1,"explanation":"Hypoxia (88%) and hypotension (84 systolic) are the two biggest causes of secondary brain injury. Secure the airway (GCS 6), oxygenate to ≥94%, ventilate to a normal ETCO2, and treat the hypotension/hemorrhage to maintain cerebral perfusion. Routine hyperventilation and permissive hypotension are wrong here.","clinicalPearl":"In the head-injured trauma patient, the usual permissive-hypotension strategy is modified—protect cerebral perfusion by keeping blood pressure up."},{"id":"c10_s03","title":"Scoring and Trending the GCS","presentation":"You assess a head-injured patient who opens his eyes to pain, makes incomprehensible sounds, and withdraws from painful stimulus.","vitals":{"hr":"98 bpm","bp":"140/88 mmHg","rr":"16/min","spo2":"97%","gcs":"calculate"},"question":"What is this patient's Glasgow Coma Scale score?","options":["GCS 5 (E1 V1 M3)","GCS 8 (E2 V2 M4)","GCS 11 (E3 V3 M5)","GCS 14 (E4 V4 M6)"],"correct":1,"explanation":"Eyes open to pain = 2, incomprehensible sounds = 2, withdraws from pain = 4, totaling GCS 8. A GCS of 8 indicates severe TBI and inability to protect the airway. Trending the GCS over time is more important than any single value.","clinicalPearl":"Always document the GCS by its components (E/V/M) and trend it—the direction of change drives decisions."}]},"c11":{"chapter":"c11","cases":[{"id":"c11_s01","title":"To Immobilize or Not?","presentation":"A 25-year-old rear-ended at low speed is walking around the scene. He is alert and sober, denies neck or back pain, has no midline tenderness, no numbness or weakness, and no other distracting injuries.","vitals":{"hr":"82 bpm","bp":"126/78 mmHg","rr":"16/min","spo2":"99%","gcs":"15"},"question":"What is the appropriate spinal management?","options":["Full immobilization on a long backboard regardless of findings","Patient-centered assessment supports NOT applying SMR; monitor and transport as appropriate","Apply a cervical collar and discharge on scene","Rapid extrication"],"correct":1,"explanation":"This reliable, alert, sober patient has no midline tenderness, no neurologic deficit, and no distracting injury. Selective (patient-centered) criteria support withholding full SMR, avoiding the harms of unnecessary immobilization.","clinicalPearl":"SMR is selective—an alert, reliable patient with a normal spinal exam and no distracting injury usually does not need a backboard."},{"id":"c11_s02","title":"Penetrating Trauma Pitfall","presentation":"A 30-year-old was shot once in the abdomen. He is in shock and needs rapid transport. He moves all extremities normally and has no neurologic complaints, but a new EMT wants to fully immobilize him on a board.","vitals":{"hr":"128 bpm","bp":"88/60 mmHg","rr":"24/min","spo2":"96%","skin":"pale"},"question":"What is the correct approach?","options":["Fully immobilize him before transport","Do not apply routine SMR for isolated penetrating trauma without deficit—expedite transport","Apply a traction splint","Delay transport to place a short device"],"correct":1,"explanation":"Routine immobilization of isolated penetrating trauma without a neurologic deficit delays transport and is associated with higher mortality. With no deficit and a critical hemorrhagic state, expedite transport to surgical care.","clinicalPearl":"Penetrating torso/neck trauma without a neuro deficit should not be routinely immobilized—time to surgery saves lives."},{"id":"c11_s03","title":"Shock in a Diving Injury","presentation":"A young man struck his head diving and cannot feel or move his legs. He is hypotensive with warm, dry, pink skin and a slow heart rate. There is no external bleeding and the abdomen is soft and nontender.","vitals":{"hr":"50 bpm","bp":"84/58 mmHg","rr":"16/min","spo2":"98%","skin":"warm, dry, pink"},"question":"What does this presentation indicate and how do you proceed?","options":["Hemorrhagic shock — ignore the spine","Neurogenic shock from cord injury — maintain SMR, support BP per protocol, keep warm, and still exclude hemorrhage","Cardiac tamponade — pericardiocentesis","Simple vasovagal episode"],"correct":1,"explanation":"Hypotension with bradycardia and warm, dry skin plus a sensorimotor deficit after a cervical mechanism indicates neurogenic shock from cord injury. Maintain spinal motion restriction, support perfusion per protocol, keep the patient warm, and continue to exclude hemorrhage since both can coexist.","clinicalPearl":"Neurogenic shock looks 'warm and slow'; hemorrhagic shock looks 'cold and fast'—but always rule out bleeding first."}]},"c12":{"chapter":"c12","cases":[{"id":"c12_s01","title":"Order of Securing","presentation":"Your team has log-rolled an SMR-eligible patient onto a long backboard. A new provider immediately tapes the head down with blocks and is about to walk away before strapping the chest and hips.","vitals":{"hr":"88 bpm","bp":"130/80 mmHg","rr":"16/min","spo2":"98%","gcs":"15"},"question":"What correction is needed?","options":["Nothing—head first is correct","Secure the torso (chest and hips) and legs first, then immobilize the head last","Remove the blocks and skip strapping","Apply a traction splint"],"correct":1,"explanation":"The head must be secured last. If the head is anchored before the torso, any shift of the body loads the cervical spine. Strap the torso and legs first, then immobilize the head with blocks and tape.","clinicalPearl":"Torso before head, every time—the head should never be the anchor point of immobilization."},{"id":"c12_s02","title":"Helmet Decision in a Motorcyclist","presentation":"A motorcyclist is down and unresponsive, still wearing a full-face helmet. You cannot access his airway, and his breathing is becoming noisy.","vitals":{"hr":"110 bpm","bp":"124/78 mmHg","rr":"noisy, 12/min","spo2":"90%","gcs":"7"},"question":"What is the appropriate action regarding the helmet?","options":["Leave the helmet on and transport","Remove the helmet with two rescuers maintaining in-line stabilization to access the airway","Cut a hole in the visor only","Wait for the hospital to remove it"],"correct":1,"explanation":"The helmet prevents airway access in a patient with a compromised airway (GCS 7, noisy breathing, falling SpO2)—a clear indication for removal. Two rescuers remove it together: one maintains in-line stabilization from below while the other spreads and lifts the helmet.","clinicalPearl":"Airway access trumps the helmet—when it blocks the airway, remove it with two rescuers and continuous stabilization."},{"id":"c12_s03","title":"Comfort and Pressure on a Long Transport","presentation":"An elderly patient with a kyphotic spine and SMR criteria faces a 60-minute transport. He is alert and complains of severe back pain lying flat on the rigid board, and gaps are visible behind his head and lower back.","vitals":{"hr":"84 bpm","bp":"150/86 mmHg","rr":"18/min","spo2":"97%","gcs":"15"},"question":"What is the best management?","options":["Force his spine flat against the board","Pad the voids to maintain neutral alignment and consider a vacuum mattress/padded stretcher for comfort and pressure relief","Remove all SMR","Apply additional straps tightly across the abdomen"],"correct":1,"explanation":"Kyphosis creates gaps that must be padded to support neutral alignment without forcing the spine flat. For a long transport, a vacuum mattress or padded surface reduces pressure injury and pain while maintaining motion restriction.","clinicalPearl":"Pad the patient's natural curves—never force the spine flat—and choose a conforming surface for long transports."}]},"c13":{"chapter":"c13","cases":[{"id":"c13_s01","title":"Seat-Belt Sign and Hidden Bleeding","presentation":"A restrained 35-year-old in a high-speed MVC has a bruise across her lower abdomen from the lap belt. She is mildly tender but says she feels 'okay.' Her heart rate is climbing and her skin is becoming cool.","vitals":{"hr":"120 bpm","bp":"108/86 mmHg","rr":"22/min","spo2":"98%","skin":"cool"},"question":"How should you proceed?","options":["Reassure and release—she feels fine","Treat as potential intra-abdominal injury: oxygen, IV en route, keep warm, rapid transport to a trauma center","Apply a traction splint","Wait for the abdomen to become rigid before acting"],"correct":1,"explanation":"A seat-belt sign with rising heart rate, narrowing pulse pressure, and cool skin signals possible intra-abdominal injury and early shock—even with a benign-feeling exam. Treat for shock and transport rapidly; do not wait for rigidity.","clinicalPearl":"A seat-belt sign plus early shock signs is intra-abdominal injury until proven otherwise—mechanism beats a reassuring exam."},{"id":"c13_s02","title":"Evisceration After a Stabbing","presentation":"A young man was stabbed in the abdomen and has a loop of bowel protruding through the wound. He is anxious and in pain.","vitals":{"hr":"118 bpm","bp":"112/74 mmHg","rr":"22/min","spo2":"98%","skin":"warm"},"question":"What is the correct wound management?","options":["Gently push the bowel back into the abdomen","Cover the exposed bowel with a moist sterile dressing and an occlusive layer; treat for shock and transport","Apply a dry tight pressure dressing","Pack the wound with hemostatic gauze around the bowel"],"correct":1,"explanation":"Never replace eviscerated organs. Cover them with a moist sterile dressing and an occlusive layer to keep them warm and moist, prevent contamination, treat for shock, and transport. Flexing the knees may reduce tension.","clinicalPearl":"Moist, cover, transport—never replace eviscerated organs into the abdomen."},{"id":"c13_s03","title":"Unstable Pelvis in Shock","presentation":"A pedestrian struck by a car has pelvic pain and is in shock. On a single gentle assessment the pelvis feels unstable. There is no external bleeding.","vitals":{"hr":"134 bpm","bp":"84/58 mmHg","rr":"24/min","spo2":"96%","skin":"pale, cool"},"question":"What is the priority intervention?","options":["Spring the pelvis several times to confirm instability","Apply a pelvic binder at the greater trochanters, treat for shock, and transport rapidly","Apply bilateral traction splints","Delay transport to obtain IV access"],"correct":1,"explanation":"An unstable pelvis with shock indicates major pelvic hemorrhage. Apply a pelvic binder at the level of the greater trochanters to close the pelvic volume and tamponade bleeding, treat for shock, and transport rapidly to surgical care. Avoid repeated pelvic manipulation.","clinicalPearl":"Bind early, assess once: a pelvic binder at the trochanters can be life-saving—repeated springing only worsens bleeding."}]},"c14":{"chapter":"c14","cases":[{"id":"c14_s01","title":"Don't Be Distracted by the Obvious","presentation":"A motorcyclist has a grotesquely angulated open tibia fracture with bone exposed. He is also pale, anxious, and breathing fast. Your new partner kneels to splint the leg immediately.","vitals":{"hr":"126 bpm","bp":"100/82 mmHg","rr":"26/min","spo2":"94%","skin":"pale"},"question":"What is the correct priority?","options":["Splint the dramatic leg fracture first","Complete the Primary Survey for life threats and treat shock; control bleeding, then address the fracture","Apply a traction splint before assessing ABCs","Transport without any assessment"],"correct":1,"explanation":"A dramatic extremity injury must not distract from life threats. Tachycardia, pallor, tachypnea, and a narrowing pulse pressure suggest shock—complete the Primary Survey, control hemorrhage, and treat for shock. The open fracture is covered and managed after life threats.","clinicalPearl":"The most eye-catching injury is rarely the most lethal—finish the Primary Survey before splinting."},{"id":"c14_s02","title":"Pulseless Angulated Forearm","presentation":"A teenager fell off a skateboard with a severely angulated forearm. The hand is pale and cool, and you cannot palpate a radial pulse distal to the deformity. Capillary refill is delayed.","vitals":{"hr":"104 bpm","bp":"122/76 mmHg","rr":"18/min","spo2":"99%","skin":"hand pale, cool"},"question":"What is the appropriate management?","options":["Splint exactly as found and transport","Apply gentle in-line traction to realign and attempt to restore distal circulation, then splint and recheck the pulse","Forcefully snap it straight","Apply a tourniquet above the elbow"],"correct":1,"explanation":"An absent distal pulse with a pale, cool hand is limb-threatening ischemia. Gentle in-line traction to realign the angulated fracture may restore circulation; then splint and recheck PMS. If the pulse does not return, splint and transport rapidly.","clinicalPearl":"A pulseless, angulated long-bone fracture warrants gentle realignment to restore perfusion—then recheck and document the pulse."},{"id":"c14_s03","title":"Prolonged Entrapment and Crush","presentation":"A worker's legs were pinned under a collapsed wall for over two hours. Heavy machinery is about to free him. He is alert with crushed, insensate legs.","vitals":{"hr":"110 bpm","bp":"118/74 mmHg","rr":"20/min","spo2":"98%","skin":"legs cold, mottled"},"question":"What is the key concern as the crushing force is released?","options":["Nothing changes on release","Crush syndrome with hyperkalemia and dysrhythmias—coordinate fluid resuscitation and monitoring with medical direction before/at release","Compartment syndrome is impossible here","He needs only a splint"],"correct":1,"explanation":"Prolonged crush causes rhabdomyolysis; releasing the compression washes potassium and myoglobin into the circulation, risking hyperkalemia, lethal dysrhythmias, and renal failure (crush syndrome). Establish IV access, begin fluids, apply cardiac monitoring, and coordinate management with medical direction around the moment of release.","clinicalPearl":"The dangerous moment in a prolonged crush is the release—pre-treat with fluids and monitoring for hyperkalemia per medical direction."}]},"c15":{"chapter":"c15","cases":[{"id":"c15_s01","title":"Isolated Femur Fracture in a Stable Patient","presentation":"A 20-year-old soccer player has an isolated, painful, deformed mid-thigh. Distal pulses, motor, and sensation are intact. He is otherwise stable with normal vitals, and transport time is 25 minutes.","vitals":{"hr":"92 bpm","bp":"126/78 mmHg","rr":"16/min","spo2":"99%","skin":"warm"},"question":"What is the appropriate management of the leg?","options":["Apply a traction splint after confirming no hip/knee/pelvis involvement, rechecking PMS before and after","Apply traction across the knee","Skip assessment of distal pulses","Defer all splinting and do nothing"],"correct":0,"explanation":"An isolated mid-shaft femur fracture in a stable patient is the ideal indication for a traction splint. Confirm the hip, knee, and pelvis are not involved, assess distal PMS before and after, and apply only enough traction to realign and relieve pain.","clinicalPearl":"Traction splints shine for the isolated mid-shaft femur fracture—but only after you've excluded hip, knee, and pelvic involvement."},{"id":"c15_s02","title":"Wrong Splint for the Injury","presentation":"A patient has an obviously deformed, painful knee after a fall. A trainee reaches for a traction splint to 'pull it straight.'","vitals":{"hr":"96 bpm","bp":"130/82 mmHg","rr":"16/min","spo2":"98%","skin":"warm"},"question":"Why is the traction splint the wrong choice here?","options":["Traction splints are only for arms","Traction across a fractured/dislocated knee can tear the popliteal vessels—immobilize the knee in position instead","It is too slow","Knees never need immobilization"],"correct":1,"explanation":"Traction splints are only for mid-shaft femur fractures. Applying traction to a knee injury can lacerate the popliteal artery. Immobilize the knee in the position found (if pulses are intact) and reassess distal PMS.","clinicalPearl":"Never apply traction across the knee—splint joint injuries in the position found when perfusion is intact."},{"id":"c15_s03","title":"Massive Extremity Hemorrhage","presentation":"A worker's arm was caught in machinery, leaving a deep, spurting wound at the upper arm. Direct pressure has not controlled the bleeding and he is becoming pale.","vitals":{"hr":"128 bpm","bp":"96/64 mmHg","rr":"22/min","spo2":"97%","skin":"pale"},"question":"What is the correct sequence of hemorrhage control?","options":["Loosely wrap gauze and transport","Apply a tourniquet 2–3 inches proximal to the wound, tighten until bleeding stops and pulse is gone, note the time","Apply a traction splint","Periodically loosen pressure to check the wound"],"correct":1,"explanation":"Arterial extremity hemorrhage uncontrolled by direct pressure requires a tourniquet placed 2–3 inches proximal to the wound (not over a joint), tightened until bleeding stops and the distal pulse disappears, with the time recorded. If a tourniquet cannot control a junctional component, pack with a hemostatic dressing.","clinicalPearl":"A tourniquet works only when tight enough to abolish the distal pulse—an under-tightened tourniquet bleeds more than none at all."}]},"c16":{"chapter":"c16","cases":[{"id":"c16_s01","title":"House Fire with Airway Risk","presentation":"A man was pulled from a burning bedroom. He has facial burns, singed nasal hairs, soot around his mouth, and a hoarse voice. He is coughing up black sputum.","vitals":{"hr":"112 bpm","bp":"138/84 mmHg","rr":"24/min","spo2":"98%","gcs":"14"},"question":"What is the priority intervention?","options":["Apply a dry dressing to the face and reassess in 20 minutes","Anticipate airway swelling—give high-flow oxygen and secure the airway early; treat for possible CO poisoning","Trust the 98% SpO2 and provide only routine care","Cool the face with prolonged wet dressings"],"correct":1,"explanation":"Facial burns, singed hairs, soot, hoarseness, and carbonaceous sputum signal impending airway obstruction from inhalation injury. Give high-flow oxygen and secure the airway early before edema closes it. The 98% SpO2 is falsely reassuring—carbon monoxide poisoning must be treated empirically with 100% oxygen.","clinicalPearl":"In inhalation injury, the window for an easy airway closes fast—intubate early and never trust the pulse oximeter for CO."},{"id":"c16_s02","title":"Estimating Burn Size","presentation":"An adult has partial- and full-thickness burns covering the entire front of the torso, the entire left arm, and the entire anterior aspect of one leg.","vitals":{"hr":"118 bpm","bp":"120/78 mmHg","rr":"22/min","spo2":"99%","skin":"burned areas as described"},"question":"Using the adult rule of nines, approximately what TBSA is burned?","options":["About 18%","About 36%","About 50%","About 9%"],"correct":1,"explanation":"Anterior trunk = 18%, entire left arm = 9%, anterior of one leg = 9% (half of 18%), totaling approximately 36% TBSA. Only partial- and full-thickness burns are counted. This large burn warrants fluid resuscitation per protocol and burn-center transport.","clinicalPearl":"Memorize the rule of nines cold—accurate TBSA drives fluid resuscitation and triage decisions."},{"id":"c16_s03","title":"Electrical Injury","presentation":"A lineman contacted a high-voltage wire. He has a small charred entry wound on one hand and an exit wound on his foot, and he is now having palpitations. The scene has been confirmed safe by the power company.","vitals":{"hr":"irregular, 130 bpm","bp":"126/80 mmHg","rr":"20/min","spo2":"98%","skin":"small entry/exit wounds"},"question":"What is the key concern despite small-appearing skin wounds?","options":["The injury is minor because the skin wounds are small","Extensive deep tissue injury along the current path and cardiac dysrhythmias—apply cardiac monitoring and transport","Only a dressing is needed","Apply a traction splint"],"correct":1,"explanation":"Electrical injury causes deep tissue destruction along the current's path far beyond the visible entry/exit wounds, plus a high risk of dysrhythmias and cardiac arrest. Apply cardiac monitoring, treat dysrhythmias, anticipate rhabdomyolysis, and transport—ideally to a burn center.","clinicalPearl":"In electrical injury, the skin lies—deep tissue and the heart bear the real damage. Always monitor the rhythm."}]},"c17":{"chapter":"c17","cases":[{"id":"c17_s01","title":"The Deceptively Stable Child","presentation":"A 5-year-old struck by a car has a tender, bruised abdomen. He is quiet and pale with a fast heart rate, but his blood pressure reads 'normal' for his age.","vitals":{"hr":"158 bpm","bp":"92/64 mmHg","rr":"30/min","spo2":"97%","skin":"pale, cool"},"question":"How should you interpret his normal blood pressure?","options":["He is stable—no urgent concern","He is in compensated shock and can decompensate suddenly—treat aggressively and transport rapidly","He has neurogenic shock","Tachycardia in children is always benign"],"correct":1,"explanation":"Children maintain blood pressure until a large volume is lost, then crash. Marked tachycardia with pallor and cool skin signals compensated shock from likely intra-abdominal injury. Provide oxygen, obtain IV/IO access, give a weight-based fluid bolus per protocol, keep him warm, and transport rapidly to a pediatric trauma center.","clinicalPearl":"In children, a normal blood pressure with tachycardia is a warning, not reassurance—treat before hypotension appears."},{"id":"c17_s02","title":"Suspicious Injuries","presentation":"You are called for a 9-month-old who is 'not acting right.' The caregiver says the infant rolled off a couch, but you note bruises of differing colors on the back and a spiral arm fracture. The story keeps changing.","vitals":{"hr":"150 bpm","bp":"—","rr":"36/min","spo2":"98%","skin":"multiple bruises, varying ages"},"question":"What should you do?","options":["Confront and accuse the caregiver on scene","Provide appropriate medical care, document findings objectively, transport, and report suspected abuse per mandate","Ignore the injuries since the caregiver explained them","Refuse to transport"],"correct":1,"explanation":"Injuries inconsistent with the stated mechanism and developmental stage, bruises in different healing stages, a spiral fracture, and an inconsistent history are red flags for non-accidental trauma. Care for the child, document objectively without accusation, transport, and report per your mandatory-reporter obligations.","clinicalPearl":"Treat, document objectively, transport, and report—do not investigate or accuse. EMS providers are mandated reporters."},{"id":"c17_s03","title":"Pediatric Airway Positioning","presentation":"An unresponsive toddler with a head injury is placed flat on a backboard. You notice his large head flexes his neck forward and his breathing becomes noisy and partially obstructed.","vitals":{"hr":"140 bpm","bp":"—","rr":"noisy 26/min","spo2":"91%","gcs":"8"},"question":"What adjustment improves his airway and alignment?","options":["Place additional padding under his head","Pad under his torso/shoulders to bring the airway and spine into neutral alignment","Hyperextend the neck","Remove all immobilization"],"correct":1,"explanation":"A toddler's large occiput flexes the neck when supine on a flat board, obstructing the airway and malaligning the spine. Padding under the torso/shoulders restores a neutral 'sniffing' position, opening the airway while maintaining SMR.","clinicalPearl":"For young children, pad under the torso—not the head—to achieve neutral airway and spinal alignment."}]},"c18":{"chapter":"c18","cases":[{"id":"c18_s01","title":"Masked Shock on Beta-Blockers","presentation":"An 80-year-old fell down stairs and has a tender abdomen and pelvic pain. He looks pale and diaphoretic, but his heart rate is only 78 and his blood pressure is 118/76. His medication list includes metoprolol.","vitals":{"hr":"78 bpm","bp":"118/76 mmHg","rr":"22/min","spo2":"96%","skin":"pale, diaphoretic"},"question":"How should you interpret these vitals?","options":["He is stable—the heart rate and pressure are normal","His beta-blocker is masking compensatory tachycardia; pallor and diaphoresis suggest shock—treat aggressively and transport","He has neurogenic shock","He needs only reassurance"],"correct":1,"explanation":"Metoprolol blunts the tachycardic response, so a 'normal' heart rate is misleading. Pallor and diaphoresis with a concerning mechanism indicate shock from likely intra-abdominal/pelvic hemorrhage. Treat for shock, anticipate rapid decompensation, and transport to a trauma center.","clinicalPearl":"Don't trust the heart rate in a patient on beta-blockers or with a pacemaker—look at skin, mentation, and mechanism."},{"id":"c18_s02","title":"Minor Bump, Major Risk","presentation":"A 76-year-old on apixaban tripped and struck her head on a doorframe. She has a small forehead hematoma, is alert, and has a normal neurologic exam. She wants to refuse transport.","vitals":{"hr":"84 bpm","bp":"150/88 mmHg","rr":"16/min","spo2":"98%","gcs":"15"},"question":"What is the most appropriate guidance?","options":["Agree she is fine and clear her on scene","Explain the high risk of delayed intracranial bleeding on anticoagulants, strongly recommend transport, and monitor closely","Tell her head injuries never matter at her age","Give a fluid bolus and leave"],"correct":1,"explanation":"Anticoagulants greatly increase the risk of intracranial hemorrhage, which can be delayed even after a minor mechanism with a currently normal exam. Strongly recommend transport for evaluation/observation and document the discussion if she still declines.","clinicalPearl":"A normal exam does not exclude bleeding in an anticoagulated elder—delayed intracranial hemorrhage is the danger."},{"id":"c18_s03","title":"Immobilizing the Kyphotic Spine","presentation":"An 84-year-old with severe kyphosis needs spinal motion restriction after a fall. When laid flat on a rigid board, her head hangs well off the surface and she is in obvious distress.","vitals":{"hr":"88 bpm","bp":"140/82 mmHg","rr":"18/min","spo2":"97%","gcs":"15"},"question":"What is the correct technique?","options":["Strap her head down forcibly to meet the board","Pad the voids behind the head and back to support her natural curvature in a comfortable neutral position","Skip SMR entirely","Apply heavy traction to straighten the spine"],"correct":1,"explanation":"Forcing a kyphotic spine flat can cause injury and severe pain. Pad the gaps behind the head and back to maintain her baseline curvature in a comfortable, neutral position, and consider a conforming device for transport.","clinicalPearl":"Immobilize the elderly spine in its natural position—pad the curves, never force them flat."}]},"c19":{"chapter":"c19","cases":[{"id":"c19_s01","title":"Supine and Hypotensive","presentation":"A 32-week pregnant woman was in an MVC. She is immobilized flat and supine on a backboard and becomes lightheaded, pale, and hypotensive, though there is no obvious bleeding.","vitals":{"hr":"104 bpm","bp":"84/56 mmHg","rr":"20/min","spo2":"98%","skin":"pale"},"question":"What is the most likely cause and immediate action?","options":["Massive hemorrhage—give blood immediately","Supine hypotension syndrome—tilt the whole board 15–30 degrees to the left (or manually displace the uterus left)","Anxiety—reassure her","Spinal shock—give a vasopressor"],"correct":1,"explanation":"Hypotension that appears when a late-pregnancy patient is supine is classic supine hypotension syndrome from caval compression by the gravid uterus. Tilt the entire board 15–30 degrees to the left (maintaining SMR) or manually displace the uterus to the left to restore venous return—while still resuscitating and looking for hemorrhage.","clinicalPearl":"If a late-pregnancy patient drops her pressure when laid flat, tilt left first—it can be instantly corrective."},{"id":"c19_s02","title":"Possible Placental Abruption","presentation":"A 28-week pregnant woman was the restrained driver in a moderate collision. She reports abdominal pain and has noticed vaginal bleeding. Her uterus is tender and feels rigid.","vitals":{"hr":"112 bpm","bp":"110/70 mmHg","rr":"22/min","spo2":"98%","skin":"warm"},"question":"What condition should you suspect and how do you manage it?","options":["A simple bruise—reassure and release","Abruptio placenta—give oxygen, resuscitate the mother, tilt left, and transport rapidly to maternal/fetal care","Supine hypotension only","Preterm labor that needs no transport"],"correct":1,"explanation":"Vaginal bleeding, abdominal pain, and a tender/rigid uterus after trauma indicate possible placental abruption—a maternal and fetal emergency. Provide high-flow oxygen, resuscitate the mother (fluids), transport in left-tilt, and go to a facility capable of maternal and fetal care, even though maternal vitals are only mildly abnormal.","clinicalPearl":"Bleeding + pain + a rigid, tender uterus after trauma is abruption until proven otherwise—resuscitate the mother and move fast."},{"id":"c19_s03","title":"Reassuring Vitals, Worrying Mechanism","presentation":"A 34-week pregnant woman was a pedestrian struck at low speed. She feels 'fine' and her vital signs look normal, but she sustained a direct blow to the abdomen.","vitals":{"hr":"96 bpm","bp":"118/74 mmHg","rr":"18/min","spo2":"99%","skin":"normal"},"question":"What is the appropriate disposition?","options":["Clear her on scene since she feels fine","Transport for evaluation despite normal vitals, because abruption and fetal compromise can occur with few external signs","Tell her pregnancy protects against injury","Only treat if she develops bleeding"],"correct":1,"explanation":"Normal maternal vitals are reassuring but not definitive—the mother's expanded volume masks early shock, and placental abruption can occur without external signs. A direct abdominal blow in late pregnancy warrants oxygen, left-tilt transport, and evaluation at a maternal/fetal-capable facility.","clinicalPearl":"In pregnancy, the mechanism outranks reassuring vitals—evaluate even when she looks well."}]},"c20":{"chapter":"c20","cases":[{"id":"c20_s01","title":"Not Just Drunk","presentation":"A man found outside a bar smells of alcohol and is slurring his words. Bystanders say he 'just had too much.' On exam you note a boggy scalp hematoma, and his level of consciousness is worsening over a few minutes.","vitals":{"hr":"58 bpm","bp":"176/98 mmHg","rr":"12/min","spo2":"95%","gcs":"11 and falling"},"question":"What is the most appropriate interpretation and action?","options":["He is simply intoxicated—let him sleep it off","Suspect a serious head injury (the bradycardia, hypertension, scalp hematoma, and falling GCS) despite alcohol—manage as TBI and transport rapidly","Restrain him prone and wait","Withhold oxygen"],"correct":1,"explanation":"Alcohol odor does not explain a boggy scalp hematoma, bradycardia, hypertension, and a declining GCS—these suggest an expanding intracranial injury (Cushing's reflex). Never attribute deterioration to intoxication; check glucose, support the airway/oxygenation, and transport as a head injury.","clinicalPearl":"The smell of alcohol is not a diagnosis—an intoxicated patient who deteriorates has a head injury until proven otherwise."},{"id":"c20_s02","title":"Excited Delirium","presentation":"Police request EMS for a man who is violently agitated, paranoid, sweating profusely, and stripping off his clothes after suspected stimulant use. He shows remarkable strength and his skin is hot to the touch.","vitals":{"hr":"150 bpm","bp":"168/96 mmHg","rr":"30/min","spo2":"—","skin":"hot, diaphoretic"},"question":"What is the correct approach?","options":["Restrain him prone and leave him face-down until he tires","Recognize excited delirium as a medical emergency—coordinate rapid control, sedate per protocol, cool him, oxygenate, and monitor continuously","Ignore it; he will calm down","Withhold all treatment"],"correct":1,"explanation":"Extreme agitation, paranoia, hyperthermia, and apparent superhuman strength after stimulant use indicate excited delirium, which can progress to sudden cardiovascular collapse. Treat it as a medical emergency: rapid, coordinated control, sedation per protocol, active cooling, oxygenation, and continuous monitoring—never prolonged prone restraint.","clinicalPearl":"Excited delirium kills—treat the hyperthermia and agitation aggressively, and never restrain the patient prone."},{"id":"c20_s03","title":"Restraint Done Safely","presentation":"An impaired, combative trauma patient must be restrained for the safety of himself and the crew so you can manage a bleeding head wound.","vitals":{"hr":"118 bpm","bp":"138/84 mmHg","rr":"20/min","spo2":"96%","gcs":"13"},"question":"Which restraint practice is correct?","options":["Place him prone in a hog-tie position","Restrain him supine or on his side, never compromising breathing, and continuously reassess his airway and circulation","Restrain and stop monitoring","Use the tightest possible restraints and leave him"],"correct":1,"explanation":"Restraint is appropriate only for safety and must be applied humanely without compromising breathing—never prone or hog-tied (positional asphyxia risk). Restrain supine or lateral, monitor continuously, and reassess airway, breathing, and circulation throughout.","clinicalPearl":"Safe restraint is never prone—position to protect breathing and keep monitoring the patient continuously."}]},"c21":{"chapter":"c21","cases":[{"id":"c21_s01","title":"Arrest After Chest Trauma","presentation":"A young man stabbed in the chest loses his pulse as you arrive. He has absent breath sounds on the left, and CPR is started. There were signs of life moments ago.","vitals":{"hr":"0 (PEA)","bp":"—","rr":"apneic","spo2":"—","skin":"cyanotic"},"question":"Beyond compressions, what is the most important immediate intervention?","options":["Give antiarrhythmic drugs and analyze the rhythm repeatedly","Address reversible causes—secure the airway/oxygenate and perform bilateral chest decompression, control hemorrhage, and transport rapidly for surgery","Apply a traction splint","Terminate resuscitation immediately"],"correct":1,"explanation":"Traumatic arrest from chest trauma is driven by reversible mechanical causes. Secure the airway and oxygenate, perform bilateral needle decompression for likely tension pneumothorax, control hemorrhage, and transport immediately—penetrating arrest with recent signs of life may be salvageable with surgery.","clinicalPearl":"In traumatic arrest, fix the cause: decompress the chest, control bleeding, oxygenate—then transport fast. Rhythm-and-drugs is not the answer."},{"id":"c21_s02","title":"Choking Collapse","presentation":"A man at a restaurant suddenly clutches his throat, cannot speak or breathe, and then collapses unconscious. Bystanders had seen him eating steak.","vitals":{"hr":"weak then absent","bp":"—","rr":"obstructed then apneic","spo2":"falling","skin":"cyanotic"},"question":"What is the correct management once he is unconscious?","options":["Only apply oxygen by mask","Begin CPR, look for and remove a visualized obstruction, and consider laryngoscopy with Magill forceps","Apply abdominal thrusts while he lies motionless and do nothing else","Declare him unsalvageable"],"correct":1,"explanation":"Foreign-body airway obstruction causes a rapidly reversible hypoxic arrest. For the unconscious patient, begin CPR, inspect the mouth and remove a visualized object, and consider direct laryngoscopy with Magill forceps to extract the obstruction—relieving it can immediately reverse the arrest.","clinicalPearl":"FBAO arrest is one of the most reversible arrests there is—clear the airway and the patient can recover instantly."},{"id":"c21_s03","title":"Obvious Death","presentation":"You arrive at a high-speed crash to find an occupant with injuries obviously incompatible with life—decapitation. Another bystander urges you to 'do everything.'","vitals":{"hr":"0","bp":"—","rr":"apneic","spo2":"—","skin":"—"},"question":"What is the appropriate action?","options":["Begin full resuscitation regardless","Withhold resuscitation per protocol for injuries obviously incompatible with life, and support the scene/family appropriately","Transport with CPR in progress","Decide entirely on your own without any protocol"],"correct":1,"explanation":"Injuries obviously incompatible with life (such as decapitation) are criteria for withholding resuscitation under protocol. Resuscitation would be futile; follow local protocol, document carefully, and manage the scene and family compassionately.","clinicalPearl":"Recognize the unsalvageable patient—withholding resuscitation per protocol for injuries incompatible with life is appropriate and compassionate care."}]},"c22":{"chapter":"c22","cases":[{"id":"c22_s01","title":"Needlestick After an IV","presentation":"While starting an IV on a bleeding trauma patient of unknown history, you sustain a needlestick to your finger. The patient's infection status is unknown.","vitals":{"hr":"—","bp":"—","rr":"—","spo2":"—","skin":"small puncture, bleeding"},"question":"What is the correct immediate sequence of actions?","options":["Ignore it and finish the shift","Wash the site with soap and water, report the exposure per protocol, and seek prompt evaluation including consideration of HIV PEP","Apply a tourniquet to your arm","Wait several days to see if symptoms develop"],"correct":1,"explanation":"A needlestick is a true bloodborne exposure. Immediately wash the site with soap and water, report per protocol, and seek prompt evaluation. HIV post-exposure prophylaxis is time-sensitive and most effective when started as soon as possible; hepatitis B status and testing are addressed based on your vaccination status.","clinicalPearl":"Wash, report, evaluate—and remember HIV PEP works best within hours. Never sit on an exposure."},{"id":"c22_s02","title":"Choosing the Right Precautions","presentation":"You respond to a patient with several weeks of cough, fever, night sweats, and weight loss who lives in a shelter. He is coughing frequently in the back of your ambulance.","vitals":{"hr":"98 bpm","bp":"124/78 mmHg","rr":"20/min","spo2":"96%","skin":"thin, diaphoretic"},"question":"Which precautions are most appropriate?","options":["Standard precautions only","Airborne precautions—fit-tested N95 for you and a surgical mask on the patient—because of suspected tuberculosis","Contact precautions only","No precautions needed"],"correct":1,"explanation":"Chronic cough with fever, night sweats, and weight loss in a high-risk setting suggests tuberculosis, which is spread by the airborne route. Don a fit-tested N95 respirator, place a surgical mask on the patient, and ventilate the patient compartment—standard precautions alone are insufficient.","clinicalPearl":"Match the precaution to the route: suspected TB means airborne precautions—N95 for you, surgical mask for the patient."},{"id":"c22_s03","title":"Splash Risk During Active Hemorrhage","presentation":"You are managing a patient with a spurting arterial wound and active airway bleeding. There is significant potential for blood splash to your face and eyes.","vitals":{"hr":"128 bpm","bp":"92/60 mmHg","rr":"24/min","spo2":"95%","skin":"actively bleeding"},"question":"What PPE level is appropriate?","options":["Gloves alone are sufficient","Gloves plus face/eye protection and a gown, because splashing of blood and OPIM is likely","No PPE is needed if you work quickly","Only a surgical mask"],"correct":1,"explanation":"When splashing of blood or other potentially infectious materials is likely, standard precautions escalate to include face/eye protection and a gown in addition to gloves and hand hygiene. Active arterial and airway bleeding clearly warrant full barrier protection.","clinicalPearl":"Standard precautions scale to the risk—when blood can splash, protect your eyes, face, and body, not just your hands."}]}},"algorithms":{"c01":{"chapter":"c01","algorithms":[{"id":"c01_alg01","title":"Scene Size-Up Algorithm","description":"The scene size-up is the first step in the ITLS Primary survey and involves taking standard precautions, evaluating the scene for dangers, determining the total number of patients, identifying essential equipment needed, and assessing the mechanism of injury.","steps":["Take standard precautions to prevent exposure to blood and other potentially infectious material (OPIM).","Evaluate the scene for potential hazards such as fire, toxic substances, unstable structures, low oxygen levels, or other dangers.","Determine the total number of patients present at the scene.","Identify essential equipment needed based on the type of incident and number of patients.","Assess the mechanism of injury (MOI) to predict potential injuries. Consider the direction and speed of impact, patient kinetics, and signs of energy release.","If necessary, call for additional resources or special equipment."]}]}},"tables":{"c01":{"chapter":"c01","tables":[{"id":"c01_t01","title":"Table 1-1: ITLS Patient Assessment","headers":["ITLS Primary Survey","Perform a scene size-up","Perform initial assessment","Perform a rapid trauma survey or focused exam","Make critical interventions and transport decision","Contact medical direction"],"rows":[["ITLS Secondary Survey","Repeat initial assessment","Repeat vital signs and consider monitors","Perform a neurological exam","Perform a detailed (head-to-toe) exam"]]},{"id":"c01_t02","title":"Table 1-3: Mechanisms of Injury and Potential Injury Patterns","headers":["Mechanisms of Injury","Potential Injury Patterns"],"rows":[["Frontal impact","Deformed steering wheel, dashboard knee imprints, spider-web deformity of windscreen, cervical-spine fracture, flail chest, myocardial contusion, pneumothorax, aortic disruption, spleen or liver laceration, posterior hip dislocation, knee dislocation"],["Lateral impact (T-bone)","Contralateral neck sprain, cervical-spine fracture, lateral flail chest, pneumothorax, aortic disruption, diaphragmatic rupture, laceration of spleen, liver, kidney, pelvic fracture"],["Rear impact","Cervical-spine injury"],["Ejection","Exposure to all mechanisms and mortality increased"],["Pedestrian vs. car","Head injury, aortic disruption, abdominal visceral injuries, fracture lower extremities and pelvis"]]},{"id":"c01_t03","title":"Table 1-4: Basic Mechanisms of Motion Injury","headers":["Blunt Injuries","Penetrating Injuries"],"rows":[["Rapid forward deceleration (collisions)","Projectiles, knives, falls on fixed objects"]]}]}}};
